  app.post<{
    Params: { campaignId: string };
    Querystring: { sceneId?: string; setAsBackground?: string };
    Body: Buffer;
  }>("/api/v1/campaigns/:campaignId/assets/upload", async (request, reply) => {
    const allowed = requireCampaignPermission(store, reply, request.headers, request.params.campaignId, "scene.create");
    if (allowed !== true) return allowed;
    const userId = currentUserId(store, request.headers)!;
    const shouldSetBackground = request.query.sceneId && truthyQuery(request.query.setAsBackground);
    if (shouldSetBackground) {
      const sceneUpdateAllowed = requireCampaignPermission(store, reply, request.headers, request.params.campaignId, "scene.update");
      if (sceneUpdateAllowed !== true) return sceneUpdateAllowed;
    }
    const body = Buffer.isBuffer(request.body) ? request.body : Buffer.from([]);
    if (body.length === 0) return reply.code(400).send({ error: "empty_upload", message: "Asset upload body is empty" });
    if (body.length > maxAssetBytes)
      return reply.code(413).send({
        error: "asset_too_large",
        message: `Asset exceeds ${maxAssetBytes} bytes`
      });
    const mimeType = normalizeAssetMimeType(request.headers["content-type"]);
    const sourceName = displayNameFromHeader(request.headers["x-asset-name"]) ?? "Uploaded Map";
    const folder = normalizeAssetFolder(headerText(request.headers["x-asset-folder"]));
    const tags = normalizeAssetTags(headerText(request.headers["x-asset-tags"]));
    const scan = await scanUploadedAsset(body, mimeType, sourceName);
    if (scan.blocked) return assetSecurityBlocked(reply, scan);
    const quotaExceeded = assetQuotaExceeded(store, request.params.campaignId, body.length);
    if (quotaExceeded) return reply.code(413).send(quotaExceeded);
    const checksum = checksumForBuffer(body);
    const scene = shouldSetBackground ? store.state.scenes.find((item) => item.id === request.query.sceneId && item.campaignId === request.params.campaignId) : undefined;
    if (shouldSetBackground && !scene) return notFound(reply, "Scene not found");
    const asset: MapAsset = createTimestamped("asset", {
      campaignId: request.params.campaignId,
      name: sourceName,
      url: "",
      mimeType,
      sizeBytes: body.length,
      checksum,
      folder,
      tags,
      lifecycle: defaultAssetLifecycle(),
      security: scan.security
    });
    asset.storage = await assetStorage.put(asset, body);
    asset.url = `/api/v1/assets/${asset.id}/blob`;
    store.state.assets.push(asset);

    if (scene) {
      scene.backgroundAssetId = asset.id;
      scene.updatedAt = nowIso();
    }

    appendServerAuditLog(store, userId, {
      campaignId: asset.campaignId,
      action: "asset.upload",
      targetType: "asset",
      targetId: asset.id,
      after: {
        ...assetAuditSummary(asset),
        sceneId: scene?.id,
        setAsBackground: Boolean(scene)
      }
    });
    store.save();
    broadcast(createEvent({ campaignId: asset.campaignId, type: "asset.created", actorUserId: userId, targetId: asset.id, payload: asset }));
    if (scene)
      broadcast(
        createEvent({
          campaignId: scene.campaignId,
          type: "scene.updated",
          targetId: scene.id,
          payload: scene
        })
      );
    return { asset, scene };
  });

  app.patch<{ Params: { assetId: string }; Body: { name?: string; folder?: string | null; tags?: string[] | string } }>("/api/v1/assets/:assetId", async (request, reply) => {
    const body = request.body ?? {};
    const asset = store.state.assets.find((item) => item.id === request.params.assetId);
    if (!asset) return notFound(reply, "Asset not found");
    const userId = requireUser(store, reply, request.headers);
    if (typeof userId !== "string") return userId;
    const allowed = requireCampaignPermissionForUser(store, reply, request.headers, userId, asset.campaignId, "scene.update");
    if (allowed !== true) return allowed;
    const before = assetAuditSummary(asset);
    if (typeof body.name === "string" && body.name.trim()) asset.name = body.name.trim().slice(0, 160);
    if (body.folder !== undefined) asset.folder = normalizeAssetFolder(body.folder);
    if (body.tags !== undefined) asset.tags = normalizeAssetTags(body.tags);
    asset.updatedAt = nowIso();
    appendServerAuditLog(store, userId, {
      campaignId: asset.campaignId,
      action: "asset.update",
      targetType: "asset",
      targetId: asset.id,
      before,
      after: assetAuditSummary(asset)
    });
    store.save();
    broadcast(createEvent({ campaignId: asset.campaignId, type: "asset.updated", actorUserId: userId, targetId: asset.id, payload: asset }));
    return asset;
  });

  app.post<{ Params: { assetId: string }; Body: { expiresInSeconds?: number; disposition?: "inline" | "attachment" } }>("/api/v1/assets/:assetId/delivery-url", async (request, reply) => {
    const body = request.body ?? {};
    const asset = store.state.assets.find((item) => item.id === request.params.assetId);
    if (!asset) return notFound(reply, "Asset not found");
    if (!isAssetDeliverable(asset)) return assetUnavailable(reply, asset);
    const allowed = requireCampaignPermission(store, reply, request.headers, asset.campaignId, "scene.read");
    if (allowed !== true) return allowed;
    const userId = currentUserId(store, request.headers)!;
    if (!canReadAssetRecord(store, userId, asset)) return notFound(reply, "Asset not found");
    try {
      return signedAssetDelivery(asset, request.headers, body.expiresInSeconds, body.disposition);
    } catch (error) {
      appendAssetDeliveryAuditLog(store, asset, { status: "signing_failed", accessMode: "signed", reason: errorMessage(error) });
      store.save();
      return reply.code(500).send({ error: "asset_signing_unavailable", message: errorMessage(error) });
    }
  });

  app.patch<{ Params: { assetId: string }; Body: { status?: "active" | "archived" | "deleted"; expiresAt?: string | null; reason?: string } }>("/api/v1/assets/:assetId/lifecycle", async (request, reply) => {
    const body = request.body ?? {};
    const asset = store.state.assets.find((item) => item.id === request.params.assetId);
    if (!asset) return notFound(reply, "Asset not found");
    const userId = requireUser(store, reply, request.headers);
    if (typeof userId !== "string") return userId;
    const allowed = requireCampaignPermissionForUser(store, reply, request.headers, userId, asset.campaignId, "scene.update");
    if (allowed !== true) return allowed;
    const status = normalizeAssetLifecycleStatus(body.status);
    if (!status) return badRequest(reply, "Asset lifecycle status must be active, archived, or deleted");
    const expiresAt = normalizeOptionalIsoDate(body.expiresAt);
    if (body.expiresAt !== undefined && body.expiresAt !== null && !expiresAt) return badRequest(reply, "expiresAt must be an ISO date");
    const before = assetAuditSummary(asset);
    asset.lifecycle = {
      status,
      expiresAt,
      updatedAt: nowIso(),
      updatedByUserId: userId,
      reason: body.reason?.trim().slice(0, 160)
    };
    asset.updatedAt = nowIso();
    appendServerAuditLog(store, userId, {
      campaignId: asset.campaignId,
      action: status === "deleted" ? "asset.delete" : "asset.lifecycle.update",
      targetType: "asset",
      targetId: asset.id,
      before,
      after: assetAuditSummary(asset)
    });
    store.save();
    broadcast(
      createEvent({
        campaignId: asset.campaignId,
        type: status === "deleted" ? "asset.deleted" : "asset.updated",
        actorUserId: userId,
        targetId: asset.id,
        payload: asset
      })
    );
    return asset;
  });

  app.get<{ Params: { assetId: string }; Querystring: { userId?: string; sessionToken?: string; expiresAt?: string; signature?: string; disposition?: "inline" | "attachment" } }>("/api/v1/assets/:assetId/blob", async (request, reply) => {
    const asset = store.state.assets.find((item) => item.id === request.params.assetId);
    if (!asset) return notFound(reply, "Asset not found");
    const accessMode = request.query.signature ? "signed" : "session";
    if (!isAssetDeliverable(asset)) {
      appendAssetDeliveryAuditLog(store, asset, {
        status: "unavailable",
        accessMode,
        reason: asset.lifecycle?.status === "deleted" ? "deleted" : "expired_or_deleted",
        lifecycleStatus: asset.lifecycle?.status ?? "active"
      });
      return assetUnavailable(reply, asset);
    }
    const signedAccess = isValidAssetSignature(asset.id, request.query.expiresAt, request.query.signature, request.query.disposition);
    if (!signedAccess) {
      const userId = userIdFromRequest(store, request.url, request.headers);
      if (!userId) {
        appendAssetDeliveryAuditLog(store, asset, { status: "denied", accessMode, reason: "missing_session" });
        return unauthorized(reply, "Missing asset session");
      }
      const allowed = requireCampaignPermissionForUser(store, reply, headersWithRequestSessionToken(request.url, request.headers), userId, asset.campaignId, "scene.read");
      if (allowed !== true) {
        appendAssetDeliveryAuditLog(store, asset, { status: "denied", accessMode, reason: "missing_permission_or_active_organization" });
        return allowed;
      }
      if (!canReadAssetRecord(store, userId, asset)) {
        appendAssetDeliveryAuditLog(store, asset, { status: "denied", accessMode, reason: "asset_not_visible" });
        return notFound(reply, "Asset not found");
      }
    }
    const cacheControl = signedAccess ? signedAssetCacheControl(request.query.expiresAt) : "private, max-age=60";
    const contentDisposition = request.query.disposition === "attachment" ? `attachment; filename="${safeDownloadFileName(asset.name)}"` : undefined;
    if (!asset.storage) {
      appendAssetDeliveryAuditLog(store, asset, { status: "missing_bytes", accessMode: signedAccess ? "signed" : "session", reason: "asset_storage_reference_missing" });
      return notFound(reply, "Asset file not found");
    }
    const stream = await assetStorage.stream?.(asset);
    if (contentDisposition) reply.header("content-disposition", contentDisposition);
    if (stream) {
      appendAssetDeliveryAuditLog(store, asset, { status: "served", accessMode: signedAccess ? "signed" : "session", bytes: asset.sizeBytes, cacheControl });
      return reply.header("content-type", asset.mimeType).header("cache-control", cacheControl).send(stream);
    }
    const body = await assetStorage.read(asset);
    if (!body) {
      appendAssetDeliveryAuditLog(store, asset, { status: "missing_bytes", accessMode: signedAccess ? "signed" : "session", reason: "asset_file_not_found" });
      return notFound(reply, "Asset file not found");
    }
    appendAssetDeliveryAuditLog(store, asset, { status: "served", accessMode: signedAccess ? "signed" : "session", bytes: body.length, cacheControl });
    return reply.header("content-type", asset.mimeType).header("cache-control", cacheControl).send(body);
  });

