  app.post<{ Params: { sceneId: string } }>("/api/v1/scenes/:sceneId/fog/undo", async (request, reply) => {
    const campaignId = campaignIdForScene(store, request.params.sceneId);
    if (!campaignId) return notFound(reply, "Scene not found");
    const userId = requireUser(store, reply, request.headers);
    if (typeof userId !== "string") return userId;
    const allowed = requireCampaignPermissionForUser(store, reply, request.headers, userId, campaignId, "token.reveal");
    if (allowed !== true) return allowed;
    const scene = store.state.scenes.find((item) => item.id === request.params.sceneId)!;
    const target = latestUndoableFogHistoryEntry(scene);
    if (!target) return badRequest(reply, "No fog history to undo");

    let before: FogRegion | undefined;
    let after: FogRegion | undefined;
    if (target.action === "create") {
      const index = scene.fog.findIndex((region) => region.id === target.fogId);
      if (index < 0) return badRequest(reply, "Fog history entry is no longer undoable");
      before = cloneFogRegion(scene.fog[index]!);
      scene.fog.splice(index, 1);
    } else if (target.region) {
      if (scene.fog.some((region) => region.id === target.fogId)) return badRequest(reply, "Fog history entry is no longer undoable");
      after = cloneFogRegion(target.region);
      scene.fog.push(after);
    } else {
      return badRequest(reply, "Fog history entry is missing its region snapshot");
    }

    const undoEntry = appendFogHistoryEntry(scene, {
      sceneId: scene.id,
      action: "undo",
      fogId: target.fogId,
      actorUserId: userId,
      region: before ?? after,
      targetHistoryId: target.id
    });
    appendServerAuditLog(store, userId, {
      campaignId,
      action: "scene.fog.undo",
      targetType: "fog",
      targetId: target.fogId,
      before,
      after: { sceneId: scene.id, restored: after, targetHistoryId: target.id, undoHistoryId: undoEntry.id }
    });
    scene.updatedAt = nowIso();
    store.save();
    broadcast(
      createEvent({
        campaignId: scene.campaignId,
        type: "scene.updated",
        actorUserId: userId,
        targetId: scene.id,
        payload: scene
      })
    );
    return scene;
  });

  app.post<{ Params: { sceneId: string }; Body: { presetId?: string; mode?: "append" | "replace" } }>("/api/v1/scenes/:sceneId/fog/apply-preset", async (request, reply) => {
    const body = request.body ?? {};
    const campaignId = campaignIdForScene(store, request.params.sceneId);
    if (!campaignId) return notFound(reply, "Scene not found");
    const userId = requireUser(store, reply, request.headers);
    if (typeof userId !== "string") return userId;
    const allowed = requireCampaignPermissionForUser(store, reply, request.headers, userId, campaignId, "token.reveal");
    if (allowed !== true) return allowed;
    const preset = store.state.fogPresets.find((item) => item.id === body.presetId && item.campaignId === campaignId);
    if (!preset) return notFound(reply, "Fog preset not found");
    const scene = store.state.scenes.find((item) => item.id === request.params.sceneId)!;
    const mode = body.mode === "replace" ? "replace" : "append";
    const removedRegions = mode === "replace" ? scene.fog.map(cloneFogRegion) : [];
    if (mode === "replace") {
      for (const region of removedRegions) {
        appendFogHistoryEntry(scene, {
          sceneId: scene.id,
          action: "delete",
          fogId: region.id,
          actorUserId: userId,
          region
        });
      }
      scene.fog = [];
    }
    const appliedRegions = preset.regions.map((region) => ({ id: createId("fog"), ...cloneFogPresetRegion(region) }) satisfies FogRegion);
    for (const region of appliedRegions) {
      scene.fog.push(region);
      appendFogHistoryEntry(scene, {
        sceneId: scene.id,
        action: "create",
        fogId: region.id,
        actorUserId: userId,
        region
      });
    }
    appendServerAuditLog(store, userId, {
      campaignId,
      action: "scene.fogPreset.apply",
      targetType: "fogPreset",
      targetId: preset.id,
      before: { sceneId: scene.id, removedRegionCount: removedRegions.length },
      after: { sceneId: scene.id, mode, appliedRegionCount: appliedRegions.length, presetName: preset.name }
    });
    scene.updatedAt = nowIso();
    store.save();
    broadcast(
      createEvent({
        campaignId: scene.campaignId,
        type: "scene.updated",
        actorUserId: userId,
        targetId: scene.id,
        payload: scene
      })
    );
    return scene;
  });

