function readAccountToolOutput(context: AiToolContext): unknown {
  const user = context.state.users.find((item) => item.id === context.userId);
  if (!user) return toolError("not_found", { entity: "user", id: context.userId });
  const sessions = context.state.sessions.filter((session) => session.userId === context.userId);
  const identities = context.state.identities.filter((identity) => identity.userId === context.userId);
  return {
    user: redactedUserToolSummary(user),
    mfa: {
      totpEnabled: Boolean(user.mfa?.totpEnabledAt),
      recoveryCodeCount: user.mfa?.recoveryCodeHashes?.length ?? 0
    },
    sessions: {
      count: sessions.length,
      recent: sessions
        .slice()
        .sort((left, right) => right.updatedAt.localeCompare(left.updatedAt))
        .slice(0, 5)
        .map((session) => ({
          id: session.id,
          createdAt: session.createdAt,
          updatedAt: session.updatedAt,
          expiresAt: session.expiresAt,
          lastSeenAt: session.lastSeenAt,
          activeOrganizationId: session.activeOrganizationId
        }))
    },
    identities: identities.map((identity) => ({
      id: identity.id,
      provider: identity.provider,
      issuer: identity.issuer,
      subject: identity.subject,
      email: identity.email,
      createdAt: identity.createdAt,
      updatedAt: identity.updatedAt
    })),
    campaignMemberships: context.state.members
      .filter((member) => member.userId === context.userId)
      .map((member) => ({ campaignId: member.campaignId, role: member.role, createdAt: member.createdAt, updatedAt: member.updatedAt }))
  };
}

function readWorkspaceToolOutput(context: AiToolContext): unknown {
  const campaign = context.state.campaigns.find((item) => item.id === context.campaignId);
  if (!campaign) return toolError("not_found", { entity: "campaign", id: context.campaignId });
  const organization = context.state.organizations.find((item) => item.id === campaign.organizationId);
  const members = organization ? context.state.organizationMembers.filter((member) => member.organizationId === organization.id) : [];
  const callerMembership = members.find((member) => member.userId === context.userId);
  const canManageWorkspace = Boolean(
    organization?.ownerUserId === context.userId || callerMembership?.role === "owner" || callerMembership?.role === "admin",
  );
  const visibleMembers = canManageWorkspace ? members : members.filter((member) => member.userId === context.userId);
  return {
    organization: organization
      ? {
          id: organization.id,
          name: organization.name,
          ownerUserId: organization.ownerUserId,
          defaultSystemId: organization.defaultSystemId,
          defaultCampaignVisibility: organization.defaultCampaignVisibility,
          defaultPermissionTemplate: organization.defaultPermissionTemplate,
          defaultInviteRole: organization.defaultInviteRole,
          defaultSceneName: organization.defaultSceneName,
          defaultSceneFolder: organization.defaultSceneFolder,
          defaultSceneWidth: organization.defaultSceneWidth,
          defaultSceneHeight: organization.defaultSceneHeight,
          defaultSceneGridSize: organization.defaultSceneGridSize,
          createdAt: organization.createdAt,
          updatedAt: organization.updatedAt
        }
      : undefined,
    members: visibleMembers.map((member) => ({
      id: member.id,
      userId: member.userId,
      role: member.role,
      user: rosterUserToolSummary(context.state.users.find((user) => user.id === member.userId)),
      createdAt: member.createdAt,
      updatedAt: member.updatedAt
    })),
    memberCount: visibleMembers.length
  };
}

function readCampaignToolOutput(context: AiToolContext): unknown {
  const campaign = context.state.campaigns.find((item) => item.id === context.campaignId);
  if (!campaign) return toolError("not_found", { entity: "campaign", id: context.campaignId });
  const canViewPrep = proposalPermissionsIncludePrepAccess(context.permissions);
  const scenes = context.state.scenes.filter((scene) => scene.campaignId === campaign.id && (canViewPrep || scene.active));
  const sceneIds = new Set(scenes.map((scene) => scene.id));
  const proposals = visibleProposalsForUser(context.state, context.userId, campaign.id, context.permissions);
  const members = context.state.members.filter((member) => member.campaignId === campaign.id);
  const canManageCampaign = context.permissions.includes("campaign.update");
  return {
    campaign: {
      id: campaign.id,
      organizationId: campaign.organizationId,
      name: campaign.name,
      description: campaign.description,
      visibility: campaign.visibility,
      defaultSystemId: campaign.defaultSystemId,
      archivedAt: campaign.archivedAt,
      createdAt: campaign.createdAt,
      updatedAt: campaign.updatedAt
    },
    permissions: [...context.permissions].sort(),
    activeScene: scenes.find((scene) => scene.active)
      ? {
          id: scenes.find((scene) => scene.active)?.id,
          name: scenes.find((scene) => scene.active)?.name
        }
      : undefined,
    counts: {
      members: members.length,
      invites: canManageCampaign ? context.state.invites.filter((invite) => invite.campaignId === campaign.id && inviteStatus(invite) === "pending").length : undefined,
      scenes: scenes.length,
      ...(canViewPrep
        ? {
            aiEditLayers: scenes.filter((scene) => scene.folder === AI_EDIT_SCENE_FOLDER).length,
            tokens: context.state.tokens.filter((token) => sceneIds.has(token.sceneId)).length,
            actors: context.state.actors.filter((actor) => actor.campaignId === campaign.id).length,
            items: context.state.items.filter((item) => item.campaignId === campaign.id).length,
            journals: context.state.journals.filter((journal) => journal.campaignId === campaign.id).length,
            assets: context.state.assets.filter((asset) => asset.campaignId === campaign.id).length,
            encounters: context.state.encounters.filter((encounter) => encounter.campaignId === campaign.id).length,
            combats: context.state.combats.filter((combat) => combat.campaignId === campaign.id).length,
          }
        : {}),
      proposals: proposals.length
    },
    members: members.map((member) => ({
      id: member.id,
      userId: member.userId,
      role: member.role,
      user: rosterUserToolSummary(context.state.users.find((user) => user.id === member.userId)),
      createdAt: member.createdAt,
      updatedAt: member.updatedAt
    })),
    invites: canManageCampaign
      ? context.state.invites
          .filter((invite) => invite.campaignId === campaign.id)
          .map((invite) => ({
            id: invite.id,
            email: invite.email,
            role: invite.role,
            status: inviteStatus(invite),
            expiresAt: invite.expiresAt,
            createdAt: invite.createdAt,
            updatedAt: invite.updatedAt
          }))
      : undefined,
    aiEditLayers: canViewPrep
      ? scenes
          .filter((scene) => scene.folder === AI_EDIT_SCENE_FOLDER)
          .map((scene) => ({
            id: scene.id,
            name: scene.name,
            targetSceneId: stringFromRecord(scene.metadata, "targetSceneId"),
            backgroundAssetId: scene.backgroundAssetId,
            tokenCount: context.state.tokens.filter((token) => token.sceneId === scene.id).length,
            updatedAt: scene.updatedAt
          }))
      : [],
    proposalStatusCounts: countBy(proposals, (proposal) => proposal.status)
  };
}

function readWorldToolOutput(context: AiToolContext, input: { worldId?: string; query: string; limit: number }): unknown {
  const normalizedQuery = input.query.toLocaleLowerCase();
  const worlds = context.state.worlds
    .filter((world) => world.campaignId === context.campaignId)
    .filter((world) => !input.worldId || world.id === input.worldId)
    .filter((world) => !normalizedQuery || world.name.toLocaleLowerCase().includes(normalizedQuery) || world.description.toLocaleLowerCase().includes(normalizedQuery))
    .sort((left, right) => left.name.localeCompare(right.name) || left.id.localeCompare(right.id))
    .slice(0, input.limit)
    .map((world) => ({ ...world }));
  if (input.worldId && worlds.length === 0) return toolError("not_found", { entity: "world", id: input.worldId });
  return { worldId: input.worldId, query: input.query, count: worlds.length, worlds };
}

function readHandoutToolOutput(context: AiToolContext, input: { handoutId?: string; query: string; limit: number }): unknown {
  const store = readOnlyToolStore(context);
  const normalizedQuery = input.query.toLocaleLowerCase();
  const handouts = context.state.handouts
    .map((handout) => normalizeHandout(handout))
    .filter((handout) => handout.campaignId === context.campaignId && canReadHandout(store, context.userId, handout))
    .filter((handout) => !input.handoutId || handout.id === input.handoutId)
    .filter((handout) => !normalizedQuery || handout.title.toLocaleLowerCase().includes(normalizedQuery) || handout.body.toLocaleLowerCase().includes(normalizedQuery) || handout.tags.some((tag) => tag.toLocaleLowerCase().includes(normalizedQuery)))
    .sort((left, right) => right.updatedAt.localeCompare(left.updatedAt) || left.title.localeCompare(right.title))
    .slice(0, input.limit)
    .map((handout) => ({ ...handout, visibleToUserIds: [...handout.visibleToUserIds], visibleToActorIds: [...handout.visibleToActorIds], assetIds: [...handout.assetIds], tags: [...handout.tags], readByUserIds: [...handout.readByUserIds] }));
  if (input.handoutId && handouts.length === 0) return toolError("not_found", { entity: "handout", id: input.handoutId });
  return { handoutId: input.handoutId, query: input.query, count: handouts.length, handouts };
}

function searchCampaignToolOutput(context: AiToolContext, input: { query: string; types: string[]; worldId?: string; limit: number }): unknown {
  const query = input.query.trim();
  if (!query || query.length > 200) return toolError("invalid_tool_input", { message: "query must be 1-200 characters" });
  const normalizedTypes = normalizeCampaignSearchTypes(input.types.length > 0 ? input.types.join(",") : undefined);
  if (!normalizedTypes.ok) return toolError("invalid_tool_input", { message: normalizedTypes.error });
  if (
    input.worldId &&
    (!context.permissions.includes("world.read") ||
      !context.state.worlds.some((world) => world.id === input.worldId && world.campaignId === context.campaignId))
  ) {
    return toolError("not_found", { entity: "world", id: input.worldId });
  }
  const results = campaignSearchResults(readOnlyToolStore(context), context.userId, context.campaignId, query, normalizedTypes.value, input.worldId).slice(0, input.limit);
  return { query, types: [...normalizedTypes.value], worldId: input.worldId, count: results.length, results };
}

function readCampaignSessionToolOutput(context: AiToolContext, input: { sessionId?: string; status?: string; limit: number }): unknown {
  const sessions = context.state.campaignSessions
    .filter((session) => session.campaignId === context.campaignId)
    .filter((session) => !input.sessionId || session.id === input.sessionId)
    .filter((session) => !input.status || session.status === input.status)
    .sort((left, right) => left.number - right.number || left.createdAt.localeCompare(right.createdAt))
    .slice(0, input.limit)
    .map((session) => ({ ...session, sceneIds: [...session.sceneIds], encounterIds: [...session.encounterIds] }));
  if (input.sessionId && sessions.length === 0) return toolError("not_found", { entity: "campaignSession", id: input.sessionId });
  return { sessionId: input.sessionId, status: input.status, count: sessions.length, sessions };
}

function readAiActivityToolOutput(context: AiToolContext, limit: number): unknown {
  const canReadGm = context.permissions.includes("ai.readGmMemory");
  const canReadToolCalls = context.permissions.includes("ai.proposeChanges");
  const threads = context.state.aiThreads
    .filter((thread) => thread.campaignId === context.campaignId && (canReadToolCalls || thread.userId === context.userId))
    .sort((left, right) => right.updatedAt.localeCompare(left.updatedAt));
  const threadIds = new Set(threads.map((thread) => thread.id));
  const visibleProposals = visibleProposalsForUser(context.state, context.userId, context.campaignId, context.permissions);
  return {
    threads: threads
      .slice(0, limit)
      .map((thread) => ({
        id: thread.id,
        userId: thread.userId,
        provider: thread.provider,
        title: thread.title,
        status: thread.status,
        toolCallCount: thread.toolCallCount,
        advertisedToolNames: thread.advertisedToolNames,
        providerError: thread.providerError,
        createdAt: thread.createdAt,
        updatedAt: thread.updatedAt
      })),
    proposals: visibleProposals
      .sort((left, right) => right.updatedAt.localeCompare(left.updatedAt))
      .slice(0, limit)
      .map(proposalToolSummary),
    memory: context.state.aiMemory
      .filter((memory) => memory.campaignId === context.campaignId)
      .filter((memory) => canReadGm || (memory.visibility === "public" && aiMemoryFactStatus(memory) === "approved"))
      .sort((left, right) => right.updatedAt.localeCompare(left.updatedAt))
      .slice(0, limit)
      .map((memory) => ({
        id: memory.id,
        text: memory.text,
        visibility: memory.visibility,
        sourceIds: memory.sourceIds,
        status: aiMemoryFactStatus(memory),
        approved: aiMemoryFactStatus(memory) === "approved",
        createdAt: memory.createdAt,
        updatedAt: memory.updatedAt
      })),
    evaluations: context.state.aiEvaluations
      .filter((evaluation) => evaluation.campaignId === context.campaignId && threadIds.has(evaluation.threadId))
      .sort((left, right) => right.updatedAt.localeCompare(left.updatedAt))
      .slice(0, limit)
      .map((evaluation) => ({
        id: evaluation.id,
        threadId: evaluation.threadId,
        status: evaluation.status,
        checkCount: evaluation.checks.length,
        failedCheckCount: evaluation.checks.filter((check) => check.status === "failed").length,
        createdAt: evaluation.createdAt,
        updatedAt: evaluation.updatedAt
      })),
    toolCalls: canReadToolCalls
      ? context.state.aiToolCalls
          .filter((call) => threadIds.has(call.threadId))
          .sort((left, right) => right.updatedAt.localeCompare(left.updatedAt))
          .slice(0, limit)
          .map((call) => ({
            id: call.id,
            threadId: call.threadId,
            toolName: call.toolName,
            status: call.status,
            error: aiToolErrorCode(call.output),
            createdAt: call.createdAt,
            updatedAt: call.updatedAt
          }))
      : undefined
  };
}

function readDiceMacroToolOutput(context: AiToolContext, input: { macroId?: string; query: string; limit: number }): unknown {
  const canManage = context.permissions.includes("campaign.update");
  const normalizedQuery = input.query.toLocaleLowerCase();
  const macros = context.state.diceMacros
    .filter((macro) => macro.campaignId === context.campaignId && (macro.visibility === "public" || canManage))
    .filter((macro) => !input.macroId || macro.id === input.macroId)
    .filter((macro) => !normalizedQuery || macro.name.toLocaleLowerCase().includes(normalizedQuery) || macro.formula.toLocaleLowerCase().includes(normalizedQuery))
    .sort((left, right) => left.name.localeCompare(right.name) || left.id.localeCompare(right.id))
    .slice(0, input.limit)
    .map((macro) => ({
      id: macro.id,
      name: macro.name,
      formula: macro.formula,
      visibility: macro.visibility,
      createdBy: macro.createdBy,
      createdAt: macro.createdAt,
      updatedAt: macro.updatedAt
    }));
  if (input.macroId && macros.length === 0) return toolError("not_found", { entity: "diceMacro", id: input.macroId });
  return { macroId: input.macroId, query: input.query, count: macros.length, macros };
}

async function draftDiceMacroToolOutput(context: AiToolContext, request: Record<string, unknown>): Promise<ProposalToolOutput | ToolErrorOutput> {
  const action = enumStringFromRecord(request, "action", ["create", "update", "delete"] as const);
  if (!action) return toolError("invalid_tool_input", { message: "action must be create, update, or delete." });
  const macroId = stringFromRecord(request, "macroId");
  const existing = macroId ? context.state.diceMacros.find((macro) => macro.id === macroId && macro.campaignId === context.campaignId) : undefined;
  if ((action === "update" || action === "delete") && (!macroId || !existing)) return toolError("not_found", { entity: "diceMacro", id: macroId ?? "" });
  const name = stringFromRecord(request, "name");
  const formula = stringFromRecord(request, "formula");
  if ((action === "create" || (action === "update" && formula !== undefined)) && !formula) return toolError("invalid_tool_input", { message: "formula is required." });
  if ((action === "create" || (action === "update" && formula !== undefined)) && formula) {
    try {
      rollFormula(formula);
    } catch (error) {
      return toolError("invalid_tool_input", { message: error instanceof Error ? error.message : "Invalid dice macro formula." });
    }
  }
  const visibility = enumStringFromRecord(request, "visibility", ["public", "gm_only"] as const);
  let change: ProposalChange;
  if (action === "create") {
    if (!name) return toolError("invalid_tool_input", { message: "name is required." });
    const macro = createTimestamped("mac", {
      campaignId: context.campaignId,
      createdBy: context.userId,
      name,
      formula: formula ?? "1d20",
      visibility: visibility ?? "public"
    }) satisfies DiceMacro;
    change = { entity: "diceMacro", action: "create", data: { ...macro } };
  } else if (action === "delete") {
    change = { entity: "diceMacro", action: "delete", id: existing!.id, data: {} };
  } else {
    const data: Record<string, unknown> = {};
    if (name) data.name = name;
    if (formula) data.formula = formula;
    if (visibility) data.visibility = visibility;
    if (Object.keys(data).length === 0) return toolError("empty_change", { entity: "diceMacro", id: existing!.id });
    change = { entity: "diceMacro", action: "update", id: existing!.id, data };
  }
  const title = `${titleCase(action)} dice macro${name ? `: ${name}` : existing ? `: ${existing.name}` : ""}`;
  const proposalId = await context.createProposal({ title, summary: title, changes: [change] });
  return { proposalId, title, changeCount: 1 };
}

function readFogPresetToolOutput(context: AiToolContext, input: { presetId?: string; sceneId?: string; limit: number }): unknown {
  const presets = context.state.fogPresets
    .filter((preset) => preset.campaignId === context.campaignId)
    .filter((preset) => !input.presetId || preset.id === input.presetId)
    .filter((preset) => !input.sceneId || preset.sourceSceneId === input.sceneId)
    .sort((left, right) => right.updatedAt.localeCompare(left.updatedAt))
    .slice(0, input.limit)
    .map((preset) => ({
      id: preset.id,
      name: preset.name,
      description: preset.description,
      sourceSceneId: preset.sourceSceneId,
      regionCount: preset.regions.length,
      regions: preset.regions.slice(0, 10).map((region) => ({
        x: region.x,
        y: region.y,
        radius: region.radius,
        hidden: region.hidden,
        shape: region.shape ?? "circle",
        mode: region.mode ?? "reveal",
        pointCount: region.points?.length ?? 0
      })),
      createdAt: preset.createdAt,
      updatedAt: preset.updatedAt
    }));
  if (input.presetId && presets.length === 0) return toolError("not_found", { entity: "fogPreset", id: input.presetId });
  return { presetId: input.presetId, sceneId: input.sceneId, count: presets.length, presets };
}

async function draftFogPresetToolOutput(context: AiToolContext, request: Record<string, unknown>): Promise<ProposalToolOutput | ToolErrorOutput> {
  const action = enumStringFromRecord(request, "action", ["create", "update", "delete"] as const);
  if (!action) return toolError("invalid_tool_input", { message: "action must be create, update, or delete." });
  const presetId = stringFromRecord(request, "presetId");
  const existing = presetId ? context.state.fogPresets.find((preset) => preset.id === presetId && preset.campaignId === context.campaignId) : undefined;
  if ((action === "update" || action === "delete") && (!presetId || !existing)) return toolError("not_found", { entity: "fogPreset", id: presetId ?? "" });
  const sceneId = stringFromRecord(request, "sceneId");
  const sourceScene = sceneId ? context.state.scenes.find((scene) => scene.id === sceneId && scene.campaignId === context.campaignId) : undefined;
  if (sceneId && !sourceScene) return toolError("not_found", { entity: "scene", id: sceneId });
  const regionsInput = Array.isArray(request.regions) ? request.regions : undefined;
  const inputRegions = regionsInput ? fogPresetRegionsFromInput(regionsInput) : undefined;
  if (regionsInput && !inputRegions) return toolError("invalid_tool_input", { message: "regions must be valid fog preset regions." });
  const name = stringFromRecord(request, "name");
  let change: ProposalChange;
  if (action === "create") {
    if (!name) return toolError("invalid_tool_input", { message: "name is required." });
    const preset = createTimestamped("fogp", {
      campaignId: context.campaignId,
      name,
      description: stringFromRecord(request, "description"),
      sourceSceneId: sourceScene?.id,
      regions: inputRegions ?? sourceScene?.fog.map(cloneFogPresetRegion) ?? [],
      metadata: { source: "ai_tool" }
    }) satisfies FogPreset;
    change = { entity: "fogPreset", action: "create", data: { ...preset } };
  } else if (action === "delete") {
    change = { entity: "fogPreset", action: "delete", id: existing!.id, data: {} };
  } else {
    const data: Record<string, unknown> = {};
    if (name) data.name = name;
    const description = stringFromRecord(request, "description");
    if (description !== undefined) data.description = description;
    if (sourceScene) data.sourceSceneId = sourceScene.id;
    if (inputRegions) data.regions = inputRegions;
    if (Object.keys(data).length === 0) return toolError("empty_change", { entity: "fogPreset", id: existing!.id });
    change = { entity: "fogPreset", action: "update", id: existing!.id, data };
  }
  const title = `${titleCase(action)} fog preset${name ? `: ${name}` : existing ? `: ${existing.name}` : ""}`;
  const proposalId = await context.createProposal({ title, summary: title, changes: [change] });
  return { proposalId, title, changeCount: 1 };
}

function readSystemsToolOutput(context: AiToolContext, input: { systemId?: string; actorId?: string; includeDetails: boolean; limit: number }): unknown {
  const campaign = context.state.campaigns.find((item) => item.id === context.campaignId);
  const systems = registeredSystems(context.state)
    .filter((system) => !input.systemId || system.id === input.systemId)
    .map((system) => ({
      ...systemRuntimeInfo({ state: context.state }, system),
      active: campaign?.defaultSystemId === system.id,
      templates: input.includeDetails && hasSystemRuntimeCapability(system.id, "character-templates") ? characterTemplatesForSystem(system.id).slice(0, input.limit).map((template) => ({ id: template.id, name: template.name, actorType: template.actorType, systemId: template.systemId })) : undefined,
      origins: input.includeDetails && system.id === DND_5E_SRD_SYSTEM_ID ? dnd5eSrdCharacterOrigins() : undefined,
      encounterThreats: input.includeDetails && hasSystemRuntimeCapability(system.id, "encounter-builder") ? encounterThreatsForSystem(system.id).slice(0, input.limit).map((threat) => ({ id: threat.id, name: threat.name, challenge: "challenge" in threat ? threat.challenge : undefined, xp: "xp" in threat ? threat.xp : undefined })) : undefined,
      compendium: input.includeDetails && hasSystemRuntimeCapability(system.id, "compendium") ? compendiumEntriesForSystem(system.id).slice(0, input.limit).map((entry) => ({ id: entry.id, type: entry.type, name: entry.name, summary: entry.summary })) : undefined
    }));
  if (input.systemId && systems.length === 0) return toolError("not_found", { entity: "system", id: input.systemId });
  const actor = input.actorId ? context.state.actors.find((item) => item.id === input.actorId && item.campaignId === context.campaignId) : undefined;
  if (input.actorId && !actor) return toolError("not_found", { entity: "actor", id: input.actorId });
  const actorStore = { state: context.state, save: () => undefined, replace: () => undefined } satisfies StateStore;
  const actorPrivateDataVisible = actor ? canReadActorPrivateData(actorStore, context.userId, context.campaignId, actor) : false;
  return {
    defaultSystemId: campaign?.defaultSystemId,
    systems,
    actor: actor
      ? {
          id: actor.id,
          name: actor.name,
          systemId: actor.systemId,
          privateDataVisible: actorPrivateDataVisible,
          ...(actorPrivateDataVisible ? { sheet: systemSheet(actor, actorItems(actorStore, actor)), advancementOptions: advancementOptionsForActor(actor) } : {})
        }
      : undefined
  };
}

function readPluginsToolOutput(context: AiToolContext, input: { pluginId?: string; includeStorage: boolean; limit: number }): unknown {
  const campaignPluginGrants = context.state.permissionGrants.filter((grant) => grant.campaignId === context.campaignId && grant.subjectType === "plugin");
  const pluginIds = new Set(campaignPluginGrants.map((grant) => grant.subjectId));
  if (input.pluginId && !pluginIds.has(input.pluginId)) return toolError("not_found", { entity: "plugin", id: input.pluginId });
  const pluginGrants = campaignPluginGrants.filter((grant) => !input.pluginId || grant.subjectId === input.pluginId);
  const storage = input.includeStorage
    ? context.state.pluginStorage
        .filter((entry) => entry.campaignId === context.campaignId && pluginIds.has(entry.pluginId) && (!input.pluginId || entry.pluginId === input.pluginId))
        .sort((left, right) => left.pluginId.localeCompare(right.pluginId) || left.key.localeCompare(right.key))
        .slice(0, input.limit)
        .map((entry) => ({
          id: entry.id,
          pluginId: entry.pluginId,
          key: entry.key,
          valueSize: JSON.stringify(entry.value).length,
          updatedByType: entry.updatedByType,
          updatedById: entry.updatedById,
          createdAt: entry.createdAt,
          updatedAt: entry.updatedAt
        }))
    : undefined;
  return {
    installed: pluginGrants.slice(0, input.limit).map((grant) => ({
      pluginId: grant.subjectId,
      permissions: grant.permissions,
      metadata: grant.metadata,
      createdAt: grant.createdAt,
      updatedAt: grant.updatedAt
    })),
    reviews: context.state.pluginReviews
      .filter((review) => pluginIds.has(review.pluginId) && (!input.pluginId || review.pluginId === input.pluginId))
      .slice(0, input.limit)
      .map((review) => ({ pluginId: review.pluginId, version: review.version, status: review.status, reviewedAt: review.reviewedAt })),
    storage,
    registryNote: "Plugin install, configure, registry sync, storage writes, and chat-command execution are intentionally excluded from the agent MCP surface."
  };
}

function readContentImportsToolOutput(context: AiToolContext, input: { importId?: string; status?: string; limit: number }): unknown {
  const imports = context.state.contentImports
    .filter((batch) => batch.campaignId === context.campaignId)
    .filter((batch) => batch.status !== "deleted")
    .filter((batch) => !input.importId || batch.id === input.importId)
    .filter((batch) => !input.status || batch.status === input.status)
    .sort((left, right) => right.updatedAt.localeCompare(left.updatedAt))
    .slice(0, input.limit)
    .map((batch) => ({
      id: batch.id,
      status: batch.status,
      source: {
        sourceName: batch.source.sourceName,
        adapterId: batch.source.adapterId,
        adapterName: batch.source.sourceType,
        license: batch.source.license
      },
      entityCount: batch.entities.length,
      selectedEntityIds: batch.selectedEntityIds,
      appliedRecordCount: batch.appliedRecords.length,
      appliedAt: batch.appliedAt,
      rolledBackAt: batch.rolledBackAt,
      deletedAt: batch.deletedAt,
      entities: batch.entities.slice(0, 20).map((entity) => ({
        id: entity.id,
        kind: entity.kind,
        name: entity.name,
        warnings: entity.warnings,
        dataKeys: Object.keys(entity.data ?? {})
      })),
      createdAt: batch.createdAt,
      updatedAt: batch.updatedAt
    }));
  if (input.importId && imports.length === 0) return toolError("not_found", { entity: "contentImport", id: input.importId });
  return {
    importId: input.importId,
    status: input.status,
    count: imports.length,
    imports,
    mutationNote: "Content import apply, rollback, delete, and raw import are intentionally not exposed as direct agent MCP tools."
  };
}

async function draftAiEditLayerApplyToolOutput(context: AiToolContext, request: Record<string, unknown>): Promise<ProposalToolOutput | ToolErrorOutput> {
  const requestedEditSceneId = stringFromRecord(request, "aiEditSceneId");
  const targetSceneId = stringFromRecord(request, "targetSceneId");
  const targetScene = targetSceneId
    ? context.state.scenes.find((scene) => scene.id === targetSceneId && scene.campaignId === context.campaignId)
    : context.state.scenes.find((scene) => scene.campaignId === context.campaignId && scene.active) ?? context.state.scenes.find((scene) => scene.campaignId === context.campaignId);
  if (targetSceneId && !targetScene) return toolError("not_found", { entity: "scene", id: targetSceneId });
  const aiEditScene = requestedEditSceneId
    ? context.state.scenes.find((scene) => scene.id === requestedEditSceneId && scene.campaignId === context.campaignId)
    : targetScene
      ? findAiEditSceneForTarget(context.state, context.campaignId, targetScene.id)
      : undefined;
  if (!aiEditScene) return toolError("not_found", { entity: "ai_edit_scene", id: requestedEditSceneId ?? targetSceneId ?? "active" });
  if (aiEditScene.folder !== AI_EDIT_SCENE_FOLDER) return toolError("invalid_tool_input", { message: "Scene is not an AI edit layer.", sceneId: aiEditScene.id });
  const resolvedTargetSceneId = stringFromRecord(aiEditScene.metadata, "targetSceneId") ?? targetScene?.id;
  const resolvedTargetScene = resolvedTargetSceneId ? context.state.scenes.find((scene) => scene.id === resolvedTargetSceneId && scene.campaignId === context.campaignId) : undefined;
  if (!resolvedTargetScene) return toolError("not_found", { entity: "target_scene", id: resolvedTargetSceneId ?? "" });
  const draft = draftAiEditLayerApplyChanges(context.state, aiEditScene, resolvedTargetScene);
  if (draft.changes.length === 0) return toolError("empty_change", { entity: "scene", id: aiEditScene.id });
  const title = stringFromRecord(request, "title") ?? `Apply AI edits: ${aiEditScene.name}`;
  const summary = stringFromRecord(request, "summary") ?? `Apply AI edit layer ${aiEditScene.name} onto ${resolvedTargetScene.name}.`;
  const proposalId = await context.createProposal({ title, summary, changes: draft.changes });
  return { proposalId, title, changeCount: draft.changes.length, aiEditSceneId: aiEditScene.id, targetSceneId: resolvedTargetScene.id, copiedTokenCount: draft.copiedTokenCount, replacedTokenCount: draft.replacedTokenCount };
}

function draftAiEditLayerApplyChanges(state: EngineState, aiEditScene: Scene, targetScene: Scene): { changes: ProposalChange[]; copiedTokenCount: number; replacedTokenCount: number } {
  const appliedAt = nowIso();
  const sceneData: Record<string, unknown> = {
    metadata: {
      ...targetScene.metadata,
      aiEditAppliedSceneId: aiEditScene.id,
      aiEditAppliedAt: appliedAt
    }
  };
  if (aiEditScene.backgroundAssetId) sceneData.backgroundAssetId = aiEditScene.backgroundAssetId;
  if (aiEditScene.fog.length > 0) sceneData.fog = cloneJsonValue(aiEditScene.fog);
  if (aiEditScene.walls.length > 0) sceneData.walls = cloneJsonValue(aiEditScene.walls);
  if (aiEditScene.lights.length > 0) sceneData.lights = cloneJsonValue(aiEditScene.lights);
  if ((aiEditScene.annotations?.length ?? 0) > 0) sceneData.annotations = cloneJsonValue(aiEditScene.annotations ?? []);
  const changes: ProposalChange[] = [{ entity: "scene", action: "update", id: targetScene.id, data: sceneData }];
  const replacementTokens = state.tokens.filter((token) => token.sceneId === targetScene.id && token.metadata.aiEditSourceSceneId === aiEditScene.id);
  for (const token of replacementTokens) changes.push({ entity: "token", action: "delete", id: token.id, data: {} });
  const sourceTokens = state.tokens.filter((token) => token.sceneId === aiEditScene.id);
  for (const source of sourceTokens) {
    const token = createTimestamped("tok", {
      sceneId: targetScene.id,
      actorId: source.actorId,
      name: source.name,
      x: source.x,
      y: source.y,
      width: source.width,
      height: source.height,
      rotation: source.rotation,
      layer: source.layer,
      hidden: source.hidden,
      locked: source.locked,
      visionEnabled: source.visionEnabled,
      visionRadius: source.visionRadius,
      brightVisionRadius: source.brightVisionRadius,
      dimVisionRadius: source.dimVisionRadius,
      disposition: source.disposition,
      imageAssetId: source.imageAssetId,
      ownerUserIds: source.ownerUserIds,
      notes: source.notes,
      conditions: cloneJsonValue(source.conditions ?? []) as Token["conditions"],
      auras: cloneJsonValue(source.auras ?? []) as Token["auras"],
      targetedByUserIds: [],
      metadata: {
        ...source.metadata,
        aiEditSourceSceneId: aiEditScene.id,
        aiEditSourceTokenId: source.id
      }
    }) satisfies Token;
    changes.push({ entity: "token", action: "create", data: { ...token } });
  }
  return { changes, copiedTokenCount: sourceTokens.length, replacedTokenCount: replacementTokens.length };
}

function redactedUserToolSummary(user: User | undefined): Record<string, unknown> | undefined {
  if (!user) return undefined;
  return {
    id: user.id,
    displayName: user.displayName,
    email: user.email,
    serverAdmin: user.serverAdmin,
    disabledAt: user.disabledAt,
    disabledReason: user.disabledReason,
    passwordResetRequired: user.passwordResetRequired,
    createdAt: user.createdAt,
    updatedAt: user.updatedAt
  };
}

function rosterUserToolSummary(user: User | undefined): Pick<User, "id" | "displayName"> | undefined {
  if (!user) return undefined;
  return { id: user.id, displayName: user.displayName };
}

function fogPresetRegionsFromInput(values: unknown[]): FogPresetRegion[] | undefined {
  const regions: FogPresetRegion[] = [];
  for (const value of values) {
    if (!isRecord(value)) return undefined;
    const x = numberFromRecord(value, "x", 0, 100000);
    const y = numberFromRecord(value, "y", 0, 100000);
    const radius = numberFromRecord(value, "radius", 0, 100000);
    if (x === undefined || y === undefined || radius === undefined) return undefined;
    const points = Array.isArray(value.points)
      ? value.points
          .filter(isRecord)
          .map((point) => ({ x: numberFromRecord(point, "x", 0, 100000) ?? 0, y: numberFromRecord(point, "y", 0, 100000) ?? 0 }))
      : undefined;
    regions.push({
      x,
      y,
      radius,
      hidden: booleanFromRecord(value, "hidden") ?? false,
      shape: enumStringFromRecord(value, "shape", ["circle", "polygon"] as const),
      mode: enumStringFromRecord(value, "mode", ["reveal", "hide"] as const),
      points
    });
  }
  return regions;
}

interface SystemRollPoolEffectResult {
  type: "damage" | "healing";
  targetActorId: string;
  targetActorName: string;
  pool: string;
  amount: number;
  before: number;
  after: number;
  max: number;
  damageType?: string;
  damageTypes?: string[];
  effectChoice?: string;
  choiceKind?: string;
}

interface SystemRollUtilityEffectResult {
  type: "utility";
  targetActorId: string;
  targetActorName: string;
  effectChoice?: string;
  choiceKind?: string;
  resistance?: string[];
  immunity?: string[];
  vulnerability?: string[];
  duration?: string;
}

interface SystemRollConditionEffectResult {
  type: "condition";
  targetActorId: string;
  targetActorName: string;
  conditionId: string;
  conditionName: string;
  before: string[];
  after: string[];
  alreadyPresent: boolean;
}

type SystemRollEffectResult = SystemRollPoolEffectResult | SystemRollConditionEffectResult | SystemRollUtilityEffectResult;
interface SystemRollEffectOptions {
  allowConditionEffects?: boolean;
}

type SystemRollEffectApplication = { data: Record<string, unknown>; effect: SystemRollEffectResult; effects?: SystemRollEffectResult[] } | { error: string; message: string };

function createAiToolContext(store: StateStore, campaignId: string, userId: string, permissions: PermissionName[], runtime: AiToolRuntime, signal?: AbortSignal, sourceId?: string): AiToolContext {
  const createAiProposal: AiToolContext["createProposal"] = async ({ title, summary, changes }) => {
    const proposal: Proposal = createTimestamped("prop", {
      campaignId,
      createdByUserId: userId,
      createdByType: "ai" as const,
      sourceId,
      title,
      summary,
      status: "pending" as const,
      changesJson: normalizeProposalChanges(changes, campaignId, userId, store.state),
      diffJson: {
        source: "ai_tool"
      },
      approvalRequired: true
    });
    proposal.history = [proposalHistoryEntry({ action: "created", status: "pending", at: proposal.createdAt, actorUserId: userId, actorType: "ai", auditAction: "ai.proposal.created" })];
    store.state.proposals.push(proposal);
    return proposal.id;
  };

  const context: OpenTabletopAiToolContext = {
    campaignId,
    userId,
    permissions,
    state: aiToolStateSnapshot(store.state),
    signal,
    sourceImageDataUrlForAsset: async (asset) => {
      if (!asset.mimeType.startsWith("image/")) return undefined;
      const body = await runtime.assetStorage.read(asset);
      if (!body) return undefined;
      return `data:${asset.mimeType};base64,${body.toString("base64")}`;
    },
    createProposal: createAiProposal,
    listProposals: async ({ status, limit }) => {
      const proposals = visibleProposalsForUser(store.state, userId, campaignId, permissions).filter((proposal) => !status || proposal.status === status);
      return {
        status,
        count: proposals.length,
        proposals: proposals
          .sort((left, right) => right.updatedAt.localeCompare(left.updatedAt) || right.id.localeCompare(left.id))
          .slice(0, Math.max(1, Math.min(20, limit ?? 10)))
          .map(proposalToolSummary)
      };
    },
    getProposal: async ({ proposalId }) => {
      const proposal = store.state.proposals.find((item) => item.id === proposalId && item.campaignId === campaignId);
      if (!proposal) return toolError("not_found", { entity: "proposal", id: proposalId });
      if (!proposalVisibleToUser(store.state, userId, campaignId, permissions, proposal)) return toolError("not_found", { entity: "proposal", id: proposalId });
      return { proposal: proposalToolSummary(proposal), changes: proposal.changesJson };
    },
    reviseProposal: async ({ proposalId, title, summary, changes }) => {
      const proposal = store.state.proposals.find((item) => item.id === proposalId && item.campaignId === campaignId);
      if (!proposal) return toolError("not_found", { entity: "proposal", id: proposalId });
      if (!proposalVisibleToUser(store.state, userId, campaignId, permissions, proposal)) return toolError("not_found", { entity: "proposal", id: proposalId });
      if (proposal.status !== "pending") return toolError("proposal_not_pending", { proposalId, status: proposal.status });
      const nextChanges = changes ? normalizeProposalChanges(changes, campaignId, userId, store.state) : proposal.changesJson;
      const preparedChanges = prepareProposalChanges(store, campaignId, userId, nextChanges, { currentProposalId: proposal.id });
      if ("error" in preparedChanges) return toolError(preparedChanges.error, { message: preparedChanges.message });
      const missingPermission = missingProposalChangePermission(preparedChanges.changes, permissions);
      if (missingPermission) return missingPermissionToolOutput(missingPermission);
      proposal.title = title ?? proposal.title;
      proposal.summary = summary ?? proposal.summary;
      proposal.changesJson = preparedChanges.changes;
      proposal.updatedAt = nowIso();
      proposal.history = [
        ...(proposal.history ?? []),
        proposalHistoryEntry({
          action: "revised",
          status: proposal.status,
          at: proposal.updatedAt,
          actorUserId: userId,
          actorType: "ai",
          auditAction: "ai.proposal.revised"
        })
      ];
      store.save();
      runtime.broadcast?.(
        createEvent({
          campaignId,
          type: "proposal.updated",
          actorUserId: userId,
          targetId: proposal.id,
          payload: proposal
        })
      );
      return { proposal: proposalToolSummary(proposal), changes: proposal.changesJson };
    },
    applyApprovedProposal: async ({ proposalId }) => {
      if (!permissions.includes("ai.applyChanges")) return missingPermissionToolOutput("ai.applyChanges");
      const proposal = store.state.proposals.find((item) => item.id === proposalId && item.campaignId === campaignId);
      if (!proposal) return toolError("not_found", { entity: "proposal", id: proposalId });
      if (proposal.status !== "approved") return toolError("proposal_not_approved", { proposalId, status: proposal.status });
      const preparedChanges = prepareProposalChanges(store, proposal.campaignId, proposal.createdByUserId ?? userId, proposal.changesJson, { currentProposalId: proposal.id });
      if ("error" in preparedChanges) return toolError(preparedChanges.error, { message: preparedChanges.message });
      const missingPermission = missingProposalChangePermission(preparedChanges.changes, permissions);
      if (missingPermission) return missingPermissionToolOutput(missingPermission);
      const beforeState = store.state;
      const appliedChanges = structuredClone(preparedChanges.changes);
      const applyState = structuredClone(store.state);
      const applyStateProposal = applyState.proposals.find((item) => item.id === proposal.id);
      if (!applyStateProposal) return toolError("proposal_apply_incomplete", { proposalId });
      applyStateProposal.changesJson = structuredClone(preparedChanges.changes);
      const boardStateChanged = proposalTouchesBoardState(applyStateProposal);
      const nextState = applyProposal(applyState, applyStateProposal, userId);
      const nextProposal = nextState.proposals.find((item) => item.id === proposal.id);
      if (!nextProposal) return toolError("proposal_apply_incomplete", { proposalId });
      linkAppliedRecapToSessionState(nextState, nextProposal, userId);
      store.replace(nextState);
      refreshAiToolContextState(context, store.state);
      const applied = store.state.proposals.find((item) => item.id === proposalId);
      if (!applied) return toolError("proposal_apply_incomplete", { proposalId });
      appendServerAuditLog(store, userId, {
        campaignId,
        action: "proposal.apply",
        targetType: "proposal",
        targetId: applied.id,
        before: { status: "approved", changeCount: appliedChanges.length },
        after: { status: applied.status, entities: [...new Set(appliedChanges.map((change) => change.entity))], reversible: Boolean(applied.inverseChangesJson), appliedBy: "ai_tool" }
      });
      broadcastProposalEntityChanges(store, beforeState, campaignId, appliedChanges, userId, (event) => runtime.broadcast?.(event));
      store.save();
      runtime.broadcast?.(
        createEvent({
          campaignId,
          type: "proposal.applied",
          actorUserId: userId,
          targetId: proposal.id,
          payload: applied
        })
      );
      return { proposal: proposalToolSummary(applied), boardStateChanged };
    },
    createMemory: async ({ text, visibility, sourceIds }) => {
      const memory = normalizeAiMemoryFact(createTimestamped("mem", {
        campaignId,
        text: text.slice(0, 500),
        type: "ai_suggestion" as const,
        visibility,
        sourceIds,
        source: { type: "ai_tool" },
        createdBy: "ai" as const,
        status: "candidate" as const
      }) satisfies AiMemoryFact);
      store.state.aiMemory.push(memory);
      return memory.id;
    },
    generateImageAsset: async ({ kind, prompt, name, folder, tags, size, quality, outputFormat, sourceImageUrl, sourceImageMimeType }) => {
      const sourcePrompt = prompt.trim();
      if (!sourcePrompt) return { error: "invalid_tool_input", message: "Prompt is required." };
      const generated = await runtime.imageAssetGenerator.generate({
        kind,
        prompt: sourcePrompt,
        name,
        size,
        quality,
        outputFormat,
        sourceImageUrl,
        sourceImageMimeType,
        campaignId,
        userId,
        signal
      });
      if (generated.body.length === 0) return { error: "image_generation_failed", message: "Generated image body was empty." };
      const rasterMimeType = rasterMimeTypeForGeneratedImage(generated.body);
      if (!rasterMimeType) {
        return {
          error: "image_generation_failed",
          message: "Generated image was not a raster PNG, JPEG, or WebP image. Codex app-server must return actual image-generation output, not SVG, HTML, text, or placeholder markup."
        };
      }
      if (generated.body.length > runtime.maxAssetBytes) {
        return { error: "asset_too_large", message: `Generated asset exceeds ${runtime.maxAssetBytes} bytes.`, sizeBytes: generated.body.length };
      }
      const quotaExceeded = assetQuotaExceeded(store, campaignId, generated.body.length);
      if (quotaExceeded) return { error: quotaExceeded.error, message: quotaExceeded.message, quotaBytes: quotaExceeded.quotaBytes, usedBytes: quotaExceeded.usedBytes, incomingBytes: quotaExceeded.incomingBytes };
      const asset: MapAsset = createTimestamped("asset", {
        campaignId,
        name: normalizeGeneratedAssetName(name, kind),
        url: "",
        mimeType: rasterMimeType,
        sizeBytes: generated.body.length,
        checksum: checksumForBuffer(generated.body),
        folder: normalizeAssetFolder(folder),
        tags: normalizeAssetTags(tags),
        lifecycle: defaultAssetLifecycle(),
        security: {
          status: "clean" as const,
          scanner: "ai-generated-asset",
          scannedAt: nowIso(),
          findings: []
        }
      });
      asset.storage = await runtime.assetStorage.put(asset, generated.body);
      asset.url = `/api/v1/assets/${asset.id}/blob`;
      asset.security = {
        status: "clean",
        scanner: "ai-generated-asset",
        scannedAt: nowIso(),
        findings: [
          {
            code: "ai_generated_asset",
            severity: "low",
            message: `${kind === "map" ? "Map" : "Token"} image generated by ${generated.provider}; review before use.`
          }
        ]
      };
      return {
        asset,
        provider: generated.provider,
        model: generated.model,
        revisedPrompt: generated.revisedPrompt,
        sourcePrompt: generated.sourcePrompt
      };
    },
    rollDice: async ({ formula, label, visibility }) => {
      const rolled = rollFormula(formula);
      const roll = createTimestamped("roll", {
        campaignId,
        userId,
        formula,
        label,
        visibility,
        terms: rolled.terms,
        total: rolled.total
      }) satisfies DiceRoll;
      const message = createTimestamped("msg", {
        campaignId,
        userId,
        type: "roll" as const,
        body: `${label ? `${label}: ` : ""}${formula} = ${roll.total}`,
        visibility,
        recipientUserIds: [],
        rollId: roll.id
      }) satisfies ChatMessage;
      const proposalId = await createAiProposal({
        title: label ? `Roll: ${label}` : `Roll ${formula}`,
        summary: `${formula} = ${roll.total}. Publish the verified result to campaign roll history and chat after approval.`,
        changes: [
          { entity: "roll", action: "create", data: { ...roll } },
          { entity: "chat", action: "create", data: { ...message } }
        ]
      });
      return { proposalId, rollId: roll.id, formula: roll.formula, label: roll.label, total: roll.total, visibility: roll.visibility, approvalRequired: true };
    },
    sendChatMessage: async ({ body, sceneId, type, visibility, recipientUserIds }) => {
      if (sceneId && !store.state.scenes.some((scene) => scene.id === sceneId && scene.campaignId === campaignId)) return toolError("not_found", { entity: "scene", id: sceneId });
      const messageType = type === "emote" || type === "ooc" || type === "gm" || type === "whisper" ? type : "plain";
      const resolvedVisibility = messageType === "whisper" ? "whisper" : visibility;
      if (resolvedVisibility === "whisper") {
        const campaignUserIds = new Set(store.state.members.filter((member) => member.campaignId === campaignId).map((member) => member.userId));
        const invalidRecipient = recipientUserIds.find((recipientId) => !campaignUserIds.has(recipientId));
        if (recipientUserIds.length === 0) return toolError("invalid_tool_input", { message: "Whisper messages require recipientUserIds." });
        if (invalidRecipient) return toolError("not_found", { entity: "recipient_user", id: invalidRecipient });
      }
      const message = createTimestamped("msg", {
        campaignId,
        sceneId,
        userId,
        type: messageType as MessageType,
        body,
        visibility: resolvedVisibility,
        recipientUserIds: resolvedVisibility === "whisper" ? [...new Set(recipientUserIds)].sort() : []
      }) satisfies ChatMessage;
      const proposalId = await createAiProposal({
        title: messageType === "whisper" ? "Send private chat message" : "Send campaign chat message",
        summary: "Publish the drafted chat message after human review.",
        changes: [{ entity: "chat", action: "create", data: { ...message } }]
      });
      return { proposalId, messageId: message.id, type: message.type, visibility: message.visibility, recipientUserIds: message.recipientUserIds, sceneId: message.sceneId, approvalRequired: true };
    },
    targetToken: async ({ tokenId, targeted }) => {
      const tokenCampaignId = campaignIdForToken(store, tokenId);
      if (tokenCampaignId !== campaignId) return toolError("not_found", { entity: "token", id: tokenId });
      const token = store.state.tokens.find((item) => item.id === tokenId);
      if (!token) return toolError("not_found", { entity: "token", id: tokenId });
      if (!isTokenVisibleToUser(store, userId, campaignId, token)) return toolError("not_found", { entity: "token", id: tokenId });
      if (!canReadHiddenTokens(store, userId, campaignId) && tokenLayer(token) !== "player") return missingPermissionToolOutput("token.read");
      const targetedByUserIds = new Set(token.targetedByUserIds ?? []);
      if (targeted) targetedByUserIds.add(userId);
      else targetedByUserIds.delete(userId);
      const nextTargets = [...targetedByUserIds].sort();
      const proposalId = await createAiProposal({
        title: targeted ? `Target ${token.name}` : `Untarget ${token.name}`,
        summary: targeted ? `Mark ${token.name} as targeted by the current user.` : `Remove the current user's target marker from ${token.name}.`,
        changes: [
          {
            entity: "token",
            action: "update",
            id: token.id,
            data: { targetedByUserIds: nextTargets }
          }
        ]
      });
      return { proposalId, tokenId: token.id, targeted, targetedByUserIds: nextTargets };
    },
    captureBoardView: async ({ sceneId }) => {
      if (!runtime.requestBoardCapture) {
        return {
          status: "board_capture_unavailable",
          reason: "Board capture is not configured for this server.",
          sceneId
        };
      }
      return runtime.requestBoardCapture({ campaignId, userId, sceneId });
    },
    useActorAction: async ({ actorId, actionRollId, actionName, targetActorId, applyEffect, saveOutcomes, spellSlotLevel, resourceAmount, useFreeResource, visibility }) => {
      const actor = store.state.actors.find((item) => item.id === actorId && item.campaignId === campaignId);
      if (!actor) return toolError("not_found", { entity: "actor", id: actorId });
      if (!canUpdateActorForUser(store, userId, actor)) return missingPermissionToolOutput("actor.update");
      if (!canReadActorPrivateData(store, userId, campaignId, actor)) return missingPermissionToolOutput("actor.readPrivate");
      const items = actorItems(store, actor);
      const quickRolls = systemQuickRolls(actor, items);
      const action = resolveSystemActionRoll(quickRolls, actionRollId, actionName);
      if (!action) {
        return toolError("not_found", {
          entity: "actor_action",
          id: actionRollId ?? actionName ?? "",
          availableActions: quickRolls.map((item) => ({ rollId: item.id, label: item.label, formula: item.formula }))
        });
      }
      const actionOptions = systemActionOptions(spellSlotLevel, resourceAmount, useFreeResource);
      const resolvedFormula = systemActionFormula(actor, items, action.id, actionOptions) ?? action.formula;
      if (actor.systemId === DND_5E_SRD_SYSTEM_ID) {
        const targetActorIds = systemRollTargetActorIds(undefined, targetActorId, applyEffect ? actor.id : undefined);
        const targetActors: Actor[] = [];
        for (const id of targetActorIds) {
          const target = store.state.actors.find((item) => item.id === id && item.campaignId === campaignId);
          if (!target) return toolError("not_found", { entity: "target_actor", id });
          if (!canReadActorPrivateData(store, userId, campaignId, target)) return missingPermissionToolOutput("actor.readPrivate");
          targetActors.push(target);
        }
        const activeCombat = store.state.combats.find((combat) => combat.campaignId === campaignId && combat.active);
        const resolutionOptions = { ...actionOptions, consumeResources: true, applyEffect: Boolean(applyEffect), commit: true, saveOutcomes };
        let resolution = resolveDnd5eSrdAction({
          actor,
          items,
          roll: { ...action, formula: resolvedFormula },
          targets: targetActors.map((target) => ({ actor: target, saveOutcome: saveOutcomes?.[target.id] })),
          combat: activeCombat,
          options: resolutionOptions,
          now: nowIso()
        });
        if (resolution.blocked) return toolError("conflict", { message: resolution.blocked.reason, resolution });
        const pendingMessage = dnd5eSrdCommitInputMessage(resolution, Boolean(applyEffect));
        if (pendingMessage) return toolError("pending_resolution", { message: pendingMessage, resolution });
        const rolledResults = resolution.rolls.map((resolutionRoll) => ({ resolutionRoll, rolled: rollFormula(resolutionRoll.formula) }));
        const defaultRollTotal = rolledResults[0]?.rolled.total;
        const rollTotalByTarget = new Map<string, number>();
        for (const result of rolledResults) {
          if (result.resolutionRoll.targetActorId) rollTotalByTarget.set(result.resolutionRoll.targetActorId, result.rolled.total);
        }
        resolution = resolveDnd5eSrdAction({
          actor,
          items,
          roll: { ...action, formula: resolvedFormula },
          targets: targetActors.map((target) => ({ actor: target, saveOutcome: saveOutcomes?.[target.id], rollTotal: rollTotalByTarget.get(target.id) ?? defaultRollTotal })),
          combat: activeCombat,
          options: resolutionOptions,
          now: nowIso()
        });
        if (resolution.blocked) return toolError("conflict", { message: resolution.blocked.reason, resolution });
        const finalPendingMessage = dnd5eSrdCommitInputMessage(resolution, Boolean(applyEffect));
        if (finalPendingMessage) return toolError("pending_resolution", { message: finalPendingMessage, resolution });
        for (const actorUpdate of resolution.actorUpdates) {
          const updatedActor = store.state.actors.find((item) => item.id === actorUpdate.actorId && item.campaignId === campaignId);
          if (!updatedActor) return toolError("not_found", { entity: "actor", id: actorUpdate.actorId });
          if (!canUpdateActorForUser(store, userId, updatedActor)) return missingPermissionToolOutput("actor.update");
        }
        const actorDataUpdates = new Map<string, Record<string, unknown>>();
        for (const actorUpdate of resolution.actorUpdates) actorDataUpdates.set(actorUpdate.actorId, actorUpdate.after);
        const roll = createTimestamped("roll", {
          campaignId,
          userId,
          actorId: actor.id,
          formula: resolution.rolls[0]?.formula ?? resolvedFormula,
          label: `${actor.name} ${action.label}`,
          visibility,
          terms: rolledResults[0]?.rolled.terms ?? [],
          total: rolledResults[0]?.rolled.total ?? 0
        }) satisfies DiceRoll;
        const message = createTimestamped("msg", {
          campaignId,
          userId,
          type: "roll" as const,
          body: `${actor.name} ${action.label}: ${roll.formula} = ${roll.total}`,
          visibility,
          recipientUserIds: [],
          rollId: roll.id
        }) satisfies ChatMessage;
        const changes: ProposalChange[] = [
          ...[...actorDataUpdates].map(([updatedActorId, data]) => ({ entity: "actor" as const, action: "update" as const, id: updatedActorId, data: { data } })),
          ...resolution.itemUpdates.map((item) => ({ entity: "item" as const, action: "update" as const, id: item.id, data: { data: item.data } })),
          { entity: "roll", action: "create", data: roll },
          { entity: "chat", action: "create", data: message }
        ];
        const proposalId = await createAiProposal({
          title: `Actor action: ${actor.name} ${action.label}`,
          summary: `Draft ${actor.name} ${action.label}: ${roll.formula} = ${roll.total}.`,
          changes
        });
        return {
          proposalId,
          changeCount: changes.length,
          actorId: actor.id,
          systemId: actor.systemId,
          actionRollId: action.id,
          rollId: roll.id,
          formula: roll.formula,
          label: action.label,
          total: roll.total,
          visibility: roll.visibility,
          slotLevel: resolution.usage?.slotLevel,
          consumed: resolution.resourceConsumption,
          updatedItems: resolution.itemUpdates.map((item) => {
            const data = isRecord(item.data) ? item.data : {};
            return {
              id: item.id,
              name: item.name,
              quantity: typeof data.quantity === "number" ? data.quantity : undefined
            };
          }),
          effect: resolution.effects[0],
          effects: resolution.effects,
          resolution
        };
      }
      let usage: SystemActionUseResult;
      try {
        usage = useSystemAction(actor, items, action.id, actionOptions);
      } catch (error) {
        return toolError("conflict", { message: error instanceof Error ? error.message : "System action resources are unavailable" });
      }
      const actorDataUpdates = new Map<string, Record<string, unknown>>();
      let itemUpdates: Item[] = [];
      let effect: SystemRollPoolEffectResult | undefined;
      if (usage.consumed.length > 0 || usage.items.length > 0) {
        actorDataUpdates.set(actor.id, usage.data);
        itemUpdates = usage.items;
      }
      const rolled = rollFormula(resolvedFormula);
      if (applyEffect) {
        const target = store.state.actors.find((item) => item.id === (targetActorId ?? actor.id) && item.campaignId === campaignId);
        if (!target) return toolError("not_found", { entity: "target_actor", id: targetActorId ?? actor.id });
        if (!canUpdateActorForUser(store, userId, target)) return missingPermissionToolOutput("actor.update");
        if (!canReadActorPrivateData(store, userId, campaignId, target)) return missingPermissionToolOutput("actor.readPrivate");
        const targetForEffect = { ...target, data: actorDataUpdates.get(target.id) ?? target.data };
        const applied = applySystemRollEffect(targetForEffect, action, rolled.total);
        if ("error" in applied) return toolError(applied.error, { message: applied.message });
        actorDataUpdates.set(target.id, applied.data);
        effect = applied.effect as SystemRollPoolEffectResult;
      }
      const roll = createTimestamped("roll", {
        campaignId,
        userId,
        actorId: actor.id,
        formula: resolvedFormula,
        label: `${actor.name} ${action.label}`,
        visibility,
        terms: rolled.terms,
        total: rolled.total
      }) satisfies DiceRoll;
      const message = createTimestamped("msg", {
        campaignId,
        userId,
        type: "roll" as const,
        body: `${actor.name} ${action.label}: ${resolvedFormula} = ${roll.total}`,
        visibility,
        recipientUserIds: [],
        rollId: roll.id
      }) satisfies ChatMessage;
      const changes: ProposalChange[] = [
        ...[...actorDataUpdates].map(([updatedActorId, data]) => ({ entity: "actor" as const, action: "update" as const, id: updatedActorId, data: { data } })),
        ...itemUpdates.map((item) => ({ entity: "item" as const, action: "update" as const, id: item.id, data: { data: item.data } })),
        { entity: "roll", action: "create", data: roll },
        { entity: "chat", action: "create", data: message }
      ];
      const proposalId = await createAiProposal({
        title: `Actor action: ${actor.name} ${action.label}`,
        summary: `Draft ${actor.name} ${action.label}: ${resolvedFormula} = ${roll.total}.`,
        changes
      });
      return {
        proposalId,
        changeCount: changes.length,
        actorId: actor.id,
        systemId: actor.systemId,
        actionRollId: action.id,
        rollId: roll.id,
        formula: roll.formula,
        label: action.label,
        total: roll.total,
        visibility: roll.visibility,
        slotLevel: usage.slotLevel,
        consumed: usage.consumed,
        updatedItems: usage.items.map((item) => {
          const data = isRecord(item.data) ? item.data : {};
          return {
            id: item.id,
            name: item.name,
            quantity: typeof data.quantity === "number" ? data.quantity : undefined
          };
        }),
        effect
      };
    }
  };
  return context;
}

function aiToolStateSnapshot(state: EngineState): EngineState {
  return deepFreeze(structuredClone(state) as EngineState);
}

function refreshAiToolContextState(context: AiToolContext, state: EngineState): void {
  context.state = aiToolStateSnapshot(state);
}

function deepFreeze<T>(value: T, seen = new WeakSet<object>()): T {
  if (typeof value !== "object" || value === null) return value;
  if (seen.has(value)) return value;
  seen.add(value);
  for (const child of Object.values(value)) deepFreeze(child, seen);
  return Object.freeze(value);
}

function enrichAiContextWithSystemActions(context: PermissionFilteredContext, store: StateStore): PermissionFilteredContext {
  if (!context.actors) return context;
  return {
    ...context,
    actors: context.actors.map((summary) => {
      if (!summary.privateDataVisible) return summary;
      const actor = store.state.actors.find((item) => item.id === summary.id && item.campaignId === context.campaignId);
      if (!actor) return summary;
      return {
        ...summary,
        systemId: actor.systemId,
        actions: systemQuickRolls(actor, actorItems(store, actor)).map((action) => ({
          rollId: action.id,
          label: action.label,
          formula: action.formula
        }))
      };
    })
  };
}

function readBoardStateToolOutput(context: AiToolContext, scene: Scene, selectedTokenIds: string[]): BoardStateToolOutput {
  const store = { state: context.state, save: () => undefined, replace: () => undefined } satisfies StateStore;
  const sceneTokens = context.state.tokens.filter((token) => token.sceneId === scene.id);
  const visibleTokens = visibleTokensForUser(store, context.userId, context.campaignId, sceneTokens);
  const visibleTokenIds = new Set(visibleTokens.map((token) => token.id));
  const mapAsset = scene.backgroundAssetId ? context.state.assets.find((asset) => asset.id === scene.backgroundAssetId && asset.campaignId === context.campaignId) : undefined;
  const activeCombat = context.state.combats.find((combat) => combat.campaignId === context.campaignId && combat.active);
  const annotationLayerCounts = { measurement: 0, effects: 0, drawings: 0, notes: 0 } satisfies Record<SceneAnnotationLayer, number>;
  for (const annotation of scene.annotations ?? []) {
    annotationLayerCounts[annotation.layer ?? boardAnnotationDefaultLayer(annotation.kind)] += 1;
  }
  const tokenLayerCounts = { map: 0, player: 0, gm: 0 } satisfies Record<TokenLayer, number>;
  for (const token of visibleTokens) tokenLayerCounts[tokenLayer(token)] += 1;
  return {
    scene: {
      id: scene.id,
      name: scene.name,
      active: scene.active,
      width: scene.width,
      height: scene.height,
      gridType: scene.gridType,
      gridSize: scene.gridSize,
      backgroundAssetId: scene.backgroundAssetId
    },
    mapAsset: mapAsset
      ? {
          id: mapAsset.id,
          name: mapAsset.name,
          mimeType: mapAsset.mimeType,
          sizeBytes: mapAsset.sizeBytes,
          lifecycleStatus: mapAsset.lifecycle?.status ?? "active"
        }
      : undefined,
    tokens: visibleTokens
      .sort((left, right) => tokenLayer(left).localeCompare(tokenLayer(right)) || left.name.localeCompare(right.name) || left.id.localeCompare(right.id))
      .slice(0, 100)
      .map((token) => ({
        id: token.id,
        name: token.name,
        actorId: token.actorId,
        x: token.x,
        y: token.y,
        width: token.width,
        height: token.height,
        layer: tokenLayer(token),
        hidden: token.hidden,
        disposition: token.disposition,
        imageAssetId: token.imageAssetId
      })),
    tokenLayerCounts,
    selectedTokens: selectedTokenIds.filter((id) => visibleTokenIds.has(id)).slice(0, 50),
    fog: {
      active: scene.fog.some((fog) => !fog.hidden),
      regionCount: scene.fog.length,
      historyCount: scene.fogHistory?.length ?? 0,
      sample: scene.fog.slice(0, 12).map((fog) => ({ id: fog.id, mode: fog.mode ?? "reveal", shape: fog.shape ?? "circle", hidden: fog.hidden, x: fog.x, y: fog.y, radius: fog.radius, pointCount: fog.points?.length ?? 0 }))
    },
    walls: {
      count: scene.walls.length,
      terrainCount: scene.walls.filter((wall) => wall.kind === "terrain").length,
      sample: scene.walls.slice(0, 12).map((wall) => ({ id: wall.id, kind: wall.kind ?? "wall", x1: wall.x1, y1: wall.y1, x2: wall.x2, y2: wall.y2, blocksVision: wall.blocksVision, blocksMovement: wall.blocksMovement ?? wall.kind !== "terrain" }))
    },
    lights: {
      count: scene.lights.length,
      sample: scene.lights.slice(0, 12).map((light) => ({ id: light.id, x: light.x, y: light.y, radius: light.radius, brightRadius: light.brightRadius, dimRadius: light.dimRadius, color: light.color, intensity: light.intensity }))
    },
    annotations: {
      count: scene.annotations?.length ?? 0,
      layerCounts: annotationLayerCounts,
      sample: (scene.annotations ?? []).slice(0, 12).map((annotation) => ({ id: annotation.id, kind: annotation.kind, layer: annotation.layer ?? boardAnnotationDefaultLayer(annotation.kind), pointCount: annotation.points.length, color: annotation.color, label: annotation.label }))
    },
    activeCombat: activeCombat
      ? {
          id: activeCombat.id,
          round: activeCombat.round,
          turnIndex: activeCombat.turnIndex,
          combatantCount: activeCombat.combatants.length,
          currentCombatantId: activeCombat.combatants[activeCombat.turnIndex]?.id,
          combatants: activeCombat.combatants
            .filter((combatant) => !combatant.tokenId || visibleTokenIds.has(combatant.tokenId))
            .slice(0, 20)
            .map((combatant) => ({ id: combatant.id, tokenId: combatant.tokenId, actorId: combatant.actorId, name: combatant.name, initiative: combatant.initiative, defeated: combatant.defeated }))
        }
      : undefined
  };
}

function boardAnnotationDefaultLayer(kind: SceneAnnotationKind): SceneAnnotationLayer {
  if (kind === "ruler") return "measurement";
  if (kind === "template") return "effects";
  if (kind === "drawing") return "drawings";
  return "notes";
}

function actorReadToolSummary(context: AiToolContext, actor: Actor): ActorReadToolOutput["actors"][number] {
  const store = { state: context.state, save: () => undefined, replace: () => undefined } satisfies StateStore;
  const privateDataVisible = canReadActorPrivateData(store, context.userId, context.campaignId, actor);
  if (!privateDataVisible) {
    return {
      id: actor.id,
      name: actor.name,
      type: actor.type,
      systemId: actor.systemId,
      privateDataVisible,
      ownerUserId: actor.ownerUserId,
      imageAssetId: actor.imageAssetId,
      pools: {},
      conditions: [],
      itemCount: 0,
      items: [],
      actions: [],
      createdAt: actor.createdAt,
      updatedAt: actor.updatedAt
    };
  }
  const items = context.state.items.filter((item) => item.actorId === actor.id && item.campaignId === actor.campaignId);
  return {
    id: actor.id,
    name: actor.name,
    type: actor.type,
    systemId: actor.systemId,
    privateDataVisible,
    ownerUserId: actor.ownerUserId,
    imageAssetId: actor.imageAssetId,
    pools: actorReadToolPools(actor),
    conditions: actorReadToolConditions(actor),
    itemCount: items.length,
    items: items.slice(0, 12).map(actorReadToolItemSummary),
    actions: systemQuickRolls(actor, items)
      .slice(0, 20)
      .map((action) => ({ rollId: action.id, label: action.label, formula: action.formula })),
    createdAt: actor.createdAt,
    updatedAt: actor.updatedAt
  };
}

function actorReadToolPools(actor: Actor): Record<string, { current?: number; max?: number }> {
  const pools: Record<string, { current?: number; max?: number }> = {};
  for (const key of ["hp", "stamina", "composure", "focus"]) {
    const value = actor.data[key];
    if (!isRecord(value)) continue;
    const current = typeof value.current === "number" ? value.current : undefined;
    const max = typeof value.max === "number" ? value.max : undefined;
    if (current !== undefined || max !== undefined) pools[key] = { current, max };
  }
  return pools;
}

function actorReadToolConditions(actor: Actor): string[] {
  const conditions = actor.data.conditions;
  if (!Array.isArray(conditions)) return [];
  return conditions.filter((condition): condition is string => typeof condition === "string").slice(0, 20);
}

function actorReadToolItemSummary(item: Item): ActorReadToolOutput["actors"][number]["items"][number] {
  const data = isRecord(item.data) ? item.data : {};
  return {
    id: item.id,
    name: item.name,
    type: item.type,
    quantity: typeof data.quantity === "number" ? data.quantity : undefined,
    equipped: typeof data.equipped === "boolean" ? data.equipped : undefined
  };
}

function resolveSystemActionRoll(
  quickRolls: Array<{ id: string; label: string; formula: string; metadata?: Record<string, unknown> }>,
  actionRollId: string | undefined,
  actionName: string | undefined
): { id: string; label: string; formula: string; metadata?: Record<string, unknown> } | undefined {
  if (actionRollId) return quickRolls.find((action) => action.id === actionRollId);
  if (!actionName) return undefined;
  const normalized = normalizeActionLookup(actionName);
  return quickRolls.find((action) => normalizeActionLookup(action.label) === normalized || normalizeActionLookup(action.id) === normalized);
}

function normalizeActionLookup(value: string): string {
  return value.toLowerCase().replace(/[^a-z0-9]+/g, " ").trim();
}

function systemRollTargetActorIds(targetActorIds: string[] | undefined, targetActorId?: string, fallbackTargetActorId?: string): string[] {
  const explicitTargets = [...(Array.isArray(targetActorIds) ? targetActorIds : []), targetActorId].filter((value): value is string => typeof value === "string" && value.trim().length > 0);
  const targets = explicitTargets.length > 0 ? explicitTargets : fallbackTargetActorId ? [fallbackTargetActorId] : [];
  return [...new Set(targets.map((value) => value.trim()))];
}

function dnd5eSrdCommitInputMessage(resolution: RulesActionResolutionResult, applyEffect: boolean): string | undefined {
  if (resolution.pendingSaves.some((save) => save.requiredForCommit)) return "Save outcomes are required before this D&D action can be committed.";
  if (applyEffect && resolution.pendingChoice) return resolution.pendingChoice.reason;
  if (applyEffect && resolution.manualResolutionRequired) return resolution.manualResolutionRequired.reason;
  return undefined;
}

function syncDnd5eSrdResolvedConditionToCombat(combat: Combat, condition: { actorId: string; operation: string; conditionId?: string; durationRounds?: number }): boolean {
  if (condition.operation !== "apply" || !condition.conditionId) return false;
  const combatant = combat.combatants.find((item) => item.actorId === condition.actorId);
  if (!combatant) return false;
  const addition = condition.durationRounds ? `${condition.conditionId}:${condition.durationRounds}` : condition.conditionId;
  const before = normalizeCombatantConditionList(combatant.conditions);
  const after = normalizeCombatantConditionList([...before, addition]);
  if (after.length === before.length && after.every((item, index) => item === before[index])) return false;
  combatant.conditions = after;
  return true;
}

function systemRollEffectTotalForSave(rollDefinition: { id: string; label: string; metadata?: Record<string, unknown> }, total: number, saveOutcome?: RulesSaveOutcome): number | undefined {
  if (saveOutcome !== "success") return total;
  const metadata = isRecord(rollDefinition.metadata) ? rollDefinition.metadata : {};
  const save = isRecord(metadata.save) ? metadata.save : {};
  const success = typeof save.success === "string" ? save.success.toLowerCase() : "";
  if (success.includes("half")) return Math.floor(total / 2);
  if (systemRollEffectType(rollDefinition) === "damage") return 0;
  return undefined;
}

function syncDnd5eSrdRollConditionToCombat(combat: Combat, targetActorId: string, rollDefinition: { id: string; metadata?: Record<string, unknown> }): boolean {
  const combatant = combat.combatants.find((item) => item.actorId === targetActorId);
  if (!combatant) return false;
  const conditions = systemRollConditionEffects(rollDefinition);
  if (conditions.length === 0) return false;
  const durationRounds = systemRollConditionDurationRounds(rollDefinition);
  const additions = conditions.map((condition) => (durationRounds ? `${condition.id}:${durationRounds}` : condition.id));
  const before = normalizeCombatantConditionList(combatant.conditions);
  const after = normalizeCombatantConditionList([...before, ...additions]);
  if (after.length === before.length && after.every((condition, index) => condition === before[index])) return false;
  combatant.conditions = after;
  return true;
}

function systemRollConditionDurationRounds(rollDefinition: { metadata?: Record<string, unknown> }): number | undefined {
  const metadata = isRecord(rollDefinition.metadata) ? rollDefinition.metadata : {};
  const duration = stringValue(metadata.conditionDuration) ?? stringValue(metadata.duration);
  if (!duration) return undefined;
  const normalized = duration.toLowerCase().replace(/^up to\s+/, "").trim();
  if (normalized.includes("current turn") || normalized.includes("next turn")) return 1;
  const match = normalized.match(/(\d+)\s*(round|minute|hour|day)s?/);
  if (!match) return undefined;
  const amount = Math.max(1, Math.floor(Number(match[1])));
  const unit = match[2];
  if (unit === "round") return amount;
  if (unit === "minute") return amount * 10;
  if (unit === "hour") return amount * 600;
  return amount * 14_400;
}

function applySystemRollEffect(actor: Actor, rollDefinition: { id: string; label: string; metadata?: Record<string, unknown> }, total: number, options: SystemRollEffectOptions = {}): SystemRollEffectApplication {
  const type = systemRollEffectType(rollDefinition);
  if (!type) {
    const conditions = options.allowConditionEffects ? systemRollConditionEffects(rollDefinition) : [];
    if (conditions.length > 0) return applySystemConditionRollEffects(actor, conditions);
    return { error: "unsupported_effect", message: "Roll is not a damage, healing, or supported condition action" };
  }
  const pool = systemEffectPool(actor);
  if (!pool) return { error: "unsupported_target", message: "Target actor does not expose a supported damage/healing pool" };
  const poolValue = actor.data[pool];
  if (!isRecord(poolValue)) return { error: "unsupported_target", message: `Target actor ${pool} pool is unavailable` };
  const current = typeof poolValue.current === "number" ? poolValue.current : Number.NaN;
  const max = typeof poolValue.max === "number" ? poolValue.max : Number.NaN;
  if (!Number.isFinite(current) || !Number.isFinite(max)) return { error: "unsupported_target", message: `Target actor ${pool} pool is invalid` };
  const amount = Math.max(0, Math.floor(total));
  const after = type === "healing" ? Math.min(max, current + amount) : Math.max(0, current - amount);
  return {
    data: {
      ...actor.data,
      [pool]: {
        ...poolValue,
        current: after
      }
    },
    effect: {
      type,
      targetActorId: actor.id,
      targetActorName: actor.name,
      pool,
      amount,
      before: current,
      after,
      max
    }
  };
}

function applySystemConditionRollEffects(actor: Actor, conditions: Array<{ id: string; name: string }>): SystemRollEffectApplication {
  let data = actor.data;
  const effects: SystemRollEffectResult[] = [];
  try {
    for (const condition of conditions) {
      const before = systemConditionIds(data.conditions);
      data = applySystemCondition({ ...actor, data }, condition.id, nowIso());
      effects.push({
        type: "condition",
        targetActorId: actor.id,
        targetActorName: actor.name,
        conditionId: condition.id,
        conditionName: condition.name,
        before,
        after: systemConditionIds(data.conditions),
        alreadyPresent: before.includes(condition.id)
      });
    }
    return { data, effect: effects[0]!, effects };
  } catch (error) {
    return { error: "unsupported_effect", message: error instanceof Error ? error.message : "Unknown condition effect" };
  }
}

function systemRollEffectType(rollDefinition: { id: string; label: string }): "damage" | "healing" | undefined {
  const id = rollDefinition.id.toLowerCase();
  const label = rollDefinition.label.toLowerCase();
  if (id.endsWith("-healing") || /\bhealing\b/.test(label)) return "healing";
  if (id.endsWith("-damage") || /\bdamage\b/.test(label)) return "damage";
  return undefined;
}

function systemRollConditionEffects(rollDefinition: { id: string; metadata?: Record<string, unknown> }): Array<{ id: string; name: string }> {
  const metadata = isRecord(rollDefinition.metadata) ? rollDefinition.metadata : {};
  const failure = isRecord(metadata.failure) ? metadata.failure : {};
  const conditionNames = uniqueStrings([
    ...splitSystemConditionNames(typeof metadata.condition === "string" ? metadata.condition : undefined),
    ...splitSystemConditionNames(typeof failure.condition === "string" ? failure.condition : undefined),
    ...stringArrayValue(metadata.conditions).flatMap(splitSystemConditionNames),
    ...stringArrayValue(metadata.additionalConditions).flatMap(splitSystemConditionNames)
  ]);
  return conditionNames.map((name) => ({ id: slugConditionId(name), name }));
}

function splitSystemConditionNames(value: string | undefined): string[] {
  return value
    ? value
        .split(/[\/,]/)
        .map((item) => item.trim())
        .filter(Boolean)
    : [];
}

function stringArrayValue(value: unknown): string[] {
  if (Array.isArray(value)) return value.filter((item): item is string => typeof item === "string" && item.trim().length > 0);
  if (typeof value === "string" && value.trim()) return [value.trim()];
  return [];
}

function stringValue(value: unknown): string | undefined {
  return typeof value === "string" && value.trim() ? value.trim() : undefined;
}

function uniqueStrings(values: string[]): string[] {
  return [...new Set(values.map((value) => value.trim()).filter(Boolean))];
}

function slugConditionId(value: string): string {
  return value.toLowerCase().replace(/[^a-z0-9]+/g, "-").replace(/^-+|-+$/g, "");
}

function systemConditionIds(value: unknown): string[] {
  if (!Array.isArray(value)) return [];
  return value.flatMap((condition) => {
    if (typeof condition === "string") return condition;
    if (isRecord(condition) && typeof condition.id === "string") return condition.id;
    return [];
  });
}

function systemEffectPool(actor: Actor): "hp" | "strain" | "composure" | undefined {
  if (isRecord(actor.data.hp)) return "hp";
  if (isRecord(actor.data.strain)) return "strain";
  if (isRecord(actor.data.composure)) return "composure";
  return undefined;
}

const proposalChangeEntities = new Set<ProposalChange["entity"]>(["campaign", "world", "scene", "token", "actor", "item", "journal", "handout", "chat", "roll", "diceMacro", "encounter", "combat", "asset", "fogPreset", "pluginStorage"]);
const proposalChangeActions = new Set<ProposalChange["action"]>(["create", "update", "delete"]);
const campaignProposalMutableFields = new Set(["name", "description", "defaultSystemId", "visibility"]);

function prepareProposalChanges(
  store: StateStore,
  campaignId: string,
  userId: string,
  value: unknown,
  options: { currentProposalId?: string } = {}
): { changes: ProposalChange[] } | { error: string; message: string } {
  if (!Array.isArray(value)) return { error: "invalid_proposal_changes", message: "Proposal changesJson must be an array" };
  const changes: ProposalChange[] = [];
  for (const [index, rawChange] of value.entries()) {
    const change = proposalChangeFromInput(rawChange);
    if (!change) return { error: "invalid_proposal_change", message: `Proposal change ${index + 1} is invalid` };
    changes.push(change);
  }
  const normalizedChanges = normalizeProposalChanges(changes, campaignId, userId, store.state);
  const createdSceneIds = new Set(
    normalizedChanges
      .filter((change) => change.entity === "scene" && change.action === "create")
      .map((change) => stringFromRecord(change.data, "id"))
      .filter((id): id is string => Boolean(id))
  );
  const createdActorIds = new Set(
    normalizedChanges
      .filter((change) => change.entity === "actor" && change.action === "create")
      .map((change) => stringFromRecord(change.data, "id"))
      .filter((id): id is string => Boolean(id))
  );
  const createdWorldIds = new Set(
    normalizedChanges
      .filter((change) => change.entity === "world" && change.action === "create")
      .map((change) => stringFromRecord(change.data, "id"))
      .filter((id): id is string => Boolean(id))
  );
  for (const [index, change] of normalizedChanges.entries()) {
    const scopeError = proposalChangeScopeError(store, campaignId, change, createdSceneIds, createdActorIds, createdWorldIds, options);
    if (scopeError) return { error: "invalid_proposal_scope", message: `Proposal change ${index + 1} ${scopeError}` };
  }
  return { changes: normalizedChanges };
}

function proposalChangeFromInput(value: unknown): ProposalChange | undefined {
  if (!isRecord(value)) return undefined;
  if (!proposalChangeEntities.has(value.entity as ProposalChange["entity"])) return undefined;
  if (!proposalChangeActions.has(value.action as ProposalChange["action"])) return undefined;
  const entity = value.entity as ProposalChange["entity"];
  const action = value.action as ProposalChange["action"];
  const id = typeof value.id === "string" && value.id.trim() ? value.id.trim() : undefined;
  if (action !== "create" && !id) return undefined;
  const data = isRecord(value.data) ? { ...value.data } : {};
  return id ? { entity, action, id, data } : { entity, action, data };
}

function proposalChangeScopeError(store: StateStore, campaignId: string, change: ProposalChange, createdSceneIds: Set<string>, createdActorIds: Set<string>, createdWorldIds: Set<string>, options: { currentProposalId?: string }): string | undefined {
  if (change.entity === "campaign") {
    if (change.action === "create") return "cannot create campaigns from a campaign proposal";
    if (change.action === "delete") return "cannot delete campaigns from a campaign proposal";
    const targetId = change.id ?? stringFromRecord(change.data, "id");
    if (targetId !== campaignId) return "targets a different campaign";
    const immutableField = Object.keys(change.data).find((field) => !campaignProposalMutableFields.has(field));
    return immutableField ? `cannot edit immutable or lifecycle campaign field ${immutableField}` : undefined;
  }
  if (change.action === "create") return proposalCreateScopeError(store, campaignId, change, createdSceneIds, createdActorIds, createdWorldIds, options);
  const existingCampaignId = campaignIdForProposalEntity(store, change.entity, change.id);
  if (!existingCampaignId) return `targets a missing ${change.entity}`;
  if (existingCampaignId !== campaignId) return `targets a ${change.entity} outside this campaign`;
  const dataCampaignId = stringFromRecord(change.data, "campaignId");
  if (dataCampaignId && dataCampaignId !== campaignId) return `moves a ${change.entity} outside this campaign`;
  const sceneScopeError = proposalSceneReferenceScopeError(store, campaignId, change.data, createdSceneIds);
  if (sceneScopeError) return sceneScopeError;
  const actorScopeError = proposalActorReferenceScopeError(store, campaignId, change.data, createdActorIds);
  if (actorScopeError) return actorScopeError;
  const worldScopeError = proposalWorldReferenceScopeError(store, campaignId, change.data, createdWorldIds);
  if (worldScopeError) return worldScopeError;
  return undefined;
}

function proposalCreateScopeError(store: StateStore, campaignId: string, change: ProposalChange, createdSceneIds: Set<string>, createdActorIds: Set<string>, createdWorldIds: Set<string>, options: { currentProposalId?: string }): string | undefined {
  const createdId = stringFromRecord(change.data, "id");
  if (createdId && proposalEntityExists(store, change.entity, createdId, options)) return `creates a ${change.entity} id that already exists`;
  if (change.entity === "token") {
    const sceneId = stringFromRecord(change.data, "sceneId");
    if (!sceneId) return "must include a sceneId for token creation";
    if (!createdSceneIds.has(sceneId) && !store.state.scenes.some((scene) => scene.id === sceneId && scene.campaignId === campaignId)) return "creates a token outside this campaign";
    return proposalActorReferenceScopeError(store, campaignId, change.data, createdActorIds);
  }
  const dataCampaignId = stringFromRecord(change.data, "campaignId");
  if (dataCampaignId !== campaignId) return `creates a ${change.entity} outside this campaign`;
  const sceneScopeError = proposalSceneReferenceScopeError(store, campaignId, change.data, createdSceneIds);
  if (sceneScopeError) return sceneScopeError;
  const actorScopeError = proposalActorReferenceScopeError(store, campaignId, change.data, createdActorIds);
  if (actorScopeError) return actorScopeError;
  const worldScopeError = proposalWorldReferenceScopeError(store, campaignId, change.data, createdWorldIds);
  if (worldScopeError) return worldScopeError;
  return undefined;
}

function proposalEntityExists(store: StateStore, entity: ProposalChange["entity"], id: string, options: { currentProposalId?: string } = {}): boolean {
  switch (entity) {
    case "campaign":
      return store.state.campaigns.some((item) => item.id === id);
    case "world":
      return store.state.worlds.some((item) => item.id === id);
    case "scene":
      return store.state.scenes.some((item) => item.id === id);
    case "token":
      return store.state.tokens.some((item) => item.id === id);
    case "actor":
      return store.state.actors.some((item) => item.id === id);
    case "item":
      return store.state.items.some((item) => item.id === id);
    case "journal":
      return store.state.journals.some((item) => item.id === id);
    case "handout":
      return store.state.handouts.some((item) => item.id === id);
    case "chat":
      return store.state.chat.some((item) => item.id === id);
    case "roll":
      return store.state.rolls.some((item) => item.id === id);
    case "diceMacro":
      return store.state.diceMacros.some((item) => item.id === id);
    case "encounter":
      return store.state.encounters.some((item) => item.id === id);
    case "campaignSession":
      return store.state.campaignSessions.some((item) => item.id === id);
    case "combat":
      return store.state.combats.some((item) => item.id === id);
    case "asset":
      return store.state.assets.some((item) => item.id === id) || Boolean(pendingProposalAssetForDelivery(store, id, options.currentProposalId));
    case "fogPreset":
      return store.state.fogPresets.some((item) => item.id === id);
    case "pluginStorage":
      return store.state.pluginStorage.some((item) => item.id === id);
    case "aiMemory":
      return store.state.aiMemory.some((item) => item.id === id);
  }
}

function proposalSceneReferenceScopeError(store: StateStore, campaignId: string, data: Record<string, unknown>, createdSceneIds: Set<string>): string | undefined {
  const sceneId = stringFromRecord(data, "sceneId");
  if (!sceneId) return undefined;
  if (createdSceneIds.has(sceneId) || store.state.scenes.some((scene) => scene.id === sceneId && scene.campaignId === campaignId)) return undefined;
  return "references a scene outside this campaign";
}

function proposalActorReferenceScopeError(store: StateStore, campaignId: string, data: Record<string, unknown>, createdActorIds: Set<string> = new Set()): string | undefined {
  const actorId = stringFromRecord(data, "actorId");
  if (!actorId) return undefined;
  if (createdActorIds.has(actorId)) return undefined;
  return store.state.actors.some((actor) => actor.id === actorId && actor.campaignId === campaignId) ? undefined : "references an actor outside this campaign";
}

function proposalWorldReferenceScopeError(store: StateStore, campaignId: string, data: Record<string, unknown>, createdWorldIds: Set<string> = new Set()): string | undefined {
  const worldId = stringFromRecord(data, "worldId");
  if (!worldId) return undefined;
  if (createdWorldIds.has(worldId)) return undefined;
  return store.state.worlds.some((world) => world.id === worldId && world.campaignId === campaignId) ? undefined : "references a world outside this campaign";
}

function campaignIdForProposalEntity(store: StateStore, entity: ProposalChange["entity"], id: string | undefined): string | undefined {
  if (!id) return undefined;
  switch (entity) {
    case "world":
      return store.state.worlds.find((item) => item.id === id)?.campaignId;
    case "scene":
      return store.state.scenes.find((item) => item.id === id)?.campaignId;
    case "token": {
      const token = store.state.tokens.find((item) => item.id === id);
      return token ? campaignIdForScene(store, token.sceneId) : undefined;
    }
    case "actor":
      return store.state.actors.find((item) => item.id === id)?.campaignId;
    case "item":
      return store.state.items.find((item) => item.id === id)?.campaignId;
    case "journal":
      return store.state.journals.find((item) => item.id === id)?.campaignId;
    case "handout":
      return store.state.handouts.find((item) => item.id === id)?.campaignId;
    case "chat":
      return store.state.chat.find((item) => item.id === id)?.campaignId;
    case "roll":
      return store.state.rolls.find((item) => item.id === id)?.campaignId;
    case "diceMacro":
      return store.state.diceMacros.find((item) => item.id === id)?.campaignId;
    case "encounter":
      return store.state.encounters.find((item) => item.id === id)?.campaignId;
    case "campaignSession":
      return store.state.campaignSessions.find((item) => item.id === id)?.campaignId;
    case "combat":
      return store.state.combats.find((item) => item.id === id)?.campaignId;
    case "asset":
      return store.state.assets.find((item) => item.id === id)?.campaignId ?? pendingProposalAssetForDelivery(store, id)?.campaignId;
    case "fogPreset":
      return store.state.fogPresets.find((item) => item.id === id)?.campaignId;
    case "pluginStorage":
      return store.state.pluginStorage.find((item) => item.id === id)?.campaignId;
    case "aiMemory":
      return store.state.aiMemory.find((item) => item.id === id)?.campaignId;
    case "campaign":
      return store.state.campaigns.find((item) => item.id === id)?.id;
  }
}

function normalizeProposalChanges(changes: ProposalChange[], campaignId: string, userId: string, state?: EngineState): ProposalChange[] {
  return changes.map((change) => {
    const data = {
      ...change.data
    };
    if (change.entity === "token" && change.action === "create") normalizeProposalTokenCreateData(data, state);
    if (change.action !== "create") return { ...change, data };
    if (typeof data.id !== "string") data.id = createId(prefixForProposalEntity(change.entity));
    if (change.entity !== "token" && typeof data.campaignId !== "string") data.campaignId = campaignId;
    if (typeof data.createdAt !== "string") data.createdAt = nowIso();
    if (typeof data.updatedAt !== "string") data.updatedAt = data.createdAt;

    if (change.entity === "journal") {
      if (typeof data.visibility !== "string") data.visibility = "gm_only";
      if (!Array.isArray(data.visibleToUserIds)) data.visibleToUserIds = [];
      if (!Array.isArray(data.visibleToActorIds)) data.visibleToActorIds = [];
      if (!Array.isArray(data.tags)) data.tags = ["ai"];
      if (typeof data.createdBy !== "string") data.createdBy = userId;
      if (typeof data.updatedBy !== "string") data.updatedBy = userId;
    }

    if (change.entity === "handout") {
      if (typeof data.visibility !== "string") data.visibility = "gm_only";
      if (!Array.isArray(data.visibleToUserIds)) data.visibleToUserIds = [];
      if (!Array.isArray(data.visibleToActorIds)) data.visibleToActorIds = [];
      if (!Array.isArray(data.assetIds)) data.assetIds = [];
      if (!Array.isArray(data.tags)) data.tags = ["ai"];
      if (!Array.isArray(data.readByUserIds)) data.readByUserIds = [];
      if (typeof data.createdBy !== "string") data.createdBy = userId;
      if (typeof data.updatedBy !== "string") data.updatedBy = userId;
    }

    if (change.entity === "pluginStorage") {
      if (typeof data.updatedByType !== "string") data.updatedByType = "plugin";
      if (typeof data.updatedById !== "string") data.updatedById = userId;
    }

    if (change.entity === "diceMacro") {
      if (typeof data.createdBy !== "string") data.createdBy = userId;
      if (data.visibility !== "gm_only") data.visibility = "public";
    }

    if (change.entity === "fogPreset") {
      if (!Array.isArray(data.regions)) data.regions = [];
      if (!isRecord(data.metadata)) data.metadata = { source: "ai_tool" };
    }

    return {
      ...change,
      data
    };
  });
}

function normalizeProposalTokenCreateData(data: Record<string, unknown>, state: EngineState | undefined): void {
  const sceneId = stringFromRecord(data, "sceneId");
  const scene = sceneId && state ? state.scenes.find((item) => item.id === sceneId) : undefined;
  if (!scene) return;
  const width = normalizeProposalTokenDimension(data.width, scene.width, scene.gridSize);
  const height = normalizeProposalTokenDimension(data.height, scene.height, scene.gridSize);
  const centerX =
    typeof data.centerX === "number" && Number.isFinite(data.centerX)
      ? data.centerX
      : typeof data.x === "number" && Number.isFinite(data.x)
        ? data.x
        : scene.gridSize / 2;
  const centerY =
    typeof data.centerY === "number" && Number.isFinite(data.centerY)
      ? data.centerY
      : typeof data.y === "number" && Number.isFinite(data.y)
        ? data.y
        : scene.gridSize / 2;
  const position = tokenCoordinatesFromGridCenter(scene, width, height, centerX, centerY);
  data.x = position.x;
  data.y = position.y;
  data.width = width;
  data.height = height;
  delete data.centerX;
  delete data.centerY;
  if (typeof data.rotation !== "number" || !Number.isFinite(data.rotation)) data.rotation = 0;
  if (data.layer !== "map" && data.layer !== "player" && data.layer !== "gm") data.layer = "player";
  if (typeof data.hidden !== "boolean") data.hidden = false;
  if (typeof data.locked !== "boolean") data.locked = false;
  if (typeof data.visionEnabled !== "boolean") data.visionEnabled = true;
  if (typeof data.visionRadius !== "number" || !Number.isFinite(data.visionRadius)) data.visionRadius = 160;
  if (data.disposition !== "friendly" && data.disposition !== "neutral" && data.disposition !== "hostile") data.disposition = "neutral";
  if (!Array.isArray(data.conditions)) data.conditions = [];
  if (!Array.isArray(data.auras)) data.auras = [];
  if (!Array.isArray(data.targetedByUserIds)) data.targetedByUserIds = [];
  if (!isRecord(data.metadata)) data.metadata = { source: "ai_tool" };
}

function normalizeProposalTokenDimension(value: unknown, sceneAxisSize: number, gridSize: number): number {
  const safeGridSize = Math.max(1, Math.round(gridSize) || 1);
  if (typeof value !== "number" || !Number.isFinite(value)) return Math.min(sceneAxisSize, safeGridSize);
  if (value > 0 && value <= 8) return Math.min(sceneAxisSize, Math.max(safeGridSize, Math.round(value * safeGridSize)));
  if (value > 0 && value < safeGridSize / 2) return Math.min(sceneAxisSize, safeGridSize);
  return Math.min(sceneAxisSize, Math.max(1, Math.round(value)));
}

function proposalToolSummary(proposal: Proposal): Record<string, unknown> {
  return {
    id: proposal.id,
    campaignId: proposal.campaignId,
    createdByUserId: proposal.createdByUserId,
    createdByType: proposal.createdByType,
    sourceId: proposal.sourceId,
    title: proposal.title,
    summary: proposal.summary,
    status: proposal.status,
    changeCount: proposal.changesJson.length,
    entities: [...new Set(proposal.changesJson.map((change) => change.entity))],
    boardStateChanged: proposalTouchesBoardState(proposal),
    approvalRequired: proposal.approvalRequired,
    approvedByUserId: proposal.approvedByUserId,
    createdAt: proposal.createdAt,
    updatedAt: proposal.updatedAt
  };
}

function proposalAppliedEntityRefs(proposal: Proposal): Omit<AutoAppliedProposalToolOutput, "proposalId" | "boardStateChanged" | "proposal"> {
  const sceneIds = new Set<string>();
  const createdSceneIds = new Set<string>();
  const updatedSceneIds = new Set<string>();
  const tokenIds = new Set<string>();
  const createdTokenIds = new Set<string>();
  const assetIds = new Set<string>();
  const createdAssetIds = new Set<string>();
  const actorIds = new Set<string>();
  const createdActorIds = new Set<string>();

  for (const change of proposal.changesJson) {
    const id = proposalChangeEntityId(change);
    switch (change.entity) {
      case "scene":
        if (id) {
          sceneIds.add(id);
          if (change.action === "create") createdSceneIds.add(id);
          if (change.action === "update") updatedSceneIds.add(id);
        }
        break;
      case "token":
        if (id) {
          tokenIds.add(id);
          if (change.action === "create") createdTokenIds.add(id);
        }
        if (typeof change.data.sceneId === "string") sceneIds.add(change.data.sceneId);
        break;
      case "asset":
        if (id) {
          assetIds.add(id);
          if (change.action === "create") createdAssetIds.add(id);
        }
        break;
      case "actor":
        if (id) {
          actorIds.add(id);
          if (change.action === "create") createdActorIds.add(id);
        }
        break;
      default:
        break;
    }
  }

  return {
    sceneIds: [...sceneIds],
    createdSceneIds: [...createdSceneIds],
    updatedSceneIds: [...updatedSceneIds],
    tokenIds: [...tokenIds],
    createdTokenIds: [...createdTokenIds],
    assetIds: [...assetIds],
    createdAssetIds: [...createdAssetIds],
    actorIds: [...actorIds],
    createdActorIds: [...createdActorIds]
  };
}

function proposalChangeEntityId(change: ProposalChange): string | undefined {
  if (change.action === "create") return typeof change.data.id === "string" ? change.data.id : undefined;
  if (typeof change.id === "string") return change.id;
  return typeof change.data.id === "string" ? change.data.id : undefined;
}

function visibleProposalsForUser(state: EngineState, userId: string, campaignId: string, permissions: PermissionName[]): Proposal[] {
  return state.proposals.filter((proposal) => proposalVisibleToUser(state, userId, campaignId, permissions, proposal));
}

function proposalVisibleToUser(state: EngineState, userId: string, campaignId: string, permissions: PermissionName[], proposal: Proposal): boolean {
  if (proposal.campaignId !== campaignId) return false;
  if (permissions.includes("ai.applyChanges")) return true;
  if (proposal.createdByType === "ai" && proposal.status === "pending") return false;
  return proposal.changesJson.every((change) => proposalChangePayloadVisibleToUser(state, userId, campaignId, permissions, change));
}

function proposalChangePayloadVisibleToUser(state: EngineState, userId: string, campaignId: string, permissions: PermissionName[], change: ProposalChange): boolean {
  if (change.entity === "journal") return journalProposalChangePayloadVisibleToUser(state, userId, campaignId, permissions, change);
  const canViewPrep = proposalPermissionsIncludePrepAccess(permissions);
  const changeId = proposalChangeEntityId(change);

  if (change.entity === "campaign") return permissions.includes("campaign.update");
  if (change.entity === "world") return permissions.includes("world.read") && canViewPrep;
  if (change.entity === "scene") {
    const existing = changeId ? state.scenes.find((scene) => scene.id === changeId && scene.campaignId === campaignId) : undefined;
    const active = typeof change.data.active === "boolean" ? change.data.active : existing?.active ?? false;
    return canViewPrep || active;
  }
  if (change.entity === "token") {
    const existing = changeId ? state.tokens.find((token) => token.id === changeId) : undefined;
    const sceneId = typeof change.data.sceneId === "string" ? change.data.sceneId : existing?.sceneId;
    const scene = sceneId ? state.scenes.find((candidate) => candidate.id === sceneId && candidate.campaignId === campaignId) : undefined;
    if (!scene || (!scene.active && !canViewPrep)) return false;
    if (canViewPrep) return true;
    const hidden = typeof change.data.hidden === "boolean" ? change.data.hidden : existing?.hidden ?? false;
    const layer = change.data.layer === "map" || change.data.layer === "player" || change.data.layer === "gm" ? change.data.layer : existing?.layer ?? "player";
    return !hidden && layer === "player";
  }
  if (change.entity === "actor") {
    const existing = changeId ? state.actors.find((actor) => actor.id === changeId && actor.campaignId === campaignId) : undefined;
    const ownerUserId = typeof change.data.ownerUserId === "string" ? change.data.ownerUserId : existing?.ownerUserId;
    const actorPermissions = isRecord(change.data.permissions) ? change.data.permissions : existing?.permissions;
    const userPermissions = actorPermissions && Array.isArray(actorPermissions[userId]) ? actorPermissions[userId] : [];
    return permissions.includes("actor.readPrivate") || ownerUserId === userId || userPermissions.includes("actor.readPrivate");
  }
  if (change.entity === "item") {
    const existing = changeId ? state.items.find((item) => item.id === changeId && item.campaignId === campaignId) : undefined;
    const actorId = typeof change.data.actorId === "string" ? change.data.actorId : existing?.actorId;
    if (!actorId) return permissions.includes("actor.readPrivate");
    const actor = state.actors.find((candidate) => candidate.id === actorId && candidate.campaignId === campaignId);
    return Boolean(
      actor &&
        (permissions.includes("actor.readPrivate") || actor.ownerUserId === userId || actor.permissions[userId]?.includes("actor.readPrivate"))
    );
  }
  if (change.entity === "handout") return handoutProposalChangePayloadVisibleToUser(state, userId, campaignId, permissions, change);
  if (change.entity === "chat") {
    const existing = changeId ? state.chat.find((message) => message.id === changeId && message.campaignId === campaignId) : undefined;
    const visibility = change.data.visibility === "public" || change.data.visibility === "gm_only" || change.data.visibility === "whisper" ? change.data.visibility : existing?.visibility;
    const senderUserId = typeof change.data.userId === "string" ? change.data.userId : existing?.userId;
    const recipients = Array.isArray(change.data.recipientUserIds) ? stringArrayFromRecord(change.data, "recipientUserIds") : existing?.recipientUserIds ?? [];
    return visibility === "public" || (visibility === "gm_only" && permissions.includes("chat.moderate")) || (visibility === "whisper" && (senderUserId === userId || recipients.includes(userId)));
  }
  if (change.entity === "roll") {
    const existing = changeId ? state.rolls.find((roll) => roll.id === changeId && roll.campaignId === campaignId) : undefined;
    const visibility = change.data.visibility === "public" || change.data.visibility === "gm_only" || change.data.visibility === "whisper" ? change.data.visibility : existing?.visibility;
    const rollerUserId = typeof change.data.userId === "string" ? change.data.userId : existing?.userId;
    return visibility === "public" || rollerUserId === userId || (visibility === "gm_only" && permissions.includes("chat.moderate"));
  }
  if (change.entity === "diceMacro") {
    const existing = changeId ? state.diceMacros.find((macro) => macro.id === changeId && macro.campaignId === campaignId) : undefined;
    const visibility = change.data.visibility === "public" || change.data.visibility === "gm_only" ? change.data.visibility : existing?.visibility;
    return visibility === "public" || permissions.includes("campaign.update");
  }
  if (change.entity === "encounter") {
    if (canViewPrep) return true;
    return Boolean(changeId && state.combats.some((combat) => combat.campaignId === campaignId && combat.active && combat.encounterId === changeId));
  }
  if (change.entity === "combat") return permissions.includes("combat.manage");
  if (change.entity === "asset") return canViewPrep;
  if (change.entity === "fogPreset") return permissions.includes("token.reveal");
  if (change.entity === "pluginStorage") return permissions.includes("plugin.configure");
  // Newly introduced proposal entities must opt into an explicit visibility
  // rule. Failing closed prevents a future payload type from leaking by
  // default through terminal proposal history.
  return false;
}

function handoutProposalChangePayloadVisibleToUser(state: EngineState, userId: string, campaignId: string, permissions: PermissionName[], change: ProposalChange): boolean {
  const handoutId = proposalChangeEntityId(change);
  const existing = handoutId ? state.handouts.find((handout) => handout.id === handoutId && handout.campaignId === campaignId) : undefined;
  if (change.action !== "create" && !existing) return false;
  const visibility = visibilityFromRecord(change.data, "visibility", existing?.visibility ?? "gm_only");
  const visibleToUserIds = Array.isArray(change.data.visibleToUserIds) ? stringArrayFromRecord(change.data, "visibleToUserIds") : existing?.visibleToUserIds ?? [];
  const visibleToActorIds = Array.isArray(change.data.visibleToActorIds) ? stringArrayFromRecord(change.data, "visibleToActorIds") : existing?.visibleToActorIds ?? [];
  if (visibility === "public" || permissions.includes("handout.readSecret") || visibleToUserIds.includes(userId)) return true;
  return visibleToActorIds.some((actorId) => {
    const actor = state.actors.find((candidate) => candidate.id === actorId && candidate.campaignId === campaignId);
    return actor?.ownerUserId === userId || actor?.permissions[userId]?.includes("actor.readPrivate");
  });
}

function proposalPermissionsIncludePrepAccess(permissions: PermissionName[]): boolean {
  return ["campaign.update", "scene.create", "scene.update", "scene.delete", "scene.activate", "token.reveal", "combat.manage"].some((permission) => permissions.includes(permission as PermissionName));
}

function linkAppliedRecapToSessionState(state: EngineState, proposal: Proposal, userId: string): void {
  const sessionId = typeof proposal.diffJson.sessionId === "string" ? proposal.diffJson.sessionId : undefined;
  if (!sessionId) return;
  const session = state.campaignSessions.find((item) => item.id === sessionId && item.campaignId === proposal.campaignId);
  if (!session) return;
  const recapJournalId = proposal.changesJson
    .filter((change) => change.entity === "journal" && change.action === "create")
    .map((change) => (typeof change.data.id === "string" ? change.data.id : undefined))
    .find((id): id is string => Boolean(id));
  session.recapProposalId = proposal.id;
  session.recapJournalId = recapJournalId;
  session.updatedBy = userId;
  session.updatedAt = nowIso();
}

function unlinkRecapFromSession(store: StateStore, proposal: Proposal, userId: string): void {
  unlinkRecapFromSessionState(store.state, proposal, userId);
}

function unlinkRecapFromSessionState(state: EngineState, proposal: Proposal, userId: string): void {
  const sessionId = typeof proposal.diffJson.sessionId === "string" ? proposal.diffJson.sessionId : undefined;
  if (!sessionId) return;
  const session = state.campaignSessions.find((item) => item.id === sessionId && item.campaignId === proposal.campaignId);
  if (!session || session.recapProposalId !== proposal.id) return;
  session.recapProposalId = undefined;
  session.recapJournalId = undefined;
  session.updatedBy = userId;
  session.updatedAt = nowIso();
}

function broadcastProposalEntityChanges(
  store: StateStore,
  beforeState: EngineState,
  campaignId: string,
  changes: ProposalChange[],
  userId: string,
  broadcastEvent: (event: EngineEvent) => void
): void {
  const explicitEntityKeys = new Set(changes.map((change) => `${change.entity}:${proposalChangeEntityId(change) ?? ""}`));
  for (const change of changes) {
    const id = proposalChangeEntityId(change);
    let payload = proposalChangeRecordFromState(change.action === "delete" ? beforeState : store.state, campaignId, change) ?? { id, campaignId, deleted: change.action === "delete" };
    if (change.entity === "diceMacro" && change.action === "update" && isRecord(payload)) {
      const previous = proposalChangeRecordFromState(beforeState, campaignId, change);
      payload = {
        ...payload,
        ...(isRecord(previous) && (previous.visibility === "public" || previous.visibility === "gm_only")
          ? { previousVisibility: previous.visibility }
          : {})
      };
    }
    appendServerAuditLog(store, userId, {
      campaignId,
      action: `proposal.entity.${change.action}`,
      targetType: change.entity,
      targetId: id,
      after: {
        proposalEntity: change.entity,
        proposalAction: change.action,
        fieldNames: Object.keys(change.data).filter((key) => !["body", "data", "changesJson", "input", "output", "value"].includes(key)).slice(0, 30)
      }
    });
    const eventType = proposalEntityEventType(change);
    if (eventType) {
      broadcastEvent(createEvent({ campaignId, type: eventType, actorUserId: userId, targetId: id, payload }));
    } else {
      const campaign = store.state.campaigns.find((item) => item.id === campaignId);
      if (campaign) broadcastEvent(createEvent({ campaignId, type: "campaign.updated", actorUserId: userId, targetId: campaignId, payload: campaign }));
    }
  }
  const deletedActorIds = new Set(
    changes.filter((change) => change.entity === "actor" && change.action === "delete").map((change) => proposalChangeEntityId(change)).filter((id): id is string => Boolean(id))
  );
  if (deletedActorIds.size === 0) return;
  for (const beforeEncounter of beforeState.encounters) {
    if (beforeEncounter.campaignId !== campaignId || !beforeEncounter.partyActorIds?.some((id) => deletedActorIds.has(id))) continue;
    if (explicitEntityKeys.has(`encounter:${beforeEncounter.id}`)) continue;
    const encounter = store.state.encounters.find((item) => item.id === beforeEncounter.id && item.campaignId === campaignId);
    if (!encounter) continue;
    appendServerAuditLog(store, userId, {
      campaignId,
      action: "proposal.entity.update",
      targetType: "encounter",
      targetId: encounter.id,
      after: { proposalEntity: "encounter", proposalAction: "update", fieldNames: ["partyActorIds"] }
    });
    broadcastEvent(createEvent({ campaignId, type: "encounter.updated", actorUserId: userId, targetId: encounter.id, payload: encounter }));
  }
}

function proposalEntityEventType(change: ProposalChange): EngineEvent["type"] | undefined {
  const suffix = change.action === "create" ? "created" : change.action === "delete" ? "deleted" : "updated";
  if (change.entity === "world") return `world.${suffix}` as EngineEvent["type"];
  if (change.entity === "scene") return `scene.${suffix}` as EngineEvent["type"];
  if (change.entity === "token") return `token.${suffix}` as EngineEvent["type"];
  if (change.entity === "actor") return `actor.${suffix}` as EngineEvent["type"];
  if (change.entity === "item") return `item.${suffix}` as EngineEvent["type"];
  if (change.entity === "journal") return `journal.${suffix}` as EngineEvent["type"];
  if (change.entity === "handout") return `handout.${suffix}` as EngineEvent["type"];
  if (change.entity === "asset") return `asset.${suffix}` as EngineEvent["type"];
  if (change.entity === "chat") return `chat.message.${suffix}` as EngineEvent["type"];
  if (change.entity === "encounter") return `encounter.${suffix}` as EngineEvent["type"];
  if (change.entity === "roll" && change.action === "create") return "dice.roll.created";
  if (change.entity === "diceMacro") return `dice.macro.${suffix}` as EngineEvent["type"];
  if (change.entity === "combat") return change.action === "create" ? "combat.started" : change.action === "delete" ? "combat.ended" : "combat.turnChanged";
  if (change.entity === "campaign") return "campaign.updated";
  return undefined;
}

function proposalChangeRecordFromState(state: EngineState, campaignId: string, change: ProposalChange): unknown {
  const id = proposalChangeEntityId(change);
  if (!id) return undefined;
  if (change.entity === "campaign") return state.campaigns.find((item) => item.id === id && item.id === campaignId);
  if (change.entity === "world") return state.worlds.find((item) => item.id === id && item.campaignId === campaignId);
  if (change.entity === "scene") return state.scenes.find((item) => item.id === id && item.campaignId === campaignId);
  if (change.entity === "token") return state.tokens.find((item) => item.id === id && state.scenes.some((scene) => scene.id === item.sceneId && scene.campaignId === campaignId));
  if (change.entity === "actor") return state.actors.find((item) => item.id === id && item.campaignId === campaignId);
  if (change.entity === "item") return state.items.find((item) => item.id === id && item.campaignId === campaignId);
  if (change.entity === "journal") return state.journals.find((item) => item.id === id && item.campaignId === campaignId);
  if (change.entity === "handout") return state.handouts.find((item) => item.id === id && item.campaignId === campaignId);
  if (change.entity === "chat") return state.chat.find((item) => item.id === id && item.campaignId === campaignId);
  if (change.entity === "roll") return state.rolls.find((item) => item.id === id && item.campaignId === campaignId);
  if (change.entity === "diceMacro") return state.diceMacros.find((item) => item.id === id && item.campaignId === campaignId);
  if (change.entity === "encounter") return state.encounters.find((item) => item.id === id && item.campaignId === campaignId);
  if (change.entity === "campaignSession") return state.campaignSessions.find((item) => item.id === id && item.campaignId === campaignId);
  if (change.entity === "combat") return state.combats.find((item) => item.id === id && item.campaignId === campaignId);
  if (change.entity === "asset") return state.assets.find((item) => item.id === id && item.campaignId === campaignId);
  if (change.entity === "fogPreset") return state.fogPresets.find((item) => item.id === id && item.campaignId === campaignId);
  if (change.entity === "pluginStorage") return state.pluginStorage.find((item) => item.id === id && item.campaignId === campaignId);
  if (change.entity === "aiMemory") return state.aiMemory.find((item) => item.id === id && item.campaignId === campaignId);
  return undefined;
}

function journalProposalChangePayloadVisibleToUser(state: EngineState, userId: string, campaignId: string, permissions: PermissionName[], change: ProposalChange): boolean {
  const existing = journalForProposalChange(state, campaignId, change);
  if (change.action !== "create" && !existing) return false;
  if (existing && !journalPayloadVisibleToUser(userId, permissions, existing.visibility, existing.visibleToUserIds)) return false;

  const proposedVisibility = visibilityFromRecord(change.data, "visibility", existing?.visibility ?? "gm_only");
  const proposedVisibleToUserIds = Array.isArray(change.data.visibleToUserIds) ? stringArrayFromRecord(change.data, "visibleToUserIds") : existing?.visibleToUserIds ?? [];
  return journalPayloadVisibleToUser(userId, permissions, proposedVisibility, proposedVisibleToUserIds);
}

function journalForProposalChange(state: EngineState, campaignId: string, change: ProposalChange): JournalEntry | undefined {
  const journalId = change.id ?? (typeof change.data.id === "string" ? change.data.id : undefined);
  return journalId ? state.journals.find((journal) => journal.id === journalId && journal.campaignId === campaignId) : undefined;
}

function journalPayloadVisibleToUser(userId: string, permissions: PermissionName[], visibility: Visibility, visibleToUserIds: string[]): boolean {
  if (visibility === "public") return true;
  if (permissions.includes("journal.readSecret")) return true;
  return visibleToUserIds.includes(userId);
}

function proposalTouchesBoardState(proposal: Proposal): boolean {
  return proposal.changesJson.some((change) => change.entity === "scene" || change.entity === "token" || change.entity === "asset" || change.entity === "combat");
}

function autoAppliedProposalIdFromToolOutput(output: unknown): string | undefined {
  if (!isRecord(output) || output.autoApplied !== true || !isRecord(output.autoAppliedProposal)) return undefined;
  return typeof output.autoAppliedProposal.proposalId === "string" ? output.autoAppliedProposal.proposalId : undefined;
}

function proposalIdsFromAiEvents(events: AiProviderEvent[]): string[] {
  const proposalIds = new Set<string>();
  for (const event of events) {
    if (event.type === "proposal.created") proposalIds.add(event.proposalId);
  }
  return [...proposalIds];
}

function autoApplyAiThreadProposal(store: StateStore, runtime: AiToolRuntime, campaignId: string, userId: string, proposalId: string): AutoAppliedProposalToolOutput | undefined {
  const proposal = store.state.proposals.find((item) => item.id === proposalId && item.campaignId === campaignId);
  if (!proposal || proposal.status === "applied" || proposal.status === "rejected") return undefined;
  try {
    const preparedChanges = prepareProposalChanges(store, proposal.campaignId, proposal.createdByUserId ?? userId, proposal.changesJson, { currentProposalId: proposal.id });
    if ("error" in preparedChanges) throw new Error(preparedChanges.message);
    const missingPermission = missingProposalChangePermission(preparedChanges.changes, permissionsForUser(store, userId, proposal.campaignId));
    if (missingPermission) throw new Error(`Missing permission: ${missingPermission}`);
    proposal.changesJson = preparedChanges.changes;
    const boardStateChanged = proposalTouchesBoardState(proposal);
    const refs = proposalAppliedEntityRefs(proposal);
    if (proposal.status === "pending") {
      Object.assign(proposal, approveProposal(proposal, userId));
      runtime.broadcast?.(
        createEvent({
          campaignId: proposal.campaignId,
          type: "proposal.approved",
          actorUserId: userId,
          targetId: proposal.id,
          payload: proposal
        })
      );
    }
    if (proposal.status !== "approved") return undefined;
    const beforeState = store.state;
    const appliedChanges = structuredClone(proposal.changesJson);
    const applyState = structuredClone(store.state);
    const applyStateProposal = applyState.proposals.find((item) => item.id === proposal.id);
    if (!applyStateProposal) throw new Error("Proposal could not be prepared for apply");
    const nextState = applyProposal(applyState, applyStateProposal, userId);
    const nextProposal = nextState.proposals.find((item) => item.id === proposal.id);
    if (!nextProposal) throw new Error("Applied proposal record was not prepared");
    linkAppliedRecapToSessionState(nextState, nextProposal, userId);
    store.replace(nextState);
    const applied = store.state.proposals.find((item) => item.id === proposal.id);
    if (!applied) throw new Error("Applied proposal record was not persisted");
    appendServerAuditLog(store, userId, {
      campaignId: proposal.campaignId,
      action: "proposal.apply",
      targetType: "proposal",
      targetId: proposal.id,
      before: { status: "approved", changeCount: appliedChanges.length },
      after: { status: applied.status, entities: [...new Set(appliedChanges.map((change) => change.entity))], reversible: Boolean(applied.inverseChangesJson), appliedBy: "ai_auto" }
    });
    broadcastProposalEntityChanges(store, beforeState, proposal.campaignId, appliedChanges, userId, (event) => runtime.broadcast?.(event));
    store.save();
    runtime.broadcast?.(
      createEvent({
        campaignId: proposal.campaignId,
        type: "proposal.applied",
        actorUserId: userId,
        targetId: proposal.id,
        payload: applied
      })
    );
    return {
      proposalId: proposal.id,
      boardStateChanged,
      proposal: proposalToolSummary(applied),
      ...refs
    };
  } catch (error) {
    const message = error instanceof Error ? error.message : "Proposal could not be auto-applied";
    store.state.auditLogs.push(
      createTimestamped("audit", {
        campaignId: proposal.campaignId,
        actorUserId: userId,
        actorType: "user" as const,
        action: "ai.proposal.apply.failed",
        targetType: "proposal",
        targetId: proposal.id,
        after: {
          proposalId: proposal.id,
          status: proposal.status,
          createdByType: proposal.createdByType,
          sourceId: proposal.sourceId,
          changeCount: proposal.changesJson.length,
          entities: [...new Set(proposal.changesJson.map((change) => change.entity))],
          reason: "auto_apply_failed",
          message
        }
      })
    );
    return undefined;
  }
}

function autoApplyAiThreadProposals(store: StateStore, runtime: AiToolRuntime, campaignId: string, userId: string, proposalIds: string[]): string[] {
  const appliedProposalIds: string[] = [];
  for (const proposalId of proposalIds) {
    const applied = autoApplyAiThreadProposal(store, runtime, campaignId, userId, proposalId);
    if (applied) appliedProposalIds.push(applied.proposalId);
  }
  return appliedProposalIds;
}

function blockedAgentProposalChange(changes: ProposalChange[]): Record<string, unknown> | undefined {
  for (const change of changes) {
    if (change.entity === "campaign") return { entity: change.entity, action: change.action, reason: "Agents cannot propose campaign lifecycle or campaign-level changes." };
    if (change.entity === "combat" && (change.action === "create" || change.action === "delete")) return { entity: change.entity, action: change.action, reason: "Agents cannot directly start or end combat." };
    if (change.entity === "combat" && change.action === "update" && ("active" in change.data || "endedAt" in change.data)) {
      return { entity: change.entity, action: change.action, reason: "Agents cannot directly start or end combat." };
    }
  }
  return undefined;
}

function prefixForProposalEntity(entity: ProposalChange["entity"]): string {
  switch (entity) {
    case "campaign":
      return "camp";
    case "world":
      return "world";
    case "scene":
      return "scn";
    case "token":
      return "tok";
    case "actor":
      return "act";
    case "item":
      return "item";
    case "journal":
      return "jnl";
    case "handout":
      return "hnd";
    case "chat":
      return "msg";
    case "roll":
      return "roll";
    case "diceMacro":
      return "mac";
    case "encounter":
      return "enc";
    case "campaignSession":
      return "campsess";
    case "combat":
      return "cmb";
    case "asset":
      return "asset";
    case "fogPreset":
      return "fogp";
    case "pluginStorage":
      return "pstore";
    case "aiMemory":
      return "aimem";
  }
}

function missingProposalChangePermission(changes: ProposalChange[], permissions: PermissionName[]): PermissionName | undefined {
  for (const change of changes) {
    const permission = permissionForProposalChange(change);
    if (permission && !permissions.includes(permission)) return permission;
  }
  return undefined;
}

function permissionForProposalChange(change: ProposalChange): PermissionName | undefined {
  if (change.entity === "campaign") return "campaign.update";
  if (change.entity === "world") {
    if (change.action === "create") return "world.create";
    if (change.action === "delete") return "world.delete";
    return "world.update";
  }
  if (change.entity === "scene") {
    if (change.action === "create") return "scene.create";
    if (change.action === "delete") return "scene.delete";
    return "scene.update";
  }
  if (change.entity === "token") {
    if (change.action === "create") return "token.create";
    if (change.action === "delete") return "token.delete";
    return "token.update";
  }
  if (change.entity === "actor") {
    if (change.action === "create") return "actor.create";
    if (change.action === "delete") return "actor.delete";
    return "actor.update";
  }
  if (change.entity === "journal") {
    if (change.action === "create") return "journal.create";
    if (change.action === "delete") return "journal.delete";
    return "journal.update";
  }
  if (change.entity === "handout") {
    if (change.action === "create") return "handout.create";
    if (change.action === "delete") return "handout.delete";
    return "handout.update";
  }
  if (change.entity === "chat") return change.action === "create" ? "chat.write" : "chat.moderate";
  if (change.entity === "roll") return "dice.roll";
  if (change.entity === "diceMacro") return "campaign.update";
  if (change.entity === "combat") return "combat.manage";
  if (change.entity === "encounter") return "combat.manage";
  if (change.entity === "item") return "actor.update";
  if (change.entity === "asset") {
    if (change.action === "create") return "scene.create";
    return "scene.update";
  }
  if (change.entity === "fogPreset") return "token.reveal";
  if (change.entity === "pluginStorage") return "plugin.configure";
  if (change.entity === "campaignSession" || change.entity === "aiMemory") return "campaign.update";
  return undefined;
}

function missingPermissionToolOutput(permission: PermissionName): ToolErrorOutput {
  return {
    error: "missing_permission",
    permission
  };
}

function toolError(error: string, details: Record<string, unknown> = {}): ToolErrorOutput {
  return {
    error,
    ...details
  };
}

function readOnlyToolStore(context: AiToolContext): StateStore {
  return { state: context.state, save: () => undefined, replace: () => undefined };
}

function tokenForCampaign(context: AiToolContext, tokenId: string): Token | undefined {
  return context.state.tokens.find((token) => token.id === tokenId && context.state.scenes.some((scene) => scene.id === token.sceneId && scene.campaignId === context.campaignId));
}

function imageAssetForCampaign(context: AiToolContext, assetId: string): MapAsset | undefined {
  return context.state.assets.find((asset) => asset.id === assetId && asset.campaignId === context.campaignId && asset.mimeType.startsWith("image/") && asset.lifecycle?.status !== "deleted");
}

function inferredSourceAssetKind(asset: MapAsset, scene?: Scene): "map" | "token" {
  if (scene?.backgroundAssetId === asset.id) return "map";
  const folder = normalizeAssetFolder(asset.folder)?.toLowerCase() ?? "";
  const tags = (asset.tags ?? []).map((tag) => tag.toLowerCase());
  const name = asset.name.toLowerCase();
  if (folder.startsWith("maps") || folder.includes("/maps") || tags.some((tag) => tag === "map" || tag === "battlemap" || tag === "background") || /\b(map|battlemap|background|scene)\b/i.test(name)) return "map";
  return "token";
}

async function sourceImageUrlForInternalAgent(context: AiToolContext, asset: MapAsset): Promise<string | ToolErrorOutput> {
  const resolver = (context as OpenTabletopAiToolContext).sourceImageDataUrlForAsset;
  const dataUrl = resolver ? await resolver(asset) : undefined;
  if (dataUrl) return dataUrl;
  return toolError("asset_bytes_unavailable", {
    entity: "asset",
    id: asset.id,
    message: "Source image bytes are unavailable, so the image generator cannot attach this asset as a visual reference."
  });
}

function aiToolAvailableToCaller(tool: AiToolDefinition, permissions: PermissionName[]): boolean {
  if (!aiToolPermissionSafe(tool) && !tool.requiredPermissions.includes("ai.proposeChanges")) return false;
  return tool.requiredPermissions.every((permission) => permissions.includes(permission));
}

const AI_PERMISSION_SAFE_TOOL_NAMES = new Set([
  "list_proposals",
  "get_proposal",
  "apply_approved_proposal",
  "read_account",
  "read_workspace",
  "read_campaign",
  "read_world",
  "read_handout",
  "search_campaign",
  "read_campaign_session",
  "read_ai_activity",
  "search_memory",
  "read_chat",
  "read_roll",
  "read_journal",
  "read_board_state",
  "capture_board_view",
  "read_scene",
  "read_token",
  "read_asset",
  "read_combat",
  "read_encounter",
  "read_actor",
  "read_dice_macro",
  "read_fog_preset",
  "read_systems",
  "read_plugins",
  "read_content_imports",
  "read_compendium"
]);

function aiToolPermissionSafe(tool: AiToolDefinition): boolean {
  return AI_PERMISSION_SAFE_TOOL_NAMES.has(tool.name);
}

async function executeAiTool(tools: AiToolDefinition[], toolName: string, input: unknown, context: AiToolContext): Promise<AiToolExecutionResult> {
  if (context.signal?.aborted) {
    return failedToolOutput({
      error: "tool_cancelled",
      message: "Agent turn stopped by the user."
    });
  }
  const tool = tools.find((item) => item.name === toolName);
  if (!tool) return failedToolOutput({ error: "unknown_tool", toolName });

  if (!aiToolPermissionSafe(tool) && !tool.requiredPermissions.includes("ai.proposeChanges")) {
    return failedToolOutput({
      error: "missing_permission",
      permission: "ai.proposeChanges"
    });
  }

  const missingPermission = tool.requiredPermissions.find((permission) => !context.permissions.includes(permission));
  if (missingPermission) {
    return failedToolOutput({
      error: "missing_permission",
      permission: missingPermission
    });
  }

  const invalidInput = validateAiToolInput(tool, input);
  if (invalidInput) {
    return failedToolOutput({
      error: "invalid_tool_input",
      message: invalidInput
    });
  }

  try {
    const output = await tool.execute(input, context);
    if (context.signal?.aborted) {
      return failedToolOutput({
        error: "tool_cancelled",
        message: "Agent turn stopped by the user."
      });
    }
    return {
      output,
      failed: isToolErrorOutput(output)
    };
  } catch (error) {
    return failedToolOutput({
      error: "tool_failed",
      message: error instanceof Error ? error.message.slice(0, 300) : "Tool execution failed"
    });
  }
}

function failedToolOutput(output: ToolErrorOutput): AiToolExecutionResult {
  return {
    output,
    failed: true
  };
}

function isProposalToolOutput(value: unknown): value is ProposalToolOutput {
  return isRecord(value) && typeof value.proposalId === "string";
}

function isToolErrorOutput(value: unknown): value is ToolErrorOutput {
  return isRecord(value) && typeof value.error === "string";
}

function isGeneratedImageAssetToolOutput(value: unknown): value is GeneratedImageAssetToolOutput {
  return isRecord(value) && isRecord(value.asset) && typeof value.asset.id === "string" && typeof value.provider === "string" && typeof value.sourcePrompt === "string";
}

function sendAiToolErrorReply(reply: FastifyReply, output: unknown): FastifyReply {
  if (!isToolErrorOutput(output)) {
    return reply.code(500).send({ error: "tool_failed", message: "AI tool execution failed." });
  }
  return reply.code(aiToolErrorHttpStatus(output)).send(output);
}

function aiToolErrorHttpStatus(output: ToolErrorOutput): number {
  if (output.error === "missing_permission") return 403;
  if (output.error === "not_found") return 404;
  if (output.error === "conflict") return 409;
  if (output.error === "asset_too_large" || output.error === "asset_quota_exceeded") return 413;
  if (output.error === "image_generation_failed" || output.error === "tool_failed") return 502;
  return 400;
}

function validateAiToolInput(tool: AiToolDefinition, input: unknown): string | undefined {
  const schema = tool.parameters;
  if (!schema) return undefined;
  if (!isRecord(input)) return "Tool input must be an object.";

  for (const key of schema.required ?? []) {
    if (!(key in input) || input[key] === undefined) return `Missing required field: ${key}`;
  }

  for (const [key, value] of Object.entries(input)) {
    const property = schema.properties[key];
    if (!property) {
      if (schema.additionalProperties === false) return `Unexpected field: ${key}`;
      if (schema.additionalProperties && typeof schema.additionalProperties === "object" && !matchesAiToolJsonSchema(value, schema.additionalProperties)) return `Invalid field: ${key}`;
      continue;
    }
    if (!matchesAiToolJsonSchema(value, property)) return `Invalid field: ${key}`;
  }

  return undefined;
}

function matchesAiToolJsonSchema(value: unknown, schema: AiToolJsonSchema): boolean {
  if (schema.enum && !schema.enum.includes(String(value))) return false;
  const types = Array.isArray(schema.type) ? schema.type : schema.type ? [schema.type] : [];
  if (types.length === 0) return true;
  return types.some((type) => {
    if (type === "string") return typeof value === "string";
    if (type === "number" || type === "integer") return typeof value === "number" && Number.isFinite(value);
    if (type === "boolean") return typeof value === "boolean";
    if (type === "array") return Array.isArray(value) && (!schema.items || value.every((item) => matchesAiToolJsonSchema(item, schema.items!)));
    if (type === "object") return matchesAiToolObjectSchema(value, schema);
    if (type === "null") return value === null;
    return true;
  });
}

function matchesAiToolObjectSchema(value: unknown, schema: AiToolJsonSchema): boolean {
  if (!isRecord(value)) return false;
  for (const key of schema.required ?? []) {
    if (!(key in value) || value[key] === undefined) return false;
  }
  for (const [key, child] of Object.entries(value)) {
    const property = schema.properties?.[key];
    if (!property) {
      if (schema.additionalProperties === false) return false;
      if (schema.additionalProperties && typeof schema.additionalProperties === "object" && !matchesAiToolJsonSchema(child, schema.additionalProperties)) return false;
      continue;
    }
    if (!matchesAiToolJsonSchema(child, property)) return false;
  }
  return true;
}

function isProposalChange(value: unknown): value is ProposalChange {
  if (!isRecord(value)) return false;
  return (
    typeof value.entity === "string" &&
    typeof value.action === "string" &&
    isRecord(value.data) &&
    ["campaign", "scene", "token", "actor", "item", "journal", "chat", "roll", "diceMacro", "encounter", "combat", "asset", "fogPreset"].includes(value.entity) &&
    ["create", "update", "delete"].includes(value.action)
  );
}

function stringFromRecord(record: Record<string, unknown>, key: string): string | undefined {
  const value = record[key];
  return typeof value === "string" && value.trim() ? value.trim() : undefined;
}

function numberFromRecord(record: Record<string, unknown>, key: string, min: number, max: number): number | undefined {
  const value = record[key];
  return typeof value === "number" ? clampNumber(value, min, max) : undefined;
}

function booleanFromRecord(record: Record<string, unknown>, key: string): boolean | undefined {
  const value = record[key];
  return typeof value === "boolean" ? value : undefined;
}

function recordFromRecord(record: Record<string, unknown>, key: string): Record<string, unknown> | undefined {
  const value = record[key];
  return isRecord(value) ? value : undefined;
}

function saveOutcomesFromRecord(record: Record<string, unknown>, key: string): Record<string, RulesSaveOutcome> | undefined {
  const value = recordFromRecord(record, key);
  if (!value) return undefined;
  const outcomes: Record<string, RulesSaveOutcome> = {};
  for (const [actorId, outcome] of Object.entries(value)) {
    if (!actorId.trim()) continue;
    if (outcome === "success" || outcome === "failure") outcomes[actorId] = outcome;
  }
  return Object.keys(outcomes).length > 0 ? outcomes : undefined;
}

function enumStringFromRecord<T extends string>(record: Record<string, unknown>, key: string, allowed: readonly T[]): T | undefined {
  const value = record[key];
  return typeof value === "string" && allowed.includes(value as T) ? (value as T) : undefined;
}

function visibilityFromRecord(record: Record<string, unknown>, key: string, fallback: Visibility): Visibility {
  const value = record[key];
  return value === "public" || value === "gm_only" ? value : fallback;
}

function rollVisibilityFromRecord(record: Record<string, unknown>, key: string, fallback: "public" | "gm_only" | "whisper"): "public" | "gm_only" | "whisper" {
  const value = record[key];
  return value === "public" || value === "gm_only" || value === "whisper" ? value : fallback;
}

function stringArrayFromRecord(record: Record<string, unknown>, key: string): string[] {
  const value = record[key];
  return Array.isArray(value) ? value.filter((item): item is string => typeof item === "string" && item.trim().length > 0) : [];
}

function appendFogHistoryEntry(scene: Scene, input: Omit<FogHistoryEntry, "id" | "createdAt" | "updatedAt">): FogHistoryEntry {
  scene.fogHistory ??= [];
  const entry = createTimestamped("fogh", {
    ...input,
    region: input.region ? cloneFogRegion(input.region) : undefined
  }) satisfies FogHistoryEntry;
  scene.fogHistory.push(entry);
  if (scene.fogHistory.length > MAX_FOG_HISTORY_ENTRIES) {
    scene.fogHistory.splice(0, scene.fogHistory.length - MAX_FOG_HISTORY_ENTRIES);
  }
  return entry;
}

function latestUndoableFogHistoryEntry(scene: Scene): FogHistoryEntry | undefined {
  const history = scene.fogHistory ?? [];
  const undoneHistoryIds = new Set(history.map((entry) => (entry.action === "undo" ? entry.targetHistoryId : undefined)).filter((id): id is string => Boolean(id)));
  for (let index = history.length - 1; index >= 0; index -= 1) {
    const entry = history[index]!;
    if ((entry.action !== "create" && entry.action !== "delete") || undoneHistoryIds.has(entry.id)) continue;
    const fogExists = scene.fog.some((region) => region.id === entry.fogId);
    if (entry.action === "create" && fogExists) return entry;
    if (entry.action === "delete" && entry.region && !fogExists) return entry;
  }
  return undefined;
}

function cloneFogRegion(region: FogRegion): FogRegion {
  return {
    ...region,
    points: region.points?.map((point) => ({ ...point }))
  };
}

function fogPresetRegionFromFog(region: FogRegion): FogPresetRegion {
  const { id: _id, ...presetRegion } = cloneFogRegion(region);
  return presetRegion;
}

function cloneFogPresetRegion(region: FogPresetRegion): FogPresetRegion {
  return {
    ...region,
    points: region.points?.map((point) => ({ ...point }))
  };
}

function sourceSceneForFogPreset(store: StateStore, campaignId: string, sceneId: string | undefined): Scene | undefined {
  if (sceneId) return store.state.scenes.find((scene) => scene.id === sceneId && scene.campaignId === campaignId);
  return store.state.scenes.find((scene) => scene.campaignId === campaignId && scene.active) ?? store.state.scenes.find((scene) => scene.campaignId === campaignId);
}

function normalizeFogPresetName(name: string | undefined, scene: Scene): string {
  const normalized = name?.trim();
  return normalized || `${scene.name} fog preset`;
}

function ensureSceneAnnotations(scene: Scene): SceneAnnotation[] {
  if (!Array.isArray(scene.annotations)) scene.annotations = [];
  return scene.annotations;
}

function ensureSceneAnnotationHistory(scene: Scene) {
  if (!Array.isArray(scene.annotationHistory)) scene.annotationHistory = [];
  return scene.annotationHistory;
}

function appendSceneAnnotationHistory(scene: Scene, actorUserId: string, action: "create" | "update" | "delete", annotation: SceneAnnotation) {
  const history = ensureSceneAnnotationHistory(scene);
  history.push(
    createTimestamped("annoh", {
      sceneId: scene.id,
      annotationId: annotation.id,
      action,
      kind: annotation.kind,
      layer: annotation.layer,
      groupId: annotation.groupId,
      groupLabel: annotation.groupLabel,
      templateShape: annotation.templateShape,
      templateSaveAbility: annotation.templateSaveAbility,
      templateSaveDc: annotation.templateSaveDc,
      templateDamageFormula: annotation.templateDamageFormula,
      templateDamageType: annotation.templateDamageType,
      affectedTokenIds: annotation.affectedTokenIds,
      rulesSystemId: annotation.rulesSystemId,
      actorUserId
    })
  );
  if (history.length > 100) history.splice(0, history.length - 100);
}

function normalizeSceneAnnotationKind(kind: unknown): SceneAnnotationKind | undefined {
  if (kind === "ping" || kind === "ruler" || kind === "template" || kind === "drawing") return kind;
  return undefined;
}

function normalizeSceneAnnotationLayer(layer: unknown, kind: SceneAnnotationKind): SceneAnnotationLayer {
  if (layer === "measurement" || layer === "effects" || layer === "drawings" || layer === "notes") return layer;
  if (kind === "template") return "effects";
  if (kind === "drawing") return "drawings";
  return "measurement";
}

function normalizeAnnotationGroupLabel(value: unknown): string | undefined {
  if (typeof value !== "string") return undefined;
  const normalized = value.trim().replace(/\s+/g, " ").slice(0, 48);
  return normalized || undefined;
}

function normalizeAnnotationGroupId(groupId: unknown, groupLabel: string | undefined): string | undefined {
  if (typeof groupId === "string" && /^[a-zA-Z0-9_-]{1,64}$/.test(groupId.trim())) return groupId.trim();
  if (!groupLabel) return undefined;
  return groupLabel.toLowerCase().replace(/[^a-z0-9]+/g, "-").replace(/^-+|-+$/g, "").slice(0, 64) || undefined;
}

function normalizeSceneTemplateShape(value: unknown): SceneTemplateShape {
  if (value === "line" || value === "cone") return value;
  return "circle";
}

function normalizeTemplateSaveAbility(value: unknown): string | undefined {
  if (typeof value !== "string") return undefined;
  const normalized = value.trim().toLowerCase().replace(/\s+/g, " ");
  if (!normalized || normalized === "none") return undefined;
  return normalized.slice(0, 24);
}

function normalizeTemplateSaveDc(value: unknown): number | undefined {
  if (typeof value !== "number" || !Number.isFinite(value)) return undefined;
  return Math.min(40, Math.max(1, Math.round(value)));
}

function normalizeTemplateDamageFormula(value: unknown): string | undefined {
  if (typeof value !== "string") return undefined;
  const normalized = value.trim().replace(/\s+/g, " ").slice(0, 48);
  if (!normalized) return undefined;
  return /^[0-9dD+\-*/ ()]+$/.test(normalized) ? normalized : undefined;
}

function normalizeTemplateDamageType(value: unknown): string | undefined {
  if (typeof value !== "string") return undefined;
  const normalized = value.trim().toLowerCase().replace(/[^a-z -]/g, "").replace(/\s+/g, " ").slice(0, 24);
  return normalized || undefined;
}

function normalizeSceneAnnotationInput(
  scene: Scene,
  userId: string,
  body: {
    label?: string;
    color?: string;
    layer?: string;
    groupId?: string;
    groupLabel?: string;
    sortOrder?: number;
    templateShape?: string;
    templateSaveAbility?: string;
    templateSaveDc?: number;
    templateDamageFormula?: string;
    templateDamageType?: string;
    snapToGrid?: boolean;
    points?: VisionPoint[];
    radius?: number;
    expiresInSeconds?: number;
  },
  kind: SceneAnnotationKind
): { annotation: SceneAnnotation } | { error: string } {
  const points = Array.isArray(body.points) ? body.points.map((point) => normalizeScenePoint(scene, point)).filter((point): point is VisionPoint => Boolean(point)) : [];
  const minPoints = kind === "ping" ? 1 : 2;
  if (points.length < minPoints) return { error: `${kind} annotation requires at least ${minPoints} valid point${minPoints === 1 ? "" : "s"}` };
  const maxPoints = kind === "drawing" ? 80 : kind === "template" ? 16 : 2;
  const snapToGrid = body.snapToGrid === true;
  const normalizedPoints = points.slice(0, maxPoints).map((point) => (snapToGrid ? snapScenePointToGrid(scene, point) : point));
  const radius = kind === "template" ? normalizeAnnotationRadius(body.radius, scene, normalizedPoints) : undefined;
  if (kind === "template" && radius === undefined) return { error: "template annotation requires a non-negative radius" };
  const layer = normalizeSceneAnnotationLayer(body.layer, kind);
  const groupLabel = normalizeAnnotationGroupLabel(body.groupLabel);
  const groupId = normalizeAnnotationGroupId(body.groupId, groupLabel);
  const templateShape = kind === "template" ? normalizeSceneTemplateShape(body.templateShape) : undefined;
  const templateSaveAbility = kind === "template" ? normalizeTemplateSaveAbility(body.templateSaveAbility) : undefined;
  const templateSaveDc = kind === "template" ? normalizeTemplateSaveDc(body.templateSaveDc) : undefined;
  const templateDamageFormula = kind === "template" ? normalizeTemplateDamageFormula(body.templateDamageFormula) : undefined;
  const templateDamageType = kind === "template" ? normalizeTemplateDamageType(body.templateDamageType) : undefined;
  const annotation = createTimestamped("anno", {
    sceneId: scene.id,
    kind,
    createdByUserId: userId,
    label: body.label?.trim().slice(0, 80) || undefined,
    layer,
    groupId,
    groupLabel,
    sortOrder: typeof body.sortOrder === "number" && Number.isFinite(body.sortOrder) ? Math.round(body.sortOrder) : undefined,
    templateShape,
    templateSaveAbility,
    templateSaveDc,
    templateDamageFormula,
    templateDamageType,
    snapToGrid,
    color: normalizeAnnotationColor(body.color),
    points: normalizedPoints,
    radius,
    expiresAt: normalizeAnnotationExpiry(body.expiresInSeconds)
  }) satisfies SceneAnnotation;
  return { annotation };
}

function normalizeSceneAnnotationPatch(
  scene: Scene,
  annotation: SceneAnnotation,
  body: {
    label?: string;
    color?: string;
    layer?: string;
    groupId?: string;
    groupLabel?: string;
    sortOrder?: number;
    templateSaveAbility?: string;
    templateSaveDc?: number;
    templateDamageFormula?: string;
    templateDamageType?: string;
    snapToGrid?: boolean;
    points?: VisionPoint[];
    radius?: number;
    expiresInSeconds?: number;
  }
): { patch: Partial<SceneAnnotation> } | { error: string } {
  const patch: Partial<SceneAnnotation> = {};
  if (body.label !== undefined) patch.label = body.label.trim().slice(0, 80) || undefined;
  if (body.color !== undefined) patch.color = normalizeAnnotationColor(body.color);
  if (body.layer !== undefined) patch.layer = normalizeSceneAnnotationLayer(body.layer, annotation.kind);
  if (body.groupLabel !== undefined || body.groupId !== undefined) {
    const groupLabel = normalizeAnnotationGroupLabel(body.groupLabel);
    patch.groupLabel = groupLabel;
    patch.groupId = normalizeAnnotationGroupId(body.groupId, groupLabel);
  }
  if (body.sortOrder !== undefined) {
    if (!Number.isFinite(body.sortOrder)) return { error: "Annotation sortOrder must be a finite number" };
    patch.sortOrder = Math.round(body.sortOrder);
  }
  if (body.snapToGrid !== undefined) patch.snapToGrid = body.snapToGrid === true;
  if (body.points !== undefined) {
    if (!Array.isArray(body.points)) return { error: "Annotation points must be an array" };
    const points = body.points.map((point) => normalizeScenePoint(scene, point)).filter((point): point is VisionPoint => Boolean(point));
    const minPoints = annotation.kind === "ping" ? 1 : 2;
    if (points.length < minPoints) return { error: `${annotation.kind} annotation requires at least ${minPoints} valid point${minPoints === 1 ? "" : "s"}` };
    const maxPoints = annotation.kind === "drawing" ? 80 : annotation.kind === "template" ? 16 : 2;
    const snapToGrid = patch.snapToGrid ?? annotation.snapToGrid ?? false;
    patch.points = points.slice(0, maxPoints).map((point) => (snapToGrid ? snapScenePointToGrid(scene, point) : point));
  }
  if (annotation.kind === "template") {
    if (body.radius !== undefined) {
      const points = patch.points ?? annotation.points;
      const radius = normalizeAnnotationRadius(body.radius, scene, points);
      if (radius === undefined) return { error: "template annotation requires a non-negative radius" };
      patch.radius = radius;
    }
    if (body.templateSaveAbility !== undefined) patch.templateSaveAbility = normalizeTemplateSaveAbility(body.templateSaveAbility);
    if (body.templateSaveDc !== undefined) patch.templateSaveDc = normalizeTemplateSaveDc(body.templateSaveDc);
    if (body.templateDamageFormula !== undefined) patch.templateDamageFormula = normalizeTemplateDamageFormula(body.templateDamageFormula);
    if (body.templateDamageType !== undefined) patch.templateDamageType = normalizeTemplateDamageType(body.templateDamageType);
  }
  if (body.expiresInSeconds !== undefined) patch.expiresAt = normalizeAnnotationExpiry(body.expiresInSeconds);
  if (Object.keys(patch).length === 0) return { error: "Annotation update must include at least one field" };
  return { patch };
}

function normalizeScenePoint(scene: Scene, point: VisionPoint | undefined): VisionPoint | undefined {
  if (!point || !Number.isFinite(point.x) || !Number.isFinite(point.y)) return undefined;
  return {
    x: Math.max(0, Math.min(scene.width, Math.round(point.x))),
    y: Math.max(0, Math.min(scene.height, Math.round(point.y)))
  };
}

function snapScenePointToGrid(scene: Scene, point: VisionPoint): VisionPoint {
  const gridSize = Math.max(1, Math.round(scene.gridSize || 1));
  return {
    x: Math.max(0, Math.min(scene.width, Math.round(point.x / gridSize) * gridSize)),
    y: Math.max(0, Math.min(scene.height, Math.round(point.y / gridSize) * gridSize))
  };
}

function templateAffectedTokenIds(store: StateStore, scene: Scene, annotation: SceneAnnotation): string[] {
  if (annotation.kind !== "template" || !annotation.points[0] || typeof annotation.radius !== "number") return [];
  return store.state.tokens
    .filter((token) => token.sceneId === scene.id)
    .filter((token) => tokenIntersectsTemplate(scene, annotation, token))
    .map((token) => token.id);
}

function tokenIntersectsTemplate(scene: Scene, annotation: SceneAnnotation, token: Token): boolean {
  const [start, end] = annotation.points;
  if (!start) return false;
  const tokenCenter = centerOfToken(token);
  const tokenRadius = Math.max(token.width, token.height) / 2;
  const radius = annotation.radius ?? 0;
  const shape = annotation.templateShape ?? "circle";
  if (shape === "line") {
    if (!end) return false;
    const halfWidth = Math.max(scene.gridSize / 2, 1);
    return pointDistanceToSegment(tokenCenter, start, end) <= halfWidth + tokenRadius;
  }
  if (shape === "cone") {
    if (!end) return false;
    return pointInCone(tokenCenter, start, end, radius + tokenRadius, 90);
  }
  return distanceBetweenPoints(start, tokenCenter) <= radius + tokenRadius;
}

function distanceBetweenPoints(left: VisionPoint, right: VisionPoint): number {
  return Math.hypot(left.x - right.x, left.y - right.y);
}

function pointDistanceToSegment(point: VisionPoint, start: VisionPoint, end: VisionPoint): number {
  const dx = end.x - start.x;
  const dy = end.y - start.y;
  const lengthSquared = dx * dx + dy * dy;
  if (lengthSquared === 0) return distanceBetweenPoints(point, start);
  const t = Math.max(0, Math.min(1, ((point.x - start.x) * dx + (point.y - start.y) * dy) / lengthSquared));
  return distanceBetweenPoints(point, { x: start.x + t * dx, y: start.y + t * dy });
}

function pointInCone(point: VisionPoint, origin: VisionPoint, directionPoint: VisionPoint, radius: number, angleDegrees: number): boolean {
  const directionX = directionPoint.x - origin.x;
  const directionY = directionPoint.y - origin.y;
  const directionLength = Math.hypot(directionX, directionY);
  if (directionLength === 0) return false;
  const pointX = point.x - origin.x;
  const pointY = point.y - origin.y;
  const pointDistance = Math.hypot(pointX, pointY);
  if (pointDistance > radius) return false;
  if (pointDistance === 0) return true;
  const cosine = (pointX * directionX + pointY * directionY) / (pointDistance * directionLength);
  return cosine >= Math.cos((angleDegrees / 2) * (Math.PI / 180));
}

function templateEffectHint(systemId: string | undefined, annotation: SceneAnnotation): string | undefined {
  if (annotation.kind !== "template") return undefined;
  const shape = titleCaseAnnotationShape(annotation.templateShape ?? "circle");
  const resolution = templateResolutionHint(annotation);
  if (systemId === DND_5E_SRD_SYSTEM_ID) return `${shape} template: ${annotation.affectedTokenIds?.length ?? 0} affected token${annotation.affectedTokenIds?.length === 1 ? "" : "s"}${resolution}; apply the spell or feature save, damage, or condition from the D&D action before consuming resources.`;
  return `${shape} template: ${annotation.affectedTokenIds?.length ?? 0} affected token${annotation.affectedTokenIds?.length === 1 ? "" : "s"}${resolution} in this area template.`;
}

function titleCaseAnnotationShape(shape: SceneTemplateShape): string {
  return shape.charAt(0).toUpperCase() + shape.slice(1);
}

function templateResolutionHint(annotation: SceneAnnotation): string {
  const parts: string[] = [];
  if (annotation.templateSaveAbility && annotation.templateSaveDc) parts.push(`${titleCaseAnnotationLabel(annotation.templateSaveAbility)} save DC ${annotation.templateSaveDc}`);
  else if (annotation.templateSaveDc) parts.push(`Save DC ${annotation.templateSaveDc}`);
  if (annotation.templateDamageFormula) parts.push(`damage ${annotation.templateDamageFormula}${annotation.templateDamageType ? ` ${annotation.templateDamageType}` : ""}`);
  return parts.length > 0 ? `; ${parts.join("; ")}` : "";
}

function titleCaseAnnotationLabel(value: string): string {
  return value.replace(/\b\w/g, (letter) => letter.toUpperCase());
}

function normalizeAnnotationRadius(radius: unknown, scene: Scene, points: VisionPoint[]): number | undefined {
  if (typeof radius === "number" && Number.isFinite(radius) && radius >= 0) return Math.min(Math.max(0, Math.round(radius)), Math.max(scene.width, scene.height));
  const [start, end] = points;
  if (!start || !end) return undefined;
  return Math.min(Math.round(Math.hypot(end.x - start.x, end.y - start.y)), Math.max(scene.width, scene.height));
}

function normalizeAnnotationExpiry(expiresInSeconds: unknown): string | undefined {
  if (typeof expiresInSeconds !== "number" || !Number.isFinite(expiresInSeconds) || expiresInSeconds <= 0) return undefined;
  const seconds = Math.min(Math.max(5, Math.round(expiresInSeconds)), 60 * 60 * 24);
  return new Date(Date.now() + seconds * 1000).toISOString();
}

function normalizeAnnotationColor(color: unknown): string {
  return typeof color === "string" && /^#[0-9a-f]{6}$/i.test(color.trim()) ? color.trim() : "#38bdf8";
}

function sceneAnnotationAuditSummary(annotation: SceneAnnotation): Record<string, unknown> {
  return {
    sceneId: annotation.sceneId,
    kind: annotation.kind,
    pointCount: annotation.points.length,
    radius: annotation.radius,
    label: annotation.label,
    layer: annotation.layer,
    groupId: annotation.groupId,
    groupLabel: annotation.groupLabel,
    templateShape: annotation.templateShape,
    templateSaveAbility: annotation.templateSaveAbility,
    templateSaveDc: annotation.templateSaveDc,
    templateDamageFormula: annotation.templateDamageFormula,
    templateDamageType: annotation.templateDamageType,
    snapToGrid: annotation.snapToGrid,
    color: annotation.color,
    affectedTokenIds: annotation.affectedTokenIds,
    rulesSystemId: annotation.rulesSystemId,
    effectHint: annotation.effectHint,
    expiresAt: annotation.expiresAt
  };
}

function normalizeFogRegion(body: { x?: number; y?: number; radius?: number; brushRadius?: number; hidden?: boolean; shape?: FogShape | "brush"; mode?: FogMode; points?: VisionPoint[] }, scene: Scene): Omit<FogRegion, "id"> | undefined {
  const rawPoints = Array.isArray(body.points) ? body.points : undefined;
  const mode: FogMode = body.mode === "hide" ? "hide" : "reveal";
  if (body.shape === "brush") {
    const brush = rawPoints ? buildSmoothFogBrushPolygon(scene, rawPoints, { radius: body.brushRadius ?? body.radius }) : undefined;
    if (!brush) return undefined;
    const center = polygonCenter(brush.points);
    return {
      x: center.x,
      y: center.y,
      radius: brush.radius,
      hidden: body.hidden ?? false,
      shape: "polygon",
      mode,
      points: brush.points
    };
  }
  const shape: FogShape = body.shape === "polygon" || rawPoints?.length ? "polygon" : "circle";
  if (shape === "polygon") {
    const points = normalizeFogPoints(rawPoints, scene);
    if (!points) return undefined;
    const center = polygonCenter(points);
    return {
      x: center.x,
      y: center.y,
      radius: 0,
      hidden: body.hidden ?? false,
      shape,
      mode,
      points
    };
  }
  const x = clampNumber(body.x ?? scene.width / 2, 0, scene.width);
  const y = clampNumber(body.y ?? scene.height / 2, 0, scene.height);
  const radius = clampNumber(body.radius ?? 120, 1, Math.max(scene.width, scene.height));
  if (x === undefined || y === undefined || radius === undefined) return undefined;
  return {
    x,
    y,
    radius,
    hidden: body.hidden ?? false,
    shape,
    mode
  };
}

function normalizeFogPoints(points: unknown[] | undefined, scene: Scene): VisionPoint[] | undefined {
  if (!points || points.length < 3 || points.length > 64) return undefined;
  const normalized = points
    .map((point) => {
      if (!isRecord(point)) return undefined;
      const x = typeof point.x === "number" ? clampNumber(point.x, 0, scene.width) : undefined;
      const y = typeof point.y === "number" ? clampNumber(point.y, 0, scene.height) : undefined;
      return x === undefined || y === undefined ? undefined : { x, y };
    })
    .filter((point): point is VisionPoint => Boolean(point));
  return normalized.length >= 3 ? normalized : undefined;
}

function polygonCenter(points: VisionPoint[]): VisionPoint {
  return {
    x: Math.round(points.reduce((sum, point) => sum + point.x, 0) / points.length),
    y: Math.round(points.reduce((sum, point) => sum + point.y, 0) / points.length)
  };
}

function clampNumber(value: number, min: number, max: number): number | undefined {
  if (!Number.isFinite(value)) return undefined;
  return Math.max(min, Math.min(max, value));
}

function clampLightIntensity(value: number): number {
  return Math.max(0.05, Math.min(1, value));
}

function normalizeWallPatch(body: Partial<Pick<Wall, "x1" | "y1" | "x2" | "y2" | "blocksVision" | "blocksMovement" | "kind">>): { patch: Partial<Wall> } | { error: string } {
  const patch: Partial<Wall> = {};
  for (const key of ["x1", "y1", "x2", "y2"] as const) {
    if (body[key] === undefined) continue;
    if (!Number.isFinite(body[key])) return { error: `Wall ${key} must be a finite number` };
    patch[key] = body[key];
  }
  if (body.blocksVision !== undefined) patch.blocksVision = Boolean(body.blocksVision);
  if (body.blocksMovement !== undefined) patch.blocksMovement = Boolean(body.blocksMovement);
  if (body.kind !== undefined) {
    if (body.kind !== "wall" && body.kind !== "terrain") return { error: "Wall kind must be wall or terrain" };
    patch.kind = body.kind;
    if (body.blocksMovement === undefined) patch.blocksMovement = body.kind === "wall";
  }
  if (Object.keys(patch).length === 0) return { error: "Wall update must include at least one field" };
  const next = { x1: body.x1, y1: body.y1, x2: body.x2, y2: body.y2 };
  if (next.x1 !== undefined && next.y1 !== undefined && next.x2 !== undefined && next.y2 !== undefined && Math.hypot(next.x2 - next.x1, next.y2 - next.y1) < 0.001) {
    return { error: "Wall endpoints must not be identical" };
  }
  return { patch };
}

function normalizeLightSourcePatch(body: Partial<Pick<LightSource, "x" | "y" | "radius" | "brightRadius" | "dimRadius" | "color" | "intensity">>, current?: LightSource): { patch: Partial<LightSource> } | { error: string } {
  const patch: Partial<LightSource> = {};
  if (body.x !== undefined) {
    if (!Number.isFinite(body.x)) return { error: "Light x must be a finite number" };
    patch.x = body.x;
  }
  if (body.y !== undefined) {
    if (!Number.isFinite(body.y)) return { error: "Light y must be a finite number" };
    patch.y = body.y;
  }
  if (body.radius !== undefined) {
    if (!Number.isFinite(body.radius) || body.radius <= 0) return { error: "Light radius must be greater than zero" };
    patch.radius = body.radius;
  }
  if (body.brightRadius !== undefined) {
    if (!Number.isFinite(body.brightRadius) || body.brightRadius <= 0) return { error: "Light brightRadius must be greater than zero" };
    patch.brightRadius = body.brightRadius;
  }
  if (body.dimRadius !== undefined) {
    if (!Number.isFinite(body.dimRadius) || body.dimRadius <= 0) return { error: "Light dimRadius must be greater than zero" };
    patch.dimRadius = body.dimRadius;
  }
  const nextBrightRadius = patch.brightRadius ?? current?.brightRadius;
  const nextDimRadius = patch.dimRadius ?? current?.dimRadius ?? patch.radius ?? current?.radius;
  if (nextBrightRadius !== undefined && nextDimRadius !== undefined && nextBrightRadius >= nextDimRadius) return { error: "Light brightRadius must be less than dimRadius" };
  if (body.color !== undefined) {
    if (!/^#[0-9a-fA-F]{6}$/.test(body.color)) return { error: "Light color must be a six-digit hex color" };
    patch.color = body.color;
  }
  if (body.intensity !== undefined) {
    if (!Number.isFinite(body.intensity) || body.intensity < 0 || body.intensity > 1) return { error: "Light intensity must be between 0 and 1" };
    patch.intensity = body.intensity;
  }
  if (Object.keys(patch).length === 0) return { error: "Light update must include at least one field" };
  return { patch };
}

const tokenLayerValues = ["map", "player", "gm"] as const satisfies readonly TokenLayer[];

function isTokenLayer(value: unknown): value is TokenLayer {
  return typeof value === "string" && tokenLayerValues.includes(value as TokenLayer);
}

function tokenLayer(token: Partial<Pick<Token, "layer">>): TokenLayer {
  return isTokenLayer(token.layer) ? token.layer : "player";
}

function normalizeCampaignPatch(
  store: StateStore,
  rawBody: unknown
): { ok: true; value: CampaignPatchBody } | { ok: false; error: string } {
  if (!isRecord(rawBody)) return { ok: false, error: "Campaign body must be a JSON object" };
  const patch: CampaignPatchBody = {};
  if ("name" in rawBody) {
    const name = normalizeBoundedText(rawBody.name, 160);
    if (!name) return { ok: false, error: "Campaign name must be 1-160 characters" };
    patch.name = name;
  }
  if ("description" in rawBody) {
    const description = normalizeBoundedText(rawBody.description, 20_000);
    if (description === undefined) return { ok: false, error: "Campaign description must be no longer than 20000 characters" };
    patch.description = description;
  }
  if ("defaultSystemId" in rawBody) {
    const systemId = normalizeNonEmptyString(rawBody.defaultSystemId);
    if (!systemId || !findRegisteredSystem(store.state, systemId)) return { ok: false, error: "Campaign defaultSystemId must reference an installed system" };
    patch.defaultSystemId = systemId;
  }
  if ("visibility" in rawBody) {
    if (rawBody.visibility !== "private" && rawBody.visibility !== "invite_only" && rawBody.visibility !== "public") {
      return { ok: false, error: "Campaign visibility must be private, invite_only, or public" };
    }
    patch.visibility = rawBody.visibility;
  }
  return { ok: true, value: patch };
}

function normalizeDiceMacroPatch(
  rawBody: unknown
):
  | { ok: true; value: Partial<Pick<DiceMacro, "name" | "formula" | "visibility">> }
  | { ok: false; error: string } {
  if (!isRecord(rawBody)) return { ok: false, error: "Dice macro body must be a JSON object" };
  const patch: Partial<Pick<DiceMacro, "name" | "formula" | "visibility">> = {};
  if ("name" in rawBody) {
    const name = typeof rawBody.name === "string" ? rawBody.name.trim() : "";
    if (!name) return { ok: false, error: "Dice macro name is required" };
    patch.name = name;
  }
  if ("formula" in rawBody) {
    const formula = typeof rawBody.formula === "string" ? rawBody.formula.trim() : "";
    if (!formula) return { ok: false, error: "Dice macro formula is required" };
    try {
      rollFormula(formula);
    } catch (error) {
      return { ok: false, error: error instanceof Error ? error.message : "Invalid dice macro formula" };
    }
    patch.formula = formula;
  }
  if ("visibility" in rawBody) {
    if (rawBody.visibility !== "public" && rawBody.visibility !== "gm_only") {
      return { ok: false, error: "Dice macro visibility must be public or gm_only" };
    }
    patch.visibility = rawBody.visibility;
  }
  if (Object.keys(patch).length === 0) return { ok: false, error: "Dice macro update must include at least one field" };
  return { ok: true, value: patch };
}

const SCENE_PATCH_FIELDS = new Set<keyof ScenePatchBody>([
  "worldId",
  "name",
  "width",
  "height",
  "gridType",
  "gridSize",
  "backgroundAssetId",
  "folder",
  "active",
  "sortOrder",
  "fog",
  "walls",
  "lights",
  "annotations",
  "metadata"
]);

function normalizeScenePatch(rawBody: unknown): { ok: true; value: ScenePatchBody } | { ok: false; error: string } {
  if (!isRecord(rawBody)) return { ok: false, error: "Scene body must be a JSON object" };
  const unexpected = Object.keys(rawBody).find((key) => !SCENE_PATCH_FIELDS.has(key as keyof ScenePatchBody));
  if (unexpected) return { ok: false, error: `Scene field is not editable: ${unexpected}` };
  const patch: ScenePatchBody = {};
  if ("worldId" in rawBody) {
    if (rawBody.worldId !== null && (typeof rawBody.worldId !== "string" || !rawBody.worldId.trim())) return { ok: false, error: "Scene worldId must be null or a non-empty string" };
    patch.worldId = rawBody.worldId === null ? null : (rawBody.worldId as string).trim();
  }
  if ("name" in rawBody) {
    const name = normalizeBoundedText(rawBody.name, 200);
    if (!name) return { ok: false, error: "Scene name must be 1-200 characters" };
    patch.name = name;
  }
  for (const [field, maximum] of [
    ["width", 100_000],
    ["height", 100_000],
    ["gridSize", 10_000]
  ] as const) {
    if (!(field in rawBody)) continue;
    const value = rawBody[field];
    if (typeof value !== "number" || !Number.isFinite(value) || value <= 0 || value > maximum) return { ok: false, error: `Scene ${field} must be a positive number no greater than ${maximum}` };
    patch[field] = value;
  }
  if ("gridType" in rawBody) {
    if (rawBody.gridType !== "square" && rawBody.gridType !== "gridless") return { ok: false, error: "Scene gridType must be square or gridless" };
    patch.gridType = rawBody.gridType;
  }
  if ("backgroundAssetId" in rawBody) {
    if (rawBody.backgroundAssetId !== null && (typeof rawBody.backgroundAssetId !== "string" || !rawBody.backgroundAssetId.trim())) {
      return { ok: false, error: "Scene backgroundAssetId must be null or a non-empty string" };
    }
    patch.backgroundAssetId = rawBody.backgroundAssetId === null ? null : (rawBody.backgroundAssetId as string).trim();
  }
  if ("folder" in rawBody) {
    if (rawBody.folder !== null && typeof rawBody.folder !== "string") return { ok: false, error: "Scene folder must be null or a string" };
    patch.folder = rawBody.folder as string | null;
  }
  if ("active" in rawBody) {
    if (typeof rawBody.active !== "boolean") return { ok: false, error: "Scene active must be a boolean" };
    patch.active = rawBody.active;
  }
  if ("sortOrder" in rawBody) {
    if (typeof rawBody.sortOrder !== "number" || !Number.isFinite(rawBody.sortOrder)) return { ok: false, error: "Scene sortOrder must be a finite number" };
    patch.sortOrder = rawBody.sortOrder;
  }
  for (const [field, maximum] of [
    ["fog", 5_000],
    ["walls", 10_000],
    ["lights", 5_000],
    ["annotations", 10_000]
  ] as const) {
    if (!(field in rawBody)) continue;
    const value = rawBody[field];
    if (!Array.isArray(value) || value.length > maximum || value.some((entry) => !isRecord(entry))) return { ok: false, error: `Scene ${field} must be an array of at most ${maximum} objects` };
    (patch[field] as unknown[]) = value;
  }
  if ("metadata" in rawBody) {
    if (!isRecord(rawBody.metadata)) return { ok: false, error: "Scene metadata must be an object" };
    patch.metadata = rawBody.metadata;
  }
  return { ok: true, value: patch };
}

function tokenPatchFromBody(body: TokenPatchBody): Partial<Token> {
  const patch: Partial<Token> = {};
  if (body.actorId !== undefined) patch.actorId = body.actorId;
  if (body.name !== undefined) patch.name = body.name;
  if (body.width !== undefined) patch.width = body.width;
  if (body.height !== undefined) patch.height = body.height;
  if (body.rotation !== undefined) patch.rotation = body.rotation;
  if (body.hidden !== undefined) patch.hidden = body.hidden;
  if (body.locked !== undefined) patch.locked = body.locked;
  if (body.disposition !== undefined) patch.disposition = body.disposition;
  if (body.imageAssetId !== undefined) patch.imageAssetId = body.imageAssetId;
  if (body.metadata !== undefined) patch.metadata = body.metadata;
  return patch;
}

function actorPatchFromBody(body: ActorPatchBody): ActorPatchBody {
  const patch: ActorPatchBody = {};
  if (body.worldId !== undefined) patch.worldId = body.worldId === null ? undefined : body.worldId;
  if (body.systemId !== undefined) patch.systemId = body.systemId;
  if (body.ownerUserId !== undefined) patch.ownerUserId = body.ownerUserId;
  if (body.type !== undefined) patch.type = body.type;
  if (body.name !== undefined) patch.name = body.name;
  if (body.imageAssetId !== undefined) patch.imageAssetId = body.imageAssetId;
  if (body.data !== undefined) patch.data = body.data;
  if (body.permissions !== undefined) patch.permissions = body.permissions;
  return patch;
}

function journalEntryPatchFromBody(body: JournalEntryPatchBody): JournalEntryPatchBody {
  const patch: JournalEntryPatchBody = {};
  if (body.worldId !== undefined) patch.worldId = body.worldId === null ? undefined : body.worldId;
  if (body.parentId !== undefined) patch.parentId = body.parentId;
  if (body.title !== undefined) patch.title = body.title;
  if (body.body !== undefined) patch.body = body.body;
  if (body.visibility !== undefined) patch.visibility = body.visibility;
  if (body.visibleToUserIds !== undefined) patch.visibleToUserIds = body.visibleToUserIds;
  if (body.visibleToActorIds !== undefined) patch.visibleToActorIds = body.visibleToActorIds;
  if (body.tags !== undefined) patch.tags = body.tags;
  return patch;
}

function normalizeHandoutPatch(
  store: StateStore,
  campaignId: string,
  rawBody: unknown,
  create = false
): { ok: true; value: Partial<Handout> } | { ok: false; error: string } {
  if (!isRecord(rawBody)) return { ok: false, error: "Handout body must be a JSON object" };
  const patch: Partial<Handout> = {};
  if (create || "title" in rawBody) {
    const title = normalizeBoundedText(rawBody.title ?? "New Handout", 200);
    if (!title) return { ok: false, error: "Handout title must be 1-200 characters" };
    patch.title = title;
  }
  if (create || "body" in rawBody) {
    const body = normalizeBoundedText(rawBody.body ?? "", 100_000);
    if (body === undefined) return { ok: false, error: "Handout body must be no longer than 100000 characters" };
    patch.body = body;
  }
  if (create || "visibility" in rawBody) {
    const visibility = rawBody.visibility ?? "gm_only";
    if (!VISIBILITIES.includes(visibility as Visibility)) return { ok: false, error: "Handout visibility is invalid" };
    patch.visibility = visibility as Visibility;
  }
  if ("worldId" in rawBody) {
    if (rawBody.worldId !== null && rawBody.worldId !== undefined && (typeof rawBody.worldId !== "string" || !store.state.worlds.some((world) => world.id === rawBody.worldId && world.campaignId === campaignId))) {
      return { ok: false, error: "Handout worldId must reference a world in the same campaign" };
    }
    patch.worldId = typeof rawBody.worldId === "string" ? rawBody.worldId : undefined;
  }
  for (const [field, maxItems] of [
    ["visibleToUserIds", 200],
    ["visibleToActorIds", 200],
    ["assetIds", 200],
    ["tags", 100],
    ["readByUserIds", 200]
  ] as const) {
    if (!create && !(field in rawBody)) continue;
    const ids = normalizedStringIds(rawBody[field], maxItems);
    if (!ids) return { ok: false, error: `${field} must be an array of non-empty strings` };
    (patch[field] as string[] | undefined) = ids;
  }
  const campaignUsers = campaignMemberUserIds(store, campaignId);
  if (patch.visibleToUserIds?.some((id) => !campaignUsers.has(id)) || patch.readByUserIds?.some((id) => !campaignUsers.has(id))) {
    return { ok: false, error: "Handout user IDs must reference campaign members" };
  }
  if (patch.visibleToActorIds?.some((id) => !store.state.actors.some((actor) => actor.id === id && actor.campaignId === campaignId))) {
    return { ok: false, error: "Handout actor IDs must reference actors in the same campaign" };
  }
  if (patch.assetIds?.some((id) => !store.state.assets.some((asset) => asset.id === id && asset.campaignId === campaignId))) {
    return { ok: false, error: "Handout asset IDs must reference assets in the same campaign" };
  }
  return { ok: true, value: patch };
}

function normalizeEncounterPatch(
  store: StateStore,
  campaignId: string,
  rawBody: unknown,
  create = false,
  existing?: Encounter
): { ok: true; value: NormalizedEncounterPatch } | { ok: false; error: string } {
  if (!isRecord(rawBody)) return { ok: false, error: "Encounter body must be a JSON object" };
  const patch: NormalizedEncounterPatch = {};
  if (create || "name" in rawBody) {
    const name = normalizeBoundedText(rawBody.name ?? "New Encounter", 200);
    if (!name) return { ok: false, error: "Encounter name must be 1-200 characters" };
    patch.name = name;
  }
  if (create || "summary" in rawBody) {
    const summary = normalizeBoundedText(rawBody.summary ?? "", 20_000);
    if (summary === undefined) return { ok: false, error: "Encounter summary must be no longer than 20000 characters" };
    patch.summary = summary;
  }
  if ("difficulty" in rawBody) {
    if (rawBody.difficulty !== undefined && rawBody.difficulty !== null && typeof rawBody.difficulty !== "string") return { ok: false, error: "Encounter difficulty must be a string" };
    patch.difficulty = typeof rawBody.difficulty === "string" ? rawBody.difficulty.trim() || undefined : undefined;
  }
  if (create || "tokenIds" in rawBody) {
    const tokenIds = normalizedStringIds(rawBody.tokenIds, 500);
    if (!tokenIds) return { ok: false, error: "Encounter tokenIds must be an array of non-empty strings" };
    if (tokenIds.some((id) => !store.state.tokens.some((token) => token.id === id && campaignIdForToken(store, id) === campaignId))) {
      return { ok: false, error: "Encounter tokenIds must reference tokens in the same campaign" };
    }
    patch.tokenIds = tokenIds;
  }
  if ("worldId" in rawBody) {
    if (rawBody.worldId !== null && rawBody.worldId !== undefined && (typeof rawBody.worldId !== "string" || !store.state.worlds.some((world) => world.id === rawBody.worldId && world.campaignId === campaignId))) {
      return { ok: false, error: "Encounter worldId must reference a world in the same campaign" };
    }
    patch.worldId = typeof rawBody.worldId === "string" ? rawBody.worldId : undefined;
  }
  if ("systemId" in rawBody) {
    if (typeof rawBody.systemId !== "string" || rawBody.systemId.trim().length === 0) return { ok: false, error: "Encounter systemId must be a non-empty string" };
    const systemId = rawBody.systemId.trim();
    if (!findRegisteredSystem(store.state, systemId)) return { ok: false, error: "Encounter systemId must reference a registered system" };
    if (!hasSystemRuntimeCapability(systemId, "encounter-builder")) return { ok: false, error: "Encounter systemId must support encounter building" };
    patch.systemId = systemId;
  }
  const nextSystemId = patch.systemId ?? existing?.systemId;
  if ("partyActorIds" in rawBody) {
    if (!nextSystemId) return { ok: false, error: "Encounter partyActorIds require systemId" };
    const partyActorIds = normalizedEncounterPartyActorIds(store, campaignId, nextSystemId, rawBody.partyActorIds);
    if (!partyActorIds.ok) return partyActorIds;
    patch.partyActorIds = partyActorIds.value;
  }
  if ("threats" in rawBody) {
    if (!nextSystemId) return { ok: false, error: "Encounter threats require systemId" };
    const threats = normalizedEncounterThreatSelections(rawBody.threats, nextSystemId);
    if (!threats.ok) return threats;
    patch.threats = threats.value;
  }
  if (patch.systemId && existing?.systemId && patch.systemId !== existing.systemId) {
    const retainedParty = patch.partyActorIds ?? existing.partyActorIds;
    if (retainedParty) {
      const normalized = normalizedEncounterPartyActorIds(store, campaignId, patch.systemId, retainedParty);
      if (!normalized.ok) return normalized;
    }
    const retainedThreats = patch.threats ?? existing.threats;
    if (retainedThreats) {
      const normalized = normalizedEncounterThreatSelections(retainedThreats, patch.systemId);
      if (!normalized.ok) return normalized;
    }
  }
  return { ok: true, value: patch };
}

function normalizeSystemEncounterPlanBody(
  store: StateStore,
  campaignId: string,
  system: SystemManifest,
  rawBody: unknown
): { ok: true; value: { partyActorIds?: string[]; threats: EncounterThreatSelection[]; createEncounter: boolean; name?: string } } | { ok: false; error: string } {
  if (!isRecord(rawBody)) return { ok: false, error: "Encounter plan body must be a JSON object" };
  if (rawBody.createEncounter !== undefined && typeof rawBody.createEncounter !== "boolean") return { ok: false, error: "createEncounter must be a boolean" };
  if (rawBody.name !== undefined && typeof rawBody.name !== "string") return { ok: false, error: "Encounter name must be a string" };
  const name = typeof rawBody.name === "string" ? normalizeBoundedText(rawBody.name, 200) : undefined;
  if (typeof rawBody.name === "string" && name === undefined) return { ok: false, error: "Encounter name must be no longer than 200 characters" };
  let partyActorIds: string[] | undefined;
  if (rawBody.partyActorIds !== undefined) {
    const normalized = normalizedEncounterPartyActorIds(store, campaignId, system.id, rawBody.partyActorIds);
    if (!normalized.ok) return normalized;
    partyActorIds = normalized.value;
  }
  const threats = normalizedEncounterThreatSelections(rawBody.threats, system.id);
  if (!threats.ok) return threats;
  return {
    ok: true,
    value: {
      partyActorIds,
      threats: threats.value,
      createEncounter: rawBody.createEncounter === true,
      name
    }
  };
}

function normalizedEncounterPartyActorIds(
  store: StateStore,
  campaignId: string,
  systemId: string,
  value: unknown
): { ok: true; value: string[] } | { ok: false; error: string } {
  const actorIds = normalizedStringIds(value, 100);
  if (!actorIds) return { ok: false, error: "Encounter partyActorIds must be an array of non-empty strings" };
  if (actorIds.some((id) => !store.state.actors.some((actor) => actor.id === id && actor.campaignId === campaignId && actor.systemId === systemId && actor.type === "character"))) {
    return { ok: false, error: "Encounter partyActorIds must reference character actors from the same campaign and system" };
  }
  return { ok: true, value: actorIds };
}

function normalizedEncounterThreatSelections(
  value: unknown,
  systemId: string
): { ok: true; value: Array<{ id: string; count: number }> } | { ok: false; error: string } {
  if (value === undefined) return { ok: true, value: [] };
  if (!Array.isArray(value) || value.length > 100) return { ok: false, error: "Encounter threats must be an array with at most 100 selections" };
  const catalogIds = new Set(encounterThreatsForSystem(systemId).map((threat) => threat.id));
  const seen = new Set<string>();
  const threats: Array<{ id: string; count: number }> = [];
  for (const selection of value) {
    if (!isRecord(selection) || typeof selection.id !== "string" || selection.id.trim().length === 0 || selection.id.trim().length > 160) {
      return { ok: false, error: "Each encounter threat must include a valid id" };
    }
    const id = selection.id.trim();
    if (seen.has(id)) return { ok: false, error: "Encounter threat IDs must be unique" };
    if (!catalogIds.has(id)) return { ok: false, error: `Encounter threat ${id} does not exist in system ${systemId}` };
    const count = selection.count === undefined ? 1 : selection.count;
    if (typeof count !== "number" || !Number.isInteger(count) || count < 1 || count > 99) {
      return { ok: false, error: "Encounter threat counts must be integers from 1 to 99" };
    }
    seen.add(id);
    threats.push({ id, count });
  }
  return { ok: true, value: threats };
}

function normalizeAiMemoryPatch(
  store: StateStore,
  campaignId: string,
  rawBody: unknown,
  create = false
): { ok: true; value: NormalizedAiMemoryPatch } | { ok: false; error: string } {
  if (!isRecord(rawBody)) return { ok: false, error: "AI memory body must be a JSON object" };
  const patch: NormalizedAiMemoryPatch = {};
  if (create || "text" in rawBody) {
    const text = normalizeBoundedText(rawBody.text, 4000);
    if (!text) return { ok: false, error: "AI memory text must be 1-4000 characters" };
    patch.text = text;
  }
  if (create || "type" in rawBody) {
    const type = rawBody.type ?? "canon_fact";
    if (!AI_MEMORY_TYPES.includes(type as AiMemoryFactType)) return { ok: false, error: "AI memory type is invalid" };
    patch.type = type as AiMemoryFactType;
  }
  if (create || "visibility" in rawBody) {
    const visibility = rawBody.visibility ?? "gm_only";
    if (visibility !== "public" && visibility !== "gm_only") return { ok: false, error: "AI memory visibility must be public or gm_only" };
    patch.visibility = visibility;
  }
  if ("worldId" in rawBody) {
    if (rawBody.worldId !== null && rawBody.worldId !== undefined && (typeof rawBody.worldId !== "string" || !store.state.worlds.some((world) => world.id === rawBody.worldId && world.campaignId === campaignId))) {
      return { ok: false, error: "AI memory worldId must reference a world in the same campaign" };
    }
    patch.worldId = typeof rawBody.worldId === "string" ? rawBody.worldId : undefined;
  }
  if ("subject" in rawBody) {
    if (rawBody.subject !== null && (typeof rawBody.subject !== "string" || rawBody.subject.trim().length > 300)) return { ok: false, error: "AI memory subject must be null or no longer than 300 characters" };
    patch.subject = typeof rawBody.subject === "string" ? rawBody.subject.trim() || undefined : undefined;
  }
  if ("confidence" in rawBody) {
    if (rawBody.confidence !== null && (typeof rawBody.confidence !== "number" || !Number.isFinite(rawBody.confidence) || rawBody.confidence < 0 || rawBody.confidence > 1)) {
      return { ok: false, error: "AI memory confidence must be null or a number from 0 to 1" };
    }
    patch.confidence = typeof rawBody.confidence === "number" ? rawBody.confidence : undefined;
  }
  if (create || "sourceIds" in rawBody) {
    const sourceIds = normalizedAiMemorySourceIds(rawBody.sourceIds);
    if (!sourceIds) return { ok: false, error: "AI memory sourceIds must be an array of strings" };
    patch.sourceIds = sourceIds;
  }
  if ("source" in rawBody) {
    if (rawBody.source === null || rawBody.source === undefined) patch.source = undefined;
    else if (!isRecord(rawBody.source) || typeof rawBody.source.type !== "string" || !rawBody.source.type.trim() || (rawBody.source.id !== undefined && typeof rawBody.source.id !== "string") || (rawBody.source.label !== undefined && typeof rawBody.source.label !== "string")) {
      return { ok: false, error: "AI memory source must contain a non-empty type and optional string id/label" };
    } else {
      patch.source = {
        type: rawBody.source.type.trim().slice(0, 80),
        ...(typeof rawBody.source.id === "string" ? { id: rawBody.source.id.trim().slice(0, 160) } : {}),
        ...(typeof rawBody.source.label === "string" ? { label: rawBody.source.label.trim().slice(0, 300) } : {})
      } satisfies AiMemoryFactSource;
    }
  }
  if ("createdBy" in rawBody) {
    if (typeof rawBody.createdBy !== "string" || !( ["user", "ai", "plugin", "system"] as readonly string[]).includes(rawBody.createdBy)) return { ok: false, error: "AI memory createdBy is invalid" };
    patch.createdBy = rawBody.createdBy as NonNullable<AiMemoryFact["createdBy"]>;
  }
  if ("status" in rawBody) {
    if (!AI_MEMORY_STATUSES.includes(rawBody.status as AiMemoryFactStatus)) return { ok: false, error: "AI memory status is invalid" };
    patch.status = rawBody.status as AiMemoryFactStatus;
  }
  return { ok: true, value: patch };
}

function combatPatchFromBody(body: CombatPatchBody): CombatPatchBody {
  const patch: CombatPatchBody = {};
  if (body.active !== undefined) patch.active = body.active;
  if (body.round !== undefined) patch.round = body.round;
  if (body.turnIndex !== undefined) patch.turnIndex = body.turnIndex;
  if (body.manualTurnOrder !== undefined) patch.manualTurnOrder = body.manualTurnOrder;
  if (body.combatants !== undefined) patch.combatants = body.combatants;
  return patch;
}

function normalizeTokenLayerPatch(body: Partial<Pick<Token, "layer">>): { patch: Partial<Pick<Token, "layer">> } | { error: string } {
  if (body.layer === undefined) return { patch: {} };
  if (!isTokenLayer(body.layer)) return { error: "Token layer must be map, player, or gm" };
  return { patch: { layer: body.layer } };
}

function normalizeTokenVisionPatch(body: Partial<Pick<Token, "visionEnabled" | "visionRadius">> & { brightVisionRadius?: number | null; dimVisionRadius?: number | null }, current?: Partial<Pick<Token, "visionEnabled" | "visionRadius" | "brightVisionRadius" | "dimVisionRadius">>): { patch: Partial<Token> } | { error: string } {
  const patch: Partial<Token> = {};
  if (body.visionEnabled !== undefined) {
    if (typeof body.visionEnabled !== "boolean") return { error: "Token visionEnabled must be a boolean" };
    patch.visionEnabled = body.visionEnabled;
  }
  if (body.visionRadius !== undefined) {
    if (!Number.isFinite(body.visionRadius) || body.visionRadius < 0) return { error: "Token visionRadius must be a nonnegative number" };
    patch.visionRadius = body.visionRadius;
  }
  if (body.brightVisionRadius !== undefined) {
    if (body.brightVisionRadius === null) {
      patch.brightVisionRadius = undefined;
    } else {
      if (!Number.isFinite(body.brightVisionRadius) || body.brightVisionRadius <= 0) return { error: "Token brightVisionRadius must be greater than zero" };
      patch.brightVisionRadius = body.brightVisionRadius;
    }
  }
  if (body.dimVisionRadius !== undefined) {
    if (body.dimVisionRadius === null) {
      patch.dimVisionRadius = undefined;
    } else {
      if (!Number.isFinite(body.dimVisionRadius) || body.dimVisionRadius <= 0) return { error: "Token dimVisionRadius must be greater than zero" };
      patch.dimVisionRadius = body.dimVisionRadius;
    }
  }
  const nextEnabled = body.visionEnabled ?? current?.visionEnabled ?? true;
  const nextRadius = patch.visionRadius ?? current?.visionRadius ?? 0;
  const hasBrightPatch = Object.prototype.hasOwnProperty.call(patch, "brightVisionRadius");
  const hasDimPatch = Object.prototype.hasOwnProperty.call(patch, "dimVisionRadius");
  const nextBrightRadius = hasBrightPatch ? patch.brightVisionRadius : current?.brightVisionRadius;
  const nextDimRadius = hasDimPatch ? patch.dimVisionRadius ?? nextRadius : current?.dimVisionRadius ?? nextRadius;
  if (nextEnabled && nextBrightRadius !== undefined && nextBrightRadius >= nextDimRadius) return { error: "Token brightVisionRadius must be less than dimVisionRadius" };
  return { patch };
}

function tokenMoveOnlyPatch(body: object): boolean {
  return Object.keys(body).every((key) => key === "x" || key === "y");
}

function normalizeTokenMovePatch(body: Partial<Pick<Token, "x" | "y">>): { patch: Partial<Pick<Token, "x" | "y">> } | { error: string } {
  const patch: Partial<Pick<Token, "x" | "y">> = {};
  if (body.x !== undefined) {
    if (!Number.isFinite(body.x)) return { error: "Token x must be a finite number" };
    patch.x = body.x;
  }
  if (body.y !== undefined) {
    if (!Number.isFinite(body.y)) return { error: "Token y must be a finite number" };
    patch.y = body.y;
  }
  return { patch };
}

function normalizeTokenTabletopPatch(body: Partial<Pick<Token, "ownerUserIds" | "notes" | "conditions" | "auras" | "targetedByUserIds">>, campaignUserIds: Set<string>): { patch: Partial<Token> } | { error: string } {
  const patch: Partial<Token> = {};
  if (body.ownerUserIds !== undefined) {
    if (!Array.isArray(body.ownerUserIds)) return { error: "Token owners must be an array" };
    const ownerUserIds = [...new Set(body.ownerUserIds.filter((id): id is string => typeof id === "string" && id.trim().length > 0).map((id) => id.trim()))].slice(0, 50);
    if (ownerUserIds.some((id) => !campaignUserIds.has(id))) return { error: "Token owners must be campaign members" };
    patch.ownerUserIds = ownerUserIds;
  }
  if (body.notes !== undefined) {
    if (typeof body.notes !== "string") return { error: "Token notes must be a string" };
    patch.notes = body.notes.trim().slice(0, 2000);
  }
  if (body.conditions !== undefined) {
    if (!Array.isArray(body.conditions)) return { error: "Token conditions must be an array" };
    const conditions = body.conditions.map((condition) => {
      const record = condition as unknown as Record<string, unknown>;
      const rawName = typeof record.name === "string" ? record.name : typeof record.id === "string" ? record.id : "";
      const name = rawName.trim().slice(0, 80);
      const id = (typeof record.id === "string" ? record.id : name).trim().toLowerCase().replace(/[^a-z0-9_-]+/g, "-").replace(/^-+|-+$/g, "").slice(0, 80);
      return id && name ? { id, name } : undefined;
    });
    if (conditions.some((condition) => condition === undefined)) return { error: "Token conditions require id or name" };
    const byId = new Map(conditions.map((condition) => [condition!.id, condition!]));
    patch.conditions = [...byId.values()].slice(0, 20);
  }
  if (body.auras !== undefined) {
    if (!Array.isArray(body.auras)) return { error: "Token auras must be an array" };
    const auras = body.auras.map((aura) => {
      const record = aura as unknown as Record<string, unknown>;
      const rawName = typeof record.name === "string" ? record.name : typeof record.id === "string" ? record.id : "";
      const name = rawName.trim().slice(0, 80);
      const id = (typeof record.id === "string" ? record.id : name).trim().toLowerCase().replace(/[^a-z0-9_-]+/g, "-").replace(/^-+|-+$/g, "").slice(0, 80);
      const radius = Number(record.radius);
      const color = typeof record.color === "string" && record.color.trim() ? record.color.trim().slice(0, 32) : undefined;
      return id && name && Number.isFinite(radius) && radius >= 0 ? { id, name, radius: Math.round(radius), ...(color ? { color } : {}) } : undefined;
    });
    if (auras.some((aura) => aura === undefined)) return { error: "Token auras require id, name, and non-negative radius" };
    const byId = new Map(auras.map((aura) => [aura!.id, aura!]));
    patch.auras = [...byId.values()].slice(0, 10);
  }
  if (body.targetedByUserIds !== undefined) {
    if (!Array.isArray(body.targetedByUserIds)) return { error: "Token targets must be an array" };
    patch.targetedByUserIds = [...new Set(body.targetedByUserIds.filter((id): id is string => typeof id === "string" && id.trim().length > 0).map((id) => id.trim()))].slice(0, 50);
  }
  return { patch };
}

function tokenVisionOuterRadius(token: Pick<Token, "visionRadius" | "dimVisionRadius">): number {
  return token.dimVisionRadius ?? token.visionRadius;
}

function isRecord(value: unknown): value is Record<string, unknown> {
  return typeof value === "object" && value !== null && !Array.isArray(value);
}

function optionalJsonObjectBody(value: unknown): Record<string, unknown> | undefined {
  return value === undefined ? {} : isRecord(value) ? value : undefined;
}

function aiToolCallMaintenanceBodyError(body: Record<string, unknown>, options: { allowReason?: boolean; allowToolCallId?: boolean }): string | undefined {
  if (body.dryRun !== undefined && typeof body.dryRun !== "boolean") return "dryRun must be a boolean";
  for (const field of ["campaignId", "threadId"] as const) {
    const value = body[field];
    if (value !== undefined && (typeof value !== "string" || value.trim().length === 0)) return `${field} must be a non-empty string`;
  }
  if (body.toolCallId !== undefined && (!options.allowToolCallId || typeof body.toolCallId !== "string" || body.toolCallId.trim().length === 0)) {
    return options.allowToolCallId ? "toolCallId must be a non-empty string" : "toolCallId is not supported for this operation";
  }
  if (body.reason !== undefined && (!options.allowReason || typeof body.reason !== "string")) return options.allowReason ? "reason must be a string" : "reason is not supported for this operation";
  if (body.limit !== undefined) {
    if (typeof body.limit !== "number" && typeof body.limit !== "string") return "limit must be an integer from 1 to 500";
    const limit = Number(body.limit);
    if (!Number.isInteger(limit) || limit < 1 || limit > 500) return "limit must be an integer from 1 to 500";
  }
  return undefined;
}

function normalizedAiMemorySourceIds(value: unknown): string[] | undefined {
  if (value === undefined) return [];
  if (!Array.isArray(value) || value.length > 50 || !value.every((item) => typeof item === "string" && item.trim().length > 0)) return undefined;
  return [...new Set(value.map((item) => (item as string).trim().slice(0, 160)))];
}

function normalizedStringIds(value: unknown, maxItems = 100): string[] | undefined {
  if (value === undefined) return [];
  if (!Array.isArray(value) || value.length > maxItems || !value.every((item) => typeof item === "string" && item.trim().length > 0)) return undefined;
  return [...new Set(value.map((item) => (item as string).trim()))];
}

function registerRateLimit(app: FastifyInstance, store: StateStore, config: RateLimitConfig): void {
  if (!config.enabled) return;
  const maxRequests = Math.max(1, Math.floor(config.maxRequests));
  const windowMs = Math.max(1000, Math.floor(config.windowMs));
  const buckets = new Map<string, RateLimitBucket>();

  app.addHook("onRequest", async (request, reply) => {
    if (request.method === "OPTIONS") return;
    const now = Date.now();
    if (buckets.size > maxRequests * 20) pruneExpiredRateLimitBuckets(buckets, now);
    const key = rateLimitKey(store, request);
    const existing = buckets.get(key);
    const bucket = existing && existing.resetAt > now ? existing : { count: 0, resetAt: now + windowMs };
    bucket.count += 1;
    buckets.set(key, bucket);

    const resetSeconds = Math.ceil(bucket.resetAt / 1000);
    const retryAfterSeconds = Math.max(1, Math.ceil((bucket.resetAt - now) / 1000));
    const remaining = Math.max(0, maxRequests - bucket.count);
    reply.header("X-RateLimit-Limit", String(maxRequests));
    reply.header("X-RateLimit-Remaining", String(remaining));
    reply.header("X-RateLimit-Reset", String(resetSeconds));

    if (bucket.count <= maxRequests) return;
    reply.header("Retry-After", String(retryAfterSeconds));
    return reply.code(429).send({
      error: "rate_limited",
      message: `Rate limit exceeded. Retry after ${retryAfterSeconds} seconds.`,
      details: {
        limit: maxRequests,
        windowSeconds: Math.ceil(windowMs / 1000),
        resetAt: new Date(bucket.resetAt).toISOString()
      }
    });
  });

  app.addHook("onClose", async () => {
    buckets.clear();
  });
}

function rateLimitConfigFromEnv(): RateLimitConfig {
  const windowSeconds = envNumber("OTTE_RATE_LIMIT_WINDOW_SECONDS") ?? DEFAULT_RATE_LIMIT_WINDOW_MS / 1000;
  const maxRequests = envNumber("OTTE_RATE_LIMIT_MAX_REQUESTS") ?? DEFAULT_RATE_LIMIT_MAX_REQUESTS;
  return {
    enabled: envBoolean("OTTE_RATE_LIMIT_ENABLED", process.env.NODE_ENV === "production"),
    windowMs: windowSeconds * 1000,
    maxRequests
  };
}

function pruneExpiredRateLimitBuckets(buckets: Map<string, RateLimitBucket>, now: number): void {
  for (const [key, bucket] of buckets) {
    if (bucket.resetAt <= now) buckets.delete(key);
  }
}

function rateLimitKey(store: StateStore, request: FastifyRequest): string {
  const session = sessionFromRequest(store, undefined, request.headers);
  const identity = session && isActiveUserId(store, session.userId) ? `user:${session.userId}` : `ip:${rateLimitIp(request)}`;
  const routePattern = request.routeOptions.url ?? request.url.split("?")[0] ?? request.url;
  return `${request.method.toUpperCase()}:${routePattern}:${identity}`;
}

function rateLimitIp(request: FastifyRequest): string {
  return request.ip || "unknown";
}

function registerIdempotencyReplay(app: FastifyInstance, store: StateStore): void {
  const saveScopes = new AsyncLocalStorage<IdempotencySaveScope>();
  const inFlight = new Map<string, IdempotencyFlight>();
  const persistState = store.save.bind(store);
  const persistFlush = store.flush?.bind(store);
  const persistReplace = store.replace.bind(store);
  const retainedRecords = store.state.idempotencyRecords.filter((record) => idempotencyRecordIsSafe(record));
  if (retainedRecords.length !== store.state.idempotencyRecords.length) {
    store.state.idempotencyRecords = retainedRecords;
    persistState();
  }
  store.save = () => {
    const saveScope = saveScopes.getStore();
    if (!saveScope?.deferSaves) {
      persistState();
      return;
    }
    saveScope.saveRequested = true;
  };
  store.replace = (state) => {
    const saveScope = saveScopes.getStore();
    if (!saveScope?.deferSaves) {
      persistReplace(state);
      return;
    }
    persistReplace(state, { flush: false });
    saveScope.saveRequested = true;
  };

  const flushSaveScope = (request: FastifyRequest, forceSave: boolean): void => {
    const saveScope = Reflect.get(request, idempotencySaveScopeSymbol) as IdempotencySaveScope | undefined;
    if (!saveScope) {
      if (forceSave) persistState();
      return;
    }
    const shouldSave = forceSave || saveScope.saveRequested;
    saveScope.deferSaves = false;
    saveScope.saveRequested = false;
    if (shouldSave) {
      persistState();
      persistFlush?.();
    }
  };

  const flightKey = (context: IdempotencyContext): string => stableJson([context.method, context.userId, context.authorizationHash, context.key]);
  const releaseFlight = (request: FastifyRequest, record?: IdempotencyRecord): void => {
    const flight = Reflect.get(request, idempotencyFlightSymbol) as IdempotencyFlight | undefined;
    if (!flight || flight.settled) return;
    flight.settled = true;
    const key = flightKey(flight.context);
    if (inFlight.get(key) === flight) inFlight.delete(key);
    flight.resolve(record);
  };
  const replayRecord = (request: FastifyRequest, reply: FastifyReply, record: IdempotencyRecord): boolean => {
    const authorizationHash = idempotencyAuthorizationHash(store, request.headers, record.userId);
    if (!authorizationHash || authorizationHash !== record.authorizationHash) return false;
    Reflect.set(request, idempotencyReplaySymbol, true);
    reply
      .code(record.statusCode)
      .header("Idempotency-Replayed", "true")
      .type(record.contentType ?? "application/json")
      .send(record.responseBody);
    return true;
  };

  app.addHook("preHandler", async (request, reply) => {
    if (!isIdempotentReplayCandidate(request.method)) return;
    const routePath = request.url.split("?")[0] ?? request.url;
    if (!idempotencyPathIsEligible(routePath)) return;
    const key = opaqueHeaderText(request.headers["idempotency-key"]);
    if (!key) return;
    if (key.length > IDEMPOTENCY_MAX_KEY_LENGTH) {
      return badRequest(reply, `Idempotency-Key must be ${IDEMPOTENCY_MAX_KEY_LENGTH} characters or fewer`);
    }
    const identity = idempotencyIdentityFromHeaders(store, request.headers);
    // Anonymous mutation responses include bootstrap, login, registration, invite,
    // password-reset, and OIDC credentials. They are deliberately never replayed.
    if (!identity) return;
    const context: IdempotencyContext = {
      key,
      method: request.method.toUpperCase(),
      path: request.url,
      userId: identity.userId,
      requestHash: hashStableJson(request.body ?? null),
      authorizationHash: identity.authorizationHash
    };
    const reservationKey = flightKey(context);
    while (true) {
      const existing = store.state.idempotencyRecords.find((record) => record.key === context.key && record.method === context.method && record.userId === context.userId);
      if (existing) {
        if (existing.path !== context.path || existing.requestHash !== context.requestHash) return conflict(reply, "Idempotency-Key was already used for a different request");
        if (replayRecord(request, reply, existing)) return;
      }
      const activeFlight = inFlight.get(reservationKey);
      if (activeFlight) {
        if (activeFlight.context.path !== context.path || activeFlight.context.requestHash !== context.requestHash) {
          return conflict(reply, "Idempotency-Key is already in use for a different request");
        }
        const completed = await activeFlight.completion;
        if (completed && replayRecord(request, reply, completed)) return;
        continue;
      }
      let resolveFlight!: (record: IdempotencyRecord | undefined) => void;
      const flight: IdempotencyFlight = {
        context,
        completion: new Promise((resolve) => {
          resolveFlight = resolve;
        }),
        resolve: (record) => resolveFlight(record),
        settled: false,
      };
      inFlight.set(reservationKey, flight);
      Reflect.set(request, idempotencyFlightSymbol, flight);
      break;
    }
    const saveScope: IdempotencySaveScope = { deferSaves: true, saveRequested: false };
    Reflect.set(request, idempotencySaveScopeSymbol, saveScope);
    saveScopes.enterWith(saveScope);
    Reflect.set(request, idempotencyContextSymbol, context);
  });

  app.addHook("onSend", async (request, reply, payload) => {
    if (Reflect.get(request, idempotencyReplaySymbol)) return payload;
    const context = Reflect.get(request, idempotencyContextSymbol) as IdempotencyContext | undefined;
    if (!context) return payload;
    if (reply.statusCode < 200 || reply.statusCode >= 300) {
      try {
        flushSaveScope(request, false);
      } finally {
        releaseFlight(request);
      }
      return payload;
    }
    const responseBody = typeof payload === "string" ? payload : Buffer.isBuffer(payload) ? payload.toString("utf8") : JSON.stringify(payload ?? null);
    if (Buffer.byteLength(responseBody, "utf8") > IDEMPOTENCY_MAX_RESPONSE_BYTES) {
      try {
        flushSaveScope(request, false);
      } finally {
        releaseFlight(request);
      }
      return payload;
    }
    if (idempotencyResponseContainsSecret(responseBody)) {
      try {
        flushSaveScope(request, false);
      } finally {
        releaseFlight(request);
      }
      return payload;
    }
    const authorizationHash = idempotencyAuthorizationHash(store, request.headers, context.userId);
    if (!authorizationHash) {
      try {
        flushSaveScope(request, false);
      } finally {
        releaseFlight(request);
      }
      return payload;
    }
    const now = nowIso();
    const record: IdempotencyRecord = {
      ...context,
      authorizationHash,
      statusCode: reply.statusCode,
      contentType: reply.getHeader("content-type")?.toString(),
      responseBody,
      createdAt: now,
      updatedAt: now
    };
    store.state.idempotencyRecords = [
      ...store.state.idempotencyRecords.filter((record) => !(record.key === context.key && record.method === context.method && record.userId === context.userId)),
      record
    ]
      .sort(sortTimestampsDesc)
      .slice(0, IDEMPOTENCY_MAX_RECORDS);
    try {
      flushSaveScope(request, true);
      releaseFlight(request, record);
    } catch (error) {
      store.state.idempotencyRecords = store.state.idempotencyRecords.filter((candidate) => candidate !== record);
      releaseFlight(request);
      throw error;
    }
    return payload;
  });

  app.addHook("onError", async (request) => {
    try {
      flushSaveScope(request, false);
    } finally {
      releaseFlight(request);
    }
  });

  app.addHook("onClose", async () => {
    for (const flight of inFlight.values()) {
      if (flight.settled) continue;
      flight.settled = true;
      flight.resolve(undefined);
    }
    inFlight.clear();
  });
}

function idempotencyRecordIsSafe(record: EngineState["idempotencyRecords"][number]): boolean {
  return Boolean(record.userId && record.authorizationHash) && idempotencyPathIsEligible(record.path) && !idempotencyResponseContainsSecret(record.responseBody);
}

function idempotencyPathIsEligible(path: string): boolean {
  const pathname = path.split("?")[0] ?? path;
  if (pathname === "/api/v1/auth" || pathname.startsWith("/api/v1/auth/")) return false;
  if (pathname === "/api/v1/invites/accept") return false;
  if (pathname === "/api/v1/organization/invites") return false;
  if (/^\/api\/v1\/campaigns\/[^/]+\/invites$/.test(pathname)) return false;
  if (/^\/api\/v1\/assets\/[^/]+\/delivery-url$/.test(pathname)) return false;
  if (/^\/api\/v1\/admin\/users\/[^/]+\/password-reset$/.test(pathname)) return false;
  if (pathname === "/api/v1/admin/email-outbox/retry-all" || /^\/api\/v1\/admin\/email-outbox\/[^/]+\/retry$/.test(pathname)) return false;
  return true;
}

const idempotencySecretResponseKeys = new Set([
  "accesstoken",
  "apikey",
  "accepturl",
  "authorizationcode",
  "authorizationurl",
  "bearertoken",
  "clientsecret",
  "credential",
  "credentials",
  "enrollmentsecret",
  "enrollmenturl",
  "mfasecret",
  "otpauthurl",
  "password",
  "passwordresettoken",
  "passwordreseturl",
  "privatekey",
  "recoverycode",
  "recoverycodes",
  "recoveryurl",
  "refreshtoken",
  "resettoken",
  "reseturl",
  "secret",
  "sessiontoken",
  "signature",
  "signedurl",
  "token",
  "totpsecret"
]);

function idempotencyResponseContainsSecret(responseBody: string): boolean {
  let value: unknown;
  try {
    value = JSON.parse(responseBody) as unknown;
  } catch {
    return false;
  }
  return idempotencyValueContainsSecret(value);
}

function idempotencyValueContainsSecret(value: unknown): boolean {
  if (typeof value === "string") {
    return /(?:^|[^A-Za-z0-9])(?:ots|oti|opr|oss)_[A-Za-z0-9_-]+|otr-[a-f0-9]{8}-[a-f0-9]{8}|otpauth:\/\/|[?&](?:access_?token|refresh_?token|session_?token|token|signature|invite|code)=/i.test(value);
  }
  if (Array.isArray(value)) return value.some(idempotencyValueContainsSecret);
  if (!isRecord(value)) return false;
  return Object.entries(value).some(([key, nested]) => idempotencySecretResponseKeys.has(key.replace(/[^a-z0-9]/gi, "").toLowerCase()) || idempotencyValueContainsSecret(nested));
}

function isIdempotentReplayCandidate(method: string): boolean {
  return method === "POST" || method === "PUT" || method === "PATCH" || method === "DELETE";
}

function idempotencyIdentityFromHeaders(store: StateStore, headers: Record<string, string | string[] | undefined>): IdempotencyIdentity | undefined {
  const session = sessionFromRequest(store, undefined, headers);
  if (session && isActiveUserId(store, session.userId)) {
    return {
      userId: session.userId,
      authorizationHash: idempotencyAuthorizationHashForUser(store, session.userId, session.id, session.activeOrganizationId)
    };
  }
  if (!legacyUserHeaderEnabled()) return undefined;
  const header = headers["x-user-id"];
  const userId = Array.isArray(header) ? header[0] : header;
  if (!userId || !isActiveUserId(store, userId)) return undefined;
  return {
    userId,
    authorizationHash: idempotencyAuthorizationHashForUser(store, userId, "legacy-user-header")
  };
}

function idempotencyAuthorizationHash(store: StateStore, headers: Record<string, string | string[] | undefined>, expectedUserId?: string): string | undefined {
  const identity = idempotencyIdentityFromHeaders(store, headers);
  if (!identity || (expectedUserId && identity.userId !== expectedUserId)) return undefined;
  return identity.authorizationHash;
}

function idempotencyAuthorizationHashForUser(store: StateStore, userId: string, sessionId: string, requestedOrganizationId?: string): string {
  const user = store.state.users.find((candidate) => candidate.id === userId);
  const organizationMemberships = store.state.organizationMembers
    .filter((member) => member.userId === userId)
    .map((member) => ({ organizationId: member.organizationId, role: member.role }))
    .sort((left, right) => left.organizationId.localeCompare(right.organizationId) || left.role.localeCompare(right.role));
  const campaignMemberships = store.state.members
    .filter((member) => member.userId === userId)
    .map((member) => ({ campaignId: member.campaignId, role: member.role }))
    .sort((left, right) => left.campaignId.localeCompare(right.campaignId) || left.role.localeCompare(right.role));
  const rolesByCampaign = new Map(campaignMemberships.map((member) => [member.campaignId, member.role]));
  const effectiveGrants = store.state.permissionGrants
    .filter((grant) => {
      if (grant.expiresAt && Date.parse(grant.expiresAt) <= Date.now()) return false;
      if (grant.subjectType === "user") return grant.subjectId === userId;
      return grant.subjectType === "role" && rolesByCampaign.get(grant.campaignId) === grant.subjectId;
    })
    .map((grant) => ({
      campaignId: grant.campaignId,
      subjectType: grant.subjectType,
      subjectId: grant.subjectId,
      permissions: [...grant.permissions].sort(),
      expiresAt: grant.expiresAt
    }))
    .sort((left, right) => stableJson(left).localeCompare(stableJson(right)));
  const accessibleOrganizationIds = new Set([
    ...store.state.organizations.filter((organization) => organization.ownerUserId === userId).map((organization) => organization.id),
    ...organizationMemberships.map((membership) => membership.organizationId)
  ]);
  const accessibleOrganizations = store.state.organizations
    .filter((organization) => accessibleOrganizationIds.has(organization.id))
    .map((organization) => ({ id: organization.id, ownerUserId: organization.ownerUserId }))
    .sort((left, right) => left.id.localeCompare(right.id));
  const campaigns = campaignMemberships
    .map((membership) => store.state.campaigns.find((campaign) => campaign.id === membership.campaignId))
    .filter((campaign): campaign is Campaign => Boolean(campaign))
    .map((campaign) => ({ id: campaign.id, organizationId: campaign.organizationId }))
    .sort((left, right) => left.id.localeCompare(right.id));
  return hashStableJson({
    sessionId,
    requestedOrganizationId,
    activeOrganizationId: activeOrganizationIdForUser(store, userId, requestedOrganizationId),
    user: user
      ? {
          id: user.id,
          disabledAt: user.disabledAt,
          passwordResetRequired: user.passwordResetRequired,
          serverAdmin: isServerAdminUser(store, userId)
        }
      : undefined,
    accessibleOrganizations,
    organizationMemberships,
    campaigns,
    campaignMemberships,
    effectiveGrants
  });
}

function activeOrganizationIdForUser(store: StateStore, userId: string, requestedOrganizationId?: string): string | undefined {
  if (requestedOrganizationId && canAccessOrganization(store, requestedOrganizationId, userId)) return requestedOrganizationId;
  const owned = store.state.organizations.find((organization) => organization.ownerUserId === userId);
  if (owned) return owned.id;
  const membership = store.state.organizationMembers.find((member) => member.userId === userId);
  const memberOrganization = membership ? store.state.organizations.find((organization) => organization.id === membership.organizationId) : undefined;
  if (memberOrganization) return memberOrganization.id;
  return store.state.members
    .filter((member) => member.userId === userId)
    .map((member) => store.state.campaigns.find((campaign) => campaign.id === member.campaignId)?.organizationId)
    .find((organizationId): organizationId is string => Boolean(organizationId));
}

function hashStableJson(value: unknown): string {
  return createHash("sha256").update(stableJson(value)).digest("hex");
}

function stableJson(value: unknown): string {
  if (Array.isArray(value)) return `[${value.map(stableJson).join(",")}]`;
  if (isRecord(value)) {
    return `{${Object.keys(value)
      .sort()
      .map((key) => `${JSON.stringify(key)}:${stableJson(value[key])}`)
      .join(",")}}`;
  }
  return JSON.stringify(value);
}

function permissionsForUser(store: StateStore, userId: string, campaignId: string): PermissionName[] {
  return ALL_PERMISSIONS.filter((permission) => canCampaign(store, userId, campaignId, permission));
}

interface TokenVisibilityCache {
  scenes: Map<string, CachedSceneVisibility>;
}

interface CachedSceneVisibility {
  key: string;
  activeFog: FogRegion[];
  fogPolygons: VisionPolygon[];
  hidePolygons: VisionPolygon[];
  revealPolygons: VisionPolygon[];
  ownedVisionByStoreTokens: Map<string, VisionPolygon[]>;
  ownedVisionByProvidedTokens: WeakMap<Token[], Map<string, VisionPolygon[]>>;
}

function createTokenVisibilityCache(): TokenVisibilityCache {
  return { scenes: new Map() };
}

function visibleTokensForUser(store: StateStore, userId: string, campaignId: string, tokens: Token[], cache?: TokenVisibilityCache): Token[] {
  if (canReadHiddenTokens(store, userId, campaignId)) return tokens;
  const visibilityCache = cache ?? createTokenVisibilityCache();
  return tokens.filter((token) => isTokenVisibleToUser(store, userId, campaignId, token, tokens, visibilityCache));
}

function canReadHiddenTokens(store: StateStore, userId: string, campaignId: string): boolean {
  return canCampaign(store, userId, campaignId, "token.update") || canCampaign(store, userId, campaignId, "scene.update");
}

function canMoveToken(store: StateStore, userId: string, campaignId: string, token: Token): boolean {
  if (canReadHiddenTokens(store, userId, campaignId)) return true;
  if (tokenLayer(token) !== "player") return false;
  return canCampaign(store, userId, campaignId, "token.move") && isTokenOwnedByUser(store, userId, token);
}

function isTokenVisibleToUser(store: StateStore, userId: string, campaignId: string, token: Token, sceneTokens?: Token[], cache?: TokenVisibilityCache): boolean {
  if (canReadHiddenTokens(store, userId, campaignId)) return true;
  if (tokenLayer(token) === "gm") return false;
  if (token.hidden) return false;
  if (isTokenOwnedByUser(store, userId, token)) return true;
  const scene = store.state.scenes.find((item) => item.id === token.sceneId);
  if (!scene) return false;
  const visibility = sceneVisibilityForCache(scene, cache);
  if (visibility.activeFog.length === 0) return true;
  const center = centerOfToken(token);
  if (isPointInsideVisionPolygons(center, visibility.hidePolygons)) return false;
  if (isPointInsideVisionPolygons(center, visibility.revealPolygons)) return true;
  return isPointInsideVisionPolygons(center, ownedVisionPolygonsForUser(store, userId, scene, sceneTokens, cache));
}

function isTokenOwnedByUser(store: StateStore, userId: string, token: Token): boolean {
  return Boolean(token.ownerUserIds?.includes(userId) || (token.actorId && store.state.actors.some((actor) => actor.id === token.actorId && actor.ownerUserId === userId)));
}

function campaignMemberUserIds(store: StateStore, campaignId: string): Set<string> {
  return new Set(store.state.members.filter((member) => member.campaignId === campaignId).map((member) => member.userId));
}

function visionSnapshotForUser(store: StateStore, userId: string, campaignId: string, scene: Scene, cache?: TokenVisibilityCache): VisionSnapshot {
  const activeFog = scene.fog.filter((region) => !region.hidden);
  const lightPolygons = scene.lights.flatMap((light) => computeLightVisionPolygons(scene, light));
  if (canReadHiddenTokens(store, userId, campaignId) || activeFog.length === 0) {
    return {
      sceneId: scene.id,
      userId,
      fogActive: false,
      polygons: lightPolygons
    };
  }
  const visibility = sceneVisibilityForCache(scene, cache);
  return {
    sceneId: scene.id,
    userId,
    fogActive: true,
    polygons: [...visibility.fogPolygons, ...ownedVisionPolygonsForUser(store, userId, scene, undefined, cache), ...lightPolygons]
  };
}

function ownedVisionPolygonsForUser(store: StateStore, userId: string, scene: Scene, sceneTokens?: Token[], cache?: TokenVisibilityCache): VisionPolygon[] {
  if (cache) {
    const visibility = sceneVisibilityForCache(scene, cache);
    const userCache = sceneTokens ? providedTokenVisionCache(visibility, sceneTokens) : visibility.ownedVisionByStoreTokens;
    const cached = userCache.get(userId);
    if (cached) return cached;
    const polygons = computeOwnedVisionPolygonsForUser(store, userId, scene, sceneTokens);
    userCache.set(userId, polygons);
    return polygons;
  }
  return computeOwnedVisionPolygonsForUser(store, userId, scene, sceneTokens);
}

function computeOwnedVisionPolygonsForUser(store: StateStore, userId: string, scene: Scene, sceneTokens?: Token[]): VisionPolygon[] {
  const tokens = sceneTokens ?? store.state.tokens.filter((item) => item.sceneId === scene.id);
  return tokens
    .filter((item) => tokenLayer(item) === "player" && item.visionEnabled && tokenVisionOuterRadius(item) > 0 && isTokenOwnedByUser(store, userId, item))
    .flatMap((token) => computeTokenVisionPolygons(scene, token));
}

function providedTokenVisionCache(visibility: CachedSceneVisibility, sceneTokens: Token[]): Map<string, VisionPolygon[]> {
  const cached = visibility.ownedVisionByProvidedTokens.get(sceneTokens);
  if (cached) return cached;
  const userCache = new Map<string, VisionPolygon[]>();
  visibility.ownedVisionByProvidedTokens.set(sceneTokens, userCache);
  return userCache;
}

function sceneVisibilityForCache(scene: Scene, cache?: TokenVisibilityCache): CachedSceneVisibility {
  const key = `${scene.id}:${scene.updatedAt}`;
  if (cache) {
    const cached = cache.scenes.get(scene.id);
    if (cached?.key === key) return cached;
    const visibility = computeSceneVisibility(scene, key);
    cache.scenes.set(scene.id, visibility);
    return visibility;
  }
  return computeSceneVisibility(scene, key);
}

function computeSceneVisibility(scene: Scene, key: string): CachedSceneVisibility {
  const activeFog = scene.fog.filter((region) => !region.hidden);
  const fogPolygons = activeFog.map((region) => computeFogRevealPolygon(scene, region)).filter((polygon): polygon is VisionPolygon => Boolean(polygon));
  return {
    key,
    activeFog,
    fogPolygons,
    hidePolygons: fogPolygons.filter((polygon) => polygon.mode === "hide"),
    revealPolygons: fogPolygons.filter((polygon) => polygon.mode !== "hide"),
    ownedVisionByStoreTokens: new Map(),
    ownedVisionByProvidedTokens: new WeakMap()
  };
}

function normalizeVisionSamplePoint(scene: Scene, x: string | undefined, y: string | undefined): VisionPoint | undefined {
  const point = { x: Number(x), y: Number(y) };
  if (!Number.isFinite(point.x) || !Number.isFinite(point.y)) return undefined;
  if (point.x < 0 || point.y < 0 || point.x > scene.width || point.y > scene.height) return undefined;
  return point;
}

function visionPointSampleForUser(store: StateStore, userId: string, campaignId: string, scene: Scene, point: VisionPoint, cache?: TokenVisibilityCache): VisionPointSample {
  const snapshot = visionSnapshotForUser(store, userId, campaignId, scene, cache);
  const containingPolygons = snapshot.polygons.filter((polygon) => isPointInsideVisionPolygon(point, polygon)).map(visionPointSamplePolygon);
  const hiddenBy = containingPolygons.filter((polygon) => polygon.mode === "hide");
  const illuminatedBy = containingPolygons.filter((polygon) => polygon.source === "light");
  const revealedBy = containingPolygons.filter((polygon) => polygon.source !== "light" && polygon.mode !== "hide");
  const visible = !snapshot.fogActive || (revealedBy.length > 0 && hiddenBy.length === 0);
  return {
    sceneId: scene.id,
    userId,
    point,
    fogActive: snapshot.fogActive,
    visible,
    revealedBy,
    hiddenBy,
    illuminatedBy,
    blockedBy: visible ? [] : visionBlockersForPoint(store, userId, scene, point)
  };
}

function visionPointSamplePolygon(polygon: VisionPolygon): VisionPointSamplePolygon {
  return {
    polygonId: polygon.id,
    source: polygon.source,
    sourceId: polygon.sourceId,
    mode: polygon.mode,
    radius: polygon.radius,
    lightLevel: polygon.lightLevel,
    color: polygon.color,
    opacity: polygon.opacity
  };
}

function visionBlockersForPoint(store: StateStore, userId: string, scene: Scene, point: VisionPoint): VisionPointSample["blockedBy"] {
  const origins = [
    ...store.state.tokens
      .filter((token) => token.sceneId === scene.id && token.visionEnabled && tokenVisionOuterRadius(token) > 0 && isTokenOwnedByUser(store, userId, token))
      .map((token) => ({ source: "token" as const, sourceId: token.id, origin: centerOfToken(token), radius: tokenVisionOuterRadius(token) })),
    ...scene.lights.map((light) => ({ source: "light" as const, sourceId: light.id, origin: { x: light.x, y: light.y }, radius: light.dimRadius ?? light.radius }))
  ];
  const blockers = new Map<string, VisionPointSample["blockedBy"][number]>();
  for (const source of origins) {
    if (Math.hypot(point.x - source.origin.x, point.y - source.origin.y) > source.radius) continue;
    for (const wall of scene.walls) {
      if (!wall.blocksVision) continue;
      const intersection = lineSegmentIntersection(source.origin, point, { x: wall.x1, y: wall.y1 }, { x: wall.x2, y: wall.y2 });
      if (intersection) {
        blockers.set(`${source.source}:${source.sourceId}:${wall.id}`, {
          wallId: wall.id,
          kind: wall.kind,
          blocksMovement: wall.blocksMovement,
          source: source.source,
          sourceId: source.sourceId,
          intersection: roundVisionPoint(intersection),
          distanceFromSource: roundDistance(Math.hypot(intersection.x - source.origin.x, intersection.y - source.origin.y)),
          distanceToPoint: roundDistance(Math.hypot(point.x - intersection.x, point.y - intersection.y))
        });
      }
    }
  }
  return [...blockers.values()];
}

function sceneRenderingDiagnostics(store: StateStore, scene: Scene) {
  const fogPolygons = scene.fog.map((region) => computeFogRevealPolygon(scene, region)).filter((polygon): polygon is VisionPolygon => Boolean(polygon));
  const lightPolygons = scene.lights.flatMap((light) => computeLightVisionPolygons(scene, light)).filter((polygon): polygon is VisionPolygon => Boolean(polygon));
  const sceneTokens = store.state.tokens.filter((token) => token.sceneId === scene.id);
  const tokenPolygons = sceneTokens
    .filter((token) => token.visionEnabled && tokenVisionOuterRadius(token) > 0)
    .flatMap((token) => computeTokenVisionPolygons(scene, token));
  const polygons = [...fogPolygons, ...lightPolygons, ...tokenPolygons];
  const complexity = sceneRenderingComplexity(polygons);
  const issues = [...sceneRenderingDiagnosticIssues(scene, sceneTokens), ...sceneRenderingComplexityIssues(complexity)];
  const issueSeverityCounts = countBy(issues, (issue) => String(issue.severity ?? "unknown"));
  const issueCodeCounts = countBy(issues, (issue) => String(issue.code ?? "unknown"));
  const actionReasons = sceneRenderingActionReasons(issueSeverityCounts, complexity);
  const budget = sceneRenderingBudget(complexity);
  return {
    sceneId: scene.id,
    generatedAt: nowIso(),
    dimensions: {
      width: scene.width,
      height: scene.height,
      gridSize: scene.gridSize
    },
    counts: {
      fogRegionCount: scene.fog.length,
      revealFogRegionCount: scene.fog.filter((region) => (region.mode ?? "reveal") === "reveal" && !region.hidden).length,
      hideFogRegionCount: scene.fog.filter((region) => region.mode === "hide" && !region.hidden).length,
      wallCount: scene.walls.length,
      visionBlockingWallCount: scene.walls.filter((wall) => wall.blocksVision).length,
      terrainWallCount: scene.walls.filter((wall) => wall.kind === "terrain").length,
      degenerateWallCount: scene.walls.filter((wall) => Math.hypot(wall.x2 - wall.x1, wall.y2 - wall.y1) < 0.001).length,
      lightCount: scene.lights.length,
      tokenVisionSourceCount: tokenPolygons.length,
      polygonCount: polygons.length,
      polygonVertexCount: complexity.polygonVertexCount,
      maxPolygonVertexCount: complexity.maxPolygonVertexCount,
      issueCount: issues.length
    },
    complexity,
    budget,
    issueSeverityCounts,
    issueCodeCounts,
    actionRequired: actionReasons.length > 0,
    actionReasons,
    issues
  };
}

function adminRenderingOperations(store: StateStore) {
  const diagnostics = store.state.scenes.map((scene) => {
    const campaign = store.state.campaigns.find((item) => item.id === scene.campaignId);
    const sceneDiagnostics = sceneRenderingDiagnostics(store, scene);
    return {
      sceneId: scene.id,
      sceneName: scene.name,
      campaignId: scene.campaignId,
      campaignName: campaign?.name ?? "Unknown campaign",
      counts: sceneDiagnostics.counts,
      complexity: sceneDiagnostics.complexity,
      budget: sceneDiagnostics.budget,
      issueSeverityCounts: sceneDiagnostics.issueSeverityCounts,
      issueCodes: sceneDiagnostics.issueCodeCounts,
      topIssueCodes: topCountEntries(sceneDiagnostics.issueCodeCounts, 5),
      topIssues: sceneDiagnostics.issues.slice(0, 5),
      issues: sceneDiagnostics.issues,
      featureCoverage: sceneRenderingFeatureCoverage(scene, store.state.tokens.filter((token) => token.sceneId === scene.id)),
      actionRequired: sceneDiagnostics.actionRequired,
      actionReasons: sceneDiagnostics.actionReasons
    };
  });
  const topIssues = diagnostics.flatMap((scene) =>
    scene.issues.map((issue) => ({
      sceneId: scene.sceneId,
      sceneName: scene.sceneName,
      campaignId: scene.campaignId,
      campaignName: scene.campaignName,
      ...issue
    }))
  ) as RenderingIssueSample[];
  const scenesRequiringAction = diagnostics.filter((scene) => scene.actionRequired);
  const issueCodeCounts = diagnostics.reduce<Record<string, number>>((totals, scene) => {
    for (const [code, count] of Object.entries(scene.issueCodes)) {
      totals[code] = (totals[code] ?? 0) + count;
    }
    return totals;
  }, {});
  const issueSeverityCounts = diagnostics.reduce<Record<string, number>>((totals, scene) => {
    for (const [severity, count] of Object.entries(scene.issueSeverityCounts)) {
      totals[severity] = (totals[severity] ?? 0) + count;
    }
    return totals;
  }, {});
  const actionReasons = [...new Set(scenesRequiringAction.flatMap((scene) => scene.actionReasons))];
  const authoringOperations = renderingAuthoringOperationsSummary(store);
  const failedAuthoringOperations = renderingFailedAuthoringOperationsSummary(store);
  const staleIssueOperations = renderingStaleIssueOperationsSummary(scenesRequiringAction, authoringOperations);
  const operationActionReasons = failedAuthoringOperations.actionRequired ? ["rendering_authoring_failures"] : [];
  const remediationQueue = renderingRemediationQueue(diagnostics, staleIssueOperations, failedAuthoringOperations);

  return {
    generatedAt: nowIso(),
    budget: aggregateRenderingBudget(diagnostics.map((scene) => scene.budget)),
    featureCoverage: renderingFeatureCoverageSummary(diagnostics),
    authoringOperations,
    failedAuthoringOperations,
    staleIssueOperations,
    totals: {
      sceneCount: store.state.scenes.length,
      campaignCount: new Set(store.state.scenes.map((scene) => scene.campaignId)).size,
      sceneActionRequiredCount: scenesRequiringAction.length,
      fogRegionCount: diagnostics.reduce((total, scene) => total + scene.counts.fogRegionCount, 0),
      wallCount: diagnostics.reduce((total, scene) => total + scene.counts.wallCount, 0),
      terrainWallCount: diagnostics.reduce((total, scene) => total + scene.counts.terrainWallCount, 0),
      degenerateWallCount: diagnostics.reduce((total, scene) => total + scene.counts.degenerateWallCount, 0),
      lightCount: diagnostics.reduce((total, scene) => total + scene.counts.lightCount, 0),
      tokenVisionSourceCount: diagnostics.reduce((total, scene) => total + scene.counts.tokenVisionSourceCount, 0),
      polygonVertexCount: diagnostics.reduce((total, scene) => total + scene.counts.polygonVertexCount, 0),
      maxPolygonVertexCount: diagnostics.reduce((max, scene) => Math.max(max, scene.counts.maxPolygonVertexCount), 0),
      issueCount: diagnostics.reduce((total, scene) => total + scene.counts.issueCount, 0)
    },
    issueSeverityCounts,
    issueCodeCounts,
    topIssues: topIssues
      .sort((left, right) => renderingIssueSeverityRank(right.severity) - renderingIssueSeverityRank(left.severity) || String(left.code).localeCompare(String(right.code)) || left.sceneName.localeCompare(right.sceneName))
      .slice(0, 20),
    actionRequired: actionReasons.length > 0 || operationActionReasons.length > 0,
    actionReasons: [...actionReasons, ...operationActionReasons],
    remediationQueue,
    scenesRequiringAction: scenesRequiringAction
      .slice()
      .sort((left, right) => right.counts.issueCount - left.counts.issueCount || right.counts.maxPolygonVertexCount - left.counts.maxPolygonVertexCount || left.sceneName.localeCompare(right.sceneName))
      .slice(0, 20),
    scenes: diagnostics
      .slice()
      .sort((left, right) => right.counts.issueCount - left.counts.issueCount || right.counts.polygonVertexCount - left.counts.polygonVertexCount || left.sceneName.localeCompare(right.sceneName))
      .slice(0, 50)
  };
}

function renderingAuthoringOperationsSummary(store: StateStore) {
  const authoringActions = new Set([
    "scene.fog.create",
    "scene.fog.update",
    "scene.fog.delete",
    "scene.fog.undo",
    "scene.fogPreset.apply",
    "scene.wall.create",
    "scene.wall.update",
    "scene.wall.delete",
    "scene.light.create",
    "scene.light.update",
    "scene.light.delete"
  ]);
  const logs = store.state.auditLogs.filter((log) => authoringActions.has(log.action)).sort(sortTimestampsDesc);
  const events = logs.map((log) => {
    const before = isRecord(log.before) ? log.before : {};
    const after = isRecord(log.after) ? log.after : {};
    const sceneId = stringFromRecord(after, "sceneId") ?? stringFromRecord(before, "sceneId");
    const scene = sceneId ? store.state.scenes.find((item) => item.id === sceneId) : undefined;
    const campaign = scene ? store.state.campaigns.find((item) => item.id === scene.campaignId) : undefined;
    return {
      id: log.id,
      action: log.action,
      targetType: log.targetType,
      targetId: log.targetId,
      sceneId,
      sceneName: scene?.name,
      campaignId: log.campaignId ?? scene?.campaignId,
      campaignName: campaign?.name,
      actorUserId: log.actorUserId,
      createdAt: log.createdAt
    };
  });
  const byScene = new Map<string, { sceneId: string; sceneName?: string; campaignId?: string; campaignName?: string; count: number; lastAuthoredAt?: string; actionCounts: Record<string, number> }>();
  for (const event of events) {
    const sceneId = event.sceneId ?? "unknown";
    const entry = byScene.get(sceneId) ?? {
      sceneId,
      sceneName: event.sceneName,
      campaignId: event.campaignId,
      campaignName: event.campaignName,
      count: 0,
      lastAuthoredAt: event.createdAt,
      actionCounts: {}
    };
    entry.count += 1;
    entry.lastAuthoredAt = entry.lastAuthoredAt && sortTimestampsDesc({ createdAt: entry.lastAuthoredAt }, { createdAt: event.createdAt }) <= 0 ? entry.lastAuthoredAt : event.createdAt;
    entry.actionCounts[event.action] = (entry.actionCounts[event.action] ?? 0) + 1;
    byScene.set(sceneId, entry);
  }
  return {
    totalCount: events.length,
    fogOperationCount: events.filter((event) => event.action.startsWith("scene.fog")).length,
    wallOperationCount: events.filter((event) => event.action.startsWith("scene.wall")).length,
    lightOperationCount: events.filter((event) => event.action.startsWith("scene.light")).length,
    sceneCount: byScene.size,
    actionCounts: countBy(events, (event) => event.action),
    targetTypeCounts: countBy(events, (event) => event.targetType ?? "unknown"),
    actorUserCounts: countBy(events.filter((event) => event.actorUserId), (event) => event.actorUserId ?? "unknown"),
    recent: events.slice(0, 10),
    scenes: [...byScene.values()]
      .sort((left, right) => right.count - left.count || String(right.lastAuthoredAt ?? "").localeCompare(String(left.lastAuthoredAt ?? "")) || String(left.sceneName ?? left.sceneId).localeCompare(String(right.sceneName ?? right.sceneId)))
      .slice(0, 10)
  };
}

function renderingFailedAuthoringOperationsSummary(store: StateStore) {
  const logs = store.state.auditLogs.filter((log) => log.action === "scene.renderingAuthoring.failed").sort(sortTimestampsDesc);
  const failures = logs.map((log) => {
    const after = isRecord(log.after) ? log.after : {};
    const sceneId = stringFromRecord(after, "sceneId");
    const scene = sceneId ? store.state.scenes.find((item) => item.id === sceneId) : undefined;
    const campaign = scene ? store.state.campaigns.find((item) => item.id === scene.campaignId) : undefined;
    return {
      id: log.id,
      attemptedAction: stringFromRecord(after, "attemptedAction") ?? "unknown",
      targetType: stringFromRecord(after, "targetType") ?? log.targetType,
      targetId: stringFromRecord(after, "targetId") ?? log.targetId,
      sceneId,
      sceneName: scene?.name,
      campaignId: log.campaignId ?? scene?.campaignId,
      campaignName: campaign?.name,
      actorUserId: log.actorUserId,
      reason: stringFromRecord(after, "reason") ?? "unknown",
      message: stringFromRecord(after, "message") ?? "Rendering authoring request failed validation",
      createdAt: log.createdAt
    };
  });
  return {
    actionRequired: failures.length > 0,
    failureCount: failures.length,
    byAction: countBy(failures, (failure) => failure.attemptedAction),
    byReason: countBy(failures, (failure) => failure.reason),
    byTargetType: countBy(failures, (failure) => failure.targetType ?? "unknown"),
    recentFailures: failures.slice(0, 10)
  };
}

function renderingStaleIssueOperationsSummary(
  scenesRequiringAction: Array<{
    sceneId: string;
    sceneName: string;
    campaignId: string;
    campaignName: string;
    counts: { issueCount: number };
    actionReasons: string[];
    topIssueCodes: Array<{ code: string; count: number }>;
    topIssues: Array<Record<string, unknown>>;
  }>,
  authoringOperations: ReturnType<typeof renderingAuthoringOperationsSummary>
) {
  const authorshipByScene = new Map(authoringOperations.scenes.map((scene) => [scene.sceneId, scene]));
  const staleScenes = scenesRequiringAction
    .map((scene) => {
      const authoring = authorshipByScene.get(scene.sceneId);
      return {
        sceneId: scene.sceneId,
        sceneName: scene.sceneName,
        campaignId: scene.campaignId,
        campaignName: scene.campaignName,
        issueCount: scene.counts.issueCount,
        actionReasons: scene.actionReasons,
        topIssueCodes: scene.topIssueCodes,
        topIssue: scene.topIssues[0],
        lastAuthoredAt: authoring?.lastAuthoredAt,
        authoringCount: authoring?.count ?? 0
      };
    })
    .filter((scene) => scene.authoringCount === 0)
    .sort((left, right) => right.issueCount - left.issueCount || left.sceneName.localeCompare(right.sceneName));
  return {
    sceneCount: staleScenes.length,
    issueCount: staleScenes.reduce((total, scene) => total + scene.issueCount, 0),
    actionRequired: staleScenes.length > 0,
    scenes: staleScenes.slice(0, 10)
  };
}

function sceneRenderingFeatureCoverage(scene: Scene, sceneTokens: Token[]) {
  const polygonFogCount = scene.fog.filter((region) => region.shape === "polygon" && (region.points?.length ?? 0) >= 3).length;
  const smoothFogCount = scene.fog.filter((region) => region.shape === "polygon" && (region.points?.length ?? 0) > 8).length;
  const terrainWallCount = scene.walls.filter((wall) => wall.kind === "terrain").length;
  const coloredLightCount = scene.lights.filter((light) => light.color.trim().toLowerCase() !== "#facc15").length;
  const dimmedLightCount = scene.lights.filter((light) => light.intensity !== undefined && light.intensity !== 0.28).length;
  const dualZoneLightCount = scene.lights.filter((light) => light.brightRadius !== undefined && (light.dimRadius ?? light.radius) > light.brightRadius).length;
  const dualZoneTokenVisionCount = sceneTokens.filter((token) => token.brightVisionRadius !== undefined && (token.dimVisionRadius ?? token.visionRadius) > token.brightVisionRadius).length;
  return {
    polygonFogCount,
    smoothFogCount,
    terrainWallCount,
    coloredLightCount,
    dimmedLightCount,
    dualZoneLightCount,
    dualZoneTokenVisionCount
  };
}

function renderingFeatureCoverageSummary(
  diagnostics: Array<{
    sceneId: string;
    sceneName: string;
    campaignId: string;
    campaignName: string;
    counts: { tokenVisionSourceCount: number };
    featureCoverage: ReturnType<typeof sceneRenderingFeatureCoverage>;
  }>
) {
  const sceneCount = diagnostics.length;
  const scenesWithPolygonFog = diagnostics.filter((scene) => scene.featureCoverage.polygonFogCount > 0);
  const scenesWithSmoothFog = diagnostics.filter((scene) => scene.featureCoverage.smoothFogCount > 0);
  const scenesWithTerrainWalls = diagnostics.filter((scene) => scene.featureCoverage.terrainWallCount > 0);
  const scenesWithColoredLights = diagnostics.filter((scene) => scene.featureCoverage.coloredLightCount > 0);
  const scenesWithDimmedLights = diagnostics.filter((scene) => scene.featureCoverage.dimmedLightCount > 0);
  const scenesWithDualZoneLights = diagnostics.filter((scene) => scene.featureCoverage.dualZoneLightCount > 0);
  const scenesWithTokenVision = diagnostics.filter((scene) => scene.counts.tokenVisionSourceCount > 0);
  const scenesWithDualZoneTokenVision = diagnostics.filter((scene) => scene.featureCoverage.dualZoneTokenVisionCount > 0);
  const samples = (scenes: typeof diagnostics) =>
    scenes
      .slice()
      .sort((left, right) => renderingFeatureCoverageWeight(right) - renderingFeatureCoverageWeight(left) || left.sceneName.localeCompare(right.sceneName))
      .slice(0, 5)
      .map((scene) => ({
        sceneId: scene.sceneId,
        sceneName: scene.sceneName,
        campaignId: scene.campaignId,
        campaignName: scene.campaignName,
        polygonFogCount: scene.featureCoverage.polygonFogCount,
        smoothFogCount: scene.featureCoverage.smoothFogCount,
        terrainWallCount: scene.featureCoverage.terrainWallCount,
        coloredLightCount: scene.featureCoverage.coloredLightCount,
        dimmedLightCount: scene.featureCoverage.dimmedLightCount,
        dualZoneLightCount: scene.featureCoverage.dualZoneLightCount,
        dualZoneTokenVisionCount: scene.featureCoverage.dualZoneTokenVisionCount,
        tokenVisionSourceCount: scene.counts.tokenVisionSourceCount
      }));
  const requiredFeatures = [
    {
      code: "polygon_fog",
      label: "Polygon fog",
      sceneCount: scenesWithPolygonFog.length,
      coverageRate: ratio(scenesWithPolygonFog.length, sceneCount),
      samples: samples(scenesWithPolygonFog)
    },
    {
      code: "smooth_fog",
      label: "Smoothed fog",
      sceneCount: scenesWithSmoothFog.length,
      coverageRate: ratio(scenesWithSmoothFog.length, sceneCount),
      samples: samples(scenesWithSmoothFog)
    },
    {
      code: "terrain_walls",
      label: "Terrain walls",
      sceneCount: scenesWithTerrainWalls.length,
      coverageRate: ratio(scenesWithTerrainWalls.length, sceneCount),
      samples: samples(scenesWithTerrainWalls)
    },
    {
      code: "colored_lights",
      label: "Colored lights",
      sceneCount: scenesWithColoredLights.length,
      coverageRate: ratio(scenesWithColoredLights.length, sceneCount),
      samples: samples(scenesWithColoredLights)
    },
    {
      code: "dimmed_lights",
      label: "Dimmed lights",
      sceneCount: scenesWithDimmedLights.length,
      coverageRate: ratio(scenesWithDimmedLights.length, sceneCount),
      samples: samples(scenesWithDimmedLights)
    },
    {
      code: "dual_zone_lights",
      label: "Bright/dim lights",
      sceneCount: scenesWithDualZoneLights.length,
      coverageRate: ratio(scenesWithDualZoneLights.length, sceneCount),
      samples: samples(scenesWithDualZoneLights)
    },
    {
      code: "token_vision",
      label: "Token vision",
      sceneCount: scenesWithTokenVision.length,
      coverageRate: ratio(scenesWithTokenVision.length, sceneCount),
      samples: samples(scenesWithTokenVision)
    },
    {
      code: "dual_zone_token_vision",
      label: "Bright/dim token vision",
      sceneCount: scenesWithDualZoneTokenVision.length,
      coverageRate: ratio(scenesWithDualZoneTokenVision.length, sceneCount),
      samples: samples(scenesWithDualZoneTokenVision)
    }
  ].map((feature) => ({
    ...feature,
    present: feature.sceneCount > 0
  }));
  return {
    sceneCount,
    scenesWithPolygonFogCount: scenesWithPolygonFog.length,
    scenesWithSmoothFogCount: scenesWithSmoothFog.length,
    scenesWithTerrainWallsCount: scenesWithTerrainWalls.length,
    scenesWithColoredLightsCount: scenesWithColoredLights.length,
    scenesWithDimmedLightsCount: scenesWithDimmedLights.length,
    scenesWithDualZoneLightsCount: scenesWithDualZoneLights.length,
    scenesWithTokenVisionCount: scenesWithTokenVision.length,
    scenesWithDualZoneTokenVisionCount: scenesWithDualZoneTokenVision.length,
    polygonFogCoverageRate: ratio(scenesWithPolygonFog.length, sceneCount),
    smoothFogCoverageRate: ratio(scenesWithSmoothFog.length, sceneCount),
    terrainWallCoverageRate: ratio(scenesWithTerrainWalls.length, sceneCount),
    coloredLightCoverageRate: ratio(scenesWithColoredLights.length, sceneCount),
    dimmedLightCoverageRate: ratio(scenesWithDimmedLights.length, sceneCount),
    dualZoneLightCoverageRate: ratio(scenesWithDualZoneLights.length, sceneCount),
    tokenVisionCoverageRate: ratio(scenesWithTokenVision.length, sceneCount),
    dualZoneTokenVisionCoverageRate: ratio(scenesWithDualZoneTokenVision.length, sceneCount),
    productionFeatureSceneCount: diagnostics.filter(
      (scene) =>
        scene.featureCoverage.polygonFogCount > 0 ||
        scene.featureCoverage.smoothFogCount > 0 ||
        scene.featureCoverage.terrainWallCount > 0 ||
        scene.featureCoverage.coloredLightCount > 0 ||
        scene.featureCoverage.dimmedLightCount > 0 ||
        scene.featureCoverage.dualZoneLightCount > 0 ||
        scene.featureCoverage.dualZoneTokenVisionCount > 0 ||
        scene.counts.tokenVisionSourceCount > 0
    ).length,
    requiredFeatures,
    missingRequiredFeatureCodes: requiredFeatures.filter((feature) => !feature.present).map((feature) => feature.code),
    complete: requiredFeatures.every((feature) => feature.present),
    samples: {
      polygonFog: samples(scenesWithPolygonFog),
      smoothFog: samples(scenesWithSmoothFog),
      terrainWalls: samples(scenesWithTerrainWalls),
      coloredLights: samples(scenesWithColoredLights),
      dimmedLights: samples(scenesWithDimmedLights),
      dualZoneLights: samples(scenesWithDualZoneLights),
      dualZoneTokenVision: samples(scenesWithDualZoneTokenVision),
      tokenVision: samples(scenesWithTokenVision)
    }
  };
}

function renderingFeatureCoverageWeight(scene: { counts: { tokenVisionSourceCount: number }; featureCoverage: ReturnType<typeof sceneRenderingFeatureCoverage> }) {
  return (
    scene.featureCoverage.polygonFogCount +
    scene.featureCoverage.smoothFogCount +
    scene.featureCoverage.terrainWallCount +
    scene.featureCoverage.coloredLightCount +
    scene.featureCoverage.dimmedLightCount +
    scene.featureCoverage.dualZoneLightCount +
    scene.featureCoverage.dualZoneTokenVisionCount +
    scene.counts.tokenVisionSourceCount
  );
}

interface RenderingOperationsSceneDiagnostics {
  sceneId: string;
  sceneName: string;
  campaignId: string;
  campaignName: string;
  counts: {
    issueCount: number;
    polygonVertexCount: number;
    maxPolygonVertexCount: number;
  };
  budget: ReturnType<typeof sceneRenderingBudget>;
  issues: Array<Record<string, unknown>>;
}

interface RenderingIssueSample {
  sceneId: string;
  sceneName: string;
  campaignId: string;
  campaignName: string;
  code: string;
  severity: "warning" | "error";
  targetType: string;
  targetId: string;
  message: string;
  details?: Record<string, unknown>;
}

function renderingRemediationQueue(
  diagnostics: RenderingOperationsSceneDiagnostics[],
  staleIssueOperations?: ReturnType<typeof renderingStaleIssueOperationsSummary>,
  failedAuthoringOperations?: ReturnType<typeof renderingFailedAuthoringOperationsSummary>
) {
  const remediations = new Map<string, {
    code: string;
    severity: "warning" | "error";
    action: string;
    affectedSceneCount: number;
    issueCount: number;
    sampleScenes: Array<{
      sceneId: string;
      sceneName: string;
      campaignId: string;
      campaignName: string;
      issueCount: number;
      topTarget?: { targetType: string; targetId: string };
      topIssue?: { code: string; severity: string; message: string; details?: Record<string, unknown> };
    }>;
  }>();

  for (const scene of diagnostics) {
    const sceneRemediations = new Set<string>();
    const sceneIssuesByCode = countBy(scene.issues, (issue) => String(issue.code ?? "unknown"));
    for (const [code, issueCount] of Object.entries(sceneIssuesByCode)) {
      const issueSample = scene.issues.find((issue) => issue.code === code);
      const remediation = renderingRemediationForCode(code, issueSample?.severity);
      const existing = remediations.get(remediation.code) ?? {
        code: remediation.code,
        severity: remediation.severity,
        action: remediation.action,
        affectedSceneCount: 0,
        issueCount: 0,
        sampleScenes: []
      };
      if (!sceneRemediations.has(remediation.code)) {
        existing.affectedSceneCount += 1;
        sceneRemediations.add(remediation.code);
      }
      existing.issueCount += issueCount;
      existing.severity = renderingIssueSeverityRank(remediation.severity) > renderingIssueSeverityRank(existing.severity) ? remediation.severity : existing.severity;
      if (existing.sampleScenes.length < 5) {
        existing.sampleScenes.push({
          sceneId: scene.sceneId,
          sceneName: scene.sceneName,
          campaignId: scene.campaignId,
          campaignName: scene.campaignName,
          issueCount,
          topTarget: issueSample ? { targetType: String(issueSample.targetType ?? "unknown"), targetId: String(issueSample.targetId ?? "unknown") } : undefined,
          topIssue: issueSample
            ? {
                code: String(issueSample.code ?? "unknown"),
                severity: String(issueSample.severity ?? "unknown"),
                message: String(issueSample.message ?? ""),
                details: renderingIssueDetails(issueSample)
              }
            : undefined
        });
      }
      remediations.set(remediation.code, existing);
    }

    if (scene.budget.maxPolygonExceeded || scene.budget.totalPolygonExceeded) {
      const key = "reduce_vision_geometry";
      const existing = remediations.get(key) ?? {
        code: key,
        severity: "warning" as const,
        action: "Reduce generated vision geometry by simplifying large fog polygons, lights, or token vision sources",
        affectedSceneCount: 0,
        issueCount: 0,
        sampleScenes: []
      };
      if (!sceneRemediations.has(key)) {
        existing.affectedSceneCount += 1;
        sceneRemediations.add(key);
      }
      existing.issueCount += Number(scene.budget.maxPolygonExceeded) + Number(scene.budget.totalPolygonExceeded);
      if (existing.sampleScenes.length < 5) {
        existing.sampleScenes.push({
          sceneId: scene.sceneId,
          sceneName: scene.sceneName,
          campaignId: scene.campaignId,
          campaignName: scene.campaignName,
          issueCount: scene.counts.issueCount,
          topTarget: { targetType: "scene", targetId: "rendering" },
          topIssue: scene.budget.maxPolygonExceeded
            ? {
                code: "large_vision_polygon",
                severity: "warning",
                message: "Scene generated vision geometry exceeds the per-polygon vertex budget.",
                details: {
                  maxPolygonVertexCount: scene.budget.maxPolygonVertexCount,
                  maxPolygonVertexBudget: scene.budget.maxPolygonVertexBudget
                }
              }
            : {
                code: "high_vision_vertex_count",
                severity: "warning",
                message: "Scene generated vision geometry exceeds the total vertex budget.",
                details: {
                  polygonVertexCount: scene.budget.polygonVertexCount,
                  totalPolygonVertexBudget: scene.budget.totalPolygonVertexBudget
                }
              }
        });
      }
      remediations.set(key, existing);
    }
  }

  if (staleIssueOperations && staleIssueOperations.sceneCount > 0) {
    remediations.set("triage_stale_rendering_issues", {
      code: "triage_stale_rendering_issues",
      severity: "error",
      action: "Triage rendering issue scenes that have no recent fog, wall, or light authoring activity.",
      affectedSceneCount: staleIssueOperations.sceneCount,
      issueCount: staleIssueOperations.issueCount,
      sampleScenes: staleIssueOperations.scenes.slice(0, 5).map((scene) => ({
        sceneId: scene.sceneId,
        sceneName: scene.sceneName,
        campaignId: scene.campaignId,
        campaignName: scene.campaignName,
        issueCount: scene.issueCount,
        topTarget: scene.topIssue ? { targetType: String(scene.topIssue.targetType ?? "unknown"), targetId: String(scene.topIssue.targetId ?? "unknown") } : undefined,
        topIssue: scene.topIssue
          ? {
              code: String(scene.topIssue.code ?? "unknown"),
              severity: String(scene.topIssue.severity ?? "unknown"),
              message: String(scene.topIssue.message ?? ""),
              details: renderingIssueDetails(scene.topIssue)
            }
          : undefined
      }))
    });
  }
  if (failedAuthoringOperations && failedAuthoringOperations.failureCount > 0) {
    remediations.set("review_rendering_authoring_failures", {
      code: "review_rendering_authoring_failures",
      severity: "warning",
      action: "Review failed fog, wall, and light authoring attempts so invalid rendering tools or workflows can be corrected.",
      affectedSceneCount: new Set(failedAuthoringOperations.recentFailures.map((failure) => failure.sceneId).filter(Boolean)).size,
      issueCount: failedAuthoringOperations.failureCount,
      sampleScenes: failedAuthoringOperations.recentFailures.slice(0, 5).map((failure) => ({
        sceneId: failure.sceneId ?? "unknown",
        sceneName: failure.sceneName ?? "Unknown scene",
        campaignId: failure.campaignId ?? "unknown",
        campaignName: failure.campaignName ?? "Unknown campaign",
        issueCount: 1,
        topTarget: { targetType: failure.targetType ?? "unknown", targetId: failure.targetId ?? failure.attemptedAction },
        topIssue: {
          code: failure.reason,
          severity: "warning",
          message: failure.message,
          details: {
            attemptedAction: failure.attemptedAction,
            createdAt: failure.createdAt
          }
        }
      }))
    });
  }

  return [...remediations.values()]
    .sort((left, right) => renderingIssueSeverityRank(right.severity) - renderingIssueSeverityRank(left.severity) || right.issueCount - left.issueCount || left.code.localeCompare(right.code))
    .slice(0, 8);
}

function renderingIssueDetails(issue: Record<string, unknown>): Record<string, unknown> | undefined {
  const omitted = new Set(["code", "severity", "targetType", "targetId", "message"]);
  const details = Object.fromEntries(Object.entries(issue).filter(([key]) => !omitted.has(key)));
  return Object.keys(details).length > 0 ? details : undefined;
}

function renderingRemediationForCode(code: string, severity: unknown): { code: string; severity: "warning" | "error"; action: string } {
  const normalizedSeverity = severity === "error" ? "error" : "warning";
  if (code.startsWith("invalid_fog") || code === "fog_polygon_too_small") {
    return { code: "repair_invalid_fog", severity: normalizedSeverity, action: "Repair invalid fog regions so reveal and hide masks generate stable polygons" };
  }
  if (code.startsWith("fog_")) {
    return { code: "review_fog_bounds", severity: normalizedSeverity, action: "Move fog origins and polygon points back inside scene bounds" };
  }
  if (code === "zero_length_wall" || code === "duplicate_wall_segment") {
    return { code: "dedupe_wall_geometry", severity: normalizedSeverity, action: "Remove duplicate or zero-length wall segments before they inflate vision work" };
  }
  if (code === "crossing_wall_segments") {
    return { code: "review_wall_intersections", severity: normalizedSeverity, action: "Review crossing vision-blocking wall segments so line-of-sight blockers are intentional and easy to debug" };
  }
  if (code.startsWith("wall_")) {
    return { code: "repair_wall_bounds", severity: normalizedSeverity, action: "Move wall endpoints inside scene bounds and keep blockers finite" };
  }
  if (code.startsWith("invalid_light") || code === "duplicate_light_source") {
    return { code: "repair_light_sources", severity: normalizedSeverity, action: "Fix light radius, color, intensity, and duplicate light sources" };
  }
  if (code.startsWith("light_")) {
    return { code: "review_light_bounds", severity: normalizedSeverity, action: "Move light origins inside scene bounds" };
  }
  if (code.startsWith("invalid_token") || code.startsWith("token_")) {
    return { code: "repair_token_vision", severity: normalizedSeverity, action: "Fix token vision radii and origins before players rely on line of sight" };
  }
  if (code === "large_vision_polygon" || code === "high_vision_vertex_count") {
    return { code: "reduce_vision_geometry", severity: normalizedSeverity, action: "Reduce generated vision geometry by simplifying large fog polygons, lights, or token vision sources" };
  }
  return { code: "review_rendering_issue", severity: normalizedSeverity, action: "Review rendering diagnostics for affected scenes" };
}

function renderingIssueSeverityRank(severity: unknown): number {
  if (severity === "error") return 2;
  if (severity === "warning") return 1;
  return 0;
}

function sceneRenderingComplexity(polygons: VisionPolygon[]) {
  return {
    polygonCount: polygons.length,
    polygonVertexCount: polygons.reduce((total, polygon) => total + polygon.points.length, 0),
    maxPolygonVertexCount: polygons.reduce((max, polygon) => Math.max(max, polygon.points.length), 0),
    sourceCounts: countBy(polygons, (polygon) => polygon.source)
  };
}

function sceneRenderingComplexityIssues(complexity: ReturnType<typeof sceneRenderingComplexity>): Array<Record<string, unknown>> {
  const issues: Array<Record<string, unknown>> = [];
  if (complexity.maxPolygonVertexCount > RENDERING_MAX_POLYGON_VERTEX_BUDGET) {
    issues.push(
      sceneRenderingIssue("large_vision_polygon", "warning", "scene", "rendering", "A generated vision polygon exceeds the recommended vertex budget", {
        maxPolygonVertexCount: complexity.maxPolygonVertexCount,
        maxPolygonVertexBudget: RENDERING_MAX_POLYGON_VERTEX_BUDGET
      })
    );
  }
  if (complexity.polygonVertexCount > RENDERING_TOTAL_POLYGON_VERTEX_BUDGET) {
    issues.push(
      sceneRenderingIssue("high_vision_vertex_count", "warning", "scene", "rendering", "Generated vision geometry exceeds the recommended total vertex budget", {
        polygonVertexCount: complexity.polygonVertexCount,
        totalPolygonVertexBudget: RENDERING_TOTAL_POLYGON_VERTEX_BUDGET
      })
    );
  }
  return issues;
}

function sceneRenderingActionReasons(issueSeverityCounts: Record<string, number>, complexity: ReturnType<typeof sceneRenderingComplexity>) {
  return [
    (issueSeverityCounts.error ?? 0) > 0 ? "rendering_errors" : undefined,
    complexity.maxPolygonVertexCount > RENDERING_MAX_POLYGON_VERTEX_BUDGET ? "large_vision_polygon" : undefined,
    complexity.polygonVertexCount > RENDERING_TOTAL_POLYGON_VERTEX_BUDGET ? "high_vision_vertex_count" : undefined
  ].filter((reason): reason is string => Boolean(reason));
}

function sceneRenderingBudget(complexity: ReturnType<typeof sceneRenderingComplexity>) {
  return {
    maxPolygonVertexBudget: RENDERING_MAX_POLYGON_VERTEX_BUDGET,
    totalPolygonVertexBudget: RENDERING_TOTAL_POLYGON_VERTEX_BUDGET,
    maxPolygonVertexCount: complexity.maxPolygonVertexCount,
    polygonVertexCount: complexity.polygonVertexCount,
    maxPolygonUsageRatio: ratio(complexity.maxPolygonVertexCount, RENDERING_MAX_POLYGON_VERTEX_BUDGET),
    totalPolygonUsageRatio: ratio(complexity.polygonVertexCount, RENDERING_TOTAL_POLYGON_VERTEX_BUDGET),
    maxPolygonExceeded: complexity.maxPolygonVertexCount > RENDERING_MAX_POLYGON_VERTEX_BUDGET,
    totalPolygonExceeded: complexity.polygonVertexCount > RENDERING_TOTAL_POLYGON_VERTEX_BUDGET
  };
}

function aggregateRenderingBudget(budgets: Array<ReturnType<typeof sceneRenderingBudget>>) {
  const maxPolygonVertexCount = budgets.reduce((max, budget) => Math.max(max, budget.maxPolygonVertexCount), 0);
  const polygonVertexCount = budgets.reduce((total, budget) => total + budget.polygonVertexCount, 0);
  const scenesExceedingMaxPolygonBudget = budgets.filter((budget) => budget.maxPolygonExceeded).length;
  const scenesExceedingTotalPolygonBudget = budgets.filter((budget) => budget.totalPolygonExceeded).length;
  return {
    maxPolygonVertexBudget: RENDERING_MAX_POLYGON_VERTEX_BUDGET,
    totalPolygonVertexBudget: RENDERING_TOTAL_POLYGON_VERTEX_BUDGET,
    maxPolygonVertexCount,
    polygonVertexCount,
    maxPolygonUsageRatio: ratio(maxPolygonVertexCount, RENDERING_MAX_POLYGON_VERTEX_BUDGET),
    totalPolygonUsageRatio: ratio(polygonVertexCount, RENDERING_TOTAL_POLYGON_VERTEX_BUDGET),
    maxPolygonExceeded: scenesExceedingMaxPolygonBudget > 0,
    totalPolygonExceeded: scenesExceedingTotalPolygonBudget > 0,
    scenesExceedingMaxPolygonBudget,
    scenesExceedingTotalPolygonBudget
  };
}

function sceneRenderingDiagnosticIssues(scene: Scene, sceneTokens: Token[]): Array<Record<string, unknown>> {
  const issues: Array<Record<string, unknown>> = [];
  for (const region of scene.fog) {
    if (region.radius <= 0) {
      issues.push(sceneRenderingIssue("invalid_fog_radius", "error", "fog", region.id, "Fog radius must be greater than zero"));
    }
    if (!pointWithinScene(scene, { x: region.x, y: region.y })) {
      issues.push(sceneRenderingIssue("fog_origin_out_of_bounds", "warning", "fog", region.id, "Fog origin is outside the scene bounds"));
    }
    if ((region.shape === "polygon" || region.points) && (region.points?.length ?? 0) < 3) {
      issues.push(sceneRenderingIssue("fog_polygon_too_small", "error", "fog", region.id, "Polygon fog regions need at least three points"));
    }
    for (const point of region.points ?? []) {
      if (!pointWithinScene(scene, point)) {
        issues.push(sceneRenderingIssue("fog_point_out_of_bounds", "warning", "fog", region.id, "Fog polygon point is outside the scene bounds", { point }));
      }
    }
  }
  for (const wall of scene.walls) {
    const start = { x: wall.x1, y: wall.y1 };
    const end = { x: wall.x2, y: wall.y2 };
    if (Math.hypot(wall.x2 - wall.x1, wall.y2 - wall.y1) < 0.001) {
      issues.push(sceneRenderingIssue("zero_length_wall", "error", "wall", wall.id, "Wall endpoints must not be identical"));
    }
    if (!pointWithinScene(scene, start) || !pointWithinScene(scene, end)) {
      issues.push(sceneRenderingIssue("wall_out_of_bounds", "warning", "wall", wall.id, "Wall endpoint is outside the scene bounds"));
    }
  }
  const seenWallSegments = new Map<string, Wall>();
  const finiteVisionWalls = scene.walls.filter((wall) => wall.blocksVision && Math.hypot(wall.x2 - wall.x1, wall.y2 - wall.y1) >= 0.001);
  for (let leftIndex = 0; leftIndex < finiteVisionWalls.length; leftIndex += 1) {
    const left = finiteVisionWalls[leftIndex]!;
    for (let rightIndex = leftIndex + 1; rightIndex < finiteVisionWalls.length; rightIndex += 1) {
      const right = finiteVisionWalls[rightIndex]!;
      if (wallsShareEndpoint(left, right)) continue;
      if (lineSegmentsIntersect({ x: left.x1, y: left.y1 }, { x: left.x2, y: left.y2 }, { x: right.x1, y: right.y1 }, { x: right.x2, y: right.y2 })) {
        issues.push(
          sceneRenderingIssue("crossing_wall_segments", "warning", "wall", right.id, "Vision-blocking wall crosses another wall segment away from endpoints", {
            intersectsWith: left.id
          })
        );
      }
    }
  }
  for (const wall of scene.walls) {
    const segmentKey = wallSegmentDiagnosticKey(wall);
    const duplicate = seenWallSegments.get(segmentKey);
    if (duplicate) {
      issues.push(
        sceneRenderingIssue("duplicate_wall_segment", "warning", "wall", wall.id, "Wall duplicates another wall segment and may create redundant vision blockers", {
          duplicateOf: duplicate.id
        })
      );
    } else {
      seenWallSegments.set(segmentKey, wall);
    }
  }
  for (const light of scene.lights) {
    if (light.radius <= 0) {
      issues.push(sceneRenderingIssue("invalid_light_radius", "error", "light", light.id, "Light radius must be greater than zero"));
    }
    if (!pointWithinScene(scene, light)) {
      issues.push(sceneRenderingIssue("light_origin_out_of_bounds", "warning", "light", light.id, "Light origin is outside the scene bounds"));
    }
    if (!/^#[0-9a-f]{6}$/i.test(light.color)) {
      issues.push(sceneRenderingIssue("invalid_light_color", "warning", "light", light.id, "Light color should be a six-digit hex color"));
    }
    if (light.intensity !== undefined && (!Number.isFinite(light.intensity) || light.intensity < 0 || light.intensity > 1)) {
      issues.push(
        sceneRenderingIssue("invalid_light_intensity", "warning", "light", light.id, "Light intensity should be a finite number between 0 and 1", {
          intensity: light.intensity
        })
      );
    }
    if (light.brightRadius !== undefined && (!Number.isFinite(light.brightRadius) || light.brightRadius <= 0)) {
      issues.push(sceneRenderingIssue("invalid_light_bright_radius", "warning", "light", light.id, "Light bright radius should be greater than zero"));
    }
    if (light.dimRadius !== undefined && (!Number.isFinite(light.dimRadius) || light.dimRadius <= 0)) {
      issues.push(sceneRenderingIssue("invalid_light_dim_radius", "warning", "light", light.id, "Light dim radius should be greater than zero"));
    }
    if (light.brightRadius !== undefined && (light.dimRadius ?? light.radius) <= light.brightRadius) {
      issues.push(sceneRenderingIssue("invalid_light_zone_radii", "warning", "light", light.id, "Light bright radius should be less than the dim or outer radius"));
    }
  }
  for (const token of sceneTokens) {
    if (token.visionEnabled && tokenVisionOuterRadius(token) <= 0) {
      issues.push(sceneRenderingIssue("invalid_token_vision_radius", "warning", "token", token.id, "Token vision is enabled but the radius does not generate visible geometry"));
    }
    if (token.brightVisionRadius !== undefined && (!Number.isFinite(token.brightVisionRadius) || token.brightVisionRadius <= 0)) {
      issues.push(sceneRenderingIssue("invalid_token_bright_vision_radius", "warning", "token", token.id, "Token bright vision radius should be greater than zero"));
    }
    if (token.dimVisionRadius !== undefined && (!Number.isFinite(token.dimVisionRadius) || token.dimVisionRadius <= 0)) {
      issues.push(sceneRenderingIssue("invalid_token_dim_vision_radius", "warning", "token", token.id, "Token dim vision radius should be greater than zero"));
    }
    if (token.brightVisionRadius !== undefined && (token.dimVisionRadius ?? token.visionRadius) <= token.brightVisionRadius) {
      issues.push(sceneRenderingIssue("invalid_token_vision_zone_radii", "warning", "token", token.id, "Token bright vision radius should be less than dim vision radius"));
    }
    if (token.visionEnabled && !pointWithinScene(scene, centerOfToken(token))) {
      issues.push(sceneRenderingIssue("token_vision_origin_out_of_bounds", "warning", "token", token.id, "Token vision origin is outside the scene bounds"));
    }
  }
  const seenLights = new Map<string, string>();
  for (const light of scene.lights) {
    const lightKey = lightDiagnosticKey(light);
    const duplicateOf = seenLights.get(lightKey);
    if (duplicateOf) {
      issues.push(
        sceneRenderingIssue("duplicate_light_source", "warning", "light", light.id, "Light duplicates another source and may create redundant colored-light geometry", {
          duplicateOf
        })
      );
    } else {
      seenLights.set(lightKey, light.id);
    }
  }
  return issues;
}

function sceneRenderingIssue(code: string, severity: "warning" | "error", targetType: string, targetId: string, message: string, extra?: Record<string, unknown>): Record<string, unknown> {
  return { code, severity, targetType, targetId, message, ...extra };
}

function wallSegmentDiagnosticKey(wall: Wall): string {
  const start = `${wall.x1},${wall.y1}`;
  const end = `${wall.x2},${wall.y2}`;
  return start < end ? `${start}|${end}` : `${end}|${start}`;
}

function lightDiagnosticKey(light: Scene["lights"][number]): string {
  return [light.x, light.y, light.radius, light.brightRadius ?? "default", light.dimRadius ?? "default", light.color.toLowerCase(), light.intensity ?? "default"].join("|");
}

function wallsShareEndpoint(left: Wall, right: Wall): boolean {
  const leftStart = { x: left.x1, y: left.y1 };
  const leftEnd = { x: left.x2, y: left.y2 };
  const rightStart = { x: right.x1, y: right.y1 };
  const rightEnd = { x: right.x2, y: right.y2 };
  return [rightStart, rightEnd].some((point) => Math.hypot(point.x - leftStart.x, point.y - leftStart.y) < 0.001 || Math.hypot(point.x - leftEnd.x, point.y - leftEnd.y) < 0.001);
}

function pointWithinScene(scene: Scene, point: VisionPoint): boolean {
  return Number.isFinite(point.x) && Number.isFinite(point.y) && point.x >= 0 && point.y >= 0 && point.x <= scene.width && point.y <= scene.height;
}

function lineSegmentsIntersect(a: VisionPoint, b: VisionPoint, c: VisionPoint, d: VisionPoint): boolean {
  return Boolean(lineSegmentIntersection(a, b, c, d));
}

function lineSegmentIntersection(a: VisionPoint, b: VisionPoint, c: VisionPoint, d: VisionPoint): VisionPoint | undefined {
  const ab = { x: b.x - a.x, y: b.y - a.y };
  const cd = { x: d.x - c.x, y: d.y - c.y };
  const denominator = ab.x * cd.y - ab.y * cd.x;
  if (Math.abs(denominator) < 0.000001) return undefined;
  const ac = { x: c.x - a.x, y: c.y - a.y };
  const t = (ac.x * cd.y - ac.y * cd.x) / denominator;
  const u = (ac.x * ab.y - ac.y * ab.x) / denominator;
  if (t <= 0.000001 || t >= 0.999999 || u <= 0.000001 || u >= 0.999999) return undefined;
  return {
    x: a.x + ab.x * t,
    y: a.y + ab.y * t
  };
}

function roundVisionPoint(point: VisionPoint): VisionPoint {
  return {
    x: Math.round(point.x * 1000) / 1000,
    y: Math.round(point.y * 1000) / 1000
  };
}

function roundDistance(value: number): number {
  return Math.round(value * 1000) / 1000;
}

function defaultOrganizationWorkspaceInput(ownerUserId: string): Omit<OrganizationWorkspace, "id" | "createdAt" | "updatedAt"> {
  return {
    name: "Default Workspace",
    ownerUserId,
    defaultSystemId: DEFAULT_SYSTEM_ID,
    defaultCampaignVisibility: "private",
    defaultPermissionTemplate: "standard",
    defaultInviteRole: "player",
    defaultSceneName: "Opening Scene",
    defaultSceneFolder: "session-0",
    defaultSceneWidth: 1200,
    defaultSceneHeight: 800,
    defaultSceneGridSize: 50,
    onboardingTitle: "Welcome to the Table",
    onboardingBody: "Use this handout for table rules, safety notes, and first-session goals."
  };
}

function createOrganizationWorkspace(ownerUserId: string, input: Partial<Omit<OrganizationWorkspace, "id" | "ownerUserId" | "createdAt" | "updatedAt">> = {}): OrganizationWorkspace {
  return createTimestamped("org", {
    ...defaultOrganizationWorkspaceInput(ownerUserId),
    ...input,
    ownerUserId
  }) satisfies OrganizationWorkspace;
}

function createOrganizationMember(organizationId: string, userId: string, role: OrganizationMemberRole): OrganizationMember {
  return createTimestamped("orgmem", {
    organizationId,
    userId,
    role
  }) satisfies OrganizationMember;
}

function ensureOrganizationWorkspace(store: StateStore, ownerUserId: string): OrganizationWorkspace {
  const state = store.state as EngineState & { organizations?: OrganizationWorkspace[] };
  state.organizations ??= [];
  const existing = state.organizations.find((workspace) => workspace.ownerUserId === ownerUserId);
  if (existing) {
    ensureOrganizationOwnerMember(store, existing);
    return existing;
  }
  const workspace = createOrganizationWorkspace(ownerUserId);
  state.organizations.push(workspace);
  ensureOrganizationOwnerMember(store, workspace);
  return workspace;
}

function ensureOrganizationOwnerMember(store: StateStore, workspace: OrganizationWorkspace): void {
  const state = store.state as EngineState & { organizationMembers?: OrganizationMember[] };
  state.organizationMembers ??= [];
  const existing = state.organizationMembers.find((member) => member.organizationId === workspace.id && member.userId === workspace.ownerUserId);
  if (!existing) state.organizationMembers.push(createOrganizationMember(workspace.id, workspace.ownerUserId, "owner"));
}

function publicOrganizationWorkspace(workspace: OrganizationWorkspace): OrganizationWorkspace {
  return { ...workspace };
}

function organizationWorkspaceForUser(store: StateStore, userId: string): OrganizationWorkspace {
  return publicOrganizationWorkspace(organizationWorkspaceRecordForUser(store, userId));
}

function organizationWorkspaceForRequest(store: StateStore, userId: string, headers: Record<string, string | string[] | undefined>): OrganizationWorkspace {
  return publicOrganizationWorkspace(organizationWorkspaceRecordForRequest(store, userId, headers));
}

function organizationWorkspaceRecordForRequest(store: StateStore, userId: string, headers: Record<string, string | string[] | undefined>): OrganizationWorkspace {
  const session = sessionFromRequest(store, undefined, headers);
  return organizationWorkspaceRecordForUser(store, userId, session?.activeOrganizationId);
}

function organizationWorkspaceRecordForUser(store: StateStore, userId: string, activeOrganizationId?: string): OrganizationWorkspace {
  const state = store.state as EngineState & { organizations?: OrganizationWorkspace[]; organizationMembers?: OrganizationMember[] };
  state.organizations ??= [];
  state.organizationMembers ??= [];
  const active = activeOrganizationId ? state.organizations.find((workspace) => workspace.id === activeOrganizationId) : undefined;
  if (active && canAccessOrganization(store, active.id, userId)) {
    ensureOrganizationOwnerMember(store, active);
    return active;
  }
  const owned = state.organizations.find((workspace) => workspace.ownerUserId === userId);
  if (owned) {
    ensureOrganizationOwnerMember(store, owned);
    return owned;
  }
  const membership = state.organizationMembers.find((member) => member.userId === userId);
  const memberWorkspace = membership ? state.organizations.find((workspace) => workspace.id === membership.organizationId) : undefined;
  if (memberWorkspace) return memberWorkspace;
  const campaignMemberWorkspace = state.members
    .filter((member) => member.userId === userId)
    .map((member) => store.state.campaigns.find((campaign) => campaign.id === member.campaignId))
    .map((campaign) => (campaign?.organizationId ? state.organizations.find((workspace) => workspace.id === campaign.organizationId) : undefined))
    .find((workspace): workspace is OrganizationWorkspace => Boolean(workspace));
  if (campaignMemberWorkspace) return campaignMemberWorkspace;
  return ensureOrganizationWorkspace(store, userId);
}

function organizationWorkspaceInfos(store: StateStore, userId: string): Array<OrganizationWorkspace & { role: OrganizationMemberRole; memberCount: number; campaignCount: number }> {
  const state = store.state as EngineState & { organizations?: OrganizationWorkspace[]; organizationMembers?: OrganizationMember[] };
  state.organizations ??= [];
  state.organizationMembers ??= [];
  for (const workspace of state.organizations.filter((item) => item.ownerUserId === userId)) ensureOrganizationOwnerMember(store, workspace);
  return state.organizations
    .flatMap((workspace) => {
      const member = state.organizationMembers?.find((item) => item.organizationId === workspace.id && item.userId === userId);
      if (!member) return [];
      return [{
        ...publicOrganizationWorkspace(workspace),
        role: member.role,
        memberCount: state.organizationMembers?.filter((item) => item.organizationId === workspace.id).length ?? 0,
        campaignCount: store.state.campaigns.filter((campaign) => campaign.organizationId === workspace.id && canCampaign(store, userId, campaign.id, "campaign.read")).length
      }];
    })
    .sort((left, right) => roleSortValue(left.role) - roleSortValue(right.role) || left.name.localeCompare(right.name));
}

function canAccessOrganization(store: StateStore, organizationId: string, userId: string): boolean {
  const state = store.state as EngineState & { organizations?: OrganizationWorkspace[]; organizationMembers?: OrganizationMember[] };
  return Boolean(state.organizations?.some((workspace) => workspace.id === organizationId && workspace.ownerUserId === userId) || state.organizationMembers?.some((member) => member.organizationId === organizationId && member.userId === userId));
}

function organizationMemberInfos(store: StateStore, organizationId: string): Array<OrganizationMember & { user: Pick<User, "id" | "displayName" | "email"> }> {
  const state = store.state as EngineState & { organizationMembers?: OrganizationMember[] };
  state.organizationMembers ??= [];
  return state.organizationMembers
    .filter((member) => member.organizationId === organizationId)
    .map((member) => {
      const user = store.state.users.find((candidate) => candidate.id === member.userId);
      return {
        ...member,
        user: {
          id: member.userId,
          displayName: user?.displayName ?? member.userId,
          email: user?.email
        }
      };
    })
    .sort((left, right) => roleSortValue(left.role) - roleSortValue(right.role) || left.user.displayName.localeCompare(right.user.displayName));
}

function organizationInviteInfos(store: StateStore, organizationId: string): Array<ReturnType<typeof publicInvite> & { campaign: Pick<Campaign, "id" | "name"> }> {
  const campaignById = new Map(store.state.campaigns.filter((campaign) => campaign.organizationId === organizationId).map((campaign) => [campaign.id, campaign]));
  return store.state.invites
    .flatMap((invite) => {
      const campaign = campaignById.get(invite.campaignId);
      if (!campaign) return [];
      return [{
        ...publicInvite(invite),
        campaign: {
          id: campaign.id,
          name: campaign.name
        }
      }];
    })
    .sort((left, right) => inviteStatusSortValue(left.status) - inviteStatusSortValue(right.status) || right.createdAt.localeCompare(left.createdAt));
}

function inviteStatusSortValue(status: PublicInviteStatus): number {
  if (status === "pending") return 0;
  if (status === "expired") return 1;
  if (status === "accepted") return 2;
  return 3;
}

function roleSortValue(role: OrganizationMemberRole): number {
  if (role === "owner") return 0;
  if (role === "admin") return 1;
  return 2;
}

function canManageOrganization(store: StateStore, organizationId: string, userId: string): boolean {
  if (isServerAdminUser(store, userId)) return true;
  const state = store.state as EngineState & { organizationMembers?: OrganizationMember[] };
  const member = state.organizationMembers?.find((item) => item.organizationId === organizationId && item.userId === userId);
  return member?.role === "owner" || member?.role === "admin";
}

function organizationMemberTargetUser(store: StateStore, body: OrganizationMemberCreateBody): User | undefined {
  const userId = typeof body.userId === "string" ? body.userId.trim() : "";
  if (userId) return store.state.users.find((user) => user.id === userId);
  const email = normalizeEmail(typeof body.email === "string" ? body.email : undefined);
  return email ? store.state.users.find((user) => normalizeEmail(user.email) === email) : undefined;
}

function organizationMemberRole(value: unknown): OrganizationMemberRole | undefined {
  if (value === "admin" || value === "member" || value === "owner") return value;
  return undefined;
}

function normalizeOrganizationWorkspacePatch(body: OrganizationWorkspaceDefaultsBody): { ok: true; value: Partial<OrganizationWorkspace> } | { ok: false; error: string } {
  const patch: Partial<OrganizationWorkspace> = {};
  if ("name" in body) {
    const name = normalizeNonEmptyString(body.name);
    if (!name) return { ok: false, error: "Workspace name is required" };
    patch.name = name;
  }
  if ("defaultSystemId" in body) {
    const systemId = normalizeNonEmptyString(body.defaultSystemId);
    if (!systemId) return { ok: false, error: "Default rules system is required" };
    patch.defaultSystemId = systemId;
  }
  if ("defaultCampaignVisibility" in body) {
    const visibility = campaignVisibility(body.defaultCampaignVisibility);
    if (!visibility) return { ok: false, error: "Default campaign visibility must be private, invite_only, or public" };
    patch.defaultCampaignVisibility = visibility;
  }
  if ("defaultPermissionTemplate" in body) {
    const template = campaignPermissionTemplate(body.defaultPermissionTemplate);
    if (!template) return { ok: false, error: "Default permission template must be standard, player_authoring, ai_assisted, or assistant_ops" };
    patch.defaultPermissionTemplate = template.id;
  }
  if ("defaultInviteRole" in body) {
    const role = assignableInviteRole(body.defaultInviteRole);
    if (!role) return { ok: false, error: "Default invite role must be player, observer, assistant_gm, or gm" };
    patch.defaultInviteRole = role;
  }
  if ("defaultSceneName" in body) {
    const sceneName = normalizeNonEmptyString(body.defaultSceneName);
    if (!sceneName) return { ok: false, error: "Default scene name is required" };
    patch.defaultSceneName = sceneName;
  }
  if ("defaultSceneFolder" in body) {
    patch.defaultSceneFolder = typeof body.defaultSceneFolder === "string" ? body.defaultSceneFolder.trim() : "";
  }
  if ("defaultSceneWidth" in body) {
    const width = positiveInteger(body.defaultSceneWidth);
    if (!width) return { ok: false, error: "Default scene width must be a positive number" };
    patch.defaultSceneWidth = width;
  }
  if ("defaultSceneHeight" in body) {
    const height = positiveInteger(body.defaultSceneHeight);
    if (!height) return { ok: false, error: "Default scene height must be a positive number" };
    patch.defaultSceneHeight = height;
  }
  if ("defaultSceneGridSize" in body) {
    const gridSize = positiveInteger(body.defaultSceneGridSize);
    if (!gridSize) return { ok: false, error: "Default scene grid size must be a positive number" };
    patch.defaultSceneGridSize = gridSize;
  }
  if ("onboardingTitle" in body) {
    const title = normalizeNonEmptyString(body.onboardingTitle);
    if (!title) return { ok: false, error: "Onboarding title is required" };
    patch.onboardingTitle = title;
  }
  if ("onboardingBody" in body) {
    patch.onboardingBody = typeof body.onboardingBody === "string" ? body.onboardingBody.trim() : "";
  }
  return { ok: true, value: patch };
}

function normalizeNonEmptyString(value: unknown): string | undefined {
  if (typeof value !== "string") return undefined;
  const trimmed = value.trim();
  return trimmed || undefined;
}

function campaignVisibility(value: unknown, fallback?: Campaign["visibility"]): Campaign["visibility"] | undefined {
  if (value === "private" || value === "invite_only" || value === "public") return value;
  return fallback;
}

function assignableInviteRole(value: unknown): Exclude<UserRole, "owner" | "plugin" | "ai_assistant"> | undefined {
  if (value === "player" || value === "observer" || value === "assistant_gm" || value === "gm") return value;
  return undefined;
}

function positiveInteger(value: unknown): number | undefined {
  const numberValue = typeof value === "number" ? value : typeof value === "string" ? Number(value) : NaN;
  if (!Number.isFinite(numberValue) || numberValue <= 0) return undefined;
  return Math.round(numberValue);
}

function realtimeClientAuthorizationIsCurrent(store: StateStore, client: RealtimeClient): boolean {
  if (!client.userId || !client.campaignId || !isActiveUserId(store, client.userId)) return false;
  if (!canCampaign(store, client.userId, client.campaignId, "campaign.read")) return false;
  if (!client.sessionId) return true;
  const session = store.state.sessions.find(
    (candidate) => candidate.id === client.sessionId && candidate.userId === client.userId && Date.parse(candidate.expiresAt) > Date.now()
  );
  if (!session) return false;
  const campaign = store.state.campaigns.find((candidate) => candidate.id === client.campaignId);
  if (!campaign) return false;
  return !campaign.organizationId || activeOrganizationIdForUser(store, client.userId, session.activeOrganizationId) === campaign.organizationId;
}

function filterRealtimeEvent(store: StateStore, event: EngineEvent, userId: string | undefined, visibilityCache?: TokenVisibilityCache): EngineEvent | undefined {
  if (!userId || !canCampaign(store, userId, event.campaignId, "campaign.read")) return undefined;
  if (event.type === "agent.boardCaptureRequested") {
    const payload = isRecord(event.payload) ? event.payload : {};
    return payload.userId === userId ? event : undefined;
  }
  if (event.type.startsWith("contentImport.") && !canCampaign(store, userId, event.campaignId, "campaign.update")) return undefined;
  if (event.type.startsWith("world.")) return canCampaign(store, userId, event.campaignId, "world.read") ? event : undefined;
  if (event.type.startsWith("campaign.session.")) {
    const payload = isRecord(event.payload) ? event.payload : {};
    if (canAccessPreparedScenes(store, userId, event.campaignId)) return event;
    if (payload.status !== "live") return undefined;
    return redactedRealtimeEvent(event, { ...payload, agenda: "", notes: "", encounterIds: [], recapProposalId: undefined, recapJournalId: undefined });
  }
  if (event.type.startsWith("audio.")) {
    if (canAccessPreparedScenes(store, userId, event.campaignId)) return event;
    const payload = isRecord(event.payload) ? event.payload : {};
    if (payload.playing === true) return event;
    return redactedRealtimeEvent(event, { id: event.targetId, campaignId: event.campaignId, playing: false, redacted: true });
  }
  if (event.type.startsWith("journal.")) {
    const journal = journalEntryFromRealtimeEvent(store, event);
    if (!journal) return canCampaign(store, userId, event.campaignId, "journal.readSecret") ? event : undefined;
    return canReadJournalEntry(store, userId, journal) ? event : undefined;
  }
  if (event.type.startsWith("handout.")) {
    const payload = isRecord(event.payload) ? (event.payload as unknown as Handout) : undefined;
    const handout = store.state.handouts.find((item) => item.id === event.targetId && item.campaignId === event.campaignId) ?? payload;
    return handout && canReadHandout(store, userId, handout) ? redactedRealtimeEvent(event, normalizeHandout(handout)) : undefined;
  }
  if (event.type.startsWith("asset.")) {
    const asset = assetFromRealtimeEvent(store, event);
    if (!asset) return undefined;
    if (event.type === "asset.deleted" && canAccessPreparedScenes(store, userId, event.campaignId)) {
      return redactedRealtimeEvent(event, asset);
    }
    return canReadAssetRecord(store, userId, asset) ? redactedRealtimeEvent(event, asset) : undefined;
  }
  if (event.type.startsWith("ai.memory.")) {
    const payload = isRecord(event.payload) ? (event.payload as unknown as AiMemoryFact) : undefined;
    const rawFact = store.state.aiMemory.find((item) => item.id === event.targetId && item.campaignId === event.campaignId) ?? payload;
    if (!rawFact) return undefined;
    const fact = normalizeAiMemoryFact(rawFact);
    if (canCampaign(store, userId, event.campaignId, "ai.readGmMemory")) return redactedRealtimeEvent(event, fact);
    return canCampaign(store, userId, event.campaignId, "ai.readPublicMemory") && fact.visibility === "public" && aiMemoryFactStatus(fact) === "approved"
      ? redactedRealtimeEvent(event, fact)
      : undefined;
  }
  if (event.type.startsWith("dice.macro.")) {
    const macro = diceMacroFromRealtimeEvent(store, event);
    if (!macro || !canCampaign(store, userId, event.campaignId, "dice.roll")) return undefined;
    if (macro.visibility === "public" || canCampaign(store, userId, event.campaignId, "campaign.update")) {
      return redactedRealtimeEvent(event, macro);
    }
    const payload = isRecord(event.payload) ? event.payload : undefined;
    if (event.type === "dice.macro.updated" && payload?.previousVisibility === "public") {
      return {
        ...event,
        type: "dice.macro.deleted",
        payload: { id: macro.id, campaignId: macro.campaignId, redacted: true }
      };
    }
    return undefined;
  }
  if (event.type === "dice.roll.created") {
    const roll = diceRollFromRealtimeEvent(store, event);
    if (!roll || !canCampaign(store, userId, roll.campaignId, "chat.read")) return undefined;
    const linkedMessage = store.state.chat.find((message) => message.rollId === roll.id && message.campaignId === roll.campaignId);
    return canReadDiceRoll(store, userId, roll, linkedMessage) ? event : undefined;
  }
  if (
    event.type === "ai.thread.started" ||
    event.type.startsWith("ai.message.") ||
    event.type.startsWith("ai.reasoning.") ||
    event.type.startsWith("ai.activity.") ||
    event.type.startsWith("ai.tool.")
  ) {
    const payload = isRecord(event.payload) ? event.payload : {};
    if (payload.visibility === "gm_only" && event.actorUserId !== userId && !canCampaign(store, userId, event.campaignId, "ai.readGmMemory") && !canCampaign(store, userId, event.campaignId, "chat.moderate")) return undefined;
    return event;
  }
  if (event.type.startsWith("proposal.") || event.type.startsWith("ai.proposal.")) {
    const proposal = proposalFromRealtimeEvent(store, event);
    if (proposal) return canReceiveProposalRealtimeEvent(store, userId, proposal) ? event : undefined;
    return canReceiveProposalRealtimeFeed(store, userId, event.campaignId) ? event : undefined;
  }
  if (event.type.startsWith("actor.")) {
    if (!canCampaign(store, userId, event.campaignId, "actor.read")) return undefined;
    const actor = actorFromRealtimeEvent(store, event);
    if (!actor) return canReadActorPrivateData(store, userId, event.campaignId) ? event : redactedRealtimeEvent(event, redactedTargetPayload(event.targetId));
    if (canReadActorPrivateData(store, userId, actor.campaignId, actor)) return event;
    return redactedRealtimeEvent(event, redactedActorPayload(actor));
  }
  if (event.type.startsWith("item.")) {
    if (!canCampaign(store, userId, event.campaignId, "actor.read")) return undefined;
    const payload = isRecord(event.payload) ? (event.payload as unknown as Item) : undefined;
    const item = store.state.items.find((candidate) => candidate.id === event.targetId && candidate.campaignId === event.campaignId) ?? payload;
    if (!item || !visibleItemsForUser(store, userId, event.campaignId).some((candidate) => candidate.id === item.id)) return undefined;
    return redactedRealtimeEvent(event, itemPayloadForUser(store, userId, item));
  }
  if (event.type.startsWith("encounter.")) {
    const payload = isRecord(event.payload) ? (event.payload as unknown as Encounter & { previouslyActive?: boolean }) : undefined;
    const encounter = store.state.encounters.find((item) => item.id === event.targetId && item.campaignId === event.campaignId) ?? payload;
    if (!encounter) return undefined;
    const previouslyActive = payload?.previouslyActive === true;
    if (!canReadEncounter(store, userId, encounter) && !(event.type === "encounter.deleted" && previouslyActive && canCampaign(store, userId, encounter.campaignId, "campaign.read"))) {
      return undefined;
    }
    return redactedRealtimeEvent(event, encounterPayloadForUser(store, userId, encounter));
  }
  if (event.type.startsWith("combat.")) {
    const combat = combatFromRealtimeEvent(store, event);
    return combat ? redactedRealtimeEvent(event, combatPayloadForUser(store, userId, combat)) : undefined;
  }
  if (event.type.startsWith("chat.message.")) {
    const message = event.payload as Partial<ChatMessage> | undefined;
    const campaignId = message?.campaignId ?? event.campaignId;
    if (!canCampaign(store, userId, campaignId, "chat.read")) return undefined;
    if (!message?.id || !message.userId || !message.type || typeof message.body !== "string" || !message.visibility || !Array.isArray(message.recipientUserIds)) return undefined;
    return canReadChatMessage(store, userId, message as ChatMessage) ? event : undefined;
  }
  if (event.type.startsWith("scene.")) {
    const scene = event.payload as Partial<Scene> | undefined;
    const storedScene = store.state.scenes.find((candidate) => candidate.id === (scene?.id ?? event.targetId) && candidate.campaignId === event.campaignId);
    const readableScene = storedScene ?? (scene?.campaignId === event.campaignId && typeof scene.active === "boolean" ? (scene as Scene) : undefined);
    if (readableScene && !canReadSceneRecord(store, userId, readableScene)) return undefined;
    if (!readableScene && !canAccessPreparedScenes(store, userId, event.campaignId)) return undefined;
    if (scene && "sceneEditHistory" in scene) return { ...event, payload: withoutSceneEditHistory(scene as Scene) };
    return event;
  }
  if (!event.type.startsWith("token.")) return event;
  const token = event.payload as Partial<Token> | undefined;
  if (!token?.sceneId) return event;
  const campaignId = campaignIdForScene(store, token.sceneId) ?? event.campaignId;
  if (!canCampaign(store, userId, campaignId, "campaign.read")) return undefined;
  const scene = store.state.scenes.find((candidate) => candidate.id === token.sceneId && candidate.campaignId === campaignId);
  if (!scene || !canReadSceneRecord(store, userId, scene)) return undefined;
  if (isTokenVisibleToUser(store, userId, campaignId, token as Token, undefined, visibilityCache)) return event;
  return {
    ...event,
    type: "scene.updated",
    targetId: token.sceneId,
    payload: { id: token.sceneId, redacted: true }
  };
}

function journalEntryFromRealtimeEvent(store: StateStore, event: EngineEvent): JournalEntry | undefined {
  const payload = isRecord(event.payload) ? event.payload : undefined;
  const payloadId = typeof payload?.id === "string" ? payload.id : undefined;
  const id = payloadId ?? event.targetId;
  return store.state.journals.find((journal) => journal.id === id && journal.campaignId === event.campaignId) ?? (isJournalEntryPayload(payload, event.campaignId) ? (payload as unknown as JournalEntry) : undefined);
}

function isJournalEntryPayload(payload: Record<string, unknown> | undefined, campaignId: string): boolean {
  if (!payload) return false;
  return (
    typeof payload.id === "string" &&
    payload.campaignId === campaignId &&
    typeof payload.title === "string" &&
    typeof payload.body === "string" &&
    typeof payload.visibility === "string" &&
    Array.isArray(payload.visibleToUserIds) &&
    Array.isArray(payload.visibleToActorIds) &&
    Array.isArray(payload.tags)
  );
}

function canReadJournalEntry(store: StateStore, userId: string, journal: JournalEntry): boolean {
  if (!canCampaign(store, userId, journal.campaignId, "journal.read")) return false;
  if (journal.visibility === "public") return true;
  if (journal.visibleToUserIds.includes(userId)) return true;
  if (
    journal.visibleToActorIds.some((actorId) =>
      store.state.actors.some((actor) => actor.id === actorId && actor.campaignId === journal.campaignId && actor.ownerUserId === userId)
    )
  )
    return true;
  return canCampaign(store, userId, journal.campaignId, "journal.readSecret");
}

function canReadHandout(store: StateStore, userId: string, rawHandout: Handout): boolean {
  const handout = normalizeHandout(rawHandout);
  if (!canCampaign(store, userId, handout.campaignId, "handout.read")) return false;
  if (handout.visibility === "public") return true;
  if ((handout.visibleToUserIds ?? []).includes(userId)) return true;
  if (
    (handout.visibleToActorIds ?? []).some((actorId) =>
      store.state.actors.some((actor) => actor.id === actorId && actor.campaignId === handout.campaignId && actor.ownerUserId === userId)
    )
  )
    return true;
  return canCampaign(store, userId, handout.campaignId, "handout.readSecret");
}

function canReadEncounter(store: StateStore, userId: string, encounter: Encounter): boolean {
  if (!canCampaign(store, userId, encounter.campaignId, "campaign.read")) return false;
  return (
    canAccessPreparedScenes(store, userId, encounter.campaignId) ||
    store.state.combats.some((combat) => combat.campaignId === encounter.campaignId && combat.active && combat.encounterId === encounter.id)
  );
}

function encounterPayloadForUser(store: StateStore, userId: string, encounter: Encounter): Encounter & { redacted?: true } {
  if (canAccessPreparedScenes(store, userId, encounter.campaignId)) return encounter;
  const { difficulty: _difficulty, partyActorIds: _partyActorIds, threats: _threats, ...visible } = encounter;
  return {
    ...visible,
    summary: "",
    tokenIds: [],
    redacted: true
  };
}

function diceRollFromRealtimeEvent(store: StateStore, event: EngineEvent): DiceRoll | undefined {
  const payload = isRecord(event.payload) ? event.payload : undefined;
  const payloadId = typeof payload?.id === "string" ? payload.id : undefined;
  const id = payloadId ?? event.targetId;
  return store.state.rolls.find((roll) => roll.id === id && roll.campaignId === event.campaignId) ?? (isDiceRollPayload(payload, event.campaignId) ? (payload as unknown as DiceRoll) : undefined);
}

function isDiceRollPayload(payload: Record<string, unknown> | undefined, campaignId: string): boolean {
  if (!payload) return false;
  return (
    typeof payload.id === "string" &&
    payload.campaignId === campaignId &&
    typeof payload.userId === "string" &&
    typeof payload.formula === "string" &&
    (payload.visibility === "public" || payload.visibility === "gm_only" || payload.visibility === "whisper") &&
    Array.isArray(payload.terms) &&
    typeof payload.total === "number"
  );
}

function assetFromRealtimeEvent(store: StateStore, event: EngineEvent): MapAsset | undefined {
  const payload = isRecord(event.payload) ? event.payload : undefined;
  const payloadId = typeof payload?.id === "string" ? payload.id : undefined;
  const id = payloadId ?? event.targetId;
  return store.state.assets.find((asset) => asset.id === id && asset.campaignId === event.campaignId) ?? (isMapAssetPayload(payload, event.campaignId) ? (payload as unknown as MapAsset) : undefined);
}

function isMapAssetPayload(payload: Record<string, unknown> | undefined, campaignId: string): boolean {
  return Boolean(
    payload &&
      typeof payload.id === "string" &&
      payload.campaignId === campaignId &&
      typeof payload.name === "string" &&
      typeof payload.url === "string" &&
      typeof payload.mimeType === "string" &&
      typeof payload.sizeBytes === "number"
  );
}

function diceMacroFromRealtimeEvent(store: StateStore, event: EngineEvent): DiceMacro | undefined {
  const payload = isRecord(event.payload) ? event.payload : undefined;
  const payloadId = typeof payload?.id === "string" ? payload.id : undefined;
  const id = payloadId ?? event.targetId;
  return store.state.diceMacros.find((macro) => macro.id === id && macro.campaignId === event.campaignId) ?? (isDiceMacroPayload(payload, event.campaignId) ? (payload as unknown as DiceMacro) : undefined);
}

function isDiceMacroPayload(payload: Record<string, unknown> | undefined, campaignId: string): boolean {
  return Boolean(
    payload &&
      typeof payload.id === "string" &&
      payload.campaignId === campaignId &&
      typeof payload.createdBy === "string" &&
      typeof payload.name === "string" &&
      typeof payload.formula === "string" &&
      (payload.visibility === "public" || payload.visibility === "gm_only")
  );
}

function proposalFromRealtimeEvent(store: StateStore, event: EngineEvent): Proposal | undefined {
  const payload = isRecord(event.payload) ? event.payload : undefined;
  const payloadId = typeof payload?.id === "string" ? payload.id : undefined;
  const id = payloadId ?? event.targetId;
  return store.state.proposals.find((proposal) => proposal.id === id && proposal.campaignId === event.campaignId) ?? (isProposalPayload(payload, event.campaignId) ? (payload as unknown as Proposal) : undefined);
}

function isProposalPayload(payload: Record<string, unknown> | undefined, campaignId: string): boolean {
  if (!payload) return false;
  return (
    typeof payload.id === "string" &&
    payload.campaignId === campaignId &&
    typeof payload.title === "string" &&
    typeof payload.summary === "string" &&
    typeof payload.status === "string" &&
    Array.isArray(payload.changesJson) &&
    isRecord(payload.diffJson) &&
    typeof payload.approvalRequired === "boolean"
  );
}

function canReceiveProposalRealtimeEvent(store: StateStore, userId: string, proposal: Proposal): boolean {
  const permissions = permissionsForUser(store, userId, proposal.campaignId);
  return proposal.createdByUserId === userId || proposalVisibleToUser(store.state, userId, proposal.campaignId, permissions, proposal);
}

function canReceiveProposalRealtimeFeed(store: StateStore, userId: string, campaignId: string): boolean {
  return canCampaign(store, userId, campaignId, "campaign.update") || canCampaign(store, userId, campaignId, "ai.applyChanges");
}

function actorFromRealtimeEvent(store: StateStore, event: EngineEvent): Actor | undefined {
  const payload = isRecord(event.payload) ? event.payload : undefined;
  const payloadId = typeof payload?.id === "string" ? payload.id : undefined;
  const id = payloadId ?? event.targetId;
  return store.state.actors.find((actor) => actor.id === id && actor.campaignId === event.campaignId) ?? (isActorPayload(payload, event.campaignId) ? (payload as unknown as Actor) : undefined);
}

function isActorPayload(payload: Record<string, unknown> | undefined, campaignId: string): boolean {
  if (!payload) return false;
  return (
    typeof payload.id === "string" &&
    payload.campaignId === campaignId &&
    typeof payload.systemId === "string" &&
    typeof payload.type === "string" &&
    typeof payload.name === "string" &&
    isRecord(payload.data) &&
    isRecord(payload.permissions)
  );
}

function canReadActorPrivateData(store: StateStore, userId: string, campaignId: string, actor?: Actor): boolean {
  return Boolean(
    canCampaign(store, userId, campaignId, "actor.readPrivate") ||
      actor?.ownerUserId === userId ||
      actor?.permissions[userId]?.includes("actor.readPrivate")
  );
}

function actorPayloadForUser(store: StateStore, userId: string, actor: Actor): Actor & { redacted?: true } {
  return canReadActorPrivateData(store, userId, actor.campaignId, actor) ? actor : redactedActorPayload(actor);
}

function itemPayloadForUser(store: StateStore, userId: string, item: Item, actorIds: Array<string | undefined> = [item.actorId]): Item & { redacted?: true } {
  const hiddenActor = actorIds
    .filter((actorId): actorId is string => typeof actorId === "string")
    .some((actorId) => !canReadActorPrivateDataById(store, userId, item.campaignId, actorId));
  if (!hiddenActor) return item;
  return {
    ...item,
    name: "Redacted item",
    type: "redacted",
    data: {},
    redacted: true
  };
}

function visibleItemsForUser(store: StateStore, userId: string, campaignId: string): Item[] {
  return store.state.items.filter((item) => {
    if (item.campaignId !== campaignId) return false;
    if (!item.actorId) return true;
    const actor = store.state.actors.find((candidate) => candidate.id === item.actorId && candidate.campaignId === campaignId);
    return Boolean(actor && canReadActorPrivateData(store, userId, campaignId, actor));
  });
}

function redactedActorPayload(actor: Actor): Actor & { redacted: true } {
  return {
    ...actor,
    data: {},
    permissions: {},
    redacted: true
  };
}

function combatFromRealtimeEvent(store: StateStore, event: EngineEvent): Combat | undefined {
  const payload = isRecord(event.payload) ? event.payload : undefined;
  const combatId = typeof payload?.id === "string" ? payload.id : event.targetId;
  return combatId ? store.state.combats.find((combat) => combat.id === combatId && combat.campaignId === event.campaignId) : undefined;
}

function combatPayloadForUser(store: StateStore, userId: string, combat: Combat): Combat {
  return {
    ...combat,
    combatants: combat.combatants.map((combatant) => combatantPayloadForUser(store, userId, combat.campaignId, combatant)),
    ...(combat.actions ? { actions: combat.actions.map((action) => combatActionPayloadForUser(store, userId, combat.campaignId, action)) } : {})
  };
}

function combatantPayloadForUser(store: StateStore, userId: string, campaignId: string, combatant: Combat["combatants"][number]): Combat["combatants"][number] {
  if (!combatant.actorId || canReadActorPrivateDataById(store, userId, campaignId, combatant.actorId)) return combatant;
  const redacted = { ...combatant };
  delete redacted.conditions;
  delete redacted.deathSaveSuccesses;
  delete redacted.deathSaveFailures;
  delete redacted.deathSaveOutcome;
  delete redacted.resourceKey;
  delete redacted.resourceLabel;
  delete redacted.resourceUsed;
  delete redacted.resourceSpent;
  return redacted;
}

function combatActionPayloadForUser(store: StateStore, userId: string, campaignId: string, action: CombatAction): CombatAction {
  const canModerate = canCampaign(store, userId, campaignId, "combat.manage") || canCampaign(store, userId, campaignId, "chat.moderate");
  const canReadRoll = (visibility: CombatAction["rolls"][number]["visibility"]): boolean =>
    visibility === "public" || canModerate || (visibility === "whisper" && action.requestedByUserId === userId);
  const rolls = action.rolls.filter((roll) => canReadRoll(roll.visibility));
  const actorUpdates = action.actorUpdates.map((update) =>
    canReadActorPrivateDataById(store, userId, campaignId, update.actorId) ? update : { ...update, before: {}, after: {} }
  );
  const itemUpdates = action.itemUpdates?.filter((update) => canReadItemPrivateDataById(store, userId, campaignId, update.itemId));
  const filteredResolution = rulesResolutionPayloadForUser(store, userId, campaignId, action.resolution);
  const resolution = filteredResolution && rolls.length !== action.rolls.length ? { ...filteredResolution, rolls: [] } : filteredResolution;
  return {
    ...action,
    rolls,
    actorUpdates,
    ...(action.itemUpdates ? { itemUpdates } : {}),
    ...(resolution === undefined ? { resolution: undefined } : { resolution }),
    ...(rolls.length === action.rolls.length ? {} : { resultSummary: undefined })
  };
}

function rulesResolutionPayloadForUser(store: StateStore, userId: string, campaignId: string, value: unknown): RulesActionResolutionResult | undefined {
  if (!isRulesActionResolutionResult(value)) return undefined;
  const sourceVisible = canReadActorPrivateDataById(store, userId, campaignId, value.actorId);
  const actorUpdates = value.actorUpdates.map((update) =>
    canReadActorPrivateDataById(store, userId, campaignId, update.actorId) ? update : { ...update, before: {}, after: {} }
  );
  const itemUpdates = value.itemUpdates.filter((item) => canReadItemPrivateData(store, userId, campaignId, item));
  const referencedActorIds = [
    value.actorId,
    ...value.actorUpdates.map((update) => update.actorId),
    ...value.effects.map((effect) => effect.targetActorId),
    ...value.conditions.map((condition) => condition.actorId),
    ...value.pendingSaves.map((pendingSave) => pendingSave.actorId),
    ...value.pendingReactions.map((pendingReaction) => pendingReaction.actorId),
    ...value.rolls.map((roll) => roll.targetActorId),
    ...value.auditEvents.flatMap((auditEvent) => [auditEvent.actorId, auditEvent.targetActorId])
  ].filter((actorId): actorId is string => typeof actorId === "string" && actorId.length > 0);
  const hiddenActorIds = new Set(
    referencedActorIds.filter((actorId) => !canReadActorPrivateDataById(store, userId, campaignId, actorId))
  );
  const effects = value.effects.map((effect) => {
    if (!hiddenActorIds.has(effect.targetActorId)) return effect;
    return {
      type: effect.type,
      targetActorId: effect.targetActorId,
      targetActorName: effect.targetActorName,
      ...(typeof effect.amount === "number" ? { amount: effect.amount } : {}),
      ...(typeof effect.damageType === "string" ? { damageType: effect.damageType } : {}),
      ...(Array.isArray(effect.damageTypes) ? { damageTypes: effect.damageTypes } : {}),
      ...(typeof effect.effectChoice === "string" ? { effectChoice: effect.effectChoice } : {}),
      ...(effect.choiceKind ? { choiceKind: effect.choiceKind } : {}),
      ...(typeof effect.conditionId === "string" ? { conditionId: effect.conditionId } : {}),
      ...(typeof effect.conditionName === "string" ? { conditionName: effect.conditionName } : {}),
      ...(typeof effect.duration === "string" ? { duration: effect.duration } : {})
    };
  });
  const rolls = value.rolls.map((roll) => {
    const rollActorVisible = roll.targetActorId ? !hiddenActorIds.has(roll.targetActorId) : sourceVisible;
    return rollActorVisible
      ? roll
      : {
          ...roll,
          baseFormula: "",
          formula: "",
          d20Mode: undefined,
          advantageSources: [],
          disadvantageSources: [],
          saveOutcome: undefined
        };
  });
  const auditEvents = value.auditEvents.map((auditEvent) => {
    const hiddenActor = auditEvent.actorId ? hiddenActorIds.has(auditEvent.actorId) : !sourceVisible;
    const hiddenTarget = auditEvent.targetActorId ? hiddenActorIds.has(auditEvent.targetActorId) : false;
    return hiddenActor || hiddenTarget ? { ...auditEvent, message: "Resolution event redacted", data: undefined } : auditEvent;
  });
  return {
    ...value,
    action: sourceVisible ? value.action : { ...value.action, metadata: {} },
    rolls,
    resourceConsumption: sourceVisible ? value.resourceConsumption : [],
    usage: sourceVisible ? value.usage : undefined,
    attunement: sourceVisible ? value.attunement : undefined,
    actorUpdates,
    itemUpdates,
    effects,
    conditions: value.conditions.filter((condition) => !hiddenActorIds.has(condition.actorId)),
    pendingSaves: value.pendingSaves.map((pendingSave) =>
      hiddenActorIds.has(pendingSave.actorId) ? { ...pendingSave, reason: "Save required", success: undefined, conditionIds: undefined } : pendingSave
    ),
    pendingReactions: value.pendingReactions.filter((pendingReaction) => !hiddenActorIds.has(pendingReaction.actorId)),
    warnings: sourceVisible && hiddenActorIds.size === 0 ? value.warnings : [],
    auditEvents,
    blocked: value.blocked
      ? sourceVisible && hiddenActorIds.size === 0
        ? value.blocked
        : { code: "resolution_blocked", reason: "Resolution blocked" }
      : undefined,
    pendingChoice: sourceVisible ? value.pendingChoice : undefined,
    manualResolutionRequired: value.manualResolutionRequired
      ? sourceVisible && hiddenActorIds.size === 0
        ? value.manualResolutionRequired
        : { reason: "Manual resolution required", metadata: {} }
      : undefined
  };
}

function isRulesActionResolutionResult(value: unknown): value is RulesActionResolutionResult {
  return Boolean(
    isRecord(value) &&
      typeof value.systemId === "string" &&
      typeof value.actorId === "string" &&
      typeof value.rollId === "string" &&
      Array.isArray(value.rolls) &&
      Array.isArray(value.actorUpdates) &&
      Array.isArray(value.itemUpdates) &&
      Array.isArray(value.effects) &&
      Array.isArray(value.conditions) &&
      Array.isArray(value.pendingSaves) &&
      Array.isArray(value.pendingReactions) &&
      Array.isArray(value.auditEvents)
  );
}

function combatAuditLogPayloadForUser(store: StateStore, userId: string, campaignId: string, log: AuditLog): AuditLog {
  return {
    ...log,
    ...(log.before === undefined ? {} : { before: combatAuditValueForUser(store, userId, campaignId, log.before) }),
    ...(log.after === undefined ? {} : { after: combatAuditValueForUser(store, userId, campaignId, log.after) })
  };
}

function combatAuditValueForUser(store: StateStore, userId: string, campaignId: string, value: unknown): unknown {
  if (!isRecord(value) || !Array.isArray(value.combatants)) return value;
  return {
    ...value,
    combatants: value.combatants.map((combatant) => {
      if (!isRecord(combatant) || typeof combatant.actorId !== "string" || canReadActorPrivateDataById(store, userId, campaignId, combatant.actorId)) return combatant;
      const redacted = { ...combatant };
      delete redacted.conditions;
      delete redacted.deathSaveSuccesses;
      delete redacted.deathSaveFailures;
      delete redacted.deathSaveOutcome;
      delete redacted.resourceKey;
      delete redacted.resourceLabel;
      delete redacted.resourceUsed;
      delete redacted.resourceSpent;
      return redacted;
    })
  };
}

function canReadActorPrivateDataById(store: StateStore, userId: string, campaignId: string, actorId: string): boolean {
  const actor = store.state.actors.find((candidate) => candidate.id === actorId && candidate.campaignId === campaignId);
  return actor ? canReadActorPrivateData(store, userId, campaignId, actor) : canCampaign(store, userId, campaignId, "actor.readPrivate");
}

function canReadItemPrivateData(store: StateStore, userId: string, campaignId: string, item: Item): boolean {
  return item.campaignId === campaignId && (!item.actorId || canReadActorPrivateDataById(store, userId, campaignId, item.actorId));
}

function canReadItemPrivateDataById(store: StateStore, userId: string, campaignId: string, itemId: string): boolean {
  const item = store.state.items.find((candidate) => candidate.id === itemId && candidate.campaignId === campaignId);
  return Boolean(item && canReadItemPrivateData(store, userId, campaignId, item));
}

function redactedTargetPayload(targetId: string | undefined): Record<string, unknown> {
  return targetId ? { id: targetId, redacted: true } : { redacted: true };
}

function redactedRealtimeEvent(event: EngineEvent, payload: unknown): EngineEvent {
  return {
    ...event,
    payload
  };
}

function campaignPermissionTemplate(value: unknown): CampaignPermissionTemplate | undefined {
  if (value === undefined || value === null || value === "") return campaignPermissionTemplates.standard;
  return typeof value === "string" && value in campaignPermissionTemplates ? campaignPermissionTemplates[value as CampaignPermissionTemplateId] : undefined;
}

function campaignPermissionTemplateGrants(campaignId: string, templateId: CampaignPermissionTemplateId): PermissionGrant[] {
  const template = campaignPermissionTemplates[templateId];
  return template.grants.map((grant) =>
    createTimestamped("grant", {
      subjectType: "role" as const,
      subjectId: grant.role,
      campaignId,
      permissions: grant.permissions,
      metadata: {
        source: "campaign_permission_template",
        templateId
      }
    })
  );
}

function memberSessionInfo(
  store: StateStore,
  member: CampaignMember
): CampaignMember & {
  user: Pick<User, "id" | "displayName" | "email">;
  permissions: PermissionName[];
} {
  const user = store.state.users.find((item) => item.id === member.userId);
  const grantPermissions = store.state.permissionGrants
    .filter((grant) => {
      if (grant.campaignId !== member.campaignId) return false;
      if (grant.expiresAt && Date.parse(grant.expiresAt) <= Date.now()) return false;
      if (grant.subjectType === "user" && grant.subjectId === member.userId) return true;
      return grant.subjectType === "role" && grant.subjectId === member.role;
    })
    .flatMap((grant) => grant.permissions);
  return {
    ...member,
    user: {
      id: member.userId,
      displayName: user?.displayName ?? member.userId,
      email: user?.email
    },
    permissions: [...new Set([...permissionsForRole(member.role), ...grantPermissions])]
  };
}

interface OidcProviderConfig {
  issuer: string;
  clientId: string;
  clientSecret?: string;
  redirectUri: string;
  scope: string;
  displayName: string;
  tokenAuth: "client_secret_basic" | "client_secret_post" | "none";
}

interface OidcDiscoveryDocument {
  issuer: string;
  authorization_endpoint: string;
  token_endpoint: string;
  userinfo_endpoint?: string;
}

interface OidcTokenResponse {
  access_token?: string;
  token_type?: string;
  id_token?: string;
  expires_in?: number;
}

interface OidcClaims {
  sub?: unknown;
  email?: unknown;
  name?: unknown;
  preferred_username?: unknown;
}

function oidcProviderConfig(headers: Record<string, string | string[] | undefined>): OidcProviderConfig | undefined {
  const issuer = process.env.OTTE_OIDC_ISSUER?.replace(/\/+$/, "");
  const clientId = process.env.OTTE_OIDC_CLIENT_ID;
  if (!issuer || !clientId) return undefined;
  if (!isAllowedIssuerUrl(issuer)) throw new Error("OTTE_OIDC_ISSUER must use HTTPS unless it is localhost or OTTE_OIDC_ALLOW_INSECURE=true");
  return {
    issuer,
    clientId,
    clientSecret: process.env.OTTE_OIDC_CLIENT_SECRET,
    redirectUri: process.env.OTTE_OIDC_REDIRECT_URI ?? `${requestBaseUrl(headers)}/api/v1/auth/oidc/callback`,
    scope: process.env.OTTE_OIDC_SCOPE ?? "openid email profile",
    displayName: process.env.OTTE_OIDC_DISPLAY_NAME ?? "Single Sign-On",
    tokenAuth: oidcTokenAuthMethod(process.env.OTTE_OIDC_TOKEN_AUTH, process.env.OTTE_OIDC_CLIENT_SECRET)
  };
}

async function createOidcAuthorization(store: StateStore, config: OidcProviderConfig, requestedReturnTo: string | undefined): Promise<{ authorizationUrl: string; expiresAt: string; provider: Pick<OidcProviderConfig, "issuer" | "clientId" | "scope" | "displayName" | "redirectUri"> }> {
  const discovery = await discoverOidc(config);
  const stateToken = `oss_${randomBytes(32).toString("base64url")}`;
  const nonce = randomBytes(32).toString("base64url");
  const codeVerifier = randomBytes(32).toString("base64url");
  const expiresAt = new Date(Date.now() + 10 * 60 * 1000).toISOString();
  const oauthState = createTimestamped("oauth", {
    provider: "oidc" as const,
    issuer: config.issuer,
    stateHash: hashSessionToken(stateToken),
    codeVerifier,
    nonceHash: hashSessionToken(nonce),
    redirectUri: config.redirectUri,
    returnTo: sanitizeReturnTo(requestedReturnTo),
    expiresAt
  }) satisfies OAuthLoginState;
  store.state.oauthStates.push(oauthState);
  pruneExpiredOAuthStates(store);
  store.save();

  const url = new URL(discovery.authorization_endpoint);
  url.searchParams.set("response_type", "code");
  url.searchParams.set("client_id", config.clientId);
  url.searchParams.set("redirect_uri", config.redirectUri);
  url.searchParams.set("scope", config.scope);
  url.searchParams.set("state", stateToken);
  url.searchParams.set("nonce", nonce);
  url.searchParams.set("code_challenge", base64Url(createHash("sha256").update(codeVerifier).digest()));
  url.searchParams.set("code_challenge_method", "S256");

  return {
    authorizationUrl: url.toString(),
    expiresAt,
    provider: {
      issuer: config.issuer,
      clientId: config.clientId,
      scope: config.scope,
      displayName: config.displayName,
      redirectUri: config.redirectUri
    }
  };
}

async function completeOidcCallback(
  store: StateStore,
  config: OidcProviderConfig,
  code: string,
  stateToken: string
): Promise<{ token: string; session: UserSession; user: User; identity: AuthIdentity; returnTo?: string }> {
  pruneExpiredOAuthStates(store);
  const stateHash = hashSessionToken(stateToken);
  const stateIndex = store.state.oauthStates.findIndex((state) => state.provider === "oidc" && state.issuer === config.issuer && state.stateHash === stateHash && Date.parse(state.expiresAt) > Date.now());
  if (stateIndex < 0) throw new Error("Unknown or expired OIDC state");
  const oauthState = store.state.oauthStates.splice(stateIndex, 1)[0]!;
  store.save();
  const discovery = await discoverOidc(config);
  const token = await exchangeOidcCode(config, discovery, oauthState, code);
  const claims = await fetchOidcUserInfo(discovery, token);
  const { user, identity } = upsertOidcUser(store, config, claims);
  if (isDisabledUser(user)) throw new Error("User account is disabled");
  const session = createUserSession(store, user.id);
  return {
    token: session.token,
    session: session.session,
    user,
    identity,
    returnTo: oauthState.returnTo
  };
}

async function discoverOidc(config: OidcProviderConfig): Promise<OidcDiscoveryDocument> {
  const discoveryUrl = `${config.issuer}/.well-known/openid-configuration`;
  const document = await fetchJson<Partial<OidcDiscoveryDocument>>(discoveryUrl);
  if (document.issuer !== config.issuer) throw new Error("OIDC discovery issuer mismatch");
  if (!document.authorization_endpoint || !document.token_endpoint) throw new Error("OIDC discovery document is missing required endpoints");
  if (!document.userinfo_endpoint) throw new Error("OIDC discovery document is missing userinfo_endpoint");
  return {
    issuer: document.issuer,
    authorization_endpoint: document.authorization_endpoint,
    token_endpoint: document.token_endpoint,
    userinfo_endpoint: document.userinfo_endpoint
  };
}

async function exchangeOidcCode(config: OidcProviderConfig, discovery: OidcDiscoveryDocument, oauthState: OAuthLoginState, code: string): Promise<OidcTokenResponse> {
  const body = new URLSearchParams({
    grant_type: "authorization_code",
    code,
    redirect_uri: oauthState.redirectUri,
    client_id: config.clientId,
    code_verifier: oauthState.codeVerifier
  });
  const headers: Record<string, string> = { "content-type": "application/x-www-form-urlencoded" };
  if (config.clientSecret && config.tokenAuth === "client_secret_basic") {
    headers.authorization = `Basic ${Buffer.from(`${config.clientId}:${config.clientSecret}`).toString("base64")}`;
  } else if (config.clientSecret && config.tokenAuth === "client_secret_post") {
    body.set("client_secret", config.clientSecret);
  }

  const response = await fetch(discovery.token_endpoint, {
    method: "POST",
    headers,
    body
  });
  if (!response.ok) throw new Error(`Token endpoint returned ${response.status}`);
  const token = (await response.json()) as OidcTokenResponse;
  if (!token.access_token) throw new Error("Token endpoint did not return an access token");
  return token;
}

async function fetchOidcUserInfo(discovery: OidcDiscoveryDocument, token: OidcTokenResponse): Promise<{ subject: string; email?: string; displayName: string }> {
  const response = await fetch(discovery.userinfo_endpoint!, {
    headers: { authorization: `Bearer ${token.access_token}` }
  });
  if (!response.ok) throw new Error(`UserInfo endpoint returned ${response.status}`);
  const claims = (await response.json()) as OidcClaims;
  if (typeof claims.sub !== "string" || claims.sub.length === 0) throw new Error("UserInfo response is missing sub");
  const email = typeof claims.email === "string" ? normalizeEmail(claims.email) : undefined;
  const name = typeof claims.name === "string" ? normalizeDisplayName(claims.name) : undefined;
  const preferredUsername = typeof claims.preferred_username === "string" ? normalizeDisplayName(claims.preferred_username) : undefined;
  return {
    subject: claims.sub,
    email,
    displayName: name ?? preferredUsername ?? email?.split("@")[0] ?? claims.sub
  };
}

async function fetchJson<T>(url: string): Promise<T> {
  const response = await fetch(url, { headers: { accept: "application/json" } });
  if (!response.ok) throw new Error(`${url} returned ${response.status}`);
  return (await response.json()) as T;
}

function upsertOidcUser(store: StateStore, config: OidcProviderConfig, claims: { subject: string; email?: string; displayName: string }): { user: User; identity: AuthIdentity } {
  const existingIdentity = store.state.identities.find((identity) => identity.provider === "oidc" && identity.issuer === config.issuer && identity.subject === claims.subject);
  if (existingIdentity) {
    const user = store.state.users.find((item) => item.id === existingIdentity.userId);
    if (!user) throw new Error("OIDC identity points to a missing user");
    if (claims.email && user.email !== claims.email) {
      user.email = claims.email;
      user.updatedAt = nowIso();
    }
    existingIdentity.email = claims.email;
    existingIdentity.updatedAt = nowIso();
    return { user, identity: existingIdentity };
  }

  let user = claims.email ? store.state.users.find((item) => normalizeEmail(item.email) === claims.email) : undefined;
  if (!user) {
    user = createTimestamped("usr", {
      displayName: claims.displayName,
      email: claims.email
    }) satisfies User;
    store.state.users.push(user);
  }
  const identity = createTimestamped("ident", {
    userId: user.id,
    provider: "oidc" as const,
    issuer: config.issuer,
    subject: claims.subject,
    email: claims.email
  }) satisfies AuthIdentity;
  store.state.identities.push(identity);
  return { user, identity };
}

function publicIdentity(identity: AuthIdentity): Omit<AuthIdentity, "createdAt" | "updatedAt"> {
  return {
    id: identity.id,
    userId: identity.userId,
    provider: identity.provider,
    issuer: identity.issuer,
    subject: identity.subject,
    email: identity.email
  };
}

function pruneExpiredOAuthStates(store: StateStore): void {
  const now = Date.now();
  store.state.oauthStates = store.state.oauthStates.filter((state) => Date.parse(state.expiresAt) > now);
}

function oidcTokenAuthMethod(value: string | undefined, clientSecret: string | undefined): OidcProviderConfig["tokenAuth"] {
  if (value === "client_secret_post" || value === "none") return value;
  if (value === "client_secret_basic") return value;
  return clientSecret ? "client_secret_basic" : "none";
}

function requestBaseUrl(headers: Record<string, string | string[] | undefined>): string {
  const configured = process.env.OTTE_PUBLIC_URL?.replace(/\/+$/, "");
  if (configured) return configured;
  const proto = headerValue(headers["x-forwarded-proto"]) ?? "http";
  const host = headerValue(headers["x-forwarded-host"]) ?? headerValue(headers.host) ?? "localhost:4000";
  return `${proto}://${host}`;
}

function sanitizeReturnTo(value: string | undefined): string | undefined {
  if (!value) return undefined;
  try {
    const url = new URL(value);
    const allowedOrigins = new Set(
      [
        process.env.OTTE_WEB_ORIGIN,
        ...(process.env.OTTE_OIDC_ALLOWED_RETURN_ORIGINS?.split(",") ?? [])
      ]
        .map((origin) => origin?.trim().replace(/\/+$/, ""))
        .filter((origin): origin is string => Boolean(origin))
    );
    if (isLocalhostUrl(url) || allowedOrigins.has(url.origin)) return url.toString();
  } catch {
    return undefined;
  }
  return undefined;
}

function ssoRedirectUrl(returnTo: string, token: string, userId: string): string {
  const url = new URL(returnTo);
  url.hash = new URLSearchParams({
    ssoToken: token,
    ssoUserId: userId
  }).toString();
  return url.toString();
}

function isAllowedIssuerUrl(value: string): boolean {
  if (process.env.OTTE_OIDC_ALLOW_INSECURE === "true") return true;
  const url = new URL(value);
  return url.protocol === "https:" || isLocalhostUrl(url);
}

function isLocalhostUrl(url: URL): boolean {
  return url.hostname === "localhost" || url.hostname === "127.0.0.1" || url.hostname === "::1";
}

function base64Url(input: Buffer): string {
  return input.toString("base64url");
}

function errorMessage(error: unknown): string {
  if (error instanceof Error) return error.message;
  if (isRecord(error) && typeof error.message === "string") return error.message;
  return String(error);
}

function findLoginUser(store: StateStore, input: { userId?: string; email?: string }): User | undefined {
  const email = normalizeEmail(input.email);
  if (email !== undefined) return store.state.users.find((user) => normalizeEmail(user.email) === email);
  if (input.userId && legacyUserHeaderEnabled()) return store.state.users.find((user) => user.id === input.userId);
  return undefined;
}

function isValidLoginInput(value: unknown): value is { userId?: string; email?: string; password?: string; mfaCode?: string; recoveryCode?: string } {
  if (!isRecord(value)) return false;
  return [value.userId, value.email, value.password, value.mfaCode, value.recoveryCode].every(isOptionalString);
}

function allowPasswordlessDevelopmentLogin(input: { password?: string; mfaCode?: string; recoveryCode?: string }): boolean {
  return process.env.NODE_ENV !== "production" && input.password === undefined && input.mfaCode === undefined && input.recoveryCode === undefined;
}

function resolveInviteUser(store: StateStore, headers: Record<string, string | string[] | undefined>, input: { userId?: string; email?: string; displayName?: string; password?: string; mfaCode?: string; recoveryCode?: string }, reply: FastifyReply): User | FastifyReply {
  const session = sessionFromRequest(store, undefined, headers);
  if (session) {
    const sessionUser = store.state.users.find((user) => user.id === session.userId);
    return sessionUser ?? unauthorized(reply, "Unknown user session");
  }

  const existingUser = findLoginUser(store, input);
  if (existingUser) {
    if (existingUser.passwordResetRequired) return forbidden(reply, "Password reset required");
    if (!existingUser.passwordHash && !allowPasswordlessDevelopmentLogin(input)) return unauthorized(reply, "Invalid login credentials");
    if (existingUser.passwordHash && !verifyPassword(input.password ?? "", existingUser.passwordHash)) return unauthorized(reply, "Invalid login credentials");
    const mfaResult = verifyLoginMfa(existingUser, input.mfaCode, input.recoveryCode);
    if (mfaResult === "required") return reply.code(401).send({ error: "mfa_required", message: "MFA code required", mfaRequired: true, userId: existingUser.id });
    if (mfaResult === "invalid") return unauthorized(reply, "Invalid MFA code");
    return existingUser;
  }
  if (input.userId) return unauthorized(reply, "Unknown login identity");

  const email = normalizeEmail(input.email);
  if (!email) return badRequest(reply, "A valid email is required");
  if (!isUsablePassword(input.password)) return badRequest(reply, "Password must be at least 8 characters");
  const displayName = normalizeDisplayName(input.displayName) ?? email.split("@")[0] ?? "Player";
  const user = createTimestamped("usr", {
    displayName,
    email,
    passwordHash: hashPassword(input.password)
  }) satisfies User;
  store.state.users.push(user);
  return user;
}

async function issuePasswordReset(store: StateStore, user: User, requestedByUserId: string | undefined, requestedReturnTo: string | undefined): Promise<{ reset: PasswordResetToken; email: EmailOutboxMessage; token: string }> {
  if (!user.email) throw new Error("User does not have an email address");
  pruneExpiredPasswordResetTokens(store);
  const token = `opr_${randomBytes(32).toString("base64url")}`;
  const reset = createTimestamped("reset", {
    userId: user.id,
    email: normalizeEmail(user.email)!,
    tokenHash: hashSessionToken(token),
    expiresAt: new Date(Date.now() + passwordResetTtlMs()).toISOString(),
    requestedByUserId
  }) satisfies PasswordResetToken;
  store.state.passwordResetTokens.push(reset);

  const resetUrl = passwordResetUrl(token, requestedReturnTo);
  const email = createTimestamped("email", {
    to: reset.email,
    subject: "Reset your OpenTabletop password",
    text: [
      `A password reset was requested for ${user.displayName}.`,
      resetUrl ? `Open this link to reset your password: ${resetUrl}` : `Use this reset token: ${token}`,
      "If you did not request this, you can ignore this message."
    ].join("\n\n"),
    status: "pending" as const,
    provider: emailWebhookUrl() ? "webhook" as const : "outbox" as const,
    metadata: {
      kind: "password_reset",
      userId: user.id,
      resetId: reset.id
    }
  }) satisfies EmailOutboxMessage;
  store.state.emailOutbox.push(email);
  await deliverEmailMessage(email);
  return { reset, email, token };
}

function confirmPasswordReset(store: StateStore, token: string | undefined, password: string): { token: string; session: UserSession; user: User } {
  if (!token) throw new Error("Missing password reset token");
  pruneExpiredPasswordResetTokens(store);
  const tokenHash = hashSessionToken(token);
  const reset = store.state.passwordResetTokens.find((item) => item.tokenHash === tokenHash && !item.usedAt && Date.parse(item.expiresAt) > Date.now());
  if (!reset) throw new Error("Unknown or expired password reset token");
  const user = store.state.users.find((item) => item.id === reset.userId);
  if (!user) throw new Error("Password reset user is missing");
  if (isDisabledUser(user)) throw new Error("User account is disabled");
  setUserPassword(user, password, false);
  const now = nowIso();
  reset.usedAt = now;
  reset.updatedAt = now;
  store.state.sessions = store.state.sessions.filter((session) => session.userId !== user.id);
  const session = createUserSession(store, user.id);
  return {
    token: session.token,
    session: session.session,
    user
  };
}

function setUserPassword(user: User, password: string, passwordResetRequired: boolean): void {
  const now = nowIso();
  user.passwordHash = hashPassword(password);
  user.passwordUpdatedAt = now;
  user.passwordResetRequired = passwordResetRequired;
  user.updatedAt = now;
}

type MfaVerificationResult = "ok" | "required" | "invalid";

function verifyLoginMfa(user: User, mfaCode: string | undefined, recoveryCode: string | undefined): MfaVerificationResult {
  if (!isTotpEnabled(user.mfa)) return "ok";
  if (verifyTotpCode(user.mfa.totpSecret, mfaCode)) {
    markMfaVerified(user);
    return "ok";
  }
  if (consumeRecoveryCode(user, recoveryCode)) {
    markMfaVerified(user);
    return "ok";
  }
  return mfaCode || recoveryCode ? "invalid" : "required";
}

function markMfaVerified(user: User): void {
  if (!user.mfa) return;
  const now = nowIso();
  user.mfa.lastVerifiedAt = now;
  user.updatedAt = now;
}

function isTotpEnabled(mfa: UserMfaSettings | undefined): mfa is UserMfaSettings & { totpSecret: string; totpEnabledAt: string } {
  return Boolean(mfa?.totpSecret && mfa.totpEnabledAt);
}

function publicMfaInfo(mfa: UserMfaSettings | undefined): PublicMfaInfo {
  return {
    totpEnabled: isTotpEnabled(mfa),
    totpPending: Boolean(mfa?.totpSecret && mfa.totpPendingAt && !mfa.totpEnabledAt),
    recoveryCodeCount: mfa?.recoveryCodeHashes?.length ?? 0,
    enabledAt: mfa?.totpEnabledAt,
    lastVerifiedAt: mfa?.lastVerifiedAt
  };
}

function generateTotpSecret(): string {
  return base32Encode(randomBytes(20));
}

function totpUri(user: User, secret: string): string {
  const issuer = "OpenTabletop";
  const label = encodeURIComponent(`${issuer}:${user.email ?? user.displayName}`);
  const params = new URLSearchParams({
    secret,
    issuer,
    algorithm: "SHA1",
    digits: "6",
    period: "30"
  });
  return `otpauth://totp/${label}?${params.toString()}`;
}

function verifyTotpCode(secret: string | undefined, code: unknown, nowMs = Date.now()): boolean {
  const normalizedCode = typeof code === "string" ? code.trim() : undefined;
  if (!secret || !normalizedCode || !/^\d{6}$/.test(normalizedCode)) return false;
  const counter = Math.floor(nowMs / 30_000);
  for (let offset = -1; offset <= 1; offset += 1) {
    if (totpCode(secret, counter + offset) === normalizedCode) return true;
  }
  return false;
}

function totpCode(secret: string, counter: number): string {
  const counterBytes = Buffer.alloc(8);
  counterBytes.writeUInt32BE(Math.floor(counter / 0x100000000), 0);
  counterBytes.writeUInt32BE(counter % 0x100000000, 4);
  const digest = createHmac("sha1", base32Decode(secret)).update(counterBytes).digest();
  const offset = digest[digest.length - 1]! & 0x0f;
  const binary = ((digest[offset]! & 0x7f) << 24) | ((digest[offset + 1]! & 0xff) << 16) | ((digest[offset + 2]! & 0xff) << 8) | (digest[offset + 3]! & 0xff);
  return String(binary % 1_000_000).padStart(6, "0");
}

function generateRecoveryCodes(): string[] {
  return Array.from({ length: 8 }, () => `otr-${randomBytes(4).toString("hex")}-${randomBytes(4).toString("hex")}`);
}

function consumeRecoveryCode(user: User, recoveryCode: string | undefined): boolean {
  const code = normalizeRecoveryCode(recoveryCode);
  const hashes = user.mfa?.recoveryCodeHashes;
  if (!code || !hashes?.length) return false;
  const codeHash = hashSessionToken(code);
  const index = hashes.findIndex((hash: string) => safeStringEqual(hash, codeHash));
  if (index < 0) return false;
  hashes.splice(index, 1);
  user.mfa!.recoveryCodesUpdatedAt = nowIso();
  return true;
}

function normalizeRecoveryCode(value: unknown): string | undefined {
  const normalized = typeof value === "string" ? value.trim().toLowerCase() : undefined;
  return normalized || undefined;
}

function safeStringEqual(left: string, right: string): boolean {
  const leftBytes = Buffer.from(left);
  const rightBytes = Buffer.from(right);
  return leftBytes.length === rightBytes.length && timingSafeEqual(leftBytes, rightBytes);
}

const base32Alphabet = "ABCDEFGHIJKLMNOPQRSTUVWXYZ234567";

function base32Encode(input: Buffer): string {
  let output = "";
  let value = 0;
  let bits = 0;
  for (const byte of input) {
    value = (value << 8) | byte;
    bits += 8;
    while (bits >= 5) {
      output += base32Alphabet[(value >>> (bits - 5)) & 31];
      bits -= 5;
      value &= (1 << bits) - 1;
    }
  }
  if (bits > 0) output += base32Alphabet[(value << (5 - bits)) & 31];
  return output;
}

function base32Decode(input: string): Buffer {
  const clean = input.toUpperCase().replace(/[=\s-]/g, "");
  const bytes: number[] = [];
  let value = 0;
  let bits = 0;
  for (const char of clean) {
    const index = base32Alphabet.indexOf(char);
    if (index < 0) throw new Error("Invalid base32 character");
    value = (value << 5) | index;
    bits += 5;
    if (bits >= 8) {
      bytes.push((value >>> (bits - 8)) & 0xff);
      bits -= 8;
      value &= (1 << bits) - 1;
    }
  }
  return Buffer.from(bytes);
}

function setUserDisabled(store: StateStore, user: User, disabled: boolean, adminUserId: string, reason: string | undefined): void {
  const now = nowIso();
  if (disabled) {
    user.disabledAt = user.disabledAt ?? now;
    user.disabledByUserId = adminUserId;
    user.disabledReason = normalizeDisplayName(reason) ?? reason?.trim().slice(0, 160);
    store.state.sessions = store.state.sessions.filter((session) => session.userId !== user.id);
  } else {
    user.disabledAt = undefined;
    user.disabledByUserId = undefined;
    user.disabledReason = undefined;
  }
  user.updatedAt = now;
}

function passwordResetUrl(token: string, requestedReturnTo: string | undefined): string | undefined {
  const configured = process.env.OTTE_PASSWORD_RESET_URL?.trim();
  const returnTo = configured || sanitizeReturnTo(requestedReturnTo) || (process.env.OTTE_WEB_ORIGIN ? `${process.env.OTTE_WEB_ORIGIN.replace(/\/+$/, "")}/reset-password` : undefined);
  if (!returnTo) return undefined;
  try {
    const url = new URL(returnTo);
    url.searchParams.set("token", token);
    return url.toString();
  } catch {
    return undefined;
  }
}

async function deliverEmailMessage(message: EmailOutboxMessage): Promise<void> {
  const webhookUrl = emailWebhookUrl();
  if (!webhookUrl) return;
  try {
    const headers: Record<string, string> = { "content-type": "application/json" };
    const token = process.env.OTTE_EMAIL_WEBHOOK_TOKEN;
    if (token) headers.authorization = `Bearer ${token}`;
    const response = await fetch(webhookUrl, {
      method: "POST",
      headers,
      body: JSON.stringify(publicEmailOutboxMessage(message)),
      signal: AbortSignal.timeout(emailWebhookTimeoutMs())
    });
    if (!response.ok) throw new Error(`Email webhook returned ${response.status}`);
    message.status = "delivered";
    message.sentAt = nowIso();
  } catch (error) {
    message.status = "failed";
    message.error = errorMessage(error).slice(0, 500);
  }
  message.updatedAt = nowIso();
}

async function retryEmailOutboxMessages(store: StateStore, body: AdminEmailOutboxRetryAllBody) {
  const dryRun = body.dryRun === true;
  const statuses = normalizeEmailOutboxRetryStatuses(body.status);
  const limit = normalizeEmailOutboxRetryLimit(body.limit);
  const retryable = store.state.emailOutbox
    .filter((message) => statuses.has(message.status))
    .sort((a, b) => Date.parse(a.createdAt) - Date.parse(b.createdAt));
  const selected = retryable.slice(0, limit);
  const skipped = Math.max(0, retryable.length - selected.length);
  const messages: Array<{
    id: string;
    to: string;
    subject: string;
    before: EmailOutboxMessage["status"];
    after: EmailOutboxMessage["status"];
    provider: EmailOutboxMessage["provider"];
    error?: string;
  }> = [];

  for (const message of selected) {
    const before = message.status;
    if (!dryRun) await deliverEmailMessage(message);
    messages.push({
      id: message.id,
      to: message.to,
      subject: message.subject,
      before,
      after: dryRun ? before : message.status,
      provider: message.provider,
      error: dryRun ? message.error : message.error
    });
  }

  return {
    dryRun,
    limit,
    statuses: Array.from(statuses),
    matched: retryable.length,
    retried: dryRun ? 0 : selected.length,
    planned: dryRun ? selected.length : 0,
    delivered: dryRun ? 0 : selected.filter((message) => message.status === "delivered").length,
    failed: dryRun ? 0 : selected.filter((message) => message.status === "failed").length,
    skipped,
    messages
  };
}

function normalizeEmailOutboxRetryStatuses(status: AdminEmailOutboxRetryAllBody["status"]): Set<EmailOutboxMessage["status"]> {
  if (status === "pending") return new Set(["pending"]);
  if (status === "failed") return new Set(["failed"]);
  return new Set(["pending", "failed"]);
}

function normalizeEmailOutboxRetryLimit(value: unknown): number {
  const limit = Number(value ?? 25);
  if (!Number.isFinite(limit)) return 25;
  return Math.max(1, Math.min(100, Math.floor(limit)));
}

function emailWebhookUrl(): string | undefined {
  return process.env.OTTE_EMAIL_WEBHOOK_URL?.trim() || undefined;
}

function emailWebhookTimeoutMs(): number {
  const value = Number(process.env.OTTE_EMAIL_WEBHOOK_TIMEOUT_MS);
  return Number.isFinite(value) ? Math.max(500, Math.min(30_000, value)) : 5_000;
}

function passwordResetTtlMs(): number {
  const value = Number(process.env.OTTE_PASSWORD_RESET_TTL_MINUTES);
  const minutes = Number.isFinite(value) ? Math.max(5, Math.min(24 * 60, value)) : 60;
  return minutes * 60 * 1000;
}

function sessionTtlDays(): number {
  const value = Number(process.env.OTTE_SESSION_TTL_DAYS);
  return Number.isFinite(value) ? Math.max(1, Math.min(90, value)) : 7;
}

function authRuntimeNumberEnv(name: string): { name: string; configured: boolean; value?: number } {
  const rawValue = process.env[name]?.trim();
  if (!rawValue) return { name, configured: false };
  const value = Number(rawValue);
  return Number.isFinite(value) && value >= 0 ? { name, configured: true, value } : { name, configured: true };
}

function invalidAuthRuntimeNumericEnvNames(): string[] {
  return ["OTTE_EMAIL_WEBHOOK_TIMEOUT_MS", "OTTE_PASSWORD_RESET_TTL_MINUTES"]
    .map(authRuntimeNumberEnv)
    .filter((item) => item.configured && item.value === undefined)
    .map((item) => item.name);
}

function runtimeUrlConfig(name: string): RuntimeUrlConfig {
  const value = envText(name);
  if (!value) return { configured: false, valid: true, insecureInProduction: false };
  try {
    const url = new URL(value);
    const valid = url.protocol === "http:" || url.protocol === "https:";
    const insecureInProduction = process.env.NODE_ENV === "production" && url.protocol === "http:" && !isLocalhostUrl(url);
    return { configured: true, valid, insecureInProduction };
  } catch {
    return { configured: true, valid: false, insecureInProduction: false };
  }
}

function authRuntimeUrlPosture() {
  const passwordResetUrl = runtimeUrlConfig("OTTE_PASSWORD_RESET_URL");
  const webOrigin = runtimeUrlConfig("OTTE_WEB_ORIGIN");
  const emailWebhookUrl = runtimeUrlConfig("OTTE_EMAIL_WEBHOOK_URL");
  const emailWebhookTokenConfigured = Boolean(envText("OTTE_EMAIL_WEBHOOK_TOKEN"));
  const invalidNumericConfig = invalidAuthRuntimeNumericEnvNames();
  const invalidUrlConfig = [
    passwordResetUrl.configured && !passwordResetUrl.valid ? "OTTE_PASSWORD_RESET_URL" : undefined,
    webOrigin.configured && !webOrigin.valid ? "OTTE_WEB_ORIGIN" : undefined,
    emailWebhookUrl.configured && !emailWebhookUrl.valid ? "OTTE_EMAIL_WEBHOOK_URL" : undefined
  ].filter((name): name is string => Boolean(name));
  const insecureUrlConfig = [
    passwordResetUrl.insecureInProduction ? "OTTE_PASSWORD_RESET_URL" : undefined,
    webOrigin.insecureInProduction ? "OTTE_WEB_ORIGIN" : undefined,
    emailWebhookUrl.insecureInProduction ? "OTTE_EMAIL_WEBHOOK_URL" : undefined
  ].filter((name): name is string => Boolean(name));
  const passwordResetLinkMissingInProduction = process.env.NODE_ENV === "production" && !passwordResetUrl.configured && !webOrigin.configured;
  const emailWebhookTokenMissingInProduction = process.env.NODE_ENV === "production" && emailWebhookUrl.configured && emailWebhookUrl.valid && !emailWebhookTokenConfigured;
  return {
    invalidUrlConfig,
    insecureUrlConfig,
    invalidNumericConfig,
    passwordReset: {
      configured: passwordResetUrl.configured,
      valid: passwordResetUrl.valid,
      insecureInProduction: passwordResetUrl.insecureInProduction,
      webOriginConfigured: webOrigin.configured,
      webOriginValid: webOrigin.valid,
      webOriginInsecureInProduction: webOrigin.insecureInProduction,
      linkMissingInProduction: passwordResetLinkMissingInProduction,
      ttlMinutes: Math.floor(passwordResetTtlMs() / 60_000)
    },
    emailWebhook: {
      configured: emailWebhookUrl.configured,
      valid: emailWebhookUrl.valid,
      insecureInProduction: emailWebhookUrl.insecureInProduction,
      tokenConfigured: emailWebhookTokenConfigured,
      tokenMissingInProduction: emailWebhookTokenMissingInProduction,
      timeoutMs: emailWebhookTimeoutMs()
    }
  };
}

function authSessionRuntimePosture() {
  const sessionTtl = authRuntimeNumberEnv("OTTE_SESSION_TTL_DAYS");
  return {
    ttlDays: sessionTtlDays(),
    invalidNumericConfig: sessionTtl.configured && sessionTtl.value === undefined ? ["OTTE_SESSION_TTL_DAYS"] : []
  };
}

function oidcRuntimePosture(): {
  configured: boolean;
  issuerConfigured: boolean;
  clientIdConfigured: boolean;
  clientSecretConfigured: boolean;
  redirectUriConfigured: boolean;
  allowedReturnOriginsConfigured: boolean;
  allowInsecureIssuer: boolean;
  tokenAuth: OidcProviderConfig["tokenAuth"];
  invalidConfig: string[];
  insecureConfig: string[];
  missingInProduction: boolean;
} {
  const issuer = envText("OTTE_OIDC_ISSUER")?.replace(/\/+$/, "");
  const clientId = envText("OTTE_OIDC_CLIENT_ID");
  const clientSecret = envText("OTTE_OIDC_CLIENT_SECRET");
  const redirectUri = runtimeUrlConfig("OTTE_OIDC_REDIRECT_URI");
  const tokenAuthValue = envText("OTTE_OIDC_TOKEN_AUTH");
  const tokenAuth = oidcTokenAuthMethod(tokenAuthValue, clientSecret);
  const allowInsecureIssuer = process.env.OTTE_OIDC_ALLOW_INSECURE === "true";
  const invalidConfig: string[] = [];
  const insecureConfig: string[] = [];
  let issuerAllowed = true;

  if (issuer) {
    try {
      const issuerUrl = new URL(issuer);
      const supportedProtocol = issuerUrl.protocol === "http:" || issuerUrl.protocol === "https:";
      issuerAllowed = supportedProtocol && (issuerUrl.protocol === "https:" || isLocalhostUrl(issuerUrl) || allowInsecureIssuer);
      if (!issuerAllowed) invalidConfig.push("OTTE_OIDC_ISSUER");
      if (process.env.NODE_ENV === "production" && issuerUrl.protocol === "http:" && !isLocalhostUrl(issuerUrl)) insecureConfig.push("OTTE_OIDC_ISSUER");
    } catch {
      issuerAllowed = false;
      invalidConfig.push("OTTE_OIDC_ISSUER");
    }
  }
  if (issuer && !clientId) invalidConfig.push("OTTE_OIDC_CLIENT_ID");
  if (clientId && !issuer) invalidConfig.push("OTTE_OIDC_ISSUER");
  if (redirectUri.configured && !redirectUri.valid) invalidConfig.push("OTTE_OIDC_REDIRECT_URI");
  if (redirectUri.insecureInProduction) insecureConfig.push("OTTE_OIDC_REDIRECT_URI");
  if (tokenAuthValue && tokenAuthValue !== "client_secret_basic" && tokenAuthValue !== "client_secret_post" && tokenAuthValue !== "none") invalidConfig.push("OTTE_OIDC_TOKEN_AUTH");
  if ((tokenAuthValue === "client_secret_basic" || tokenAuthValue === "client_secret_post") && !clientSecret) invalidConfig.push("OTTE_OIDC_CLIENT_SECRET");

  const configured = Boolean(issuer && clientId && issuerAllowed);
  return {
    configured,
    issuerConfigured: Boolean(issuer),
    clientIdConfigured: Boolean(clientId),
    clientSecretConfigured: Boolean(clientSecret),
    redirectUriConfigured: redirectUri.configured,
    allowedReturnOriginsConfigured: Boolean(envText("OTTE_OIDC_ALLOWED_RETURN_ORIGINS")),
    allowInsecureIssuer,
    tokenAuth,
    invalidConfig: [...new Set(invalidConfig)],
    insecureConfig: [...new Set(insecureConfig)],
    missingInProduction: process.env.NODE_ENV === "production" && !configured
  };
}

function scimRuntimePosture(store?: StateStore): {
  configured: boolean;
  bearerTokenConfigured: boolean;
  serviceProviderConfigPath: string;
  usersPath: string;
  groupsPath: string;
  userCount: number;
  groupCount: number;
  mappingCount: number;
  matchedMappingCount: number;
} {
  const mappings = store?.state.scimGroupRoleMappings ?? [];
  return {
    configured: Boolean(envText("OTTE_SCIM_BEARER_TOKEN")),
    bearerTokenConfigured: Boolean(envText("OTTE_SCIM_BEARER_TOKEN")),
    serviceProviderConfigPath: "/api/v1/scim/v2/ServiceProviderConfig",
    usersPath: "/api/v1/scim/v2/Users",
    groupsPath: "/api/v1/scim/v2/Groups",
    userCount: store?.state.users.filter((user) => Boolean(user.scim)).length ?? 0,
    groupCount: store?.state.scimGroups.length ?? 0,
    mappingCount: mappings.length,
    matchedMappingCount: store ? mappings.filter((mapping) => Boolean(findGroupForScimGroupRoleMapping(store, mapping))).length : 0
  };
}

function publicPasswordResetToken(reset: PasswordResetToken): Omit<PasswordResetToken, "tokenHash"> {
  const { tokenHash: _tokenHash, ...safeReset } = reset;
  return safeReset;
}

function publicEmailOutboxMessage(message: EmailOutboxMessage): EmailOutboxMessage {
  return {
    ...message,
    metadata: message.metadata ? { ...message.metadata } : undefined
  };
}

interface AdminSessionRiskQuery {
  staleDays?: string | number;
}

interface AdminSessionRiskRevokeBody {
  staleDays?: string | number;
  dryRun?: boolean;
  reasons?: AdminSessionRiskReason[];
}

interface AdminSessionPruneBody {
  dryRun?: boolean;
}

interface AdminPasswordResetPruneBody {
  dryRun?: boolean;
  includeExpired?: boolean;
  includeUsed?: boolean;
}

interface AdminEmailOutboxRetryAllBody {
  dryRun?: boolean;
  status?: "pending" | "failed" | "retryable";
  limit?: number;
}

type AdminSessionRiskReason = "expired" | "stale" | "disabled_user" | "unknown_user";

interface AdminSessionRiskItem {
  session: ReturnType<typeof publicSession>;
  user: PublicUser | { id: string; displayName: string };
  reasons: AdminSessionRiskReason[];
  lastSeenAgeDays?: number;
  expiresInMs: number;
}

function adminSessionRiskReport(store: StateStore, staleDays: number): {
  generatedAt: string;
  staleDays: number;
  totals: {
    totalSessionCount: number;
    activeSessionCount: number;
    expiredSessionCount: number;
    staleSessionCount: number;
    disabledUserSessionCount: number;
    unknownUserSessionCount: number;
    riskSessionCount: number;
  };
  sessions: AdminSessionRiskItem[];
} {
  const now = Date.now();
  const staleMs = staleDays * 24 * 60 * 60 * 1000;
  const sessions: AdminSessionRiskItem[] = [];
  const totals = {
    totalSessionCount: store.state.sessions.length,
    activeSessionCount: 0,
    expiredSessionCount: 0,
    staleSessionCount: 0,
    disabledUserSessionCount: 0,
    unknownUserSessionCount: 0,
    riskSessionCount: 0
  };

  for (const session of store.state.sessions) {
    const user = store.state.users.find((item) => item.id === session.userId);
    const expiresAt = Date.parse(session.expiresAt);
    const lastSeenAt = Date.parse(session.lastSeenAt);
    const expired = !Number.isFinite(expiresAt) || expiresAt <= now;
    const lastSeenAgeMs = Number.isFinite(lastSeenAt) ? now - lastSeenAt : undefined;
    const stale = !expired && lastSeenAgeMs !== undefined && lastSeenAgeMs >= staleMs;
    const reasons: AdminSessionRiskReason[] = [];

    if (expired) {
      totals.expiredSessionCount += 1;
      reasons.push("expired");
    } else {
      totals.activeSessionCount += 1;
    }
    if (stale) {
      totals.staleSessionCount += 1;
      reasons.push("stale");
    }
    if (user && isDisabledUser(user)) {
      totals.disabledUserSessionCount += 1;
      reasons.push("disabled_user");
    }
    if (!user) {
      totals.unknownUserSessionCount += 1;
      reasons.push("unknown_user");
    }
    if (reasons.length === 0) continue;

    sessions.push({
      session: publicSession(session),
      user: user ? publicUser(user) : { id: session.userId, displayName: "Unknown user" },
      reasons,
      lastSeenAgeDays: lastSeenAgeMs === undefined ? undefined : Math.max(0, Math.floor(lastSeenAgeMs / (24 * 60 * 60 * 1000))),
      expiresInMs: Number.isFinite(expiresAt) ? expiresAt - now : 0
    });
  }

  totals.riskSessionCount = sessions.length;
  return {
    generatedAt: nowIso(),
    staleDays,
    totals,
    sessions
  };
}

function normalizeSessionRiskStaleDays(value: string | number | undefined): number | undefined {
  if (value === undefined || value === "") return 30;
  const staleDays = Number(value);
  if (!Number.isInteger(staleDays) || staleDays < 1 || staleDays > 365) return undefined;
  return staleDays;
}

function normalizeSessionRiskReasons(value: unknown): Set<AdminSessionRiskReason> | undefined {
  const allowed: AdminSessionRiskReason[] = ["expired", "stale", "disabled_user", "unknown_user"];
  if (value === undefined) return new Set(allowed);
  if (!Array.isArray(value)) return undefined;
  const reasons = new Set<AdminSessionRiskReason>();
  for (const item of value) {
    if (typeof item !== "string" || !allowed.includes(item as AdminSessionRiskReason)) return undefined;
    reasons.add(item as AdminSessionRiskReason);
  }
  return reasons;
}

function revokeRiskSessions(store: StateStore, staleDays: number, reasons: Set<AdminSessionRiskReason>, dryRun: boolean) {
  const report = adminSessionRiskReport(store, staleDays);
  const matchedSessions = report.sessions.filter((item) => item.reasons.some((reason) => reasons.has(reason)));
  const matchedSessionIds = new Set(matchedSessions.map((item) => item.session.id));
  if (!dryRun && matchedSessionIds.size > 0) {
    store.state.sessions = store.state.sessions.filter((session) => !matchedSessionIds.has(session.id));
  }
  return {
    generatedAt: nowIso(),
    staleDays,
    dryRun,
    reasons: [...reasons],
    matched: matchedSessionIds.size,
    revoked: dryRun ? 0 : matchedSessionIds.size,
    remainingRiskSessionCount: dryRun ? report.totals.riskSessionCount : adminSessionRiskReport(store, staleDays).totals.riskSessionCount,
    sessions: matchedSessions.map((item) => ({
      session: item.session,
      user: item.user,
      reasons: item.reasons
    }))
  };
}

function summarizeSessionCleanupOperations(auditLogs: AuditLog[]) {
  const riskRevokeRuns = auditLogs
    .filter((log) => log.action === "admin.sessions.riskRevoke")
    .slice()
    .sort(sortTimestampsDesc)
    .map((log) => {
      const after = isRecord(log.after) ? log.after : {};
      return {
        auditLogId: log.id,
        actorUserId: log.actorUserId,
        createdAt: log.createdAt,
        staleDays: numberFromRecord(after, "staleDays", 1, 365) ?? 30,
        dryRun: booleanFromRecord(after, "dryRun") ?? false,
        reasons: Array.isArray(after.reasons) ? after.reasons.filter((reason): reason is AdminSessionRiskReason => typeof reason === "string" && ["expired", "stale", "disabled_user", "unknown_user"].includes(reason)) : [],
        matched: numberFromRecord(after, "matched", 0, 1000000) ?? 0,
        revoked: numberFromRecord(after, "revoked", 0, 1000000) ?? 0
      };
    });
  const singleSessionRevocations = auditLogs.filter((log) => log.action === "admin.session.revoke").length;
  const userSessionRevocations = auditLogs.filter((log) => log.action === "admin.user.sessionsRevoke").length;
  return {
    riskRevokeRunCount: riskRevokeRuns.length,
    riskRevokeDryRunCount: riskRevokeRuns.filter((run) => run.dryRun).length,
    riskRevokeMutationCount: riskRevokeRuns.filter((run) => !run.dryRun).length,
    riskRevokeMatchedCount: riskRevokeRuns.reduce((total, run) => total + run.matched, 0),
    riskRevokeRevokedCount: riskRevokeRuns.reduce((total, run) => total + run.revoked, 0),
    latestRiskRevokeAt: riskRevokeRuns[0]?.createdAt,
    singleSessionRevocationCount: singleSessionRevocations,
    userSessionRevocationRunCount: userSessionRevocations,
    recentRiskRevokeRuns: riskRevokeRuns.slice(0, 10)
  };
}

function adminAuthOperationsSummary(store: StateStore, staleDays: number) {
  const nowMs = Date.now();
  const runtime = publicAuthRuntimeConfig(store);
  const sessionRisk = adminSessionRiskReport(store, staleDays);
  const legacyHeaderUsage = summarizeLegacyUserHeaderUsage(store.state.auditLogs);
  const loginFailures = summarizeAuthLoginFailures(store.state.auditLogs);
  const pendingPasswordResets = store.state.passwordResetTokens.filter((reset) => !reset.usedAt && Date.parse(reset.expiresAt) > nowMs);
  const expiredPasswordResets = store.state.passwordResetTokens.filter((reset) => !reset.usedAt && Date.parse(reset.expiresAt) <= nowMs);
  const emailStatusCounts = countBy(store.state.emailOutbox, (message) => message.status);
  const emailOutboxOperations = summarizeEmailOutboxOperations(store.state.emailOutbox, nowMs);
  const failedEmailCount = emailStatusCounts.failed ?? 0;
  const pendingEmailCount = emailStatusCounts.pending ?? 0;
  const usersWithPassword = store.state.users.filter((user) => Boolean(user.passwordHash)).length;
  const usersWithMfa = store.state.users.filter((user) => isTotpEnabled(user.mfa)).length;
  const disabledUserSummaries = store.state.users
    .filter(isDisabledUser)
    .map((user) => ({
      id: user.id,
      displayName: user.displayName,
      email: user.email,
      disabledAt: user.disabledAt,
      passwordResetRequired: Boolean(user.passwordResetRequired),
      sessionCount: store.state.sessions.filter((session) => session.userId === user.id).length,
      membershipCount: store.state.members.filter((member) => member.userId === user.id).length,
      identityCount: store.state.identities.filter((identity) => identity.userId === user.id).length
    }))
    .sort((left, right) => right.sessionCount - left.sessionCount || left.displayName.localeCompare(right.displayName) || left.id.localeCompare(right.id));
  const activePasswordUsersWithoutMfa = store.state.users
    .filter((user) => !isDisabledUser(user) && Boolean(user.passwordHash) && !isTotpEnabled(user.mfa))
    .map((user) => ({
      id: user.id,
      displayName: user.displayName,
      email: user.email,
      passwordResetRequired: Boolean(user.passwordResetRequired),
      sessionCount: store.state.sessions.filter((session) => session.userId === user.id).length,
      identityCount: store.state.identities.filter((identity) => identity.userId === user.id).length
    }))
    .sort((left, right) => right.sessionCount - left.sessionCount || left.displayName.localeCompare(right.displayName) || left.id.localeCompare(right.id));
  const disabledUsers = store.state.users.filter(isDisabledUser).length;
  const passwordResetRequiredUsers = store.state.users.filter((user) => user.passwordResetRequired).length;
  const actionReasons = authOperationsActionReasons({
    riskSessionCount: sessionRisk.totals.riskSessionCount,
    disabledUserCount: disabledUsers,
    passwordResetRequiredUserCount: passwordResetRequiredUsers,
    failedEmailCount,
    pendingEmailCount,
    expiredPasswordResetCount: expiredPasswordResets.length,
    legacyUserHeaderUsageCount: legacyHeaderUsage.usageCount,
    blockedLegacyUserHeaderAttemptCount: legacyHeaderUsage.blockedAttemptCount,
    loginFailureCount: loginFailures.failureCount,
    productionLegacyHeaderEnabled: process.env.NODE_ENV === "production" && runtime.legacyUserHeader.enabled,
    invalidAuthUrlConfigCount: runtime.authUrls.invalidUrlConfig.length,
    insecureAuthUrlConfigCount: runtime.authUrls.insecureUrlConfig.length,
    invalidAuthNumericConfigCount: runtime.authUrls.invalidNumericConfig.length,
    invalidAuthSessionNumericConfigCount: runtime.sessions.invalidNumericConfig.length,
    invalidOidcConfigCount: runtime.oidc.invalidConfig.length,
    insecureOidcConfigCount: runtime.oidc.insecureConfig.length,
    productionPasswordResetLinkMissing: runtime.authUrls.passwordReset.linkMissingInProduction,
    productionEmailWebhookTokenMissing: runtime.authUrls.emailWebhook.tokenMissingInProduction,
    productionOidcMissing: runtime.oidc.missingInProduction,
    productionServerAdminsMissing: runtime.serverAdmins.missingInProduction
  });

  return {
    generatedAt: nowIso(),
    actionRequired: actionReasons.length > 0,
    actionReasons,
    remediationQueue: authOperationsRemediationQueue({
      actionReasons,
      sessionRisk,
      disabledUsers: disabledUserSummaries,
      activePasswordUsersWithoutMfa,
      passwordResetRequiredUserCount: passwordResetRequiredUsers,
      failedEmailCount,
      pendingEmailCount,
      expiredPasswordResetCount: expiredPasswordResets.length,
      oldestRetryableEmailAgeSeconds: emailOutboxOperations.oldestRetryableAgeSeconds,
      legacyUserHeaderMode: runtime.legacyUserHeader.mode,
      legacyHeaderUsage,
      loginFailures,
      authUrls: runtime.authUrls,
      authSessions: runtime.sessions,
      oidc: runtime.oidc,
      serverAdmins: runtime.serverAdmins
    }),
    runtime,
    legacyUserHeaderUsage: legacyHeaderUsage,
    loginFailures,
    users: {
      totalUserCount: store.state.users.length,
      activeUserCount: store.state.users.length - disabledUsers,
      disabledUserCount: disabledUsers,
      disabledUsers: disabledUserSummaries.slice(0, 10),
      passwordUserCount: usersWithPassword,
      passwordResetRequiredUserCount: passwordResetRequiredUsers,
      mfaEnabledUserCount: usersWithMfa,
      mfaCoverageRate: ratio(usersWithMfa, store.state.users.length),
      activePasswordUserWithoutMfaCount: activePasswordUsersWithoutMfa.length,
      activePasswordUsersWithoutMfa: activePasswordUsersWithoutMfa.slice(0, 10)
    },
    sessions: {
      staleDays,
      totals: sessionRisk.totals,
      recentRiskSessions: sessionRisk.sessions.slice(0, 10),
      cleanupOperations: summarizeSessionCleanupOperations(store.state.auditLogs)
    },
    passwordResets: {
      activeCount: pendingPasswordResets.length,
      expiredUnusedCount: expiredPasswordResets.length
    },
    emailOutbox: {
      messageCount: store.state.emailOutbox.length,
      statusCounts: emailStatusCounts,
      webhookConfigured: Boolean(emailWebhookUrl()),
      retryableCount: pendingEmailCount + failedEmailCount,
      oldestRetryableAgeSeconds: emailOutboxOperations.oldestRetryableAgeSeconds,
      recentRetryableMessages: emailOutboxOperations.recentRetryableMessages
    },
    identities: {
      identityCount: store.state.identities.length,
      providerCounts: countBy(store.state.identities, (identity) => identity.provider)
    }
  };
}

function authOperationsActionReasons(input: {
  riskSessionCount: number;
  disabledUserCount: number;
  passwordResetRequiredUserCount: number;
  failedEmailCount: number;
  pendingEmailCount: number;
  expiredPasswordResetCount: number;
  legacyUserHeaderUsageCount: number;
  blockedLegacyUserHeaderAttemptCount: number;
  loginFailureCount: number;
  productionLegacyHeaderEnabled: boolean;
  invalidAuthUrlConfigCount: number;
  insecureAuthUrlConfigCount: number;
  invalidAuthNumericConfigCount: number;
  invalidAuthSessionNumericConfigCount: number;
  invalidOidcConfigCount: number;
  insecureOidcConfigCount: number;
  productionPasswordResetLinkMissing: boolean;
  productionEmailWebhookTokenMissing: boolean;
  productionOidcMissing: boolean;
  productionServerAdminsMissing: boolean;
}) {
  return [
    input.invalidAuthUrlConfigCount > 0 ? "auth_runtime_url_config_invalid" : undefined,
    input.insecureAuthUrlConfigCount > 0 ? "auth_runtime_url_insecure" : undefined,
    input.invalidAuthNumericConfigCount > 0 ? "auth_runtime_numeric_config_invalid" : undefined,
    input.invalidAuthSessionNumericConfigCount > 0 ? "auth_session_numeric_config_invalid" : undefined,
    input.invalidOidcConfigCount > 0 ? "auth_oidc_config_invalid" : undefined,
    input.insecureOidcConfigCount > 0 ? "auth_oidc_config_insecure" : undefined,
    input.productionPasswordResetLinkMissing ? "auth_password_reset_link_unconfigured" : undefined,
    input.productionEmailWebhookTokenMissing ? "auth_email_webhook_token_missing" : undefined,
    input.productionOidcMissing ? "auth_oidc_unconfigured_in_production" : undefined,
    input.productionServerAdminsMissing ? "auth_server_admins_unconfigured" : undefined,
    input.riskSessionCount > 0 ? "risk_sessions" : undefined,
    input.disabledUserCount > 0 ? "disabled_users" : undefined,
    input.passwordResetRequiredUserCount > 0 ? "password_reset_required_users" : undefined,
    input.failedEmailCount > 0 ? "failed_email_delivery" : undefined,
    input.pendingEmailCount > 0 ? "pending_email_delivery" : undefined,
    input.expiredPasswordResetCount > 0 ? "expired_password_resets" : undefined,
    input.legacyUserHeaderUsageCount > 0 ? "legacy_user_header_recent_usage" : undefined,
    input.blockedLegacyUserHeaderAttemptCount > 0 ? "legacy_user_header_blocked_attempts" : undefined,
    input.loginFailureCount > 0 ? "auth_login_failures" : undefined,
    input.productionLegacyHeaderEnabled ? "legacy_user_header_enabled_in_production" : undefined
  ].filter((reason): reason is string => Boolean(reason));
}

function authOperationsRemediationQueue(input: {
  actionReasons: string[];
  sessionRisk: ReturnType<typeof adminSessionRiskReport>;
  disabledUsers: Array<{ id: string; displayName: string; email?: string; disabledAt?: string; passwordResetRequired: boolean; sessionCount: number; membershipCount: number; identityCount: number }>;
  activePasswordUsersWithoutMfa: Array<{ id: string; displayName: string; email?: string; passwordResetRequired: boolean; sessionCount: number; identityCount: number }>;
  passwordResetRequiredUserCount: number;
  failedEmailCount: number;
  pendingEmailCount: number;
  expiredPasswordResetCount: number;
  oldestRetryableEmailAgeSeconds: number;
  legacyUserHeaderMode: string;
  legacyHeaderUsage: ReturnType<typeof summarizeLegacyUserHeaderUsage>;
  loginFailures: ReturnType<typeof summarizeAuthLoginFailures>;
  authUrls: ReturnType<typeof authRuntimeUrlPosture>;
  authSessions: ReturnType<typeof authSessionRuntimePosture>;
  oidc: ReturnType<typeof oidcRuntimePosture>;
  serverAdmins: ReturnType<typeof serverAdminRuntimePosture>;
}) {
  const remediations: Array<{
    code: string;
    severity: "warning" | "critical";
    action: string;
    affectedCount: number;
    samples?: Array<Record<string, unknown>>;
  }> = [];
  if (input.authUrls.invalidUrlConfig.length > 0 || input.authUrls.insecureUrlConfig.length > 0) {
    remediations.push({
      code: "fix_auth_runtime_url_configuration",
      severity: input.authUrls.invalidUrlConfig.length > 0 ? "critical" : "warning",
      action: "Fix password-reset, web-origin, or email-webhook URL configuration so auth operations can issue secure reset links and deliver email reliably.",
      affectedCount: input.authUrls.invalidUrlConfig.length + input.authUrls.insecureUrlConfig.length,
      samples: [
        ...input.authUrls.invalidUrlConfig.map((name) => ({ env: name, reason: "invalid_url" })),
        ...input.authUrls.insecureUrlConfig.map((name) => ({ env: name, reason: "insecure_production_http" }))
      ].slice(0, 5)
    });
  }
  if (input.authUrls.invalidNumericConfig.length > 0) {
    remediations.push({
      code: "fix_auth_runtime_numeric_configuration",
      severity: "warning",
      action: "Keep password-reset TTL and email-webhook timeout settings numeric and nonnegative so auth operations do not silently fall back or clamp unexpectedly.",
      affectedCount: input.authUrls.invalidNumericConfig.length,
      samples: input.authUrls.invalidNumericConfig.map((name) => ({ env: name, reason: "invalid_number" })).slice(0, 5)
    });
  }
  if (input.authSessions.invalidNumericConfig.length > 0) {
    remediations.push({
      code: "fix_auth_session_numeric_configuration",
      severity: "warning",
      action: "Keep session TTL settings numeric and nonnegative so production session lifetime does not silently fall back or clamp unexpectedly.",
      affectedCount: input.authSessions.invalidNumericConfig.length,
      samples: input.authSessions.invalidNumericConfig.map((name) => ({ env: name, reason: "invalid_number" })).slice(0, 5)
    });
  }
  if (input.oidc.invalidConfig.length > 0 || input.oidc.insecureConfig.length > 0) {
    remediations.push({
      code: "fix_auth_oidc_configuration",
      severity: input.oidc.invalidConfig.length > 0 ? "critical" : "warning",
      action: "Fix OIDC issuer, client, redirect URI, token-auth, or secret configuration so production SSO can start reliably without exposing provider secrets.",
      affectedCount: input.oidc.invalidConfig.length + input.oidc.insecureConfig.length,
      samples: [
        ...input.oidc.invalidConfig.map((name) => ({ env: name, reason: "invalid_oidc_config" })),
        ...input.oidc.insecureConfig.map((name) => ({ env: name, reason: "insecure_production_http" }))
      ].slice(0, 5)
    });
  }
  if (input.authUrls.passwordReset.linkMissingInProduction) {
    remediations.push({
      code: "configure_auth_password_reset_link",
      severity: "critical",
      action: "Configure OTTE_PASSWORD_RESET_URL or OTTE_WEB_ORIGIN in production so password-reset emails contain browser reset links instead of raw reset tokens.",
      affectedCount: 1,
      samples: [{ env: "OTTE_PASSWORD_RESET_URL", fallbackEnv: "OTTE_WEB_ORIGIN", reason: "missing_production_reset_link" }]
    });
  }
  if (input.authUrls.emailWebhook.tokenMissingInProduction) {
    remediations.push({
      code: "configure_auth_email_webhook_token",
      severity: "critical",
      action: "Configure OTTE_EMAIL_WEBHOOK_TOKEN for the production email webhook so password-reset delivery is authenticated.",
      affectedCount: 1,
      samples: [{ env: "OTTE_EMAIL_WEBHOOK_TOKEN", reason: "missing_production_webhook_token" }]
    });
  }
  if (input.oidc.missingInProduction) {
    remediations.push({
      code: "configure_oidc_sso",
      severity: "warning",
      action: "Configure OTTE_OIDC_ISSUER and OTTE_OIDC_CLIENT_ID for production SSO, or document that this deployment intentionally relies on local password accounts.",
      affectedCount: 1,
      samples: [{ env: "OTTE_OIDC_ISSUER", companionEnv: "OTTE_OIDC_CLIENT_ID", reason: "missing_production_oidc" }]
    });
  }
  if (input.serverAdmins.missingInProduction) {
    remediations.push({
      code: "configure_server_admins",
      severity: "critical",
      action: "Configure OTTE_ADMIN_USER_IDS in production so at least one trusted user can access server-admin operations.",
      affectedCount: 1,
      samples: [{ env: "OTTE_ADMIN_USER_IDS", reason: "missing_production_server_admins" }]
    });
  }
  if (input.actionReasons.includes("legacy_user_header_enabled_in_production")) {
    remediations.push({
      code: "disable_legacy_user_header",
      severity: "critical",
      action: "Disable legacy x-user-id compatibility in production and require bearer or OIDC authentication.",
      affectedCount: 1,
      samples: [{ mode: input.legacyUserHeaderMode }]
    });
  }
  if (input.legacyHeaderUsage.usageCount > 0) {
    remediations.push({
      code: "replace_legacy_user_header_clients",
      severity: "warning",
      action: "Identify recent x-user-id compatibility clients, migrate them to bearer or OIDC sessions, then disable legacy header compatibility.",
      affectedCount: input.legacyHeaderUsage.usageCount,
      samples: input.legacyHeaderUsage.recentSamples.slice(0, 5)
    });
  }
  if (input.legacyHeaderUsage.blockedAttemptCount > 0) {
    remediations.push({
      code: "investigate_blocked_legacy_user_header_clients",
      severity: "warning",
      action: "Investigate clients still attempting x-user-id after compatibility was disabled and migrate them to bearer or OIDC sessions.",
      affectedCount: input.legacyHeaderUsage.blockedAttemptCount,
      samples: input.legacyHeaderUsage.blockedSamples.slice(0, 5)
    });
  }
  if (input.loginFailures.failureCount > 0) {
    const credentialOrMfaFailures = (input.loginFailures.reasonCounts.invalid_credentials ?? 0) + (input.loginFailures.reasonCounts.invalid_mfa ?? 0) + (input.loginFailures.reasonCounts.mfa_required ?? 0);
    remediations.push({
      code: "review_auth_login_failures",
      severity: credentialOrMfaFailures >= 5 ? "critical" : "warning",
      action: "Review recent failed login attempts for disabled accounts, reset-required users, credential failures, and MFA failures.",
      affectedCount: input.loginFailures.failureCount,
      samples: input.loginFailures.recentFailures.slice(0, 5).map((failure) => ({
        userId: failure.userId,
        reason: failure.reason,
        statusCode: failure.statusCode,
        createdAt: failure.createdAt
      }))
    });
  }
  if (input.sessionRisk.totals.riskSessionCount > 0) {
    remediations.push({
      code: "revoke_risk_sessions",
      severity: input.sessionRisk.totals.unknownUserSessionCount > 0 || input.sessionRisk.totals.disabledUserSessionCount > 0 ? "critical" : "warning",
      action: "Review recent risk-session samples, then dry-run and revoke expired, stale, disabled-user, or unknown-user sessions.",
      affectedCount: input.sessionRisk.totals.riskSessionCount,
      samples: input.sessionRisk.sessions.slice(0, 5).map((item) => ({
        sessionId: item.session.id,
        userId: item.user.id,
        reasons: item.reasons,
        lastSeenAgeDays: item.lastSeenAgeDays
      }))
    });
  }
  if (input.disabledUsers.length > 0) {
    remediations.push({
      code: "review_disabled_accounts",
      severity: "warning",
      action: "Review disabled accounts with active sessions or memberships and revoke sessions where access should remain blocked.",
      affectedCount: input.disabledUsers.length,
      samples: input.disabledUsers.slice(0, 5).map((user) => ({
        userId: user.id,
        displayName: user.displayName,
        sessionCount: user.sessionCount,
        membershipCount: user.membershipCount
      }))
    });
  }
  if (input.passwordResetRequiredUserCount > 0) {
    remediations.push({
      code: "complete_required_password_resets",
      severity: "warning",
      action: "Issue reset emails or coordinate password changes for users flagged as requiring a password reset.",
      affectedCount: input.passwordResetRequiredUserCount
    });
  }
  if (input.failedEmailCount > 0 || input.pendingEmailCount > 0) {
    remediations.push({
      code: "retry_auth_email_delivery",
      severity: input.failedEmailCount > 0 ? "warning" : "warning",
      action: "Configure the email webhook if needed and retry failed or pending password-reset delivery messages.",
      affectedCount: input.failedEmailCount + input.pendingEmailCount,
      samples: [{ failed: input.failedEmailCount, pending: input.pendingEmailCount, oldestRetryableAgeSeconds: input.oldestRetryableEmailAgeSeconds }]
    });
  }
  if (input.expiredPasswordResetCount > 0) {
    remediations.push({
      code: "prune_expired_password_resets",
      severity: "warning",
      action: "Dry-run and prune expired password reset tokens so stale reset material does not accumulate.",
      affectedCount: input.expiredPasswordResetCount
    });
  }
  if (input.activePasswordUsersWithoutMfa.length > 0) {
    remediations.push({
      code: "enroll_password_users_in_mfa",
      severity: "warning",
      action: "Ask active password users without MFA to enroll TOTP or move them to SSO-only access.",
      affectedCount: input.activePasswordUsersWithoutMfa.length,
      samples: input.activePasswordUsersWithoutMfa.slice(0, 5).map((user) => ({
        userId: user.id,
        displayName: user.displayName,
        sessionCount: user.sessionCount,
        passwordResetRequired: user.passwordResetRequired
      }))
    });
  }
  return remediations.sort((left, right) => authRemediationSeverityRank(right.severity) - authRemediationSeverityRank(left.severity) || right.affectedCount - left.affectedCount || left.code.localeCompare(right.code)).slice(0, 12);
}

function authRemediationSeverityRank(severity: "warning" | "critical"): number {
  return severity === "critical" ? 2 : 1;
}

function summarizeAuthLoginFailures(auditLogs: AuditLog[]) {
  const logs = auditLogs.filter((log) => log.action === "auth.login.failed").sort(sortTimestampsDesc);
  const failures = logs.map((log) => {
    const after = isRecord(log.after) ? log.after : {};
    const userId = log.actorUserId ?? log.targetId;
    return {
      auditLogId: log.id,
      userId,
      userKnown: Boolean(userId),
      reason: stringFromRecord(after, "reason") ?? "unknown",
      statusCode: numberFromRecord(after, "statusCode", 100, 599) ?? 0,
      createdAt: log.createdAt
    };
  });
  return {
    failureCount: failures.length,
    distinctKnownUserCount: new Set(failures.map((failure) => failure.userId).filter((userId): userId is string => Boolean(userId))).size,
    unknownIdentityCount: failures.filter((failure) => !failure.userKnown || failure.reason === "unknown_identity").length,
    reasonCounts: countBy(failures, (failure) => failure.reason),
    statusCounts: countBy(failures, (failure) => String(failure.statusCode)),
    recentFailures: failures.slice(0, 10)
  };
}

function summarizeLegacyUserHeaderUsage(auditLogs: AuditLog[]) {
  const logs = auditLogs.filter((log) => log.action === "auth.legacyUserHeader").sort(sortTimestampsDesc);
  const acceptedLogs = logs.filter((log) => legacyUserHeaderAuditStatus(log) !== "blocked");
  const blockedLogs = logs.filter((log) => legacyUserHeaderAuditStatus(log) === "blocked");
  const userCounts = countBy(acceptedLogs, (log) => log.actorUserId ?? "unknown");
  const sample = (log: AuditLog) => ({
    auditLogId: log.id,
    userId: log.actorUserId ?? log.targetId ?? "unknown",
    createdAt: log.createdAt,
    mode: (log.after as { mode?: string } | undefined)?.mode ?? "unknown",
    source: (log.after as { source?: string } | undefined)?.source ?? "unknown"
  });
  return {
    usageCount: acceptedLogs.length,
    blockedAttemptCount: blockedLogs.length,
    distinctUserCount: Object.keys(userCounts).length,
    lastSeenAt: acceptedLogs[0]?.createdAt,
    lastBlockedAt: blockedLogs[0]?.createdAt,
    userCounts,
    recentSamples: acceptedLogs.slice(0, 10).map(sample),
    blockedSamples: blockedLogs.slice(0, 10).map(sample)
  };
}

function legacyUserHeaderAuditStatus(log: AuditLog): string {
  return (log.after as { status?: string } | undefined)?.status ?? "accepted";
}

function summarizeEmailOutboxOperations(messages: EmailOutboxMessage[], nowMs: number) {
  const retryable = messages
    .filter((message) => message.status === "pending" || message.status === "failed")
    .sort((a, b) => Date.parse(a.createdAt) - Date.parse(b.createdAt));
  const oldestRetryableAt = retryable[0]?.createdAt;
  return {
    oldestRetryableAgeSeconds: oldestRetryableAt ? Math.max(0, Math.floor((nowMs - Date.parse(oldestRetryableAt)) / 1000)) : 0,
    recentRetryableMessages: retryable.slice(-10).reverse().map(redactedEmailOutboxOperationMessage)
  };
}

function redactedEmailOutboxOperationMessage(message: EmailOutboxMessage) {
  return {
    id: message.id,
    to: message.to,
    subject: message.subject,
    status: message.status,
    provider: message.provider,
    createdAt: message.createdAt,
    updatedAt: message.updatedAt,
    sentAt: message.sentAt,
    error: message.error,
    metadata: message.metadata ? { ...message.metadata } : undefined
  };
}

function adminUserInfo(store: StateStore, user: User): PublicUser & { disabled: boolean; membershipCount: number; identityCount: number; sessionCount: number } {
  return {
    ...publicUser(user),
    disabled: isDisabledUser(user),
    membershipCount: store.state.members.filter((member) => member.userId === user.id).length,
    identityCount: store.state.identities.filter((identity) => identity.userId === user.id).length,
    sessionCount: store.state.sessions.filter((session) => session.userId === user.id && Date.parse(session.expiresAt) > Date.now()).length
  };
}

interface AdminAuditLogOptions {
  filters: {
    campaignId?: string;
    actorUserId?: string;
    actorType?: AuditLog["actorType"];
    action?: string;
    targetType?: string;
    targetId?: string;
    since?: string;
    until?: string;
  };
  limit: number;
  format: "json" | "ndjson";
}

interface ServerAuditLogInput {
  campaignId?: string;
  action: string;
  targetType: string;
  targetId?: string;
  before?: unknown;
  after?: unknown;
}

function appendServerAuditLog(store: StateStore, adminUserId: string, input: ServerAuditLogInput): AuditLog {
  const log = createTimestamped("audit", {
    campaignId: input.campaignId,
    actorUserId: adminUserId,
    actorType: "user" as const,
    action: input.action,
    targetType: input.targetType,
    targetId: input.targetId,
    before: input.before,
    after: input.after
  }) satisfies AuditLog;
  store.state.auditLogs.push(log);
  return log;
}

function normalizeJobType(value: string): JobType | undefined {
  return ADMIN_JOB_TYPES.find((type) => type === value);
}

function normalizeJobStatus(value: string): JobStatus | undefined {
  return ADMIN_JOB_STATUSES.find((status) => status === value);
}

function normalizeAdminJobLimit(value: string | undefined): number | undefined {
  if (value === undefined) return 100;
  const parsed = Number(value);
  if (!Number.isInteger(parsed) || parsed < 1 || parsed > 500) return undefined;
  return parsed;
}

function normalizeAdminJobMaxAttempts(value: unknown): number | undefined {
  if (value === undefined) return ADMIN_JOB_DEFAULT_MAX_ATTEMPTS;
  const parsed = Number(value);
  if (!Number.isInteger(parsed) || parsed < 1 || parsed > ADMIN_JOB_MAX_ATTEMPTS) return undefined;
  return parsed;
}

function normalizeAdminJobLeaseSeconds(value: unknown): number | undefined {
  if (value === undefined) return ADMIN_JOB_DEFAULT_LEASE_SECONDS;
  const parsed = Number(value);
  if (!Number.isInteger(parsed) || parsed < 1 || parsed > ADMIN_JOB_MAX_LEASE_SECONDS) return undefined;
  return parsed;
}

function normalizeWorkerId(value: unknown): string | undefined {
  if (value === undefined) return undefined;
  if (typeof value !== "string") return undefined;
  const normalized = value.trim().slice(0, 120);
  return normalized || undefined;
}

function normalizeJobTypeFilter(value: unknown): { value?: Set<JobType> } | { error: string } {
  if (value === undefined) return { value: undefined };
  if (!Array.isArray(value)) return { error: "types must be an array of supported job types" };
  const types = new Set<JobType>();
  for (const item of value) {
    if (typeof item !== "string") return { error: "types must contain only supported job types" };
    const type = normalizeJobType(item);
    if (!type) return { error: "types must contain only supported job types" };
    types.add(type);
  }
  return { value: types };
}

function leaseNextAdminJob(
  jobs: WorkerJobRecord[],
  input: { workerId: string; leaseSeconds: number; adminUserId: string; types?: Set<JobType> }
): WorkerJobRecord | undefined {
  const nowMs = Date.now();
  const candidates = jobs
    .filter((job) => !input.types || input.types.has(job.type))
    .filter((job) => job.attempts < job.maxAttempts)
    .filter((job) => job.status === "queued" || (job.status === "running" && job.leaseExpiresAt !== undefined && Date.parse(job.leaseExpiresAt) <= nowMs))
    .sort((left, right) => Date.parse(left.queuedAt) - Date.parse(right.queuedAt));
  const job = candidates[0];
  if (!job) return undefined;
  const now = nowIso();
  const wasExpiredLease = job.status === "running";
  job.status = "running";
  job.startedAt = job.startedAt ?? now;
  job.attempts += 1;
  job.leasedBy = input.workerId;
  job.lastHeartbeatAt = now;
  job.leaseExpiresAt = new Date(Date.parse(now) + input.leaseSeconds * 1000).toISOString();
  job.updatedAt = now;
  job.updatedByUserId = input.adminUserId;
  appendJobLog(job, {
    at: now,
    level: wasExpiredLease ? "warning" : "info",
    message: wasExpiredLease ? `Expired lease reclaimed by ${input.workerId}` : `Job leased by ${input.workerId}`
  });
  return job;
}

function adminJobOperations(jobs: WorkerJobRecord[]) {
  const generatedAt = nowIso();
  const nowMs = Date.parse(generatedAt);
  const byStatus = Object.fromEntries(ADMIN_JOB_STATUSES.map((status) => [status, jobs.filter((job) => job.status === status).length])) as Record<JobStatus, number>;
  const byType = Object.fromEntries(ADMIN_JOB_TYPES.map((type) => [type, jobs.filter((job) => job.type === type).length])) as Record<JobType, number>;
  const queuedJobs = jobs.filter((job) => job.status === "queued").sort((left, right) => Date.parse(left.queuedAt) - Date.parse(right.queuedAt));
  const runningJobs = jobs.filter((job) => job.status === "running");
  const failedJobs = jobs.filter((job) => job.status === "failed");
  const retryableJobs = jobs.filter((job) => (job.status === "failed" || job.status === "cancelled") && job.attempts < job.maxAttempts);
  const exhaustedJobs = jobs.filter((job) => job.attempts >= job.maxAttempts && job.status !== "succeeded");
  const expiredLeaseJobs = runningJobs.filter((job) => job.leaseExpiresAt !== undefined && Date.parse(job.leaseExpiresAt) <= nowMs);
  const staleHeartbeatJobs = runningJobs.filter((job) => job.lastHeartbeatAt === undefined || nowMs - Date.parse(job.lastHeartbeatAt) > ADMIN_JOB_STALE_HEARTBEAT_MS);
  const staleQueuedJobs = queuedJobs.filter((job) => nowMs - Date.parse(job.queuedAt) > ADMIN_JOB_STALE_QUEUED_MS);
  const actionReasons = [
    failedJobs.length > 0 ? "failed_jobs" : undefined,
    expiredLeaseJobs.length > 0 ? "expired_job_leases" : undefined,
    staleHeartbeatJobs.length > 0 ? "stale_job_heartbeats" : undefined,
    exhaustedJobs.length > 0 ? "retry_exhausted_jobs" : undefined,
    staleQueuedJobs.length > 0 ? "stale_queued_jobs" : undefined
  ].filter((reason): reason is string => Boolean(reason));
  const workerIds = Array.from(new Set(runningJobs.map((job) => job.leasedBy).filter((workerId): workerId is string => Boolean(workerId)))).sort();
  const workers = workerIds.map((workerId) => {
    const workerJobs = runningJobs.filter((job) => job.leasedBy === workerId);
    const lastHeartbeatAt = workerJobs.reduce<string | undefined>((latest, job) => {
      if (!job.lastHeartbeatAt) return latest;
      return !latest || Date.parse(job.lastHeartbeatAt) > Date.parse(latest) ? job.lastHeartbeatAt : latest;
    }, undefined);
    return {
      workerId,
      runningCount: workerJobs.length,
      lastHeartbeatAt,
      expiredLeaseCount: workerJobs.filter((job) => job.leaseExpiresAt !== undefined && Date.parse(job.leaseExpiresAt) <= nowMs).length,
      staleHeartbeatCount: workerJobs.filter((job) => job.lastHeartbeatAt === undefined || nowMs - Date.parse(job.lastHeartbeatAt) > ADMIN_JOB_STALE_HEARTBEAT_MS).length
    };
  });
  const oldestQueuedAt = queuedJobs[0]?.queuedAt;
  const newestCompletedAt = jobs.reduce<string | undefined>((latest, job) => {
    if (!job.completedAt) return latest;
    return !latest || Date.parse(job.completedAt) > Date.parse(latest) ? job.completedAt : latest;
  }, undefined);
  const maxQueueAgeSeconds = oldestQueuedAt ? Math.max(0, Math.floor((nowMs - Date.parse(oldestQueuedAt)) / 1000)) : 0;
  const remediationQueue = [
    failedJobs.length > 0
      ? {
          code: "retry_or_inspect_failed_jobs",
          severity: "error" as const,
          action: "Inspect failed job errors, retry safe jobs, or cancel jobs that should not run.",
          affectedCount: failedJobs.length,
          samples: failedJobs.slice(0, 5).map(jobOperationSample)
        }
      : undefined,
    expiredLeaseJobs.length > 0
      ? {
          code: "reclaim_expired_job_leases",
          severity: "error" as const,
          action: "Start healthy workers or retry jobs whose worker lease has expired.",
          affectedCount: expiredLeaseJobs.length,
          samples: expiredLeaseJobs.slice(0, 5).map(jobOperationSample)
        }
      : undefined,
    staleHeartbeatJobs.length > 0
      ? {
          code: "investigate_stale_job_workers",
          severity: "warning" as const,
          action: "Check worker processes whose running jobs have not heartbeated recently.",
          affectedCount: staleHeartbeatJobs.length,
          samples: staleHeartbeatJobs.slice(0, 5).map(jobOperationSample)
        }
      : undefined,
    exhaustedJobs.length > 0
      ? {
          code: "resolve_retry_exhausted_jobs",
          severity: "error" as const,
          action: "Inspect exhausted jobs before increasing attempts or recreating work.",
          affectedCount: exhaustedJobs.length,
          samples: exhaustedJobs.slice(0, 5).map(jobOperationSample)
        }
      : undefined,
    staleQueuedJobs.length > 0
      ? {
          code: "increase_job_worker_capacity",
          severity: "warning" as const,
          action: "Start workers or reduce queued work whose queue age exceeds the operations threshold.",
          affectedCount: staleQueuedJobs.length,
          samples: staleQueuedJobs.slice(0, 5).map(jobOperationSample)
        }
      : undefined
  ].filter((item): item is { code: string; severity: "warning" | "error"; action: string; affectedCount: number; samples: Array<Record<string, unknown>> } => Boolean(item));
  return {
    generatedAt,
    actionRequired: actionReasons.length > 0,
    actionReasons,
    thresholds: {
      staleHeartbeatSeconds: Math.floor(ADMIN_JOB_STALE_HEARTBEAT_MS / 1000),
      staleQueuedSeconds: Math.floor(ADMIN_JOB_STALE_QUEUED_MS / 1000)
    },
    totals: {
      totalCount: jobs.length,
      byStatus,
      byType,
      retryableCount: retryableJobs.length,
      exhaustedCount: exhaustedJobs.length
    },
    queue: {
      oldestQueuedAt,
      maxQueueAgeSeconds,
      staleQueuedCount: staleQueuedJobs.length,
      recentQueued: queuedJobs.slice(0, 10).map(jobOperationSample)
    },
    leases: {
      runningCount: runningJobs.length,
      leasedWorkerCount: workerIds.length,
      expiredCount: expiredLeaseJobs.length,
      staleHeartbeatCount: staleHeartbeatJobs.length,
      workers,
      expired: expiredLeaseJobs.slice(0, 10).map(jobOperationSample),
      staleHeartbeats: staleHeartbeatJobs.slice(0, 10).map(jobOperationSample)
    },
    failures: {
      failedCount: failedJobs.length,
      retryableCount: retryableJobs.length,
      exhaustedCount: exhaustedJobs.length,
      recentFailed: failedJobs
        .slice()
        .sort((left, right) => Date.parse(right.updatedAt) - Date.parse(left.updatedAt))
        .slice(0, 10)
        .map(jobOperationSample)
    },
    throughput: {
      succeededCount: byStatus.succeeded,
      cancelledCount: byStatus.cancelled,
      newestCompletedAt
    },
    remediationQueue
  };
}

function jobOperationSample(job: WorkerJobRecord): Record<string, unknown> {
  return {
    id: job.id,
    type: job.type,
    status: job.status,
    attempts: job.attempts,
    maxAttempts: job.maxAttempts,
    queuedAt: job.queuedAt,
    updatedAt: job.updatedAt,
    leasedBy: job.leasedBy,
    leaseExpiresAt: job.leaseExpiresAt,
    lastHeartbeatAt: job.lastHeartbeatAt,
    error: job.error
  };
}

function adminJobMetrics(jobs: WorkerJobRecord[]): string {
  const operations = adminJobOperations(jobs);
  const lines: string[] = [
    "# HELP otte_admin_jobs_total Total persisted server-admin job ledger records.",
    "# TYPE otte_admin_jobs_total gauge",
    `otte_admin_jobs_total ${operations.totals.totalCount}`,
    "# HELP otte_admin_jobs_by_status Server-admin jobs by lifecycle status.",
    "# TYPE otte_admin_jobs_by_status gauge"
  ];
  for (const [status, count] of Object.entries(operations.totals.byStatus)) {
    lines.push(`otte_admin_jobs_by_status{status="${metricLabel(status)}"} ${count}`);
  }
  lines.push("# HELP otte_admin_jobs_by_type Server-admin jobs by job type.");
  lines.push("# TYPE otte_admin_jobs_by_type gauge");
  for (const [type, count] of Object.entries(operations.totals.byType)) {
    lines.push(`otte_admin_jobs_by_type{type="${metricLabel(type)}"} ${count}`);
  }
  lines.push("# HELP otte_admin_jobs_retryable Failed or cancelled jobs with attempts remaining.");
  lines.push("# TYPE otte_admin_jobs_retryable gauge");
  lines.push(`otte_admin_jobs_retryable ${operations.totals.retryableCount}`);
  lines.push("# HELP otte_admin_jobs_retry_exhausted Jobs that exhausted retry attempts before success.");
  lines.push("# TYPE otte_admin_jobs_retry_exhausted gauge");
  lines.push(`otte_admin_jobs_retry_exhausted ${operations.totals.exhaustedCount}`);
  lines.push("# HELP otte_admin_jobs_queue_max_age_seconds Age in seconds of the oldest queued job.");
  lines.push("# TYPE otte_admin_jobs_queue_max_age_seconds gauge");
  lines.push(`otte_admin_jobs_queue_max_age_seconds ${operations.queue.maxQueueAgeSeconds}`);
  lines.push("# HELP otte_admin_jobs_queue_stale Queued jobs older than the operations threshold.");
  lines.push("# TYPE otte_admin_jobs_queue_stale gauge");
  lines.push(`otte_admin_jobs_queue_stale ${operations.queue.staleQueuedCount}`);
  lines.push("# HELP otte_admin_jobs_leases_expired Running jobs whose worker lease has expired.");
  lines.push("# TYPE otte_admin_jobs_leases_expired gauge");
  lines.push(`otte_admin_jobs_leases_expired ${operations.leases.expiredCount}`);
  lines.push("# HELP otte_admin_jobs_heartbeats_stale Running jobs with missing or stale worker heartbeats.");
  lines.push("# TYPE otte_admin_jobs_heartbeats_stale gauge");
  lines.push(`otte_admin_jobs_heartbeats_stale ${operations.leases.staleHeartbeatCount}`);
  lines.push("# HELP otte_admin_jobs_workers Workers currently holding running job leases.");
  lines.push("# TYPE otte_admin_jobs_workers gauge");
  lines.push(`otte_admin_jobs_workers ${operations.leases.leasedWorkerCount}`);
  lines.push("# HELP otte_admin_jobs_action_required Whether job operations posture requires operator action.");
  lines.push("# TYPE otte_admin_jobs_action_required gauge");
  lines.push(`otte_admin_jobs_action_required ${operations.actionRequired ? 1 : 0}`);
  lines.push("# HELP otte_admin_jobs_remediation_items Remediation rows currently generated from job posture.");
  lines.push("# TYPE otte_admin_jobs_remediation_items gauge");
  lines.push(`otte_admin_jobs_remediation_items ${operations.remediationQueue.length}`);
  lines.push("");
  return lines.join("\n");
}

function metricLabel(value: string): string {
  return value.replace(/\\/g, "\\\\").replace(/"/g, '\\"').replace(/\n/g, "\\n");
}

async function deliverJobAlert(
  operations: ReturnType<typeof adminJobOperations>,
  input: { dryRun: boolean; force: boolean; reason: string | undefined; adminUserId: string }
) {
  const configured = Boolean(jobAlertWebhookUrl());
  const base = {
    configured,
    actionRequired: operations.actionRequired,
    actionReasons: operations.actionReasons,
    remediationCount: operations.remediationQueue.length,
    generatedAt: operations.generatedAt
  };
  if (!operations.actionRequired && !input.force) {
    return { ...base, status: "skipped" as const, reason: "no_action_required" };
  }
  if (input.dryRun) {
    return { ...base, status: "dry_run" as const, reason: input.reason };
  }
  const webhookUrl = jobAlertWebhookUrl();
  if (!webhookUrl) {
    return { ...base, status: "failed" as const, error: "OTTE_JOB_ALERT_WEBHOOK_URL is not configured" };
  }
  const headers: Record<string, string> = { "content-type": "application/json" };
  const token = envText("OTTE_JOB_ALERT_WEBHOOK_TOKEN");
  if (token) headers.authorization = `Bearer ${token}`;
  try {
    const response = await fetch(webhookUrl, {
      method: "POST",
      headers,
      signal: AbortSignal.timeout(jobAlertWebhookTimeoutMs()),
      body: JSON.stringify({
        kind: "open_tabletop.job_operations_alert",
        requestedAt: nowIso(),
        requestedByUserId: input.adminUserId,
        reason: input.reason,
        operations
      })
    });
    if (!response.ok) {
      return { ...base, status: "failed" as const, webhookStatus: response.status, error: `Job alert webhook returned ${response.status}` };
    }
    return { ...base, status: "delivered" as const, deliveredAt: nowIso(), webhookStatus: response.status, reason: input.reason };
  } catch (error) {
    return { ...base, status: "failed" as const, error: errorMessage(error).slice(0, 500) };
  }
}

function jobAlertWebhookUrl(): string | undefined {
  return envText("OTTE_JOB_ALERT_WEBHOOK_URL");
}

function jobAlertWebhookTimeoutMs(): number {
  const value = Number(process.env.OTTE_JOB_ALERT_WEBHOOK_TIMEOUT_MS);
  return Number.isFinite(value) && value > 0 ? value : 5000;
}

function publicJobInfo(job: WorkerJobRecord): PublicJobInfo {
  const { payload: _payload, output: _output, ...rest } = job;
  return {
    ...rest,
    payload: redactJobValue(job.payload),
    ...(job.output !== undefined ? { output: redactJobValue(job.output) } : {})
  };
}

function leasedJobInfo(job: WorkerJobRecord): WorkerJobRecord {
  return {
    ...job,
    logs: job.logs.map((log) => ({ ...log, details: log.details ? { ...log.details } : undefined }))
  };
}

function redactJobValue(value: unknown, key?: string): unknown {
  if (key && ["archive", "sourceText", "transcript", "html", "text", "token", "password"].includes(key)) {
    return {
      redacted: true,
      field: key,
      ...(typeof value === "string" ? { length: value.length } : {})
    };
  }
  if (value === null || typeof value === "string" || typeof value === "number" || typeof value === "boolean") return value;
  if (Array.isArray(value)) return value.slice(0, 50).map((item) => redactJobValue(item));
  if (!isRecordValue(value)) return { redacted: true, kind: typeof value };
  return Object.fromEntries(Object.entries(value).slice(0, 50).map(([entryKey, entryValue]) => [entryKey, redactJobValue(entryValue, entryKey)]));
}

function normalizeJobProgress(value: unknown): { value: JobProgress } | { error: string } {
  if (!isRecordValue(value)) return { error: "Job progress must be an object" };
  const progress: JobProgress = {};
  for (const field of ["current", "total", "percent"] as const) {
    if (value[field] === undefined) continue;
    const parsed = Number(value[field]);
    if (!Number.isFinite(parsed) || parsed < 0) return { error: `Job progress ${field} must be a non-negative number` };
    progress[field] = parsed;
  }
  if (value.message !== undefined) {
    if (typeof value.message !== "string") return { error: "Job progress message must be a string" };
    progress.message = value.message.slice(0, 240);
  }
  if (progress.percent !== undefined && progress.percent > 100) return { error: "Job progress percent must be between 0 and 100" };
  return { value: progress };
}

function normalizeJobLogEntry(value: unknown): { value: JobLogEntry } | { error: string } {
  if (!isRecordValue(value)) return { error: "Job log must be an object" };
  const level = typeof value.level === "string" && ["info", "warning", "error"].includes(value.level) ? (value.level as JobLogEntry["level"]) : undefined;
  if (!level) return { error: "Job log level must be info, warning, or error" };
  if (typeof value.message !== "string" || value.message.trim().length === 0) return { error: "Job log message is required" };
  return {
    value: {
      at: nowIso(),
      level,
      message: value.message.trim().slice(0, 500),
      ...(isRecordValue(value.details) ? { details: redactJobValue(value.details) as Record<string, unknown> } : {})
    }
  };
}

function transitionAdminJob(job: WorkerJobRecord, nextStatus: JobStatus, adminUserId: string): { ok: true } | { error: string } {
  if (job.status === nextStatus) return { ok: true };
  const allowed: Record<JobStatus, JobStatus[]> = {
    queued: ["running", "cancelled"],
    running: ["succeeded", "failed", "cancelled"],
    succeeded: [],
    failed: [],
    cancelled: []
  };
  if (!allowed[job.status].includes(nextStatus)) return { error: `Cannot transition job from ${job.status} to ${nextStatus}` };
  const now = nowIso();
  if (nextStatus === "running") {
    if (job.attempts >= job.maxAttempts) return { error: "Job has exhausted its retry attempts" };
    job.startedAt = now;
    job.attempts += 1;
  }
  job.status = nextStatus;
  if (nextStatus === "succeeded" || nextStatus === "failed") job.completedAt = now;
  if (nextStatus === "cancelled") {
    job.cancelledAt = now;
    job.completedAt = now;
    job.cancelledByUserId = adminUserId;
  }
  if (nextStatus === "succeeded" || nextStatus === "failed" || nextStatus === "cancelled") {
    job.leasedBy = undefined;
    job.leaseExpiresAt = undefined;
    job.lastHeartbeatAt = undefined;
  }
  appendJobLog(job, { at: now, level: nextStatus === "failed" || nextStatus === "cancelled" ? "warning" : "info", message: `Job marked ${nextStatus}` });
  return { ok: true };
}

function appendJobLog(job: WorkerJobRecord, log: JobLogEntry): void {
  job.logs = [...job.logs, log].slice(-ADMIN_JOB_MAX_LOGS);
}

function isRecordValue(value: unknown): value is Record<string, unknown> {
  return Boolean(value && typeof value === "object" && !Array.isArray(value));
}

function appendRenderingAuthoringFailureAudit(
  store: StateStore,
  userId: string,
  input: {
    campaignId: string;
    sceneId: string;
    attemptedAction: string;
    targetType: "fog" | "wall" | "light";
    targetId?: string;
    reason: string;
    message: string;
  }
): AuditLog {
  return appendServerAuditLog(store, userId, {
    campaignId: input.campaignId,
    action: "scene.renderingAuthoring.failed",
    targetType: input.targetType,
    targetId: input.targetId,
    after: {
      sceneId: input.sceneId,
      attemptedAction: input.attemptedAction,
      targetType: input.targetType,
      targetId: input.targetId,
      reason: input.reason,
      message: input.message
    }
  });
}

function appendAssetDeliveryAuditLog(
  store: StateStore,
  asset: MapAsset,
  input: {
    status: "served" | "denied" | "unavailable" | "missing_bytes" | "signing_failed";
    accessMode: "signed" | "session";
    reason?: string;
    bytes?: number;
    cacheControl?: string;
    lifecycleStatus?: string;
  }
): AuditLog {
  const log = createTimestamped("audit", {
    campaignId: asset.campaignId,
    actorType: "system" as const,
    action: "asset.delivery",
    targetType: "asset",
    targetId: asset.id,
    after: {
      status: input.status,
      accessMode: input.accessMode,
      reason: input.reason,
      bytes: input.bytes,
      cacheControl: input.cacheControl,
      provider: asset.storage?.provider ?? "missing",
      lifecycleStatus: input.lifecycleStatus ?? asset.lifecycle?.status ?? "active"
    }
  }) satisfies AuditLog;
  store.state.auditLogs.push(log);
  return log;
}

function normalizeAdminAuditLogQuery(query: AdminAuditLogQuery): AdminAuditLogOptions | { error: string } {
  const format = query.format === undefined || query.format === "" ? "json" : query.format;
  if (format !== "json" && format !== "ndjson") return { error: "Audit export format must be json or ndjson" };
  const limit = normalizeAuditLogLimit(query.limit);
  if (!limit) return { error: "Audit export limit must be an integer from 1 to 10000" };
  const since = normalizeAuditLogDate(query.since, "since");
  if ("error" in since) return since;
  const until = normalizeAuditLogDate(query.until, "until");
  if ("error" in until) return until;
  const actorType = normalizeAuditActorType(query.actorType);
  if (query.actorType && !actorType) return { error: "Audit actorType must be user, ai, plugin, or system" };

  return {
    format,
    limit,
    filters: compactRecord({
      campaignId: nonEmptyQueryValue(query.campaignId),
      actorUserId: nonEmptyQueryValue(query.actorUserId),
      actorType,
      action: nonEmptyQueryValue(query.action),
      targetType: nonEmptyQueryValue(query.targetType),
      targetId: nonEmptyQueryValue(query.targetId),
      since: since.value,
      until: until.value
    })
  };
}

function filterAuditLogs(auditLogs: AuditLog[], options: AdminAuditLogOptions): AuditLog[] {
  const sinceMs = options.filters.since ? Date.parse(options.filters.since) : undefined;
  const untilMs = options.filters.until ? Date.parse(options.filters.until) : undefined;
  return auditLogs
    .filter((entry) => {
      if (options.filters.campaignId !== undefined && entry.campaignId !== options.filters.campaignId) return false;
      if (options.filters.actorUserId !== undefined && entry.actorUserId !== options.filters.actorUserId) return false;
      if (options.filters.actorType !== undefined && entry.actorType !== options.filters.actorType) return false;
      if (options.filters.action !== undefined && entry.action !== options.filters.action) return false;
      if (options.filters.targetType !== undefined && entry.targetType !== options.filters.targetType) return false;
      if (options.filters.targetId !== undefined && entry.targetId !== options.filters.targetId) return false;
      const createdAtMs = Date.parse(entry.createdAt);
      if (sinceMs !== undefined && createdAtMs < sinceMs) return false;
      if (untilMs !== undefined && createdAtMs > untilMs) return false;
      return true;
    })
    .sort((left, right) => Date.parse(right.createdAt) - Date.parse(left.createdAt) || right.id.localeCompare(left.id))
    .slice(0, options.limit);
}

function adminAuditLogExportSummary(auditLogs: AuditLog[], options: AdminAuditLogOptions) {
  const truncated = auditLogs.length >= options.limit;
  const oldest = auditLogs.at(-1);
  const newest = auditLogs.at(0);
  const adminActionCount = auditLogs.filter((entry) => entry.action.startsWith("admin.")).length;
  return {
    actionRequired: truncated,
    actionReasons: truncated ? ["audit_export_limit_reached"] : [],
    remediationQueue: truncated
      ? [
          {
            code: "narrow_audit_export_filters",
            severity: "warning" as const,
            action: "Narrow audit export filters by action, target type, actor, campaign, or time range before treating this sample as complete.",
            affectedCount: auditLogs.length,
            samples: oldest
              ? [
                  {
                    oldestReturnedAt: oldest.createdAt,
                    newestReturnedAt: newest?.createdAt,
                    limit: options.limit,
                    filters: options.filters
                  }
                ]
              : []
          }
        ]
      : [],
    byAction: topCountEntries(countBy(auditLogs, (entry) => entry.action), 8),
    byTargetType: topCountEntries(countBy(auditLogs, (entry) => entry.targetType), 8),
    byActorType: topCountEntries(countBy(auditLogs, (entry) => entry.actorType), 8),
    byCampaign: topCountEntries(countBy(auditLogs.filter((entry) => entry.campaignId), (entry) => entry.campaignId ?? "unknown"), 8),
    adminActionCount,
    oldestReturnedAt: oldest?.createdAt,
    newestReturnedAt: newest?.createdAt,
    truncated
  };
}

interface NormalizedScimUser {
  userName: string;
  email?: string;
  displayName: string;
  externalId?: string;
  active: boolean;
}

interface NormalizedScimGroup {
  displayName: string;
  externalId?: string;
  memberUserIds: string[];
}

function requireScimBearer(reply: FastifyReply, headers: Record<string, string | string[] | undefined>): true | FastifyReply {
  const expected = process.env.OTTE_SCIM_BEARER_TOKEN?.trim();
  if (!expected) return notFound(reply, "SCIM is not configured");
  const authorization = headerValue(headers.authorization);
  const token = authorization?.toLowerCase().startsWith("bearer ") ? authorization.slice("bearer ".length).trim() : undefined;
  if (!token || !safeStringEqual(token, expected)) return unauthorized(reply, "SCIM bearer token required");
  return true;
}

function scimLocation(headers: Record<string, string | string[] | undefined>, path: string): string {
  const host = headerValue(headers["x-forwarded-host"]) ?? headerValue(headers.host) ?? "localhost";
  const protocol = headerValue(headers["x-forwarded-proto"]) ?? (host.startsWith("localhost") || host.startsWith("127.0.0.1") ? "http" : "https");
  return `${protocol}://${host}${path}`;
}

function scimListResponse<T>(items: T[], query: ScimListQuery, mapItem: (item: T) => unknown): unknown {
  const startIndex = Math.max(1, Number.parseInt(query.startIndex ?? "1", 10) || 1);
  const count = Math.max(0, Math.min(200, Number.parseInt(query.count ?? "100", 10) || 100));
  const resources = items.slice(startIndex - 1, startIndex - 1 + count).map(mapItem);
  return {
    schemas: ["urn:ietf:params:scim:api:messages:2.0:ListResponse"],
    totalResults: items.length,
    startIndex,
    itemsPerPage: resources.length,
    Resources: resources
  };
}

function filterScimUsers(users: User[], query: ScimListQuery): User[] {
  const filter = parseScimEqFilter(query.filter);
  if (!filter) return users;
  return users.filter((user) => {
    const value = filter.value.toLowerCase();
    if (filter.path === "username" || filter.path === "userName".toLowerCase()) return (user.scim?.userName ?? user.email ?? "").toLowerCase() === value;
    if (filter.path === "externalid") return (user.scim?.externalId ?? "").toLowerCase() === value;
    if (filter.path === "email" || filter.path === "emails.value") return (user.email ?? "").toLowerCase() === value;
    return false;
  });
}

function filterScimGroups(groups: ScimGroup[], query: ScimListQuery): ScimGroup[] {
  const filter = parseScimEqFilter(query.filter);
  if (!filter) return groups;
  return groups.filter((group) => {
    const value = filter.value.toLowerCase();
    if (filter.path === "displayname") return group.displayName.toLowerCase() === value;
    if (filter.path === "externalid") return (group.externalId ?? "").toLowerCase() === value;
    return false;
  });
}

function parseScimEqFilter(filter: string | undefined): { path: string; value: string } | undefined {
  const match = filter?.trim().match(/^([\w.]+)\s+eq\s+"([^"]+)"$/i);
  if (!match) return undefined;
  return { path: match[1]!.toLowerCase(), value: match[2]! };
}

function scimUserResource(user: User, headers: Record<string, string | string[] | undefined>): unknown {
  const userName = user.scim?.userName ?? user.email ?? user.id;
  return {
    schemas: ["urn:ietf:params:scim:schemas:core:2.0:User"],
    id: user.id,
    externalId: user.scim?.externalId,
    userName,
    displayName: user.displayName,
    name: { formatted: user.displayName },
    active: !isDisabledUser(user),
    emails: user.email ? [{ value: user.email, primary: true, type: "work" }] : [],
    meta: {
      resourceType: "User",
      created: user.createdAt,
      lastModified: user.updatedAt,
      location: scimLocation(headers, `/api/v1/scim/v2/Users/${user.id}`)
    }
  };
}

function scimGroupResource(group: ScimGroup, headers: Record<string, string | string[] | undefined>): unknown {
  return {
    schemas: ["urn:ietf:params:scim:schemas:core:2.0:Group"],
    id: group.id,
    externalId: group.externalId,
    displayName: group.displayName,
    members: group.memberUserIds.map((userId) => ({ value: userId, $ref: scimLocation(headers, `/api/v1/scim/v2/Users/${userId}`) })),
    meta: {
      resourceType: "Group",
      created: group.createdAt,
      lastModified: group.updatedAt,
      location: scimLocation(headers, `/api/v1/scim/v2/Groups/${group.id}`)
    }
  };
}

function normalizeScimUserInput(input: ScimUserInput, existing?: User): NormalizedScimUser | { error: string } {
  if (!isRecord(input)) return { error: "SCIM user payload must be an object" };
  if (![input.userName, input.externalId, input.displayName].every(isOptionalNullableString)) return { error: "SCIM user text fields must be strings" };
  if (input.name !== undefined && input.name !== null && (!isRecord(input.name) || ![input.name.formatted, input.name.givenName, input.name.familyName].every(isOptionalNullableString))) {
    return { error: "SCIM name fields must be strings" };
  }
  if (input.emails !== undefined && !isValidScimEmails(input.emails)) return { error: "SCIM emails must be an array of email records" };
  if (input.active !== undefined && typeof input.active !== "boolean") return { error: "SCIM active must be a boolean" };
  const inputEmail = scimEmail(input);
  const userName = normalizeScimText(input.userName) ?? existing?.scim?.userName ?? inputEmail ?? existing?.email;
  if (!userName) return { error: "SCIM userName is required" };
  const email = inputEmail ?? normalizeEmail(userName) ?? existing?.email;
  const displayName = normalizeDisplayName(input.displayName) ?? normalizeDisplayName(input.name?.formatted) ?? existing?.displayName ?? email ?? userName;
  const externalId = Object.prototype.hasOwnProperty.call(input, "externalId") ? normalizeScimText(input.externalId) : existing?.scim?.externalId;
  return {
    userName,
    email,
    displayName,
    externalId,
    active: input.active ?? (existing ? !isDisabledUser(existing) : true)
  };
}

function scimEmail(input: ScimUserInput): string | undefined {
  if (!isValidScimEmails(input.emails)) return undefined;
  const primary = input.emails.find((email) => email.primary)?.value ?? input.emails[0]?.value;
  return normalizeEmail(primary);
}

function isValidScimEmails(value: unknown): value is Array<{ value: string; primary?: boolean }> {
  return Array.isArray(value) && value.every((email) => isRecord(email) && typeof email.value === "string" && (email.primary === undefined || typeof email.primary === "boolean") && (email.type === undefined || typeof email.type === "string"));
}

function isOptionalNullableString(value: unknown): value is string | null | undefined {
  return value === undefined || value === null || typeof value === "string";
}

function isOptionalString(value: unknown): value is string | undefined {
  return value === undefined || typeof value === "string";
}

function normalizeScimText(value: unknown): string | undefined {
  const trimmed = typeof value === "string" ? value.trim() : undefined;
  return trimmed || undefined;
}

function findScimUser(store: StateStore, userName: string | undefined, email: string | undefined, exceptUserId?: string): User | undefined {
  const normalizedUserName = userName?.toLowerCase();
  const normalizedEmail = normalizeEmail(email);
  return store.state.users.find((user) => {
    if (exceptUserId && user.id === exceptUserId) return false;
    if (normalizedUserName && (user.scim?.userName ?? user.email ?? "").toLowerCase() === normalizedUserName) return true;
    return Boolean(normalizedEmail && normalizeEmail(user.email) === normalizedEmail);
  });
}

function findScimGroup(store: StateStore, displayName: string | undefined, externalId: string | undefined, exceptGroupId?: string): ScimGroup | undefined {
  const normalizedDisplayName = displayName?.toLowerCase();
  return store.state.scimGroups.find((group) => {
    if (exceptGroupId && group.id === exceptGroupId) return false;
    if (normalizedDisplayName && group.displayName.toLowerCase() === normalizedDisplayName) return true;
    return Boolean(externalId && group.externalId === externalId);
  });
}

interface ScimGroupRoleSyncResult {
  matchedGroups: number;
  createdMemberships: number;
  updatedMemberships: number;
  removedMemberships: number;
  preservedManualMemberships: number;
}

const scimAssignableRoles = new Set<ScimAssignableRole>(["gm", "assistant_gm", "player", "observer"]);

function normalizeScimGroupRoleMappingInput(store: StateStore, input: AdminScimGroupRoleMappingInput): Omit<ScimGroupRoleMapping, "id" | "createdAt" | "updatedAt"> | { error: string } {
  const role = normalizeScimAssignableRole(input.role);
  if (!role) return { error: "SCIM group role mapping role must be gm, assistant_gm, player, or observer" };
  const campaignId = normalizeScimText(input.campaignId);
  if (!campaignId || !store.state.campaigns.some((campaign) => campaign.id === campaignId)) return { error: "SCIM group role mapping campaignId is required" };
  const groupId = normalizeScimText(input.groupId);
  const groupExternalId = normalizeScimText(input.groupExternalId);
  const groupDisplayName = normalizeScimText(input.groupDisplayName);
  if ([groupId, groupExternalId, groupDisplayName].filter(Boolean).length !== 1) return { error: "SCIM group role mapping requires exactly one of groupId, groupExternalId, or groupDisplayName" };
  if (groupId && !store.state.scimGroups.some((group) => group.id === groupId)) return { error: "SCIM group role mapping groupId was not found" };
  return { groupId, groupExternalId, groupDisplayName, campaignId, role };
}

function normalizeScimAssignableRole(value: string | undefined): ScimAssignableRole | undefined {
  return scimAssignableRoles.has(value as ScimAssignableRole) ? value as ScimAssignableRole : undefined;
}

function scimGroupRoleMappingIdentity(mapping: Pick<ScimGroupRoleMapping, "groupId" | "groupExternalId" | "groupDisplayName">): string {
  if (mapping.groupId) return `id:${mapping.groupId}`;
  if (mapping.groupExternalId) return `externalId:${mapping.groupExternalId}`;
  return `displayName:${mapping.groupDisplayName?.toLowerCase() ?? ""}`;
}

function publicScimGroupRoleMapping(store: StateStore, mapping: ScimGroupRoleMapping): ScimGroupRoleMapping & { group?: Pick<ScimGroup, "id" | "displayName" | "externalId" | "memberUserIds"> } {
  const group = findGroupForScimGroupRoleMapping(store, mapping);
  return {
    ...mapping,
    group: group ? { id: group.id, displayName: group.displayName, externalId: group.externalId, memberUserIds: [...group.memberUserIds] } : undefined
  };
}

function syncScimGroupRoleMappingsForGroup(store: StateStore, group: ScimGroup): ScimGroupRoleSyncResult {
  const mappings = store.state.scimGroupRoleMappings.filter((mapping) =>
    scimGroupRoleMappingMatchesGroup(mapping, group) ||
    store.state.members.some((member) => member.source?.type === "scim_group" && member.source.groupId === group.id && member.source.mappingId === mapping.id)
  );
  return combineScimGroupRoleSyncResults(mappings.map((mapping) => syncScimGroupRoleMapping(store, mapping, group)));
}

function syncScimGroupRoleMapping(store: StateStore, mapping: ScimGroupRoleMapping, knownGroup?: ScimGroup): ScimGroupRoleSyncResult {
  const group = knownGroup ? (scimGroupRoleMappingMatchesGroup(mapping, knownGroup) ? knownGroup : undefined) : findGroupForScimGroupRoleMapping(store, mapping);
  if (!group) return { matchedGroups: 0, createdMemberships: 0, updatedMemberships: 0, removedMemberships: removeScimGroupRoleMappingMemberships(store, mapping.id), preservedManualMemberships: 0 };
  const desiredUserIds = new Set(group.memberUserIds.filter((userId) => store.state.users.some((user) => user.id === userId)));
  let createdMemberships = 0;
  let updatedMemberships = 0;
  let preservedManualMemberships = 0;

  for (const userId of desiredUserIds) {
    const sourceMember = store.state.members.find((member) => member.source?.type === "scim_group" && member.source.mappingId === mapping.id && member.userId === userId);
    if (sourceMember) {
      if (sourceMember.role !== mapping.role || sourceMember.campaignId !== mapping.campaignId || sourceMember.source?.groupId !== group.id) {
        sourceMember.campaignId = mapping.campaignId;
        sourceMember.role = mapping.role;
        sourceMember.source = { type: "scim_group", groupId: group.id, mappingId: mapping.id };
        sourceMember.updatedAt = nowIso();
        updatedMemberships += 1;
      }
      continue;
    }
    const existingOtherMember = store.state.members.find((member) => member.campaignId === mapping.campaignId && member.userId === userId);
    if (existingOtherMember) {
      preservedManualMemberships += 1;
      continue;
    }
    const member = createTimestamped("mem", {
      campaignId: mapping.campaignId,
      userId,
      role: mapping.role,
      source: { type: "scim_group" as const, groupId: group.id, mappingId: mapping.id }
    }) satisfies CampaignMember;
    store.state.members.push(member);
    createdMemberships += 1;
  }

  const before = store.state.members.length;
  store.state.members = store.state.members.filter((member) => member.source?.type !== "scim_group" || member.source.mappingId !== mapping.id || desiredUserIds.has(member.userId));
  const removedMemberships = before - store.state.members.length;
  return { matchedGroups: 1, createdMemberships, updatedMemberships, removedMemberships, preservedManualMemberships };
}

function removeScimGroupRoleMembershipsForGroup(store: StateStore, group: ScimGroup): number {
  const mappingIds = new Set(store.state.scimGroupRoleMappings.filter((mapping) => scimGroupRoleMappingMatchesGroup(mapping, group)).map((mapping) => mapping.id));
  const before = store.state.members.length;
  store.state.members = store.state.members.filter((member) => member.source?.type !== "scim_group" || !mappingIds.has(member.source.mappingId));
  return before - store.state.members.length;
}

function removeScimGroupRoleMappingMemberships(store: StateStore, mappingId: string): number {
  const before = store.state.members.length;
  store.state.members = store.state.members.filter((member) => member.source?.type !== "scim_group" || member.source.mappingId !== mappingId);
  return before - store.state.members.length;
}

function findGroupForScimGroupRoleMapping(store: StateStore, mapping: ScimGroupRoleMapping): ScimGroup | undefined {
  return store.state.scimGroups.find((group) => scimGroupRoleMappingMatchesGroup(mapping, group));
}

function scimGroupRoleMappingMatchesGroup(mapping: ScimGroupRoleMapping, group: ScimGroup): boolean {
  if (mapping.groupId && mapping.groupId === group.id) return true;
  if (mapping.groupExternalId && mapping.groupExternalId === group.externalId) return true;
  return Boolean(mapping.groupDisplayName && mapping.groupDisplayName.toLowerCase() === group.displayName.toLowerCase());
}

function combineScimGroupRoleSyncResults(results: ScimGroupRoleSyncResult[]): ScimGroupRoleSyncResult {
  return results.reduce<ScimGroupRoleSyncResult>((total, item) => ({
    matchedGroups: total.matchedGroups + item.matchedGroups,
    createdMemberships: total.createdMemberships + item.createdMemberships,
    updatedMemberships: total.updatedMemberships + item.updatedMemberships,
    removedMemberships: total.removedMemberships + item.removedMemberships,
    preservedManualMemberships: total.preservedManualMemberships + item.preservedManualMemberships
  }), { matchedGroups: 0, createdMemberships: 0, updatedMemberships: 0, removedMemberships: 0, preservedManualMemberships: 0 });
}

function applyScimUserInput(store: StateStore, user: User, input: NormalizedScimUser): void {
  const now = nowIso();
  user.displayName = input.displayName;
  user.email = input.email;
  user.scim = {
    userName: input.userName,
    externalId: input.externalId,
    syncedAt: now
  };
  setScimUserActive(store, user, input.active);
  user.updatedAt = nowIso();
}

function setScimUserActive(store: StateStore, user: User, active: boolean): void {
  const now = nowIso();
  if (active) {
    user.disabledAt = undefined;
    user.disabledByUserId = undefined;
    user.disabledReason = undefined;
  } else {
    user.disabledAt = user.disabledAt ?? now;
    user.disabledByUserId = undefined;
    user.disabledReason = "SCIM inactive";
    store.state.sessions = store.state.sessions.filter((session) => session.userId !== user.id);
  }
  user.updatedAt = now;
}

function applyScimPatchToUser(store: StateStore, user: User, body: ScimPatchInput | undefined): { ok: true } | { error: string } {
  const operations = body?.Operations;
  if (!Array.isArray(operations)) return { error: "SCIM patch Operations are required" };
  for (const operation of operations) {
    if (!isRecord(operation) || typeof operation.op !== "string" || (operation.path !== undefined && typeof operation.path !== "string")) {
      return { error: "SCIM patch operations must contain string op and path values" };
    }
    const op = operation.op.toLowerCase();
    if (op !== "replace" && op !== "add") return { error: "Only SCIM add and replace operations are supported" };
    const path = operation.path?.toLowerCase();
    if (!path && isRecord(operation.value)) {
      const normalized = normalizeScimUserInput(operation.value as ScimUserInput, user);
      if ("error" in normalized) return normalized;
      const duplicate = findScimUser(store, normalized.userName, normalized.email, user.id);
      if (duplicate) return { error: "SCIM user already exists" };
      applyScimUserInput(store, user, normalized);
      continue;
    }
    if (!path) return { error: "SCIM root patch value must be an object" };
    const result = applyScimUserPath(store, user, path, operation.value);
    if ("error" in result) return result;
  }
  user.scim = {
    ...(user.scim ?? {}),
    userName: user.scim?.userName ?? user.email ?? user.id,
    syncedAt: nowIso()
  };
  user.updatedAt = nowIso();
  return { ok: true };
}

function applyScimUserPath(store: StateStore, user: User, path: string | undefined, value: unknown): { ok: true } | { error: string } {
  if (path === "active") {
    if (typeof value !== "boolean") return { error: "SCIM active must be a boolean" };
    setScimUserActive(store, user, value);
    return { ok: true };
  }
  if (path === "displayname") {
    if (typeof value !== "string") return { error: "SCIM displayName must be a string" };
    const displayName = normalizeDisplayName(value);
    if (!displayName) return { error: "SCIM displayName is required" };
    user.displayName = displayName;
    return { ok: true };
  }
  if (path === "username") {
    if (typeof value !== "string") return { error: "SCIM userName must be a string" };
    const userName = normalizeScimText(value);
    if (!userName) return { error: "SCIM userName is required" };
    const email = normalizeEmail(userName);
    if (findScimUser(store, userName, email, user.id)) return { error: "SCIM user already exists" };
    user.scim = { ...(user.scim ?? {}), userName };
    if (email) user.email = email;
    return { ok: true };
  }
  if (path === "externalid") {
    if (value !== null && typeof value !== "string") return { error: "SCIM externalId must be a string or null" };
    user.scim = { ...(user.scim ?? {}), externalId: normalizeScimText(value) };
    return { ok: true };
  }
  if (path === "emails" || path === "emails.value") {
    if (!Array.isArray(value) && typeof value !== "string") return { error: "SCIM email must be a string or email array" };
    const email = Array.isArray(value) ? scimEmail({ emails: value as ScimUserInput["emails"] }) : normalizeEmail(value);
    if (!email) return { error: "SCIM email is invalid" };
    if (findScimUser(store, undefined, email, user.id)) return { error: "SCIM user already exists" };
    user.email = email;
    return { ok: true };
  }
  return { error: `Unsupported SCIM user patch path: ${path ?? "root"}` };
}

function normalizeScimGroupInput(store: StateStore, input: ScimGroupInput, existing?: ScimGroup): NormalizedScimGroup | { error: string } {
  if (!isRecord(input)) return { error: "SCIM group payload must be an object" };
  if (![input.displayName, input.externalId].every(isOptionalNullableString)) return { error: "SCIM group text fields must be strings" };
  const displayName = normalizeDisplayName(input.displayName) ?? existing?.displayName;
  if (!displayName) return { error: "SCIM group displayName is required" };
  const members = input.members ?? existing?.memberUserIds.map((value) => ({ value })) ?? [];
  if (!Array.isArray(members) || !members.every((member) => isRecord(member) && typeof member.value === "string" && member.value.length > 0)) {
    return { error: "SCIM group members must be an array of user references" };
  }
  const memberUserIds = members.map((member) => member.value).filter((value): value is string => typeof value === "string");
  const missingUserId = memberUserIds.find((userId) => !store.state.users.some((user) => user.id === userId));
  if (missingUserId) return { error: `SCIM group member not found: ${missingUserId}` };
  return {
    displayName,
    externalId: Object.prototype.hasOwnProperty.call(input, "externalId") ? normalizeScimText(input.externalId) : existing?.externalId,
    memberUserIds: Array.from(new Set(memberUserIds))
  };
}

function applyScimPatchToGroup(store: StateStore, group: ScimGroup, body: ScimPatchInput | undefined): { ok: true } | { error: string } {
  const operations = body?.Operations;
  if (!Array.isArray(operations)) return { error: "SCIM patch Operations are required" };
  for (const operation of operations) {
    if (!isRecord(operation) || typeof operation.op !== "string" || (operation.path !== undefined && typeof operation.path !== "string")) {
      return { error: "SCIM patch operations must contain string op and path values" };
    }
    const op = operation.op.toLowerCase();
    if (op !== "replace" && op !== "add" && op !== "remove") return { error: "Only SCIM add, replace, and remove operations are supported" };
    const path = operation.path?.toLowerCase();
    if (op === "remove" && path?.startsWith("members")) {
      const userId = scimPatchMemberValue(path, operation.value);
      if (!userId && (path !== "members" || operation.value !== undefined)) return { error: "SCIM member removal requires a user reference" };
      group.memberUserIds = userId ? group.memberUserIds.filter((item) => item !== userId) : [];
      continue;
    }
    if (path === "displayname") {
      if (typeof operation.value !== "string") return { error: "SCIM group displayName must be a string" };
      const displayName = normalizeDisplayName(operation.value);
      if (!displayName) return { error: "SCIM group displayName is required" };
      group.displayName = displayName;
    } else if (path === "externalid") {
      if (op === "remove") {
        group.externalId = undefined;
      } else {
        if (operation.value !== null && typeof operation.value !== "string") return { error: "SCIM group externalId must be a string or null" };
        group.externalId = normalizeScimText(operation.value);
      }
    } else if (path === "members") {
      const normalized = normalizeScimGroupInput(store, { displayName: group.displayName, externalId: group.externalId, members: operation.value as ScimGroupInput["members"] }, group);
      if ("error" in normalized) return normalized;
      group.memberUserIds = op === "add" ? Array.from(new Set([...group.memberUserIds, ...normalized.memberUserIds])) : normalized.memberUserIds;
    } else {
      return { error: `Unsupported SCIM group patch path: ${path ?? "root"}` };
    }
  }
  group.updatedAt = nowIso();
  return { ok: true };
}

function restoreMutableRecord<T extends object>(target: T, snapshot: T): void {
  for (const key of Object.keys(target)) Reflect.deleteProperty(target, key);
  Object.assign(target, snapshot);
}

function scimPatchMemberValue(path: string | undefined, value: unknown): string | undefined {
  const pathMatch = path?.match(/members\[value eq "([^"]+)"\]/i)?.[1];
  if (pathMatch) return pathMatch;
  if (isRecord(value) && typeof value.value === "string") return value.value;
  return typeof value === "string" ? value : undefined;
}

function appendSystemAuditLog(store: StateStore, input: Omit<ServerAuditLogInput, "campaignId"> & { campaignId?: string }): AuditLog {
  const log = createTimestamped("audit", {
    campaignId: input.campaignId,
    actorType: "system" as const,
    action: input.action,
    targetType: input.targetType,
    targetId: input.targetId,
    before: input.before,
    after: input.after
  }) satisfies AuditLog;
  store.state.auditLogs.push(log);
  return log;
}

function scimError(reply: FastifyReply, status: number, detail: string): FastifyReply {
  return reply.code(status).send({
    schemas: ["urn:ietf:params:scim:api:messages:2.0:Error"],
    status: String(status),
    detail
  });
}

function normalizeAuditLogLimit(value: string | undefined): number | undefined {
  if (value === undefined || value.trim() === "") return 1000;
  const limit = Number(value);
  return Number.isInteger(limit) && limit > 0 && limit <= 10_000 ? limit : undefined;
}

function normalizeExportLimit(value: string | undefined, fallback: number): number {
  if (value === undefined || value.trim() === "") return fallback;
  const limit = Number(value);
  return Number.isInteger(limit) && limit > 0 && limit <= 10_000 ? limit : fallback;
}

function normalizeAuditLogDate(value: string | undefined, name: string): { value?: string } | { error: string } {
  if (value === undefined || value.trim() === "") return {};
  const parsed = new Date(value);
  if (Number.isNaN(parsed.getTime())) return { error: `Audit ${name} must be a valid ISO date` };
  return { value: parsed.toISOString() };
}

function normalizeAuditActorType(value: string | undefined): AuditLog["actorType"] | undefined {
  return value === "user" || value === "ai" || value === "plugin" || value === "system" ? value : undefined;
}

function nonEmptyQueryValue(value: string | undefined): string | undefined {
  const trimmed = value?.trim();
  return trimmed ? trimmed : undefined;
}

function compactRecord<T extends Record<string, unknown>>(record: T): { [K in keyof T]?: Exclude<T[K], undefined> } {
  return Object.fromEntries(Object.entries(record).filter(([, value]) => value !== undefined)) as { [K in keyof T]?: Exclude<T[K], undefined> };
}

interface PublicMfaInfo {
  totpEnabled: boolean;
  totpPending: boolean;
  recoveryCodeCount: number;
  enabledAt?: string;
  lastVerifiedAt?: string;
}

type PublicUser = Omit<User, "passwordHash" | "mfa" | "scim"> & { mfa?: PublicMfaInfo };

function publicUser(user: User): PublicUser {
  const { passwordHash: _passwordHash, mfa, scim: _scim, ...safeUser } = user;
  const safeMfa = mfa ? publicMfaInfo(mfa) : undefined;
  return safeMfa ? { ...safeUser, mfa: safeMfa } : safeUser;
}

type PublicInviteStatus = "pending" | "accepted" | "expired" | "revoked";

function createCampaignInvite(store: StateStore, campaign: Campaign, invitedByUserId: string, body: { email?: unknown; role?: unknown; expiresInDays?: unknown }): { ok: true; value: { invite: ReturnType<typeof publicInvite>; token: string; acceptUrl: string } } | { ok: false; error: string } {
  const role = body.role ?? "player";
  if (!isInvitableRole(role)) return { ok: false, error: "Invite role must be gm, assistant_gm, player, or observer" };
  const rawEmail = typeof body.email === "string" ? body.email : undefined;
  const email = rawEmail === undefined ? undefined : normalizeEmail(rawEmail);
  if (rawEmail !== undefined && !email) return { ok: false, error: "Invite email is invalid" };
  const expiresInDays = inviteExpirationDays(typeof body.expiresInDays === "number" ? body.expiresInDays : undefined);
  const token = `oti_${randomBytes(32).toString("base64url")}`;
  const invite = createTimestamped("inv", {
    campaignId: campaign.id,
    tokenHash: hashSessionToken(token),
    email,
    role,
    invitedByUserId,
    expiresAt: new Date(Date.now() + expiresInDays * 24 * 60 * 60 * 1000).toISOString()
  }) satisfies CampaignInvite;
  store.state.invites.push(invite);
  return {
    ok: true,
    value: {
      invite: publicInvite(invite),
      token,
      acceptUrl: `/join?invite=${encodeURIComponent(token)}`
    }
  };
}

function publicInvite(invite: CampaignInvite): Omit<CampaignInvite, "tokenHash"> & { status: PublicInviteStatus } {
  const { tokenHash: _tokenHash, ...safeInvite } = invite;
  return {
    ...safeInvite,
    status: inviteStatus(invite)
  };
}

function inviteStatus(invite: CampaignInvite): PublicInviteStatus {
  if (invite.revokedAt) return "revoked";
  if (invite.acceptedAt) return "accepted";
  if (Date.parse(invite.expiresAt) <= Date.now()) return "expired";
  return "pending";
}

const invitableRoles = new Set<UserRole>(["gm", "assistant_gm", "player", "observer"]);

function isInvitableRole(value: unknown): value is UserRole {
  return invitableRoles.has(value as UserRole);
}

function inviteExpirationDays(value: number | undefined): number {
  if (value === undefined || !Number.isFinite(value)) return 14;
  return Math.min(30, Math.max(1, Math.trunc(value)));
}

function normalizeEmail(value: unknown): string | undefined {
  const email = typeof value === "string" ? value.trim().toLowerCase() : undefined;
  if (!email || !email.includes("@") || email.length > 254) return undefined;
  return email;
}

function normalizeDisplayName(value: unknown): string | undefined {
  const displayName = typeof value === "string" ? value.trim() : undefined;
  return displayName && displayName.length <= 80 ? displayName : undefined;
}

function isUsablePassword(value: string | undefined): value is string {
  return typeof value === "string" && value.length >= 8;
}

function publicRegistrationEnabled(): boolean {
  const configured = process.env.OTTE_PUBLIC_REGISTRATION?.trim().toLowerCase();
  if (configured === "true" || configured === "1" || configured === "yes" || configured === "on") return true;
  if (configured === "false" || configured === "0" || configured === "no" || configured === "off") return false;
  return process.env.NODE_ENV !== "production";
}

function normalizeListPagination(query: ListPaginationQuery): ListPagination | { error: string } {
  const hasLimit = hasQueryValue(query.limit);
  const hasCursor = hasQueryValue(query.cursor);
  const hasOffset = hasQueryValue(query.offset);
  if (!hasLimit && !hasCursor && !hasOffset) return { requested: false };
  if (hasCursor && hasOffset) return { error: "Use either cursor or offset, not both" };

  const limit = hasLimit ? parseIntegerQueryValue(query.limit, "Pagination limit") : { value: LIST_DEFAULT_LIMIT };
  if ("error" in limit) return limit;
  if (limit.value < 1 || limit.value > LIST_MAX_LIMIT) return { error: `Pagination limit must be an integer from 1 to ${LIST_MAX_LIMIT}` };

  if (hasCursor) {
    const offset = decodeListCursor(query.cursor);
    if (offset === undefined) return { error: "Pagination cursor is invalid" };
    return { requested: true, limit: limit.value, offset };
  }

  const offset = hasOffset ? parseIntegerQueryValue(query.offset, "Pagination offset") : { value: 0 };
  if ("error" in offset) return offset;
  if (offset.value < 0) return { error: "Pagination offset must be a nonnegative integer" };
  return { requested: true, limit: limit.value, offset: offset.value };
}

function paginateList<T>(items: T[], pagination: Extract<ListPagination, { requested: true }>): PaginatedList<T> {
  const pageItems = items.slice(pagination.offset, pagination.offset + pagination.limit);
  const nextOffset = pagination.offset + pageItems.length;
  return {
    items: pageItems,
    pagination: {
      limit: pagination.limit,
      offset: pagination.offset,
      totalCount: items.length,
      ...(nextOffset < items.length ? { nextCursor: encodeListCursor(nextOffset) } : {})
    }
  };
}

function hasQueryValue(value: string | undefined): boolean {
  return value !== undefined && value !== "";
}

function parseIntegerQueryValue(value: string | undefined, label: string): { value: number } | { error: string } {
  if (value === undefined || value === "") return { error: `${label} is required` };
  if (!/^\d+$/.test(value)) return { error: `${label} must be an integer` };
  const parsed = Number(value);
  if (!Number.isSafeInteger(parsed)) return { error: `${label} must be a safe integer` };
  return { value: parsed };
}

function encodeListCursor(offset: number): string {
  return Buffer.from(JSON.stringify({ offset }), "utf8").toString("base64url");
}

function decodeListCursor(value: string | undefined): number | undefined {
  if (!value) return undefined;
  try {
    const parsed = JSON.parse(Buffer.from(value, "base64url").toString("utf8")) as { offset?: unknown };
    const offset = parsed.offset;
    return typeof offset === "number" && Number.isSafeInteger(offset) && offset >= 0 ? offset : undefined;
  } catch {
    return undefined;
  }
}

function parseChatMessageCreateBody(value: unknown, reply: FastifyReply): { ok: true; body: ChatMessageCreateBody } | { ok: false; reply: FastifyReply } {
  if (!value || typeof value !== "object" || Array.isArray(value)) return { ok: false, reply: badRequest(reply, "Chat message payload must be an object") };
  const input = value as Record<string, unknown>;
  const campaignId = typeof input.campaignId === "string" ? input.campaignId.trim() : "";
  if (!campaignId) return { ok: false, reply: badRequest(reply, "Chat campaignId is required") };
  if (typeof input.body !== "string" || input.body.trim().length === 0 || input.body.length > CHAT_MESSAGE_BODY_MAX_LENGTH) {
    return { ok: false, reply: badRequest(reply, CHAT_MESSAGE_BODY_VALIDATION_MESSAGE) };
  }

  const body: ChatMessageCreateBody = {
    campaignId,
    body: input.body
  };
  if (input.sceneId !== undefined) {
    if (typeof input.sceneId !== "string") return { ok: false, reply: badRequest(reply, "Chat sceneId must be a string") };
    const sceneId = input.sceneId.trim();
    if (sceneId) body.sceneId = sceneId;
  }
  if (input.type !== undefined) {
    if (!isChatMessageType(input.type)) return { ok: false, reply: badRequest(reply, "Chat message type is invalid") };
    body.type = input.type;
  }
  if (input.visibility !== undefined) {
    if (!isChatVisibility(input.visibility)) return { ok: false, reply: badRequest(reply, "Chat visibility must be public, gm_only, or whisper") };
    body.visibility = input.visibility;
  }
  if (input.recipientUserIds !== undefined) {
    if (!Array.isArray(input.recipientUserIds) || input.recipientUserIds.some((recipientId) => typeof recipientId !== "string")) {
      return { ok: false, reply: badRequest(reply, "Whisper recipients must be an array of user ids") };
    }
    body.recipientUserIds = input.recipientUserIds;
  }
  if (input.rollId !== undefined) {
    if (typeof input.rollId !== "string") return { ok: false, reply: badRequest(reply, "Chat rollId must be a string") };
    const rollId = input.rollId.trim();
    if (rollId) body.rollId = rollId;
  }
  body.replyToMessageId = input.replyToMessageId;
  return { ok: true, body };
}

function parseChatMessageEditBody(value: unknown, reply: FastifyReply): { ok: true; body: string } | { ok: false; reply: FastifyReply } {
  if (!value || typeof value !== "object" || Array.isArray(value)) return { ok: false, reply: badRequest(reply, "Chat message payload must be an object") };
  const input = value as Record<string, unknown>;
  if (typeof input.body !== "string" || input.body.trim().length === 0 || input.body.length > CHAT_MESSAGE_BODY_MAX_LENGTH) {
    return { ok: false, reply: badRequest(reply, CHAT_MESSAGE_BODY_VALIDATION_MESSAGE) };
  }
  return { ok: true, body: input.body };
}

function isChatMessageType(value: unknown): value is MessageType {
  return typeof value === "string" && (CHAT_MESSAGE_TYPES as readonly string[]).includes(value);
}

function isChatVisibility(value: unknown): value is ChatMessage["visibility"] {
  return typeof value === "string" && (CHAT_MESSAGE_VISIBILITIES as readonly string[]).includes(value);
}

function normalizeChatRecipients(store: StateStore, campaignId: string, userId: string, visibility: ChatMessage["visibility"], recipientUserIds: string[] | undefined, reply: FastifyReply): string[] | FastifyReply {
  if (visibility !== "whisper") return [];
  if (recipientUserIds !== undefined && !Array.isArray(recipientUserIds)) return badRequest(reply, "Whisper recipients must be an array");
  const uniqueRecipientIds = Array.from(new Set((recipientUserIds ?? []).map((recipientId) => (typeof recipientId === "string" ? recipientId.trim() : "")).filter(Boolean))).filter((recipientId) => recipientId !== userId);
  if (uniqueRecipientIds.length === 0) return badRequest(reply, "Whisper messages require at least one recipient");
  const memberUserIds = new Set(store.state.members.filter((member) => member.campaignId === campaignId).map((member) => member.userId));
  const invalidRecipient = uniqueRecipientIds.find((recipientId) => !memberUserIds.has(recipientId));
  if (invalidRecipient) return badRequest(reply, "Whisper recipients must be campaign members");
  return uniqueRecipientIds;
}

function normalizeChatRollLink(
  store: StateStore,
  campaignId: string,
  userId: string,
  rollId: string | undefined,
  visibility: ChatMessage["visibility"],
  recipientUserIds: string[],
  reply: FastifyReply
): { ok: true; rollId?: string } | { ok: false; reply: FastifyReply } {
  if (!rollId) return { ok: true };
  const roll = store.state.rolls.find((item) => item.id === rollId && item.campaignId === campaignId);
  if (!roll || !canReadDiceRoll(store, userId, roll)) {
    return { ok: false, reply: notFound(reply, "Dice roll not found") };
  }
  if (store.state.chat.some((message) => message.campaignId === campaignId && message.rollId === roll.id)) {
    return { ok: false, reply: conflict(reply, "Dice roll is already linked to a chat message") };
  }
  if (visibility !== roll.visibility) {
    return { ok: false, reply: badRequest(reply, "Chat visibility must match the linked dice roll") };
  }
  if (roll.visibility === "whisper" && recipientUserIds.length === 0) {
    return { ok: false, reply: badRequest(reply, "Whisper roll links require at least one recipient") };
  }
  return { ok: true, rollId: roll.id };
}

function normalizeChatReplyToMessageId(store: StateStore, campaignId: string, userId: string, value: unknown, reply: FastifyReply): string | undefined | FastifyReply {
  if (value === undefined || value === null || value === "") return undefined;
  if (typeof value !== "string") return badRequest(reply, "Reply target must be a chat message id");
  const messageId = value.trim();
  if (!messageId) return undefined;
  const parent = store.state.chat.find((message) => message.id === messageId && message.campaignId === campaignId);
  if (!parent) return badRequest(reply, "Reply target message not found");
  if (!canReadChatMessage(store, userId, parent)) return forbidden(reply, "Reply target message is not visible to this user");
  return parent.id;
}

function normalizeChatModerationStatus(value: unknown): ChatMessage["moderationStatus"] | undefined {
  return value === "open" || value === "follow_up" || value === "reviewed" ? value : undefined;
}

function canReadChatMessage(store: StateStore, userId: string, message: ChatMessage): boolean {
  if (message.visibility === "public") return true;
  if (message.visibility === "whisper") {
    return message.userId === userId || message.recipientUserIds.includes(userId) || canCampaign(store, userId, message.campaignId, "chat.moderate");
  }
  return message.userId === userId || canCampaign(store, userId, message.campaignId, "chat.moderate") || canCampaign(store, userId, message.campaignId, "journal.readSecret") || canCampaign(store, userId, message.campaignId, "ai.readGmMemory");
}

function canReadDiceRoll(store: StateStore, userId: string, roll: DiceRoll, linkedMessage?: ChatMessage): boolean {
  const canModerate = canCampaign(store, userId, roll.campaignId, "chat.moderate");
  const linkedMessageVisible = linkedMessage ? canReadChatMessage(store, userId, linkedMessage) : true;
  if (!linkedMessageVisible) return false;
  if (roll.visibility === "public") return true;
  if (roll.visibility === "whisper") {
    return roll.userId === userId || canModerate || Boolean(linkedMessage && linkedMessage.visibility === "whisper" && linkedMessage.recipientUserIds.includes(userId));
  }
  return canModerate || canCampaign(store, userId, roll.campaignId, "journal.readSecret") || canCampaign(store, userId, roll.campaignId, "ai.readGmMemory");
}

function normalizeClientSeed(value: unknown): string | undefined {
  if (typeof value !== "string") return undefined;
  const trimmed = value.trim();
  return trimmed ? trimmed.slice(0, 200) : undefined;
}

function normalizeAudioTrackKind(value: unknown): AudioTrackKind {
  return value === "music" || value === "ambient" || value === "sfx" ? value : "ambient";
}

function normalizeAudioVolume(value: unknown): number {
  if (typeof value !== "number" || !Number.isFinite(value)) return 0.8;
  return Math.max(0, Math.min(1, value));
}

function normalizeAudioTrackUrl(value: unknown): string | undefined {
  if (typeof value !== "string") return undefined;
  const trimmed = value.trim();
  if (!trimmed || trimmed.length > 2000) return undefined;
  if (trimmed.startsWith("/")) return trimmed;
  try {
    const url = new URL(trimmed);
    return url.protocol === "http:" || url.protocol === "https:" ? trimmed : undefined;
  } catch {
    return undefined;
  }
}

function rollWithFairness(formula: string, clientSeedInput: unknown): { rolled: ReturnType<typeof rollFormula>; fairness: DiceRollFairness } {
  const serverSeed = randomBytes(32).toString("hex");
  const serverSeedHash = createHash("sha256").update(serverSeed).digest("hex");
  const clientSeed = normalizeClientSeed(clientSeedInput);
  const rolled = rollFormula(formula, { rng: seededRng(composeFairnessSeed(serverSeed, clientSeed)) });
  const fairness: DiceRollFairness = {
    algorithm: "xmur3-mulberry32",
    serverSeed,
    serverSeedHash,
    ...(clientSeed ? { clientSeed } : {})
  };
  return { rolled, fairness };
}

interface DiceRollVerification {
  rollId: string;
  formula: string;
  verified: boolean;
  reason?: "fairness_unavailable" | "unsupported_algorithm" | "seed_hash_mismatch" | "formula_unparseable" | "result_mismatch";
  fairness?: DiceRollFairness;
  expected: { total: number };
  recomputed?: { total: number };
}

function verifyDiceRollRecord(roll: DiceRoll): DiceRollVerification {
  const base = { rollId: roll.id, formula: roll.formula, expected: { total: roll.total } };
  const fairness = roll.fairness;
  if (!fairness) return { ...base, verified: false, reason: "fairness_unavailable" };
  if (fairness.algorithm !== "xmur3-mulberry32") return { ...base, verified: false, reason: "unsupported_algorithm", fairness };
  const recomputedHash = createHash("sha256").update(fairness.serverSeed).digest("hex");
  if (recomputedHash !== fairness.serverSeedHash) return { ...base, verified: false, reason: "seed_hash_mismatch", fairness };
  let recomputed: ReturnType<typeof rollFormula>;
  try {
    recomputed = rollFormula(roll.formula, { rng: seededRng(composeFairnessSeed(fairness.serverSeed, fairness.clientSeed)) });
  } catch {
    return { ...base, verified: false, reason: "formula_unparseable", fairness };
  }
  const matches = recomputed.total === roll.total && stableJson(recomputed.terms) === stableJson(roll.terms);
  return {
    ...base,
    verified: matches,
    ...(matches ? {} : { reason: "result_mismatch" as const }),
    fairness,
    recomputed: { total: recomputed.total }
  };
}

interface CampaignSnapshotResult {
  generatedAt: string;
  campaign: Campaign;
  members: ReturnType<typeof memberSessionInfo>[];
  campaignSessions: CampaignSession[];
  worlds: World[];
  scenes: Scene[];
  selectedSceneId?: string;
  activeSceneId?: string;
  vision?: VisionSnapshot;
  tokens: Token[];
  fogPresets: FogPreset[];
  assets: MapAsset[];
  actors: Actor[];
  items: Item[];
  journals: JournalEntry[];
  handouts: Handout[];
  chat: ChatMessage[];
  rolls: DiceRoll[];
  diceMacros: DiceMacro[];
  encounters: Encounter[];
  combats: Combat[];
  proposals: Proposal[];
  memory: AiMemoryFact[];
  bundled: CampaignSnapshotBundled;
}

interface CampaignSnapshotBundled {
  assetStorage?: Record<string, unknown>;
  audioTracks?: AudioTrack[];
  plugins?: ReturnType<typeof pluginCampaignInfo>[];
  systems?: Array<ReturnType<typeof systemRuntimeInfo>>;
  characterTemplates?: CharacterTemplate[];
  contentImports?: ContentImportBatch[];
  aiThreads?: AiThread[];
  aiUsage?: ReturnType<typeof summarizeAiUsage>;
  aiToolCalls?: AiToolCall[];
  combatAudit?: AuditLog[];
}

/**
 * Server-composed, permission-filtered campaign snapshot. Collapses the web client's
 * per-collection fan-out into one payload while reusing the exact filters each list
 * route applies, so a caller never sees state a dedicated endpoint would withhold.
 */
function buildCampaignSnapshot(store: StateStore, userId: string, campaign: Campaign, options: { sceneId?: string; assetStorage?: AssetStorage; pluginRegistry: PluginRuntimeRegistry }): CampaignSnapshotResult {
  const campaignId = campaign.id;
  const permissions = permissionsForUser(store, userId, campaignId);
  const canReadCampaign = canCampaign(store, userId, campaignId, "campaign.read");
  const canWorld = canCampaign(store, userId, campaignId, "world.read");
  const canScene = canCampaign(store, userId, campaignId, "scene.read");
  const canActor = canCampaign(store, userId, campaignId, "actor.read");
  const canJournal = canCampaign(store, userId, campaignId, "journal.read");
  const canHandout = canCampaign(store, userId, campaignId, "handout.read");
  const canChat = canCampaign(store, userId, campaignId, "chat.read");
  const canDice = canCampaign(store, userId, campaignId, "dice.roll");
  const canManage = canCampaign(store, userId, campaignId, "campaign.update");
  const canReveal = canCampaign(store, userId, campaignId, "token.reveal");
  const canAiOperations = canCampaign(store, userId, campaignId, "ai.proposeChanges");
  const canMemory = canCampaign(store, userId, campaignId, "ai.readPublicMemory") || canCampaign(store, userId, campaignId, "ai.readGmMemory");
  const canMemoryGm = canCampaign(store, userId, campaignId, "ai.readGmMemory");
  const canViewPrep = canAccessPreparedScenes(store, userId, campaignId);

  const scenes = canScene ? readableScenesForUser(store, userId, campaignId) : [];
  const activeScene = scenes.find((scene) => scene.active);
  const selectedScene = (options.sceneId ? scenes.find((scene) => scene.id === options.sceneId) : undefined) ?? activeScene ?? scenes[0];
  const campaignSceneIds = new Set(scenes.map((scene) => scene.id));
  const visibilityCache = createTokenVisibilityCache();
  const tokens = canScene ? visibleTokensForUser(store, userId, campaignId, store.state.tokens.filter((token) => campaignSceneIds.has(token.sceneId)), visibilityCache) : [];
  const vision = canScene && selectedScene ? visionSnapshotForUser(store, userId, campaignId, selectedScene, visibilityCache) : undefined;
  const readableAssetIds = canScene ? readableAssetIdsForUser(store, userId, campaignId) : new Set<string>();
  const readableAssets = canScene ? store.state.assets.filter((asset) => asset.campaignId === campaignId && readableAssetIds.has(asset.id)) : [];

  const linkedMessagesByRollId = new Map<string, ChatMessage>();
  if (canChat) {
    for (const message of store.state.chat) {
      if (message.campaignId !== campaignId || !message.rollId || linkedMessagesByRollId.has(message.rollId)) continue;
      linkedMessagesByRollId.set(message.rollId, message);
    }
  }

  const systems = registeredSystems(store.state).map((system) => systemRuntimeInfo(store, system, campaign.defaultSystemId === system.id));
  const activeSystemId = systems.find((system) => system.active)?.id ?? systems[0]?.id;
  const activeCombat = store.state.combats.find((combat) => combat.campaignId === campaignId && combat.active);
  const aiThreads = store.state.aiThreads.filter((thread) => thread.campaignId === campaignId).sort((a, b) => b.createdAt.localeCompare(a.createdAt));
  const aiThreadIds = new Set(aiThreads.map((thread) => thread.id));
  const bundled: CampaignSnapshotBundled = {
    ...(canScene
      ? {
          assetStorage: canViewPrep
            ? campaignAssetStorageInfo(store, campaignId, options.assetStorage)
            : {
                campaignId,
                assetCount: readableAssets.length,
                activeAssetCount: readableAssets.filter((asset) => asset.lifecycle?.status !== "deleted").length,
                usedBytes: readableAssets.filter((asset) => asset.lifecycle?.status !== "deleted").reduce((total, asset) => total + asset.sizeBytes, 0),
                allBytes: readableAssets.reduce((total, asset) => total + asset.sizeBytes, 0),
                lifecycleCounts: countBy(readableAssets, (asset) => asset.lifecycle?.status ?? "active"),
                providerCounts: countBy(readableAssets, (asset) => asset.storage?.provider ?? "external"),
                largestAssets: []
              }
        }
      : {}),
    ...(canReadCampaign
      ? {
          audioTracks: store.state.audioTracks.filter((track) => track.campaignId === campaignId && (canViewPrep || track.playing)),
          plugins: options.pluginRegistry.list().map((plugin) => pluginCampaignInfo(store, options.pluginRegistry, campaignId, plugin)),
          systems,
          combatAudit: activeCombat
            ? store.state.auditLogs
                .filter((log) => log.campaignId === campaignId && log.targetType === "combat" && log.targetId === activeCombat.id)
                .sort((left, right) => right.createdAt.localeCompare(left.createdAt))
                .map((log) => combatAuditLogPayloadForUser(store, userId, campaignId, log))
            : []
        }
      : {}),
    ...(canActor && activeSystemId && hasSystemRuntimeCapability(activeSystemId, "character-templates")
      ? { characterTemplates: characterTemplatesForSystem(activeSystemId) }
      : {}),
    ...(canManage ? { contentImports: store.state.contentImports.filter((item) => item.campaignId === campaignId && item.status !== "deleted") } : {}),
    ...(canAiOperations
      ? {
          aiThreads,
          aiUsage: summarizeAiUsage(campaignId, aiThreads),
          aiToolCalls: store.state.aiToolCalls.filter((call) => aiThreadIds.has(call.threadId))
        }
      : {})
  };

  return {
    generatedAt: nowIso(),
    campaign,
    members: store.state.members.filter((member) => member.campaignId === campaignId).map((member) => memberSessionInfo(store, member)),
    campaignSessions: store.state.campaignSessions
      .filter((session) => session.campaignId === campaignId && (canViewPrep || session.status === "live"))
      .map((session) =>
        canViewPrep
          ? session
          : {
              ...session,
              agenda: "",
              notes: "",
              encounterIds: session.encounterIds.filter((encounterId) => store.state.combats.some((combat) => combat.active && combat.campaignId === campaignId && combat.encounterId === encounterId)),
              sceneIds: session.sceneIds.filter((sceneId) => scenes.some((scene) => scene.id === sceneId))
            }
      ),
    worlds: canWorld ? store.state.worlds.filter((world) => world.campaignId === campaignId) : [],
    scenes: scenes.map(withoutSceneEditHistory),
    ...(selectedScene ? { selectedSceneId: selectedScene.id } : {}),
    ...(activeScene ? { activeSceneId: activeScene.id } : {}),
    ...(vision ? { vision } : {}),
    tokens,
    fogPresets: canReveal ? store.state.fogPresets.filter((preset) => preset.campaignId === campaignId) : [],
    assets: readableAssets,
    actors: canActor ? store.state.actors.filter((actor) => actor.campaignId === campaignId).map((actor) => actorPayloadForUser(store, userId, actor)) : [],
    items: canActor ? visibleItemsForUser(store, userId, campaignId) : [],
    journals: canJournal ? store.state.journals.filter((entry) => entry.campaignId === campaignId && canReadJournalEntry(store, userId, entry)) : [],
    handouts: canHandout
      ? store.state.handouts.filter((handout) => handout.campaignId === campaignId && canReadHandout(store, userId, handout)).map((handout) => normalizeHandout(handout))
      : [],
    chat: canChat ? store.state.chat.filter((message) => message.campaignId === campaignId && canReadChatMessage(store, userId, message)) : [],
    rolls: canChat ? store.state.rolls.filter((roll) => roll.campaignId === campaignId && canReadDiceRoll(store, userId, roll, linkedMessagesByRollId.get(roll.id))) : [],
    diceMacros: canDice ? store.state.diceMacros.filter((macro) => macro.campaignId === campaignId && (macro.visibility === "public" || canManage)) : [],
    encounters: store.state.encounters.filter(
      (encounter) =>
        encounter.campaignId === campaignId &&
        (canViewPrep || store.state.combats.some((combat) => combat.campaignId === campaignId && combat.active && combat.encounterId === encounter.id))
    ),
    combats: store.state.combats.filter((combat) => combat.campaignId === campaignId).map((combat) => combatPayloadForUser(store, userId, combat)),
    proposals: visibleProposalsForUser(store.state, userId, campaignId, permissions),
    memory: canMemory
      ? store.state.aiMemory
          .filter((item) => item.campaignId === campaignId)
          .map(normalizeAiMemoryFact)
          .filter((item) => canMemoryGm || (item.visibility === "public" && aiMemoryFactStatus(item) === "approved"))
      : [],
    bundled
  };
}

const SCENE_EDIT_HISTORY_LIMIT = 50;
const SCENE_EDITABLE_PATCH_FIELDS: Array<keyof Scene> = ["worldId", "name", "width", "height", "gridType", "gridSize", "backgroundAssetId", "folder", "fog", "walls", "lights", "annotations", "metadata"];

function cloneSceneEditableState(scene: Scene): SceneEditableState {
  return structuredClone({
    worldId: scene.worldId,
    name: scene.name,
    width: scene.width,
    height: scene.height,
    gridType: scene.gridType,
    gridSize: scene.gridSize,
    backgroundAssetId: scene.backgroundAssetId,
    folder: scene.folder,
    fog: scene.fog,
    walls: scene.walls,
    lights: scene.lights,
    annotations: scene.annotations,
    metadata: scene.metadata
  });
}

/** Snapshots the scene's editable state before a mutation so a GM can undo the last N scene edits. */
function captureSceneEditSnapshot(scene: Scene, userId: string | undefined, kind: string): void {
  const snapshot: SceneEditSnapshot = {
    id: createId("sedit"),
    at: nowIso(),
    kind,
    state: cloneSceneEditableState(scene),
    ...(userId ? { byUserId: userId } : {})
  };
  scene.sceneEditHistory = [...(scene.sceneEditHistory ?? []), snapshot].slice(-SCENE_EDIT_HISTORY_LIMIT);
}

function undoSceneEdit(scene: Scene): SceneEditSnapshot | undefined {
  const history = scene.sceneEditHistory ?? [];
  const last = history[history.length - 1];
  if (!last) return undefined;
  scene.sceneEditHistory = history.slice(0, -1);
  const restored = structuredClone(last.state);
  scene.worldId = restored.worldId;
  scene.name = restored.name;
  scene.width = restored.width;
  scene.height = restored.height;
  scene.gridType = restored.gridType;
  scene.gridSize = restored.gridSize;
  scene.backgroundAssetId = restored.backgroundAssetId;
  scene.folder = restored.folder;
  scene.fog = restored.fog;
  scene.walls = restored.walls;
  scene.lights = restored.lights;
  scene.annotations = restored.annotations;
  scene.metadata = restored.metadata;
  scene.updatedAt = nowIso();
  return last;
}

function publicSceneEditHistory(scene: Scene): Array<Pick<SceneEditSnapshot, "id" | "at" | "byUserId" | "kind">> {
  return (scene.sceneEditHistory ?? []).map(({ id, at, byUserId, kind }) => ({ id, at, byUserId, kind }));
}

/** Drops the (potentially large) undo history from a scene before it is broadcast or listed; the full log is served by GET /scenes/:id/edits. */
function withoutSceneEditHistory(scene: Scene): Scene {
  if (!scene.sceneEditHistory) return scene;
  const { sceneEditHistory: _history, ...rest } = scene;
  return rest;
}

function currentUserId(store: StateStore, headers: Record<string, string | string[] | undefined>): string | undefined {
  const session = sessionFromRequest(store, undefined, headers);
  if (session && isActiveUserId(store, session.userId)) return session.userId;
  const header = headers["x-user-id"];
  const userId = Array.isArray(header) ? header[0] : header;
  if (!legacyUserHeaderEnabled()) {
    if (userId) appendLegacyUserHeaderAuditLog(store, userId, "header", "blocked");
    return undefined;
  }
  if (userId && isActiveUserId(store, userId)) {
    appendLegacyUserHeaderAuditLog(store, userId, "header", "accepted");
    return userId;
  }
  return undefined;
}

function userIdFromRequest(store: StateStore, requestUrl: string | undefined, headers: Record<string, string | string[] | undefined>): string | undefined {
  const session = sessionFromRequest(store, requestUrl, headers);
  if (session && isActiveUserId(store, session.userId)) return session.userId;
  const url = new URL(requestUrl ?? "/api/v1/realtime", "http://localhost");
  const queryUserId = url.searchParams.get("userId");
  const header = headers["x-user-id"];
  const headerUserId = Array.isArray(header) ? header[0] : header;
  if (!legacyUserHeaderEnabled()) {
    if (queryUserId) appendLegacyUserHeaderAuditLog(store, queryUserId, "query", "blocked");
    else if (headerUserId) appendLegacyUserHeaderAuditLog(store, headerUserId, "header", "blocked");
    return undefined;
  }
  if (queryUserId && isActiveUserId(store, queryUserId)) {
    appendLegacyUserHeaderAuditLog(store, queryUserId, "query", "accepted");
    return queryUserId;
  }
  if (headerUserId && isActiveUserId(store, headerUserId)) {
    appendLegacyUserHeaderAuditLog(store, headerUserId, "header", "accepted");
    return headerUserId;
  }
  return undefined;
}

function createUserSession(store: StateStore, userId: string): { token: string; session: UserSession } {
  const token = `ots_${randomBytes(32).toString("base64url")}`;
  const now = nowIso();
  const expiresAt = new Date(Date.now() + sessionTtlDays() * 24 * 60 * 60 * 1000).toISOString();
  const session = createTimestamped("sess", {
    userId,
    tokenHash: hashSessionToken(token),
    expiresAt,
    lastSeenAt: now
  }) satisfies UserSession;
  store.state.sessions.push(session);
  return { token, session };
}

function appendLegacyUserHeaderAuditLog(store: StateStore, userId: string, source: "header" | "query", status: "accepted" | "blocked"): void {
  store.state.auditLogs.push(
    createTimestamped("audit", {
      actorUserId: status === "accepted" ? userId : undefined,
      actorType: "user" as const,
      action: "auth.legacyUserHeader",
      targetType: "auth_compatibility",
      targetId: userId,
      after: {
        source,
        status,
        mode: publicAuthRuntimeConfig(store).legacyUserHeader.mode
      }
    }) satisfies AuditLog
  );
}

function appendAuthLoginFailureAudit(store: StateStore, input: { userId?: string; reason: string; statusCode: number }): void {
  store.state.auditLogs.push(
    createTimestamped("audit", {
      actorUserId: input.userId,
      actorType: "user" as const,
      action: "auth.login.failed",
      targetType: "auth_login",
      targetId: input.userId,
      after: {
        userKnown: Boolean(input.userId),
        reason: input.reason,
        statusCode: input.statusCode
      }
    }) satisfies AuditLog
  );
}

function sessionFromRequest(store: StateStore, requestUrl: string | undefined, headers: Record<string, string | string[] | undefined>): UserSession | undefined {
  const token = sessionTokenFromRequest(requestUrl, headers);
  if (!token) return undefined;
  const tokenHash = hashSessionToken(token);
  const now = Date.now();
  const session = store.state.sessions.find((item) => item.tokenHash === tokenHash && Date.parse(item.expiresAt) > now);
  if (session) {
    const previousLastSeenAt = Date.parse(session.lastSeenAt);
    if (!Number.isFinite(previousLastSeenAt) || now - previousLastSeenAt >= SESSION_LAST_SEEN_PERSIST_INTERVAL_MS) {
      session.lastSeenAt = new Date(now).toISOString();
      store.save();
    }
  }
  return session;
}

const SESSION_LAST_SEEN_PERSIST_INTERVAL_MS = 60_000;

function sessionTokenFromRequest(requestUrl: string | undefined, headers: Record<string, string | string[] | undefined>): string | undefined {
  const authorization = headerValue(headers.authorization);
  if (authorization?.toLowerCase().startsWith("bearer ")) return authorization.slice("bearer ".length).trim();
  const explicitHeader = headerValue(headers["x-session-token"]);
  if (explicitHeader) return explicitHeader;
  const cookie = headerValue(headers.cookie);
  const cookieToken = cookie
    ?.split(";")
    .map((part) => part.trim())
    .find((part) => part.startsWith("otte_session="))
    ?.slice("otte_session=".length);
  if (cookieToken) return decodeURIComponent(cookieToken);
  const protocolToken = websocketProtocolSessionToken(headers);
  if (protocolToken) return protocolToken;
  const url = new URL(requestUrl ?? "/api/v1/realtime", "http://localhost");
  return url.searchParams.get("sessionToken") ?? undefined;
}

function headersWithRequestSessionToken(requestUrl: string | undefined, headers: Record<string, string | string[] | undefined>): Record<string, string | string[] | undefined> {
  const token = sessionTokenFromRequest(requestUrl, headers);
  if (!token) return headers;
  return { ...headers, "x-session-token": token };
}

function websocketProtocolSessionToken(headers: Record<string, string | string[] | undefined>): string | undefined {
  const protocols = headerValue(headers["sec-websocket-protocol"]);
  return protocols
    ?.split(",")
    .map((protocol) => protocol.trim())
    .find((protocol) => protocol.startsWith("otte.auth."))
    ?.slice("otte.auth.".length);
}

function hashPassword(password: string): string {
  const salt = randomBytes(16).toString("base64url");
  return `scrypt:${salt}:${scryptSync(password, salt, 32).toString("base64url")}`;
}

function verifyPassword(password: unknown, storedHash: string): boolean {
  if (typeof password !== "string") return false;
  const [algorithm, salt, expected] = storedHash.split(":");
  if (algorithm !== "scrypt" || !salt || !expected) return false;
  const expectedBytes = Buffer.from(expected, "base64url");
  const actualBytes = scryptSync(password, salt, expectedBytes.length);
  return expectedBytes.length === actualBytes.length && timingSafeEqual(expectedBytes, actualBytes);
}

function hashSessionToken(token: string): string {
  return `sha256:${createHash("sha256").update(token).digest("hex")}`;
}

function pruneExpiredSessions(store: StateStore): void {
  const now = Date.now();
  store.state.sessions = store.state.sessions.filter((session) => Date.parse(session.expiresAt) > now);
}

function pruneSessionsForAdmin(store: StateStore, input: AdminSessionPruneBody) {
  const dryRun = Boolean(input.dryRun);
  const now = Date.now();
  const matchedSessions = store.state.sessions.filter((session) => Date.parse(session.expiresAt) <= now);
  if (!dryRun && matchedSessions.length > 0) {
    const matchedIds = new Set(matchedSessions.map((session) => session.id));
    store.state.sessions = store.state.sessions.filter((session) => !matchedIds.has(session.id));
  }
  return {
    generatedAt: nowIso(),
    dryRun,
    matched: matchedSessions.length,
    pruned: dryRun ? 0 : matchedSessions.length,
    activeRemaining: store.state.sessions.filter((session) => Date.parse(session.expiresAt) > now).length,
    expiredRemaining: store.state.sessions.filter((session) => Date.parse(session.expiresAt) <= now).length,
    sessions: matchedSessions.map(publicSession)
  };
}

function pruneExpiredPasswordResetTokens(store: StateStore): void {
  const now = Date.now();
  store.state.passwordResetTokens = store.state.passwordResetTokens.filter((reset) => !reset.usedAt && Date.parse(reset.expiresAt) > now);
}

function prunePasswordResetTokensForAdmin(store: StateStore, input: AdminPasswordResetPruneBody) {
  const includeExpired = input.includeExpired ?? true;
  const includeUsed = input.includeUsed ?? true;
  const dryRun = Boolean(input.dryRun);
  const now = Date.now();
  const matchedResets = store.state.passwordResetTokens.filter((reset) => {
    if (includeUsed && reset.usedAt) return true;
    return includeExpired && Date.parse(reset.expiresAt) <= now;
  });
  if (!dryRun && matchedResets.length > 0) {
    const matchedIds = new Set(matchedResets.map((reset) => reset.id));
    store.state.passwordResetTokens = store.state.passwordResetTokens.filter((reset) => !matchedIds.has(reset.id));
  }
  return {
    dryRun,
    includeExpired,
    includeUsed,
    matched: matchedResets.length,
    pruned: dryRun ? 0 : matchedResets.length,
    activeRemaining: store.state.passwordResetTokens.filter((reset) => !reset.usedAt && Date.parse(reset.expiresAt) > now).length,
    expiredRemaining: store.state.passwordResetTokens.filter((reset) => !reset.usedAt && Date.parse(reset.expiresAt) <= now).length,
    usedRemaining: store.state.passwordResetTokens.filter((reset) => Boolean(reset.usedAt)).length,
    resets: matchedResets.map(publicPasswordResetToken)
  };
}

function publicSession(session: UserSession): Pick<UserSession, "id" | "userId" | "activeOrganizationId" | "expiresAt" | "lastSeenAt" | "createdAt" | "updatedAt"> {
  return {
    id: session.id,
    userId: session.userId,
    activeOrganizationId: session.activeOrganizationId,
    expiresAt: session.expiresAt,
    lastSeenAt: session.lastSeenAt,
    createdAt: session.createdAt,
    updatedAt: session.updatedAt
  };
}

function headerValue(value: string | string[] | undefined): string | undefined {
  return Array.isArray(value) ? value[0] : value;
}

function requireUser(store: StateStore, reply: FastifyReply, headers: Record<string, string | string[] | undefined>): string | FastifyReply {
  const userId = currentUserId(store, headers);
  if (!userId) return unauthorized(reply, "Missing session token");
  const user = store.state.users.find((item) => item.id === userId);
  if (!user) return unauthorized(reply, "Unknown user session");
  if (isDisabledUser(user)) return forbidden(reply, "User account is disabled");
  return userId;
}

function requireSessionUser(store: StateStore, reply: FastifyReply, headers: Record<string, string | string[] | undefined>): { session: UserSession; user: User } | FastifyReply {
  const session = sessionFromRequest(store, undefined, headers);
  if (!session) return unauthorized(reply, "Missing session token");
  const user = store.state.users.find((item) => item.id === session.userId);
  if (!user) return unauthorized(reply, "Unknown user session");
  if (isDisabledUser(user)) return forbidden(reply, "User account is disabled");
  return { session, user };
}

function requireServerAdmin(store: StateStore, reply: FastifyReply, headers: Record<string, string | string[] | undefined>): string | FastifyReply {
  const userId = requireUser(store, reply, headers);
  if (typeof userId !== "string") return userId;
  if (!isServerAdminUser(store, userId)) return forbidden(reply, "Server admin access required");
  return userId;
}

function isServerAdminUser(store: StateStore, userId: string): boolean {
  return isServerAdminUserId(userId) || Boolean(store.state.users.find((user) => user.id === userId && user.serverAdmin && !isDisabledUser(user)));
}

function isServerAdminUserId(userId: string): boolean {
  return serverAdminUserIds().has(userId);
}

function serverAdminUserIds(): Set<string> {
  return new Set(
    (process.env.OTTE_ADMIN_USER_IDS ?? "")
      .split(",")
      .map((value) => value.trim())
      .filter(Boolean)
  );
}

function serverAdminRuntimePosture(store?: StateStore): { configured: boolean; count: number; missingInProduction: boolean } {
  const ids = serverAdminUserIds();
  for (const user of store?.state.users ?? []) {
    if (user.serverAdmin && !isDisabledUser(user)) ids.add(user.id);
  }
  const count = ids.size;
  return {
    configured: count > 0,
    count,
    missingInProduction: process.env.NODE_ENV === "production" && count === 0
  };
}

function isActiveUserId(store: StateStore, userId: string): boolean {
  const user = store.state.users.find((item) => item.id === userId);
  return Boolean(user && !isDisabledUser(user));
}

function isDisabledUser(user: User): boolean {
  return Boolean(user.disabledAt);
}

function legacyUserHeaderEnabled(): boolean {
  if (process.env.NODE_ENV === "test") return true;
  if (process.env.NODE_ENV === "production") return false;
  return process.env.OTTE_ALLOW_LEGACY_USER_HEADER === "true";
}

function publicAuthRuntimeConfig(store?: StateStore): {
  nodeEnv: string;
  legacyUserHeader: {
    enabled: boolean;
    compatibilityFlagSet: boolean;
    productionHardFence: boolean;
    mode: "test" | "production_disabled" | "non_production_compatibility" | "disabled";
  };
  authUrls: ReturnType<typeof authRuntimeUrlPosture>;
  sessions: ReturnType<typeof authSessionRuntimePosture>;
  oidc: ReturnType<typeof oidcRuntimePosture>;
  scim: ReturnType<typeof scimRuntimePosture>;
  serverAdmins: ReturnType<typeof serverAdminRuntimePosture>;
} {
  const nodeEnv = process.env.NODE_ENV ?? "development";
  const compatibilityFlagSet = process.env.OTTE_ALLOW_LEGACY_USER_HEADER === "true";
  const productionHardFence = nodeEnv === "production";
  const enabled = legacyUserHeaderEnabled();
  const mode = nodeEnv === "test" ? "test" : productionHardFence ? "production_disabled" : enabled ? "non_production_compatibility" : "disabled";
  return {
    nodeEnv,
    legacyUserHeader: {
      enabled,
      compatibilityFlagSet,
      productionHardFence,
      mode
    },
    authUrls: authRuntimeUrlPosture(),
    sessions: authSessionRuntimePosture(),
    oidc: oidcRuntimePosture(),
    scim: scimRuntimePosture(store),
    serverAdmins: serverAdminRuntimePosture(store)
  };
}

function normalizeAdminAuthConnectionProvider(value: unknown): AdminAuthConnectionProvider | undefined {
  return value === "oidc" || value === "scim" ? value : undefined;
}

async function testAdminAuthConnection(store: StateStore, provider: AdminAuthConnectionProvider, headers: Record<string, string | string[] | undefined>) {
  return provider === "oidc" ? testOidcAdminConnection(headers) : testScimAdminConnection(store);
}

async function testOidcAdminConnection(headers: Record<string, string | string[] | undefined>) {
  const testedAt = nowIso();
  const posture = oidcRuntimePosture();
  const checks = [
    { name: "issuer_configured", ok: posture.issuerConfigured, detail: posture.issuerConfigured ? "set" : "missing" },
    { name: "client_id_configured", ok: posture.clientIdConfigured, detail: posture.clientIdConfigured ? "set" : "missing" },
    { name: "config_valid", ok: posture.invalidConfig.length === 0, detail: posture.invalidConfig.length === 0 ? "valid" : posture.invalidConfig.join(", ") },
    { name: "config_secure", ok: posture.insecureConfig.length === 0, detail: posture.insecureConfig.length === 0 ? "secure" : posture.insecureConfig.join(", ") }
  ];
  if (!posture.configured || posture.invalidConfig.length > 0 || posture.insecureConfig.length > 0) {
    return {
      provider: "oidc" as const,
      testedAt,
      ok: false,
      status: "blocked" as const,
      checks: [...checks, { name: "discovery_document", ok: false, detail: "configuration must be valid before discovery test" }]
    };
  }
  try {
    const config = oidcProviderConfig(headers);
    if (!config) {
      return {
        provider: "oidc" as const,
        testedAt,
        ok: false,
        status: "blocked" as const,
        checks: [...checks, { name: "discovery_document", ok: false, detail: "oidc provider is not configured" }]
      };
    }
    const discovery = await discoverOidc(config);
    return {
      provider: "oidc" as const,
      testedAt,
      ok: true,
      status: "passed" as const,
      checks: [
        ...checks,
        { name: "discovery_document", ok: true, detail: "reachable" },
        { name: "authorization_endpoint", ok: Boolean(discovery.authorization_endpoint), detail: discovery.authorization_endpoint ? "present" : "missing" },
        { name: "token_endpoint", ok: Boolean(discovery.token_endpoint), detail: discovery.token_endpoint ? "present" : "missing" },
        { name: "userinfo_endpoint", ok: Boolean(discovery.userinfo_endpoint), detail: discovery.userinfo_endpoint ? "present" : "missing" }
      ]
    };
  } catch {
    return {
      provider: "oidc" as const,
      testedAt,
      ok: false,
      status: "failed" as const,
      checks: [...checks, { name: "discovery_document", ok: false, detail: "provider discovery failed" }]
    };
  }
}

function testScimAdminConnection(store: StateStore) {
  const testedAt = nowIso();
  const posture = scimRuntimePosture(store);
  const checks = [
    { name: "bearer_token_configured", ok: posture.bearerTokenConfigured, detail: posture.bearerTokenConfigured ? "set" : "missing" },
    { name: "service_provider_config", ok: posture.configured, detail: posture.configured ? "available" : "requires bearer token" },
    { name: "users_endpoint", ok: posture.configured, detail: posture.usersPath },
    { name: "groups_endpoint", ok: posture.configured, detail: posture.groupsPath },
    { name: "group_role_mapping_readiness", ok: posture.matchedMappingCount === posture.mappingCount, detail: `${posture.matchedMappingCount}/${posture.mappingCount} mappings matched` }
  ];
  return {
    provider: "scim" as const,
    testedAt,
    ok: posture.configured && posture.matchedMappingCount === posture.mappingCount,
    status: posture.configured ? "passed" as const : "blocked" as const,
    checks
  };
}

function requireCampaignPermission(store: StateStore, reply: FastifyReply, headers: Record<string, string | string[] | undefined>, campaignId: string, permission: PermissionName): true | FastifyReply {
  const userId = requireUser(store, reply, headers);
  if (typeof userId !== "string") return userId;
  return requireCampaignPermissionForUser(store, reply, headers, userId, campaignId, permission);
}

function requireCampaignPermissionForUser(store: StateStore, reply: FastifyReply, headers: Record<string, string | string[] | undefined>, userId: string, campaignId: string, permission: PermissionName): true | FastifyReply {
  const activeOrganization = requireCampaignActiveOrganization(store, reply, headers, userId, campaignId);
  if (activeOrganization !== true) return activeOrganization;
  if (
    !hasPermission({
      userId,
      campaignId,
      permission,
      members: store.state.members,
      grants: store.state.permissionGrants
    })
  ) {
    return forbidden(reply, `Missing permission: ${permission}`);
  }
  return true;
}

function requireCampaignActiveOrganization(store: StateStore, reply: FastifyReply, headers: Record<string, string | string[] | undefined>, userId: string, campaignId: string): true | FastifyReply {
  if (!campaignActiveOrganizationAllowed(store, headers, userId, campaignId)) return forbidden(reply, "Campaign belongs to a different active organization");
  return true;
}

function campaignActiveOrganizationAllowed(store: StateStore, headers: Record<string, string | string[] | undefined>, userId: string, campaignId: string): boolean {
  const campaign = store.state.campaigns.find((item) => item.id === campaignId);
  if (!campaign?.organizationId) return true;
  const workspace = organizationWorkspaceRecordForRequest(store, userId, headers);
  return workspace.id === campaign.organizationId;
}

function canCampaign(store: StateStore, userId: string, campaignId: string, permission: PermissionName): boolean {
  return hasPermission({
    userId,
    campaignId,
    permission,
    members: store.state.members,
    grants: store.state.permissionGrants
  });
}

/**
 * Scene read permission means "may participate at the table" for players and
 * observers.  It must not implicitly disclose the GM's inactive prep scenes.
 * Roles which can author or administer the table retain access to the full
 * scene collection.
 */
function canAccessPreparedScenes(store: StateStore, userId: string, campaignId: string): boolean {
  return (
    canCampaign(store, userId, campaignId, "campaign.update") ||
    canCampaign(store, userId, campaignId, "scene.create") ||
    canCampaign(store, userId, campaignId, "scene.update") ||
    canCampaign(store, userId, campaignId, "scene.delete") ||
    canCampaign(store, userId, campaignId, "scene.activate") ||
    canCampaign(store, userId, campaignId, "token.reveal") ||
    canCampaign(store, userId, campaignId, "combat.manage")
  );
}

function canReadSceneRecord(store: StateStore, userId: string, scene: Scene): boolean {
  if (!canCampaign(store, userId, scene.campaignId, "scene.read")) return false;
  return scene.active || canAccessPreparedScenes(store, userId, scene.campaignId);
}

function readableScenesForUser(store: StateStore, userId: string, campaignId: string): Scene[] {
  if (!canCampaign(store, userId, campaignId, "scene.read")) return [];
  const includePrepared = canAccessPreparedScenes(store, userId, campaignId);
  return store.state.scenes.filter((scene) => scene.campaignId === campaignId && (includePrepared || scene.active));
}

function readableAssetIdsForUser(store: StateStore, userId: string, campaignId: string): Set<string> {
  if (canAccessPreparedScenes(store, userId, campaignId)) {
    return new Set(store.state.assets.filter((asset) => asset.campaignId === campaignId).map((asset) => asset.id));
  }

  const scenes = readableScenesForUser(store, userId, campaignId);
  const sceneIds = new Set(scenes.map((scene) => scene.id));
  const ids = new Set<string>();
  for (const scene of scenes) {
    if (scene.backgroundAssetId) ids.add(scene.backgroundAssetId);
  }
  const visibleTokens = visibleTokensForUser(
    store,
    userId,
    campaignId,
    store.state.tokens.filter((token) => sceneIds.has(token.sceneId))
  );
  for (const token of visibleTokens) {
    if (token.imageAssetId) ids.add(token.imageAssetId);
    if (token.actorId) {
      const actor = store.state.actors.find((candidate) => candidate.id === token.actorId && candidate.campaignId === campaignId);
      if (actor?.imageAssetId) ids.add(actor.imageAssetId);
    }
  }
  for (const actor of store.state.actors) {
    if (actor.campaignId === campaignId && actor.ownerUserId === userId && actor.imageAssetId) ids.add(actor.imageAssetId);
  }
  for (const handout of store.state.handouts) {
    if (handout.campaignId !== campaignId) continue;
    if (!canReadHandout(store, userId, handout)) continue;
    for (const assetId of handout.assetIds) ids.add(assetId);
  }
  return ids;
}

function canReadAssetRecord(store: StateStore, userId: string, asset: MapAsset): boolean {
  if (!canCampaign(store, userId, asset.campaignId, "scene.read")) return false;
  return readableAssetIdsForUser(store, userId, asset.campaignId).has(asset.id);
}

function campaignIdForScene(store: StateStore, sceneId: string): string | undefined {
  return store.state.scenes.find((scene) => scene.id === sceneId)?.campaignId;
}

function compareScenesForDisplay(left: Scene, right: Scene): number {
  return left.sortOrder - right.sortOrder || left.createdAt.localeCompare(right.createdAt) || left.name.localeCompare(right.name);
}

function appendSceneActivationHistory(scene: Scene, input: { activatedAt: string; activatedByUserId?: string; previousActiveSceneId?: string; deactivatedSceneIds: string[]; source: "create" | "activate" }) {
  const history = scene.activationHistory ?? [];
  history.push({
    id: createId("sact"),
    sceneId: scene.id,
    activatedAt: input.activatedAt,
    activatedByUserId: input.activatedByUserId,
    previousActiveSceneId: input.previousActiveSceneId,
    deactivatedSceneIds: input.deactivatedSceneIds,
    source: input.source
  });
  if (history.length > 20) history.splice(0, history.length - 20);
  scene.activationHistory = history;
}

function normalizeBoundedText(value: unknown, maxLength: number): string | undefined {
  if (typeof value !== "string" || value.length > maxLength) return undefined;
  return value.trim();
}

function normalizeCampaignSessionInput(
  store: StateStore,
  campaignId: string,
  rawBody: unknown,
  existing?: CampaignSession
):
  | { ok: true; value: Partial<Pick<CampaignSession, "title" | "agenda" | "notes" | "scheduledFor" | "sceneIds" | "encounterIds">> }
  | { ok: false; error: string } {
  if (!isRecord(rawBody)) return { ok: false, error: "Campaign session body must be a JSON object" };
  const value: Partial<Pick<CampaignSession, "title" | "agenda" | "notes" | "scheduledFor" | "sceneIds" | "encounterIds">> = {};

  if ("title" in rawBody) {
    const title = normalizeBoundedText(rawBody.title, 160);
    if (!title) return { ok: false, error: "Session title must be 1-160 characters" };
    value.title = title;
  } else if (!existing) {
    value.title = undefined;
  }
  for (const [field, maxLength] of [
    ["agenda", 20_000],
    ["notes", 20_000]
  ] as const) {
    if (!(field in rawBody)) continue;
    const text = normalizeBoundedText(rawBody[field], maxLength);
    if (text === undefined) return { ok: false, error: `${field} must be a string no longer than ${maxLength} characters` };
    value[field] = text;
  }
  if ("scheduledFor" in rawBody) {
    if (rawBody.scheduledFor === null || rawBody.scheduledFor === "") {
      value.scheduledFor = undefined;
    } else if (typeof rawBody.scheduledFor === "string" && Number.isFinite(Date.parse(rawBody.scheduledFor))) {
      value.scheduledFor = new Date(rawBody.scheduledFor).toISOString();
    } else {
      return { ok: false, error: "scheduledFor must be an ISO date or null" };
    }
  }
  for (const [field, collection] of [
    ["sceneIds", store.state.scenes] as const,
    ["encounterIds", store.state.encounters] as const
  ]) {
    if (!(field in rawBody)) continue;
    const ids = rawBody[field];
    if (!Array.isArray(ids) || ids.length > 100 || ids.some((id) => typeof id !== "string" || !id.trim())) {
      return { ok: false, error: `${field} must be an array of at most 100 non-empty ids` };
    }
    const normalizedIds = [...new Set(ids.map((id) => id.trim()))];
    const missingId = normalizedIds.find((id) => !collection.some((record) => record.id === id && record.campaignId === campaignId));
    if (missingId) return { ok: false, error: `${field} contains a record outside this campaign: ${missingId}` };
    value[field] = normalizedIds;
  }
  return { ok: true, value };
}

function activateSceneForCampaignSession(store: StateStore, scene: Scene, userId: string, activatedAt: string): void {
  const deactivatedSceneIds: string[] = [];
  for (const existing of store.state.scenes) {
    if (existing.campaignId !== scene.campaignId || existing.id === scene.id || !existing.active) continue;
    existing.active = false;
    existing.updatedAt = activatedAt;
    deactivatedSceneIds.push(existing.id);
  }
  scene.active = true;
  scene.updatedAt = activatedAt;
  appendSceneActivationHistory(scene, {
    activatedAt,
    activatedByUserId: userId,
    previousActiveSceneId: deactivatedSceneIds[0],
    deactivatedSceneIds,
    source: "activate"
  });
}

function campaignSessionAuditSummary(session: CampaignSession): Record<string, unknown> {
  return {
    id: session.id,
    campaignId: session.campaignId,
    number: session.number,
    title: session.title,
    status: session.status,
    scheduledFor: session.scheduledFor,
    startedAt: session.startedAt,
    endedAt: session.endedAt,
    sceneCount: session.sceneIds.length,
    encounterCount: session.encounterIds.length,
    agendaCharacters: session.agenda.length,
    notesCharacters: session.notes.length,
    recapProposalId: session.recapProposalId,
    recapJournalId: session.recapJournalId
  };
}

const CAMPAIGN_SEARCH_TYPES = new Set<CampaignSearchResultType>(["world", "scene", "actor", "item", "journal", "handout", "encounter", "memory", "chat", "roll"]);

function normalizeCampaignSearchTypes(value: string | undefined): { ok: true; value: Set<CampaignSearchResultType> } | { ok: false; error: string } {
  if (!value?.trim()) return { ok: true, value: new Set(CAMPAIGN_SEARCH_TYPES) };
  const requested = [...new Set(value.split(",").map((item) => item.trim()).filter(Boolean))];
  const invalid = requested.find((item) => !CAMPAIGN_SEARCH_TYPES.has(item as CampaignSearchResultType));
  if (invalid) return { ok: false, error: `Unsupported search type: ${invalid}` };
  return { ok: true, value: new Set(requested as CampaignSearchResultType[]) };
}

function campaignSearchResults(
  store: StateStore,
  userId: string,
  campaignId: string,
  query: string,
  types: Set<CampaignSearchResultType>,
  worldId?: string
): CampaignSearchResult[] {
  const normalizedQuery = query.toLocaleLowerCase();
  const results: CampaignSearchResult[] = [];
  const add = (input: Omit<CampaignSearchResult, "score" | "snippet"> & { searchable: string; snippetSource?: string }) => {
    const title = input.title.trim();
    const searchable = `${title}\n${input.searchable}`.toLocaleLowerCase();
    if (!searchable.includes(normalizedQuery)) return;
    const score = campaignSearchScore(title, input.searchable, normalizedQuery);
    results.push({
      type: input.type,
      id: input.id,
      title,
      snippet: campaignSearchSnippet(input.snippetSource ?? input.searchable, normalizedQuery),
      updatedAt: input.updatedAt,
      ...(input.worldId ? { worldId: input.worldId } : {}),
      ...(input.visibility ? { visibility: input.visibility } : {}),
      score
    });
  };
  const inWorld = (recordWorldId: string | undefined) => !worldId || recordWorldId === worldId;

  if (types.has("world") && canCampaign(store, userId, campaignId, "world.read")) {
    for (const world of store.state.worlds) {
      if (world.campaignId !== campaignId || (worldId && world.id !== worldId)) continue;
      add({ type: "world", id: world.id, title: world.name, searchable: world.description, snippetSource: world.description, updatedAt: world.updatedAt, worldId: world.id });
    }
  }
  const readableScenes = readableScenesForUser(store, userId, campaignId);
  if (types.has("scene")) {
    for (const scene of readableScenes) {
      if (!inWorld(scene.worldId)) continue;
      const searchable = canAccessPreparedScenes(store, userId, campaignId) ? `${scene.folder ?? ""} ${JSON.stringify(scene.metadata)}` : scene.folder ?? "";
      add({ type: "scene", id: scene.id, title: scene.name, searchable, snippetSource: scene.folder ?? (scene.active ? "Active scene" : "Prepared scene"), updatedAt: scene.updatedAt, worldId: scene.worldId });
    }
  }
  const readableSceneIds = new Set(readableScenes.map((scene) => scene.id));
  const visibleTokenActorIds = new Set(
    visibleTokensForUser(store, userId, campaignId, store.state.tokens.filter((token) => readableSceneIds.has(token.sceneId)))
      .map((token) => token.actorId)
      .filter((actorId): actorId is string => Boolean(actorId))
  );
  if (types.has("actor") && canCampaign(store, userId, campaignId, "actor.read")) {
    for (const actor of store.state.actors) {
      if (actor.campaignId !== campaignId || !inWorld(actor.worldId)) continue;
      const canReadPrivate = canReadActorPrivateData(store, userId, campaignId, actor);
      if (!canReadPrivate && !visibleTokenActorIds.has(actor.id)) continue;
      add({
        type: "actor",
        id: actor.id,
        title: actor.name,
        searchable: canReadPrivate ? `${actor.type} ${actor.systemId} ${JSON.stringify(actor.data)}` : actor.type,
        snippetSource: actor.type,
        updatedAt: actor.updatedAt,
        worldId: actor.worldId
      });
    }
  }
  if (types.has("item") && canCampaign(store, userId, campaignId, "actor.read")) {
    for (const item of visibleItemsForUser(store, userId, campaignId)) {
      if (!inWorld(item.worldId)) continue;
      add({ type: "item", id: item.id, title: item.name, searchable: `${item.type} ${JSON.stringify(item.data)}`, snippetSource: item.type, updatedAt: item.updatedAt, worldId: item.worldId });
    }
  }
  if (types.has("journal")) {
    for (const journal of store.state.journals) {
      if (journal.campaignId !== campaignId || !inWorld(journal.worldId) || !canReadJournalEntry(store, userId, journal)) continue;
      add({ type: "journal", id: journal.id, title: journal.title, searchable: `${journal.tags.join(" ")} ${journal.body}`, snippetSource: journal.body, updatedAt: journal.updatedAt, worldId: journal.worldId, visibility: journal.visibility });
    }
  }
  if (types.has("handout")) {
    for (const rawHandout of store.state.handouts) {
      const handout = normalizeHandout(rawHandout);
      if (handout.campaignId !== campaignId || !inWorld(handout.worldId) || !canReadHandoutRecord(store, userId, handout)) continue;
      add({ type: "handout", id: handout.id, title: handout.title, searchable: `${handout.tags?.join(" ") ?? ""} ${handout.body}`, snippetSource: handout.body, updatedAt: handout.updatedAt, worldId: handout.worldId, visibility: handout.visibility });
    }
  }
  if (types.has("encounter")) {
    const canViewPrep = canAccessPreparedScenes(store, userId, campaignId);
    const activeEncounterIds = new Set(store.state.combats.filter((combat) => combat.campaignId === campaignId && combat.active && combat.encounterId).map((combat) => combat.encounterId!));
    for (const encounter of store.state.encounters) {
      if (encounter.campaignId !== campaignId || !inWorld(encounter.worldId) || (!canViewPrep && !activeEncounterIds.has(encounter.id))) continue;
      const searchable = canViewPrep ? `${encounter.difficulty ?? ""} ${encounter.summary}` : "Active encounter";
      add({ type: "encounter", id: encounter.id, title: encounter.name, searchable, snippetSource: searchable, updatedAt: encounter.updatedAt, worldId: encounter.worldId });
    }
  }
  if (types.has("memory")) {
    const canReadPublic = canCampaign(store, userId, campaignId, "ai.readPublicMemory");
    const canReadGm = canCampaign(store, userId, campaignId, "ai.readGmMemory");
    for (const rawMemory of store.state.aiMemory) {
      const memory = normalizeAiMemoryFact(rawMemory);
      if (memory.campaignId !== campaignId || !inWorld(memory.worldId) || aiMemoryFactStatus(memory) !== "approved") continue;
      if (memory.visibility === "public" ? !canReadPublic && !canReadGm : !canReadGm) continue;
      add({
        type: "memory",
        id: memory.id,
        title: memory.subject || memory.type?.replaceAll("_", " ") || "Campaign memory",
        searchable: `${memory.type ?? ""} ${memory.subject ?? ""} ${memory.text} ${memory.sourceIds.join(" ")}`,
        snippetSource: memory.text,
        updatedAt: memory.updatedAt,
        worldId: memory.worldId,
        visibility: memory.visibility
      });
    }
  }
  if (types.has("chat") && !worldId && canCampaign(store, userId, campaignId, "chat.read")) {
    for (const message of store.state.chat) {
      if (message.campaignId !== campaignId || !canReadChatMessage(store, userId, message)) continue;
      const author = store.state.users.find((candidate) => candidate.id === message.userId)?.displayName ?? message.userId;
      add({ type: "chat", id: message.id, title: `${author} - ${message.type}`, searchable: message.body, snippetSource: message.body, updatedAt: message.updatedAt, visibility: message.visibility });
    }
  }
  if (types.has("roll") && !worldId && canCampaign(store, userId, campaignId, "chat.read")) {
    const linkedMessagesByRollId = new Map(
      store.state.chat
        .filter((message) => message.campaignId === campaignId && message.rollId)
        .map((message) => [message.rollId!, message] as const)
    );
    for (const roll of store.state.rolls) {
      if (roll.campaignId !== campaignId || !canReadDiceRoll(store, userId, roll, linkedMessagesByRollId.get(roll.id))) continue;
      const title = roll.label?.trim() || roll.formula;
      const summary = `${roll.formula} = ${roll.total}`;
      add({
        type: "roll",
        id: roll.id,
        title,
        searchable: `${roll.label ?? ""} ${summary}`,
        snippetSource: summary,
        updatedAt: roll.updatedAt,
        visibility: roll.visibility
      });
    }
  }
  return results.sort((left, right) => right.score - left.score || right.updatedAt.localeCompare(left.updatedAt) || left.title.localeCompare(right.title));
}

function canReadHandoutRecord(store: StateStore, userId: string, handout: Handout): boolean {
  return canReadHandout(store, userId, handout);
}

function campaignSearchScore(title: string, body: string, normalizedQuery: string): number {
  const normalizedTitle = title.toLocaleLowerCase();
  if (normalizedTitle === normalizedQuery) return 1000;
  if (normalizedTitle.startsWith(normalizedQuery)) return 800;
  if (normalizedTitle.includes(normalizedQuery)) return 600;
  const bodyIndex = body.toLocaleLowerCase().indexOf(normalizedQuery);
  return bodyIndex < 0 ? 0 : Math.max(100, 400 - Math.min(bodyIndex, 300));
}

function campaignSearchSnippet(value: string, normalizedQuery: string): string {
  const compact = value.replace(/\s+/g, " ").trim();
  if (!compact) return "";
  const index = compact.toLocaleLowerCase().indexOf(normalizedQuery);
  const start = Math.max(0, index < 0 ? 0 : index - 70);
  const end = Math.min(compact.length, start + 220);
  return `${start > 0 ? "..." : ""}${compact.slice(start, end)}${end < compact.length ? "..." : ""}`;
}

function sessionRecapSource(
  store: StateStore,
  userId: string,
  campaignId: string,
  session: CampaignSession | undefined,
  transcript: string | undefined,
  manualNotes: string | undefined
): string {
  const startedAtMs = session?.startedAt ? Date.parse(session.startedAt) : Number.NEGATIVE_INFINITY;
  const endedAtMs = session?.endedAt ? Date.parse(session.endedAt) : Number.POSITIVE_INFINITY;
  const inWindow = (createdAt: string) => {
    const value = Date.parse(createdAt);
    return Number.isFinite(value) && value >= startedAtMs && value <= endedAtMs;
  };
  const chat = store.state.chat
    .filter((message) => message.campaignId === campaignId && inWindow(message.createdAt) && canReadChatMessage(store, userId, message))
    .slice(-500)
    .map((message) => ({ at: message.createdAt, userId: message.userId, type: message.type, visibility: message.visibility, body: message.body }));
  const rolls = store.state.rolls
    .filter((roll) => roll.campaignId === campaignId && inWindow(roll.createdAt))
    .slice(-300)
    .map((roll) => ({ at: roll.createdAt, userId: roll.userId, label: roll.label, formula: roll.formula, total: roll.total, visibility: roll.visibility }));
  const combats = store.state.combats
    .filter((combat) => combat.campaignId === campaignId && (inWindow(combat.createdAt) || inWindow(combat.updatedAt)))
    .map((combat) => ({ id: combat.id, encounterId: combat.encounterId, round: combat.round, active: combat.active, combatants: combat.combatants.map((combatant) => ({ name: combatant.name, defeated: combatant.defeated })) }));
  const audit = store.state.auditLogs
    .filter((entry) => entry.campaignId === campaignId && inWindow(entry.createdAt))
    .slice(-300)
    .map((entry) => ({ at: entry.createdAt, action: entry.action, targetType: entry.targetType, targetId: entry.targetId }));
  return JSON.stringify(
    {
      session: session
        ? {
            id: session.id,
            number: session.number,
            title: session.title,
            agenda: session.agenda,
            notes: session.notes,
            scheduledFor: session.scheduledFor,
            startedAt: session.startedAt,
            endedAt: session.endedAt,
            sceneIds: session.sceneIds,
            encounterIds: session.encounterIds
          }
        : undefined,
      transcript,
      manualNotes,
      chat,
      rolls,
      combats,
      audit
    },
    null,
    2
  ).slice(0, 120_000);
}

function sessionRecapPrompt(session: CampaignSession | undefined, source: string): string {
  return [
    `Create a structured recap for ${session ? `session ${session.number}, ${session.title}` : "the supplied campaign session"}.`,
    "Return JSON only with this exact shape:",
    '{"playerRecap":"markdown safe for all players","gmRecap":"private markdown","timelineEvents":[{"text":"fact","subject":"optional","visibility":"public|gm_only","confidence":0.0}],"unresolvedHooks":["..."],"lootGained":["..."],"xpNotes":["..."],"characterNotes":["..."],"prepSuggestions":["..."]}',
    "Separate confirmed events from suggestions. Do not expose GM-only source material in playerRecap. Do not invent facts; put uncertain possibilities only in prepSuggestions.",
    "Session source:",
    source
  ].join("\n\n");
}

function parseStructuredSessionRecap(providerOutput: string, source: string): StructuredSessionRecap {
  const parsed = parseFirstJsonObject(providerOutput);
  const record = isRecord(parsed) ? parsed : {};
  const sourceEvidence = sessionRecapSourceEvidence(source);
  const playerRecap = boundedString(record.playerRecap, 20_000) ?? "The session is complete. The GM is reviewing the detailed recap before publication.";
  // A provider can return prose or malformed JSON. Keep that response on the
  // AI thread, but seed reviewable memory from supplied evidence rather than
  // accidentally treating unstructured model prose as campaign canon.
  const gmRecap = boundedString(record.gmRecap, 30_000) ?? sourceEvidence ?? (providerOutput.trim().slice(0, 30_000) || `No provider recap was returned. Source evidence length: ${source.length} characters.`);
  const timelineEvents = Array.isArray(record.timelineEvents)
    ? record.timelineEvents
        .flatMap((entry) => {
          if (!isRecord(entry)) return [];
          const text = boundedString(entry.text, 1_000);
          if (!text) return [];
          const visibility: "public" | "gm_only" = entry.visibility === "public" ? "public" : "gm_only";
          const confidence = typeof entry.confidence === "number" && Number.isFinite(entry.confidence) ? Math.min(1, Math.max(0, entry.confidence)) : undefined;
          return [{ text, subject: boundedString(entry.subject, 160), visibility, confidence }];
        })
        .slice(0, 50)
    : [];
  return {
    playerRecap,
    gmRecap,
    timelineEvents,
    unresolvedHooks: boundedStringArray(record.unresolvedHooks, 50, 1_000),
    lootGained: boundedStringArray(record.lootGained, 50, 500),
    xpNotes: boundedStringArray(record.xpNotes, 50, 500),
    characterNotes: boundedStringArray(record.characterNotes, 50, 1_000),
    prepSuggestions: boundedStringArray(record.prepSuggestions, 50, 1_000)
  };
}

function sessionRecapSourceEvidence(source: string): string | undefined {
  try {
    const parsed = JSON.parse(source) as unknown;
    if (!isRecord(parsed)) return undefined;
    const session = isRecord(parsed.session) ? parsed.session : undefined;
    const evidence = [
      boundedString(parsed.transcript, 20_000),
      boundedString(parsed.manualNotes, 10_000),
      session ? boundedString(session.notes, 10_000) : undefined
    ].filter((value): value is string => Boolean(value));
    return evidence.length > 0 ? evidence.join("\n\n") : undefined;
  } catch {
    return undefined;
  }
}

function localSessionRecap(store: StateStore, userId: string, campaignId: string, session: CampaignSession | undefined): StructuredSessionRecap {
  const defaultWindowStart = Date.now() - 12 * 60 * 60 * 1_000;
  const sessionWindowStart = Date.parse(session?.startedAt ?? session?.createdAt ?? "");
  const windowStart = Number.isFinite(sessionWindowStart) ? sessionWindowStart : defaultWindowStart;
  const publicMessages = store.state.chat
    .filter((message) => message.campaignId === campaignId && message.visibility === "public" && Date.parse(message.createdAt) >= windowStart)
    .sort((left, right) => left.createdAt.localeCompare(right.createdAt));
  const visibleRolls = store.state.rolls
    .filter((roll) => roll.campaignId === campaignId && (roll.visibility === "public" || roll.userId === userId) && Date.parse(roll.createdAt) >= windowStart)
    .sort((left, right) => left.createdAt.localeCompare(right.createdAt));
  const sessionCombats = store.state.combats.filter((combat) => {
    if (combat.campaignId !== campaignId || Date.parse(combat.updatedAt) < windowStart) return false;
    return !session || session.encounterIds.length === 0 || (combat.encounterId !== undefined && session.encounterIds.includes(combat.encounterId));
  });
  const highlights = publicMessages
    .filter((message) => message.type !== "system" && !message.body.trim().startsWith("/"))
    .slice(-5)
    .map((message) => message.body.trim().replace(/\s+/g, " ").slice(0, 180));
  const rollSummary = visibleRolls.length > 0 ? `${visibleRolls.length} visible rolls were recorded; the highest total was ${Math.max(...visibleRolls.map((roll) => roll.total))}.` : "No visible rolls were recorded.";
  const combatSummary = sessionCombats.length > 0 ? `${sessionCombats.length} combat${sessionCombats.length === 1 ? "" : "s"} reached round ${Math.max(...sessionCombats.map((combat) => combat.round))}.` : "No combat was recorded in this session window.";
  const playerSections = [
    `## Session overview\n${rollSummary} ${combatSummary}`,
    highlights.length > 0 ? `## Table highlights\n${highlights.map((highlight) => `- ${highlight}`).join("\n")}` : undefined
  ].filter((section): section is string => Boolean(section));
  const gmSections = [
    `Local recap generated from ${publicMessages.length} public chat messages, ${visibleRolls.length} visible rolls, and ${sessionCombats.length} combat records.`,
    session?.notes ? `## Session notes\n${session.notes}` : undefined,
    session?.agenda.trim() ? `## Agenda review\n${session.agenda}` : undefined
  ].filter((section): section is string => Boolean(section));
  return {
    playerRecap: playerSections.join("\n\n"),
    gmRecap: gmSections.join("\n\n"),
    timelineEvents: highlights.map((text) => ({ text, visibility: "public" as const, confidence: 1 })),
    unresolvedHooks: [],
    lootGained: [],
    xpNotes: [],
    characterNotes: [],
    prepSuggestions: session?.agenda
      ? session.agenda
          .split(/\r?\n/)
          .map((item) => item.replace(/^\s*[-*]\s*/, "").trim())
          .filter(Boolean)
          .slice(0, 20)
          .map((item) => `Follow up on: ${item}`)
      : []
  };
}

function parseFirstJsonObject(value: string): unknown {
  const unfenced = value.replace(/^\s*```(?:json)?/i, "").replace(/```\s*$/i, "").trim();
  const start = unfenced.indexOf("{");
  const end = unfenced.lastIndexOf("}");
  if (start < 0 || end <= start) return undefined;
  try {
    return JSON.parse(unfenced.slice(start, end + 1)) as unknown;
  } catch {
    return undefined;
  }
}

function boundedString(value: unknown, maxLength: number): string | undefined {
  if (typeof value !== "string") return undefined;
  const text = value.trim();
  return text ? text.slice(0, maxLength) : undefined;
}

function boundedStringArray(value: unknown, maxItems: number, maxLength: number): string[] {
  if (!Array.isArray(value)) return [];
  return [...new Set(value.map((item) => boundedString(item, maxLength)).filter((item): item is string => Boolean(item)))].slice(0, maxItems);
}

function formatGmSessionRecap(recap: StructuredSessionRecap): string {
  const sections = [recap.gmRecap];
  if (recap.timelineEvents.length > 0) sections.push(`## Timeline\n${recap.timelineEvents.map((event) => `- ${event.text}`).join("\n")}`);
  if (recap.unresolvedHooks.length > 0) sections.push(`## Unresolved hooks\n${recap.unresolvedHooks.map((item) => `- ${item}`).join("\n")}`);
  if (recap.lootGained.length > 0) sections.push(`## Loot gained\n${recap.lootGained.map((item) => `- ${item}`).join("\n")}`);
  if (recap.xpNotes.length > 0) sections.push(`## XP and milestones\n${recap.xpNotes.map((item) => `- ${item}`).join("\n")}`);
  if (recap.characterNotes.length > 0) sections.push(`## Character notes\n${recap.characterNotes.map((item) => `- ${item}`).join("\n")}`);
  return sections.join("\n\n");
}

function formatNextSessionPrep(recap: StructuredSessionRecap): string {
  const suggestions = recap.prepSuggestions.length > 0 ? recap.prepSuggestions : recap.unresolvedHooks.map((hook) => `Decide how this thread advances: ${hook}`);
  return suggestions.length > 0 ? `## Prep suggestions\n${suggestions.map((item) => `- [ ] ${item}`).join("\n")}` : "No next-session prep suggestions were generated. Add GM notes before publishing.";
}

function sessionWorldId(store: StateStore, session: CampaignSession | undefined): string | undefined {
  if (!session) return undefined;
  return session.sceneIds.map((sceneId) => store.state.scenes.find((scene) => scene.id === sceneId && scene.campaignId === session.campaignId)?.worldId).find((worldId): worldId is string => Boolean(worldId));
}

function sessionRecapMemoryCandidates(
  campaignId: string,
  userId: string,
  proposalId: string,
  session: CampaignSession | undefined,
  recap: StructuredSessionRecap
): AiMemoryFact[] {
  const source: AiMemoryFactSource = { type: "session_recap", id: session?.id ?? proposalId, label: session ? `Session ${session.number}: ${session.title}` : "Campaign recap" };
  const candidates: AiMemoryFact[] = [];
  const add = (type: AiMemoryFactType, text: string, visibility: Visibility, subject?: string, confidence?: number) => {
    candidates.push(
      createTimestamped("mem", {
        campaignId,
        worldId: undefined,
        text,
        visibility,
        sourceIds: [proposalId, ...(session ? [session.id] : [])],
        type,
        subject,
        status: "candidate" as const,
        confidence,
        source,
        createdBy: "ai" as const
      }) satisfies AiMemoryFact
    );
  };
  add("session_summary", recap.gmRecap.slice(0, 1_000), "gm_only", session ? `Session ${session.number}` : "Session recap", 1);
  for (const event of recap.timelineEvents) add("timeline_event", event.text, event.visibility, event.subject, event.confidence);
  for (const hook of recap.unresolvedHooks) add("unresolved_thread", hook, "gm_only");
  for (const loot of recap.lootGained) add("canon_fact", loot, "public", "Loot gained");
  for (const note of recap.characterNotes) add("character_goal", note, "gm_only");
  return candidates.slice(0, 100).map((candidate) => ({ ...candidate, createdBy: "ai", status: "candidate" }));
}

function encounterDesignProviderPrompt(store: StateStore, campaignId: string, prompt: string, difficulty: string, partyActorIds: string[]): string {
  const campaign = store.state.campaigns.find((item) => item.id === campaignId);
  const party = store.state.actors
    .filter((actor) => actor.campaignId === campaignId && (partyActorIds.length === 0 ? Boolean(actor.ownerUserId) : partyActorIds.includes(actor.id)))
    .map((actor) => ({ id: actor.id, name: actor.name, type: actor.type, systemId: actor.systemId }))
    .slice(0, 20);
  const activeScene = store.state.scenes.find((scene) => scene.campaignId === campaignId && scene.active);
  return [
    `Design a playable ${difficulty} encounter for ${campaign?.name ?? "this campaign"}.`,
    `GM brief: ${prompt}`,
    `Party: ${JSON.stringify(party)}`,
    `Current scene: ${activeScene ? JSON.stringify({ id: activeScene.id, name: activeScene.name, width: activeScene.width, height: activeScene.height, gridSize: activeScene.gridSize }) : "none"}`,
    "Return JSON only with this exact shape:",
    '{"name":"encounter title","summary":"concise playable setup","difficulty":"difficulty label","sceneName":"prep scene title","objectives":["..."],"complications":["..."]}',
    "Use only the requested system-agnostic brief and visible campaign context. Do not claim that tokens or rules effects were created; this response becomes a reviewable proposal."
  ].join("\n\n");
}

function localEncounterDesign(prompt: string, difficulty: string, requestedSceneName?: string): StructuredEncounterDesign {
  const name = "AI Draft Encounter";
  return {
    name,
    summary: prompt,
    difficulty,
    sceneName: requestedSceneName ?? `${name} Scene`,
    objectives: ["Resolve the encounter objective described in the GM brief."],
    complications: []
  };
}

function parseStructuredEncounterDesign(providerOutput: string, fallback: { prompt: string; difficulty: string; sceneName?: string }): StructuredEncounterDesign {
  const parsed = parseFirstJsonObject(providerOutput);
  const record = isRecord(parsed) ? parsed : {};
  const summary = boundedString(record.summary, 5_000) ?? fallback.prompt;
  const name = boundedString(record.name, 160) ?? "AI Draft Encounter";
  return {
    name,
    summary,
    difficulty: boundedString(record.difficulty, 40) ?? fallback.difficulty,
    sceneName: fallback.sceneName ?? boundedString(record.sceneName, 160) ?? `${name} Scene`,
    objectives: boundedStringArray(record.objectives, 20, 500),
    complications: boundedStringArray(record.complications, 20, 500)
  };
}

function finiteNumberFromUnknown(value: unknown): number | undefined {
  return typeof value === "number" && Number.isFinite(value) ? value : undefined;
}

function campaignDeletionAuditSummary(store: StateStore, campaign: Campaign) {
  const sceneIds = new Set(store.state.scenes.filter((scene) => scene.campaignId === campaign.id).map((scene) => scene.id));
  const threadIds = new Set(store.state.aiThreads.filter((thread) => thread.campaignId === campaign.id).map((thread) => thread.id));
  return {
    id: campaign.id,
    name: campaign.name,
    visibility: campaign.visibility,
    defaultSystemId: campaign.defaultSystemId,
    scenes: sceneIds.size,
    members: store.state.members.filter((member) => member.campaignId === campaign.id).length,
    invites: store.state.invites.filter((invite) => invite.campaignId === campaign.id).length,
    assets: store.state.assets.filter((asset) => asset.campaignId === campaign.id).length,
    tokens: store.state.tokens.filter((token) => sceneIds.has(token.sceneId)).length,
    actors: store.state.actors.filter((actor) => actor.campaignId === campaign.id).length,
    journals: store.state.journals.filter((journal) => journal.campaignId === campaign.id).length,
    chatMessages: store.state.chat.filter((message) => message.campaignId === campaign.id).length,
    diceRolls: store.state.rolls.filter((roll) => roll.campaignId === campaign.id).length,
    combats: store.state.combats.filter((combat) => combat.campaignId === campaign.id).length,
    proposals: store.state.proposals.filter((proposal) => proposal.campaignId === campaign.id).length,
    aiThreads: threadIds.size,
    pluginStorageEntries: store.state.pluginStorage.filter((entry) => entry.campaignId === campaign.id).length,
    scimGroupRoleMappings: store.state.scimGroupRoleMappings.filter((mapping) => mapping.campaignId === campaign.id).length
  };
}

function campaignLifecycleAuditSummary(campaign: Campaign): Record<string, unknown> {
  return {
    id: campaign.id,
    name: campaign.name,
    visibility: campaign.visibility,
    defaultSystemId: campaign.defaultSystemId,
    archived: Boolean(campaign.archivedAt),
    archivedAt: campaign.archivedAt,
    archivedByUserId: campaign.archivedByUserId,
    restoredAt: campaign.restoredAt,
    restoredByUserId: campaign.restoredByUserId
  };
}

function campaignUpdateAuditSummary(campaign: Campaign): Record<string, unknown> {
  return {
    id: campaign.id,
    name: campaign.name,
    descriptionLength: campaign.description.length,
    visibility: campaign.visibility,
    defaultSystemId: campaign.defaultSystemId
  };
}

function diceMacroAuditSummary(macro: DiceMacro): Record<string, unknown> {
  return {
    id: macro.id,
    campaignId: macro.campaignId,
    createdBy: macro.createdBy,
    name: macro.name,
    formula: macro.formula,
    visibility: macro.visibility
  };
}

function campaignActorOwnerUserId(
  store: StateStore,
  campaignId: string,
  requestedOwnerUserId: unknown,
  fallbackOwnerUserId?: string
): { ok: true; value: string | undefined } | { ok: false; error: string } {
  const ownerUserId = requestedOwnerUserId === undefined ? fallbackOwnerUserId : normalizeNonEmptyString(requestedOwnerUserId);
  if (requestedOwnerUserId !== undefined && !ownerUserId) return { ok: false, error: "Actor ownerUserId must be a non-empty string" };
  if (ownerUserId && !store.state.members.some((member) => member.campaignId === campaignId && member.userId === ownerUserId)) {
    return { ok: false, error: "Actor ownerUserId must reference a member of the same campaign" };
  }
  return { ok: true, value: ownerUserId };
}

function sceneDeletionAuditSummary(store: StateStore, scene: Scene) {
  return {
    id: scene.id,
    campaignId: scene.campaignId,
    name: scene.name,
    folder: scene.folder,
    active: scene.active,
    width: scene.width,
    height: scene.height,
    gridSize: scene.gridSize,
    tokens: store.state.tokens.filter((token) => token.sceneId === scene.id).length,
    sceneChatMessages: store.state.chat.filter((message) => message.sceneId === scene.id).length,
    fogRegions: scene.fog.length,
    fogHistoryEntries: scene.fogHistory?.length ?? 0,
    walls: scene.walls.length,
    lights: scene.lights.length,
    annotations: scene.annotations?.length ?? 0,
    sourceFogPresets: store.state.fogPresets.filter((preset) => preset.sourceSceneId === scene.id).length
  };
}

function combatAuditSummary(combat: Combat) {
  return {
    id: combat.id,
    campaignId: combat.campaignId,
    encounterId: combat.encounterId,
    active: combat.active,
    round: combat.round,
    turnIndex: combat.turnIndex,
    manualTurnOrder: combat.manualTurnOrder ?? false,
    combatantCount: combat.combatants.length,
    activeCombatantId: combat.combatants[combat.turnIndex]?.id,
    defeatedCount: combat.combatants.filter((combatant) => combatant.defeated).length,
    combatants: combat.combatants.map((combatant) => ({
      id: combatant.id,
      tokenId: combatant.tokenId,
      actorId: combatant.actorId,
      name: combatant.name,
      initiative: combatant.initiative,
      defeated: combatant.defeated,
      readiness: combatant.readiness ?? "normal",
      conditions: combatant.conditions ?? [],
      deathSaveSuccesses: combatant.deathSaveSuccesses ?? 0,
      deathSaveFailures: combatant.deathSaveFailures ?? 0,
      deathSaveOutcome: combatant.deathSaveOutcome,
      resourceLabel: combatant.resourceLabel,
      resourceUsed: combatant.resourceUsed ?? false,
      resourceSpent: combatant.resourceSpent ?? false
    }))
  };
}

function orderedCombatants(combatants: Combat["combatants"], manualTurnOrder: boolean): Combat["combatants"] {
  if (manualTurnOrder) return combatants;
  return combatants
    .map((combatant, index) => ({ combatant, index }))
    .sort((left, right) => right.combatant.initiative - left.combatant.initiative || left.index - right.index)
    .map(({ combatant }) => combatant);
}

function isNpcInitiativeActor(actor: Actor): boolean {
  return actor.type === "npc" || actor.type === "monster";
}

function initiativeRollForActor(actor: Actor): { label: string; formula: string } {
  if (actor.systemId === DND_5E_SRD_SYSTEM_ID) return dnd5eSrdInitiativeRoll(actor);
  return {
    label: "Initiative",
    formula: `1d20${formatSignedFormulaNumber(genericActorInitiativeModifier(actor))}`
  };
}

function genericActorInitiativeModifier(actor: Actor): number {
  const direct = numericRecordValue(actor.data, "initiative");
  if (direct !== undefined) return Math.round(direct);
  const attributes = recordFromRecord(actor.data, "attributes") ?? recordFromRecord(actor.data, "abilities");
  if (!attributes) return 0;
  const dexterity = attributes.dexterity;
  if (typeof dexterity === "number") return Math.floor((dexterity - 10) / 2);
  if (isRecord(dexterity)) {
    const modifier = numericRecordValue(dexterity, "modifier") ?? numericRecordValue(dexterity, "mod");
    if (modifier !== undefined) return Math.round(modifier);
    const score = numericRecordValue(dexterity, "score") ?? numericRecordValue(dexterity, "value");
    if (score !== undefined) return Math.floor((score - 10) / 2);
  }
  return 0;
}

function numericRecordValue(record: Record<string, unknown>, key: string): number | undefined {
  const value = record[key];
  return typeof value === "number" && Number.isFinite(value) ? value : undefined;
}

function formatSignedFormulaNumber(value: number): string {
  if (value === 0) return "";
  return value > 0 ? `+${value}` : String(value);
}

function createPendingCombatAction(input: {
  combat: Combat;
  actor: Actor;
  userId: string;
  rollId: string;
  actionLabel: string;
  targetActorIds: string[];
  applyEffect: boolean;
  consumeResources: boolean;
  resolution: RulesActionResolutionResult;
  rolledResults: Array<{ resolutionRoll: { label?: string; formula: string; targetActorId?: string }; rolled: ReturnType<typeof rollFormula> }>;
  actorUpdates: RulesActionResolutionResult["actorUpdates"];
  itemUpdates: Item[];
  effects: SystemRollEffectResult[];
  visibility: DiceRoll["visibility"];
}): CombatAction {
  const itemUpdates = input.itemUpdates.map((item) => ({
    itemId: item.id,
    before: {},
    after: isRecord(item.data) ? cloneRecord(item.data) : { value: item.data }
  }));
  const action = createTimestamped("cact", {
    campaignId: input.combat.campaignId,
    combatId: input.combat.id,
    actorId: input.actor.id,
    actorName: input.actor.name,
    requestedByUserId: input.userId,
    status: "pending_gm" as const,
    rollId: input.rollId,
    actionLabel: input.actionLabel,
    targetActorIds: input.targetActorIds,
    applyEffect: input.applyEffect,
    consumeResources: input.consumeResources,
    resolution: input.resolution,
    rolls: input.rolledResults.map(({ resolutionRoll, rolled }) => ({
      label: resolutionRoll.label ?? input.actionLabel,
      formula: resolutionRoll.formula,
      terms: rolled.terms,
      total: rolled.total,
      targetActorId: resolutionRoll.targetActorId,
      visibility: input.visibility
    })),
    actorUpdates: input.actorUpdates.map((update) => ({
      actorId: update.actorId,
      before: cloneRecord(update.before),
      after: cloneRecord(update.after)
    })),
    itemUpdates,
    effects: input.effects.map((effect) => combatActionEffectSummary(effect)),
    resultSummary: combatActionResultSummary(input.effects, input.rolledResults.map((result) => result.rolled.total))
  }) satisfies CombatAction;
  return action;
}

function applyPendingCombatAction(
  store: StateStore,
  broadcast: (event: EngineEvent) => void,
  userId: string,
  combat: Combat,
  action: CombatAction
):
  | { combat: Combat; combatAction: CombatAction; updatedActors: Actor[]; rolls: DiceRoll[]; chatMessages: ChatMessage[] }
  | { error: string } {
  const actorIds = new Set(action.actorUpdates.map((update) => update.actorId));
  const missingActorId = [...actorIds].find((actorId) => !store.state.actors.some((actor) => actor.id === actorId && actor.campaignId === combat.campaignId));
  if (missingActorId) return { error: `Actor update target not found: ${missingActorId}` };
  const missingItemId = (action.itemUpdates ?? []).find((update) => !store.state.items.some((item) => item.id === update.itemId && item.campaignId === combat.campaignId))?.itemId;
  if (missingItemId) return { error: `Item update target not found: ${missingItemId}` };

  const updatedAt = nowIso();
  for (const actorUpdate of action.actorUpdates) {
    const actor = store.state.actors.find((item) => item.id === actorUpdate.actorId && item.campaignId === combat.campaignId);
    if (actor) {
      actor.data = cloneRecord(actorUpdate.after);
      actor.updatedAt = updatedAt;
    }
  }
  for (const itemUpdate of action.itemUpdates ?? []) {
    const item = store.state.items.find((candidate) => candidate.id === itemUpdate.itemId && candidate.campaignId === combat.campaignId);
    if (item) {
      item.data = cloneRecord(itemUpdate.after);
      item.updatedAt = updatedAt;
    }
  }
  syncCombatDefeatedFromActorIds(combat, store.state.actors, [...actorIds]);
  action.status = "confirmed";
  action.confirmedByUserId = userId;
  action.confirmedAt = updatedAt;
  action.updatedAt = updatedAt;
  combat.updatedAt = updatedAt;

  const rolls = action.rolls.map((roll) =>
    createTimestamped("roll", {
      campaignId: combat.campaignId,
      userId: action.requestedByUserId,
      formula: roll.formula,
      label: roll.targetActorId && action.rolls.length > 1 ? `${action.actionLabel} (${roll.targetActorId})` : action.actionLabel,
      visibility: roll.visibility,
      terms: roll.terms,
      total: roll.total
    }) satisfies DiceRoll
  );
  const chatMessages = rolls.map((roll) =>
    createTimestamped("msg", {
      campaignId: combat.campaignId,
      userId: action.requestedByUserId,
      type: "roll" as const,
      body: `${action.actorName} ${roll.label}: ${roll.formula} = ${roll.total}`,
      visibility: roll.visibility,
      recipientUserIds: [],
      rollId: roll.id
    }) satisfies ChatMessage
  );
  store.state.rolls.push(...rolls);
  store.state.chat.push(...chatMessages);
  appendServerAuditLog(store, userId, {
    campaignId: combat.campaignId,
    action: "combat.actionConfirmed",
    targetType: "combat",
    targetId: combat.id,
    after: {
      actionId: action.id,
      actorId: action.actorId,
      rollId: action.rollId,
      targetActorIds: action.targetActorIds,
      actorUpdateCount: action.actorUpdates.length,
      itemUpdateCount: action.itemUpdates?.length ?? 0,
      resultSummary: action.resultSummary
    }
  });
  store.save();

  const updatedActors = [...actorIds]
    .map((actorId) => store.state.actors.find((actor) => actor.id === actorId && actor.campaignId === combat.campaignId))
    .filter((actor): actor is Actor => Boolean(actor));
  for (const actor of updatedActors) broadcastActorUpdated(broadcast, actor);
  broadcast(createEvent({ campaignId: combat.campaignId, type: "combat.turnChanged", targetId: combat.id, payload: combat }));
  for (const roll of rolls) {
    broadcast(createEvent({ campaignId: roll.campaignId, type: "dice.roll.created", actorUserId: action.requestedByUserId, targetId: roll.id, payload: roll }));
  }
  for (const message of chatMessages) {
    broadcast(createEvent({ campaignId: message.campaignId, type: "chat.message.created", actorUserId: action.requestedByUserId, targetId: message.id, payload: message }));
  }
  return { combat, combatAction: action, updatedActors, rolls, chatMessages };
}

function syncCombatDefeatedFromActorIds(combat: Combat, actors: Actor[], actorIds: string[]): boolean {
  const actorIdSet = new Set(actorIds);
  let updated = false;
  for (const combatant of combat.combatants) {
    if (!combatant.actorId || !actorIdSet.has(combatant.actorId)) continue;
    const actor = actors.find((candidate) => candidate.id === combatant.actorId && candidate.campaignId === combat.campaignId);
    if (!actor || actorHpCurrent(actor) > 0 || combatant.defeated) continue;
    combatant.defeated = true;
    updated = true;
  }
  return updated;
}

function actorHpCurrent(actor: Actor): number {
  if (!isRecord(actor.data)) return Number.POSITIVE_INFINITY;
  const hp = actor.data.hp;
  if (!isRecord(hp)) return Number.POSITIVE_INFINITY;
  const current = Number(hp.current);
  return Number.isFinite(current) ? current : Number.POSITIVE_INFINITY;
}

function combatActionEffectSummary(effect: SystemRollEffectResult): NonNullable<CombatAction["effects"]>[number] {
  if (effect.type === "damage" || effect.type === "healing") {
    return { type: effect.type, targetActorId: effect.targetActorId, amount: effect.amount };
  }
  if (effect.type === "condition") {
    return { type: effect.type, targetActorId: effect.targetActorId, amount: effect.after.length - effect.before.length };
  }
  return { type: effect.type, targetActorId: effect.targetActorId };
}

function systemRollEffectsPayloadForUser(store: StateStore, userId: string, campaignId: string, effects: SystemRollEffectResult[]): unknown[] {
  return effects.map((effect) =>
    canReadActorPrivateDataById(store, userId, campaignId, effect.targetActorId) ? effect : combatActionEffectSummary(effect)
  );
}

function combatActionResultSummary(effects: SystemRollEffectResult[], totals: number[]): string {
  const damage = effects.filter((effect): effect is SystemRollPoolEffectResult => effect.type === "damage");
  const healing = effects.filter((effect): effect is SystemRollPoolEffectResult => effect.type === "healing");
  const conditions = effects.filter((effect): effect is SystemRollConditionEffectResult => effect.type === "condition");
  const parts: string[] = [];
  if (totals.length > 0) parts.push(`roll ${totals.join(", ")}`);
  if (damage.length > 0) parts.push(`${damage.reduce((sum, effect) => sum + effect.amount, 0)} damage`);
  if (healing.length > 0) parts.push(`${healing.reduce((sum, effect) => sum + effect.amount, 0)} healing`);
  if (conditions.length > 0) parts.push(`${conditions.map((effect) => effect.conditionName).join(", ")} condition`);
  return parts.join("; ") || "No automatic effect";
}

function removeCampaignRecords(store: StateStore, campaignId: string): void {
  const sceneIds = new Set(store.state.scenes.filter((scene) => scene.campaignId === campaignId).map((scene) => scene.id));
  const threadIds = new Set(store.state.aiThreads.filter((thread) => thread.campaignId === campaignId).map((thread) => thread.id));

  store.state.campaigns = store.state.campaigns.filter((item) => item.id !== campaignId);
  store.state.members = store.state.members.filter((item) => item.campaignId !== campaignId);
  store.state.invites = store.state.invites.filter((item) => item.campaignId !== campaignId);
  store.state.scimGroupRoleMappings = store.state.scimGroupRoleMappings.filter((item) => item.campaignId !== campaignId);
  store.state.worlds = store.state.worlds.filter((item) => item.campaignId !== campaignId);
  store.state.scenes = store.state.scenes.filter((item) => item.campaignId !== campaignId);
  store.state.assets = store.state.assets.filter((item) => item.campaignId !== campaignId);
  store.state.tokens = store.state.tokens.filter((item) => !sceneIds.has(item.sceneId));
  store.state.actors = store.state.actors.filter((item) => item.campaignId !== campaignId);
  store.state.items = store.state.items.filter((item) => item.campaignId !== campaignId);
  store.state.journals = store.state.journals.filter((item) => item.campaignId !== campaignId);
  store.state.handouts = store.state.handouts.filter((item) => item.campaignId !== campaignId);
  store.state.chat = store.state.chat.filter((item) => item.campaignId !== campaignId);
  store.state.rolls = store.state.rolls.filter((item) => item.campaignId !== campaignId);
  store.state.diceMacros = store.state.diceMacros.filter((item) => item.campaignId !== campaignId);
  store.state.audioTracks = store.state.audioTracks.filter((item) => item.campaignId !== campaignId);
  store.state.encounters = store.state.encounters.filter((item) => item.campaignId !== campaignId);
  store.state.campaignSessions = store.state.campaignSessions.filter((item) => item.campaignId !== campaignId);
  store.state.combats = store.state.combats.filter((item) => item.campaignId !== campaignId);
  store.state.proposals = store.state.proposals.filter((item) => item.campaignId !== campaignId);
  store.state.aiThreads = store.state.aiThreads.filter((item) => item.campaignId !== campaignId);
  store.state.aiEvaluations = store.state.aiEvaluations.filter((item) => item.campaignId !== campaignId);
  store.state.aiMemory = store.state.aiMemory.filter((item) => item.campaignId !== campaignId);
  store.state.aiToolCalls = store.state.aiToolCalls.filter((item) => !threadIds.has(item.threadId));
  store.state.auditLogs = store.state.auditLogs.filter((item) => item.campaignId !== campaignId);
  store.state.permissionGrants = store.state.permissionGrants.filter((item) => item.campaignId !== campaignId);
  store.state.pluginStorage = store.state.pluginStorage.filter((item) => item.campaignId !== campaignId);
  store.state.contentImports = store.state.contentImports.filter((item) => item.campaignId !== campaignId);
  store.state.fogPresets = store.state.fogPresets.filter((item) => item.campaignId !== campaignId);
}

function removeSceneRecords(store: StateStore, sceneId: string): void {
  const removedAt = nowIso();
  const tokenIds = new Set(store.state.tokens.filter((token) => token.sceneId === sceneId).map((token) => token.id));

  store.state.scenes = store.state.scenes.filter((item) => item.id !== sceneId);
  store.state.tokens = store.state.tokens.filter((item) => item.sceneId !== sceneId);
  store.state.chat = store.state.chat.filter((item) => item.sceneId !== sceneId);
  store.state.fogPresets = store.state.fogPresets.filter((item) => item.sourceSceneId !== sceneId);
  store.state.campaignSessions = store.state.campaignSessions.map((session) =>
    session.sceneIds.includes(sceneId)
      ? { ...session, sceneIds: session.sceneIds.filter((id) => id !== sceneId), updatedAt: removedAt }
      : session
  );
  store.state.encounters = store.state.encounters.map((encounter) => {
    const tokenIdsAfterDelete = encounter.tokenIds.filter((tokenId) => !tokenIds.has(tokenId));
    return tokenIdsAfterDelete.length === encounter.tokenIds.length ? encounter : { ...encounter, tokenIds: tokenIdsAfterDelete, updatedAt: removedAt };
  });
  store.state.combats = store.state.combats
    .map((combat) => {
      const combatants = combat.combatants.filter((combatant) => !tokenIds.has(combatant.tokenId));
      return combatants.length === combat.combatants.length ? combat : { ...combat, combatants, updatedAt: removedAt };
    })
    .filter((combat) => combat.combatants.length > 0);
}

function campaignIdForToken(store: StateStore, tokenId: string): string | undefined {
  const token = store.state.tokens.find((item) => item.id === tokenId);
  return token ? campaignIdForScene(store, token.sceneId) : undefined;
}

function campaignSceneIds(store: StateStore, campaignId: string): string[] {
  return store.state.scenes.filter((scene) => scene.campaignId === campaignId).map((scene) => scene.id);
}

function findPluginGrant(store: StateStore, campaignId: string, pluginId: string): PermissionGrant | undefined {
  return store.state.permissionGrants.find((grant) => grant.subjectType === "plugin" && grant.subjectId === pluginId && grant.campaignId === campaignId && (!grant.expiresAt || Date.parse(grant.expiresAt) > Date.now()));
}

function pluginCan(store: StateStore, campaignId: string, pluginId: string, permission: PermissionName): boolean {
  return findPluginGrant(store, campaignId, pluginId)?.permissions.includes(permission) ?? false;
}

function requirePluginStorageAccess(
  store: StateStore,
  pluginRegistry: PluginRuntimeRegistry,
  reply: FastifyReply,
  headers: Record<string, string | string[] | undefined>,
  campaignId: string,
  pluginId: string
): { ok: true; userId: string; plugin: LoadedPlugin } | { ok: false; reply: FastifyReply } {
  const allowed = requireCampaignPermission(store, reply, headers, campaignId, "plugin.configure");
  if (allowed !== true) return { ok: false, reply: allowed };
  const userId = requireUser(store, reply, headers);
  if (typeof userId !== "string") return { ok: false, reply: userId };
  const pluginGrant = findPluginGrant(store, campaignId, pluginId);
  const plugin = pluginRegistry.find(pluginId, pluginVersionFromGrant(pluginGrant));
  if (!plugin) return { ok: false, reply: notFound(reply, "Plugin not found") };
  if (!pluginGrant) return { ok: false, reply: forbidden(reply, "Plugin is not installed in this campaign") };
  if (!pluginCan(store, campaignId, plugin.id, "plugin.configure")) return { ok: false, reply: forbidden(reply, `Plugin ${plugin.id} lacks plugin.configure in this campaign`) };
  return { ok: true, userId, plugin };
}

function pluginStorageEntries(store: StateStore, campaignId: string, pluginId: string): PluginStorageEntry[] {
  return store.state.pluginStorage.filter((entry) => entry.campaignId === campaignId && entry.pluginId === pluginId).sort((left, right) => left.key.localeCompare(right.key));
}

function pluginStorageSnapshot(store: StateStore, campaignId: string, pluginId: string): Array<{ key: string; value: unknown; updatedAt: string }> {
  return pluginStorageEntries(store, campaignId, pluginId).map((entry) => ({
    key: entry.key,
    value: cloneJsonValue(entry.value),
    updatedAt: entry.updatedAt
  }));
}

function publicPluginStorageEntry(entry: PluginStorageEntry): Record<string, unknown> {
  return {
    id: entry.id,
    campaignId: entry.campaignId,
    pluginId: entry.pluginId,
    key: entry.key,
    value: cloneJsonValue(entry.value),
    updatedByType: entry.updatedByType,
    updatedById: entry.updatedById,
    createdAt: entry.createdAt,
    updatedAt: entry.updatedAt
  };
}

function upsertPluginStorageEntry(
  store: StateStore,
  campaignId: string,
  pluginId: string,
  key: string,
  value: unknown,
  updatedByType: "user" | "plugin",
  updatedById: string
): PluginStorageEntry {
  const existing = store.state.pluginStorage.find((entry) => entry.campaignId === campaignId && entry.pluginId === pluginId && entry.key === key);
  const now = nowIso();
  if (existing) {
    existing.value = cloneJsonValue(value);
    existing.updatedByType = updatedByType;
    existing.updatedById = updatedById;
    existing.updatedAt = now;
    return existing;
  }
  const entry = createTimestamped("pstore", {
    campaignId,
    pluginId,
    key,
    value: cloneJsonValue(value),
    updatedByType,
    updatedById
  }) satisfies PluginStorageEntry;
  store.state.pluginStorage.push(entry);
  return entry;
}

function deletePluginStorageEntry(store: StateStore, campaignId: string, pluginId: string, key: string): PluginStorageEntry | undefined {
  const index = store.state.pluginStorage.findIndex((entry) => entry.campaignId === campaignId && entry.pluginId === pluginId && entry.key === key);
  if (index < 0) return undefined;
  return store.state.pluginStorage.splice(index, 1)[0];
}

function pluginEventEnvelope(event: EngineEvent): PluginEventEnvelope | undefined {
  if (!isPluginEventType(event.type)) return undefined;
  return {
    id: event.id,
    campaignId: event.campaignId,
    type: event.type,
    actorUserId: event.actorUserId,
    targetId: event.targetId,
    timestamp: event.timestamp,
    causationId: event.causationId,
    correlationId: event.correlationId
  };
}

function pluginEventVisibleToGrant(store: StateStore, event: EngineEvent, permissions: PermissionName[]): boolean {
  const has = (permission: PermissionName) => permissions.includes(permission);
  if (event.type === "campaign.updated" || event.type.startsWith("campaign.member.")) return true;
  if (event.type.startsWith("campaign.session.")) return has("campaign.update");
  if (event.type.startsWith("world.")) return true;
  if (event.type.startsWith("journal.")) {
    const journal = journalEntryFromRealtimeEvent(store, event);
    return Boolean(journal && (journal.visibility === "public" || has("journal.readSecret")));
  }
  if (event.type.startsWith("handout.")) {
    const handout = handoutFromPluginEvent(store, event);
    return Boolean(handout && (handout.visibility === "public" || has("handout.readSecret")));
  }
  if (event.type.startsWith("scene.")) {
    const scene = sceneFromPluginEvent(store, event);
    return Boolean(scene && (scene.active || pluginCanAccessPreparedScenes(permissions)));
  }
  if (event.type.startsWith("token.")) {
    const token = tokenFromPluginEvent(store, event);
    if (!token) return false;
    const scene = store.state.scenes.find((candidate) => candidate.id === token.sceneId && candidate.campaignId === event.campaignId);
    if (!scene || (!scene.active && !pluginCanAccessPreparedScenes(permissions))) return false;
    if ((token.hidden || tokenLayer(token) === "gm") && !pluginCanReadHiddenTokens(permissions)) return false;
    return true;
  }
  if (event.type.startsWith("actor.")) return true;
  if (event.type.startsWith("item.")) {
    const item = itemFromPluginEvent(store, event);
    return Boolean(item && (!item.actorId || has("actor.readPrivate")));
  }
  if (event.type.startsWith("chat.message.")) {
    const message = chatMessageFromPluginEvent(store, event);
    if (!message) return false;
    if (message.visibility === "public") return true;
    if (message.visibility === "whisper") return has("chat.moderate");
    return has("chat.moderate") || has("journal.readSecret") || has("ai.readGmMemory");
  }
  if (event.type === "dice.roll.created") {
    const roll = diceRollFromRealtimeEvent(store, event);
    if (!roll) return false;
    const linkedMessage = store.state.chat.find((message) => message.rollId === roll.id && message.campaignId === roll.campaignId);
    if (linkedMessage?.visibility === "whisper" && !has("chat.moderate")) return false;
    if (roll.visibility === "public") return true;
    if (roll.visibility === "whisper") return has("chat.moderate");
    return has("chat.moderate") || has("journal.readSecret") || has("ai.readGmMemory");
  }
  if (event.type.startsWith("audio.")) {
    const track = audioTrackFromPluginEvent(store, event);
    return Boolean(track && (track.playing || pluginCanAccessPreparedScenes(permissions)));
  }
  if (event.type.startsWith("combat.")) return true;
  if (event.type.startsWith("encounter.")) {
    const encounter = encounterFromPluginEvent(store, event);
    if (!encounter) return false;
    if (pluginCanAccessPreparedScenes(permissions)) return true;
    const payload = isRecord(event.payload) ? event.payload : undefined;
    if (event.type === "encounter.deleted" && payload?.previouslyActive === true) return true;
    return store.state.combats.some(
      (combat) => combat.campaignId === event.campaignId && combat.active && combat.encounterId === encounter.id
    );
  }
  if (event.type.startsWith("proposal.") || event.type === "ai.proposal.created") {
    const proposal = proposalFromRealtimeEvent(store, event);
    return Boolean(proposal && proposalVisibleToPluginGrant(store, proposal, permissions));
  }
  if (event.type.startsWith("contentImport.")) return has("campaign.update");
  if (event.type.startsWith("ai.memory.")) {
    const memory = aiMemoryFromPluginEvent(store, event);
    if (!memory) return false;
    if (has("ai.readGmMemory")) return true;
    return has("ai.readPublicMemory") && memory.visibility === "public" && aiMemoryFactStatus(memory) === "approved";
  }
  if (
    event.type === "ai.thread.started" ||
    event.type.startsWith("ai.message.") ||
    event.type.startsWith("ai.reasoning.") ||
    event.type.startsWith("ai.activity.") ||
    event.type.startsWith("ai.tool.")
  ) {
    const payload = isRecord(event.payload) ? event.payload : undefined;
    if (payload?.visibility === "public") return true;
    return payload?.visibility === "gm_only" && (has("ai.readGmMemory") || has("chat.moderate"));
  }
  // New plugin event families must define an explicit record-visibility rule.
  return false;
}

function pluginCanAccessPreparedScenes(permissions: PermissionName[]): boolean {
  const preparedScenePermissions: PermissionName[] = ["campaign.update", "scene.create", "scene.update", "scene.delete", "scene.activate", "token.reveal", "combat.manage"];
  return preparedScenePermissions.some((permission) => permissions.includes(permission));
}

function pluginCanReadHiddenTokens(permissions: PermissionName[]): boolean {
  return permissions.includes("token.update") || permissions.includes("scene.update") || permissions.includes("token.reveal");
}

function sceneFromPluginEvent(store: StateStore, event: EngineEvent): Scene | undefined {
  const stored = store.state.scenes.find((scene) => scene.id === event.targetId && scene.campaignId === event.campaignId);
  if (stored) return stored;
  const payload = isRecord(event.payload) ? event.payload : undefined;
  if (!payload || payload.id !== event.targetId || payload.campaignId !== event.campaignId || typeof payload.active !== "boolean") return undefined;
  return payload as unknown as Scene;
}

function tokenFromPluginEvent(store: StateStore, event: EngineEvent): Token | undefined {
  const stored = store.state.tokens.find((token) => token.id === event.targetId && campaignIdForScene(store, token.sceneId) === event.campaignId);
  if (stored) return stored;
  const payload = isRecord(event.payload) ? event.payload : undefined;
  if (!payload || payload.id !== event.targetId || typeof payload.sceneId !== "string") return undefined;
  return payload as unknown as Token;
}

function handoutFromPluginEvent(store: StateStore, event: EngineEvent): Handout | undefined {
  const stored = store.state.handouts.find((handout) => handout.id === event.targetId && handout.campaignId === event.campaignId);
  if (stored) return normalizeHandout(stored);
  const payload = isRecord(event.payload) ? event.payload : undefined;
  if (!payload || payload.id !== event.targetId || payload.campaignId !== event.campaignId) return undefined;
  if (
    payload.visibility !== "public" &&
    payload.visibility !== "gm_only" &&
    payload.visibility !== "specific_players" &&
    payload.visibility !== "specific_characters"
  )
    return undefined;
  return normalizeHandout(payload as unknown as Handout);
}

function itemFromPluginEvent(store: StateStore, event: EngineEvent): Item | undefined {
  const stored = store.state.items.find((item) => item.id === event.targetId && item.campaignId === event.campaignId);
  if (stored) return stored;
  const payload = isRecord(event.payload) ? event.payload : undefined;
  if (!payload || payload.id !== event.targetId || payload.campaignId !== event.campaignId) return undefined;
  if (payload.actorId !== undefined && typeof payload.actorId !== "string") return undefined;
  return payload as unknown as Item;
}

function audioTrackFromPluginEvent(store: StateStore, event: EngineEvent): AudioTrack | undefined {
  const stored = store.state.audioTracks.find((track) => track.id === event.targetId && track.campaignId === event.campaignId);
  if (stored) return stored;
  const payload = isRecord(event.payload) ? event.payload : undefined;
  if (!payload || payload.id !== event.targetId || payload.campaignId !== event.campaignId || typeof payload.playing !== "boolean") return undefined;
  return payload as unknown as AudioTrack;
}

function encounterFromPluginEvent(store: StateStore, event: EngineEvent): Encounter | undefined {
  const stored = store.state.encounters.find((encounter) => encounter.id === event.targetId && encounter.campaignId === event.campaignId);
  if (stored) return stored;
  const payload = isRecord(event.payload) ? event.payload : undefined;
  if (!payload || payload.id !== event.targetId || payload.campaignId !== event.campaignId || !Array.isArray(payload.tokenIds)) return undefined;
  return payload as unknown as Encounter;
}

function aiMemoryFromPluginEvent(store: StateStore, event: EngineEvent): AiMemoryFact | undefined {
  const stored = store.state.aiMemory.find((memory) => memory.id === event.targetId && memory.campaignId === event.campaignId);
  if (stored) return normalizeAiMemoryFact(stored);
  const payload = isRecord(event.payload) ? event.payload : undefined;
  if (!payload || payload.id !== event.targetId || payload.campaignId !== event.campaignId) return undefined;
  if (payload.visibility !== "public" && payload.visibility !== "gm_only") return undefined;
  return normalizeAiMemoryFact(payload as unknown as AiMemoryFact);
}

function proposalVisibleToPluginGrant(store: StateStore, proposal: Proposal, permissions: PermissionName[]): boolean {
  if (permissions.includes("ai.applyChanges")) return true;
  if (proposal.createdByType === "ai" && proposal.status === "pending") return false;
  return proposal.changesJson.every((change) => proposalChangeVisibleToPluginGrant(store, proposal.campaignId, change, permissions));
}

function proposalChangeVisibleToPluginGrant(
  store: StateStore,
  campaignId: string,
  change: ProposalChange,
  permissions: PermissionName[]
): boolean {
  const has = (permission: PermissionName) => permissions.includes(permission);
  const changeId = proposalChangeEntityId(change);
  if (change.entity === "campaign" || change.entity === "campaignSession") return has("campaign.update");
  if (change.entity === "world") return has("world.read") && pluginCanAccessPreparedScenes(permissions);
  if (change.entity === "scene") {
    const existing = changeId ? store.state.scenes.find((scene) => scene.id === changeId && scene.campaignId === campaignId) : undefined;
    const active = typeof change.data.active === "boolean" ? change.data.active : existing?.active ?? false;
    return active || pluginCanAccessPreparedScenes(permissions);
  }
  if (change.entity === "token") {
    const existing = changeId ? store.state.tokens.find((token) => token.id === changeId) : undefined;
    const sceneId = typeof change.data.sceneId === "string" ? change.data.sceneId : existing?.sceneId;
    const scene = sceneId ? store.state.scenes.find((candidate) => candidate.id === sceneId && candidate.campaignId === campaignId) : undefined;
    if (!scene || (!scene.active && !pluginCanAccessPreparedScenes(permissions))) return false;
    const hidden = typeof change.data.hidden === "boolean" ? change.data.hidden : existing?.hidden ?? false;
    const layer = change.data.layer === "map" || change.data.layer === "player" || change.data.layer === "gm" ? change.data.layer : existing?.layer ?? "player";
    return (!hidden && layer !== "gm") || pluginCanReadHiddenTokens(permissions);
  }
  if (change.entity === "actor" || change.entity === "item") return has("actor.readPrivate");
  if (change.entity === "journal") {
    const existing = changeId ? store.state.journals.find((journal) => journal.id === changeId && journal.campaignId === campaignId) : undefined;
    const visibility = visibilityFromRecord(change.data, "visibility", existing?.visibility ?? "gm_only");
    return visibility === "public" || has("journal.readSecret");
  }
  if (change.entity === "handout") {
    const existing = changeId ? store.state.handouts.find((handout) => handout.id === changeId && handout.campaignId === campaignId) : undefined;
    const visibility = visibilityFromRecord(change.data, "visibility", existing?.visibility ?? "gm_only");
    return visibility === "public" || has("handout.readSecret");
  }
  if (change.entity === "chat" || change.entity === "roll") {
    const existing =
      change.entity === "chat"
        ? changeId
          ? store.state.chat.find((message) => message.id === changeId && message.campaignId === campaignId)
          : undefined
        : changeId
          ? store.state.rolls.find((roll) => roll.id === changeId && roll.campaignId === campaignId)
          : undefined;
    const visibility =
      change.data.visibility === "public" || change.data.visibility === "gm_only" || change.data.visibility === "whisper"
        ? change.data.visibility
        : existing?.visibility;
    return visibility === "public" || ((visibility === "gm_only" || visibility === "whisper") && has("chat.moderate"));
  }
  if (change.entity === "diceMacro") {
    const existing = changeId ? store.state.diceMacros.find((macro) => macro.id === changeId && macro.campaignId === campaignId) : undefined;
    const visibility = change.data.visibility === "public" || change.data.visibility === "gm_only" ? change.data.visibility : existing?.visibility;
    return visibility === "public" || has("campaign.update");
  }
  if (change.entity === "encounter") {
    return (
      pluginCanAccessPreparedScenes(permissions) ||
      Boolean(changeId && store.state.combats.some((combat) => combat.campaignId === campaignId && combat.active && combat.encounterId === changeId))
    );
  }
  if (change.entity === "combat") return has("combat.manage");
  if (change.entity === "asset") return pluginCanAccessPreparedScenes(permissions);
  if (change.entity === "fogPreset") return has("token.reveal");
  if (change.entity === "pluginStorage") return has("plugin.configure");
  if (change.entity === "aiMemory") {
    const existing = changeId ? store.state.aiMemory.find((memory) => memory.id === changeId && memory.campaignId === campaignId) : undefined;
    const visibility = visibilityFromRecord(change.data, "visibility", existing?.visibility ?? "gm_only");
    return visibility === "public" ? has("ai.readPublicMemory") : has("ai.readGmMemory");
  }
  return false;
}

function chatMessageFromPluginEvent(store: StateStore, event: EngineEvent): ChatMessage | undefined {
  const stored = store.state.chat.find((message) => message.id === event.targetId && message.campaignId === event.campaignId);
  if (stored) return stored;
  const payload = isRecord(event.payload) ? event.payload : undefined;
  if (!payload || payload.id !== event.targetId || payload.campaignId !== event.campaignId) return undefined;
  if (payload.visibility !== "public" && payload.visibility !== "gm_only" && payload.visibility !== "whisper") return undefined;
  return payload as unknown as ChatMessage;
}

async function dispatchInstalledPluginEvent(
  store: StateStore,
  pluginRegistry: PluginRuntimeRegistry,
  event: PluginEventEnvelope,
  sourceEvent: EngineEvent,
  broadcastToClients: (event: EngineEvent) => void
): Promise<void> {
  const grants = store.state.permissionGrants.filter((grant) => grant.subjectType === "plugin" && grant.campaignId === event.campaignId);
  for (const grant of grants) {
    const plugin = pluginRegistry.find(grant.subjectId, pluginVersionFromGrant(grant));
    if (!plugin?.eventSubscriptions?.some((subscription) => subscription.type === event.type)) continue;
    if (!grant.permissions.includes(pluginEventPermission(event.type))) continue;
    if (!pluginEventVisibleToGrant(store, sourceEvent, grant.permissions)) continue;
    if (!plugin.trust.installable) continue;
    if (pluginReviewInstallBlockForReview(plugin, pluginReviewForDisplay(store, plugin))) continue;
    if (pluginCoreCompatibilityBlock(plugin)) continue;
    if (pluginGrantIdentityBlock(grant, plugin)) continue;
    try {
      const result = await pluginRegistry.executeEventAsync(
        plugin.id,
        {
          campaignId: event.campaignId,
          pluginId: plugin.id,
          permissions: [...grant.permissions],
          event
        },
        plugin.version
      );
      const prepared = preparePluginBridgeProposals(store, event.campaignId, plugin, result.bridgeRequests, {
        kind: "event",
        eventType: event.type,
        eventId: event.id,
        actorUserId: event.actorUserId
      });
      if (!prepared.ok) throw new Error(prepared.message);
      if (prepared.proposals.length === 0) continue;
      store.state.proposals.push(...prepared.proposals);
      store.state.auditLogs.push(
        createTimestamped("audit", {
          campaignId: event.campaignId,
          actorUserId: plugin.id,
          actorType: "plugin" as const,
          action: "plugin.event.proposed",
          targetType: "plugin",
          targetId: plugin.id,
          after: {
            eventId: event.id,
            eventType: event.type,
            proposalIds: prepared.proposals.map((proposal) => proposal.id),
            bridgeCount: result.bridgeRequests.length,
            packageId: plugin.source.packageId,
            version: plugin.version
          }
        })
      );
      store.save();
      for (const proposal of prepared.proposals) {
        broadcastToClients(
          createEvent({
            campaignId: proposal.campaignId,
            type: "proposal.created",
            actorUserId: event.actorUserId,
            targetId: proposal.id,
            payload: proposal,
            causationId: event.id,
            correlationId: event.correlationId ?? event.id
          })
        );
      }
    } catch (error) {
      appendPluginEventFailureAudit(store, { event, plugin, reason: "runtime_or_bridge_error", message: errorMessage(error) });
      store.save();
    }
  }
}

type PluginBridgeTrigger =
  | { kind: "command"; command: string; actorUserId?: string }
  | { kind: "event"; eventType: string; eventId: string; actorUserId?: string };

function preparePluginBridgeProposals(
  store: StateStore,
  campaignId: string,
  plugin: LoadedPlugin,
  requests: PluginBridgeRequest[],
  trigger: PluginBridgeTrigger
):
  | { ok: true; proposals: Proposal[]; receipts: Record<string, string> }
  | { ok: false; reason: "missing_permission" | "invalid_changes"; message: string } {
  const proposals: Proposal[] = [];
  const receipts: Record<string, string> = {};
  const createdEntityIds = new Set<string>();
  for (const request of requests) {
    const requiredPermission: PermissionName = request.kind === "proposal.create" ? "ai.proposeChanges" : "chat.write";
    if (!pluginCan(store, campaignId, plugin.id, requiredPermission)) {
      return { ok: false, reason: "missing_permission", message: `Plugin ${plugin.id} lacks ${requiredPermission} in this campaign` };
    }
    const rawChanges: ProposalChange[] =
      request.kind === "proposal.create"
        ? request.input.changes
        : [
            {
              entity: "chat",
              action: "create",
              data: createTimestamped("msg", {
                campaignId,
                userId: plugin.id,
                type: "plugin" as const,
                body: request.input.body,
                visibility: request.input.visibility,
                recipientUserIds: []
              })
            }
          ];
    const prepared = prepareProposalChanges(store, campaignId, plugin.id, rawChanges);
    if ("error" in prepared) return { ok: false, reason: "invalid_changes", message: prepared.message };
    for (const change of prepared.changes) {
      if (change.action !== "create") continue;
      const id = stringFromRecord(change.data, "id");
      if (!id) continue;
      const key = `${change.entity}:${id}`;
      if (createdEntityIds.has(key)) return { ok: false, reason: "invalid_changes", message: `Plugin bridge creates duplicate ${change.entity} id: ${id}` };
      createdEntityIds.add(key);
    }
    const title = request.kind === "proposal.create" ? request.input.title : `${plugin.name}: reviewed chat output`;
    const summary = request.kind === "proposal.create" ? request.input.summary : "Review this plugin-generated chat message before it is posted to the campaign.";
    const proposal: Proposal = createTimestamped("prop", {
      campaignId,
      createdByUserId: trigger.actorUserId,
      createdByType: "plugin" as const,
      sourceId: plugin.id,
      title,
      summary,
      status: "pending" as const,
      changesJson: prepared.changes,
      diffJson: {
        pluginId: plugin.id,
        bridgeRequestId: request.requestId,
        trigger: trigger.kind === "command" ? { kind: "command", command: trigger.command } : { kind: "event", eventType: trigger.eventType, eventId: trigger.eventId },
        packageId: plugin.source.packageId,
        version: plugin.version,
        checksum: pluginPackageIdentityChecksum(plugin)
      },
      approvalRequired: true
    });
    proposal.history = [
      proposalHistoryEntry({
        action: "created",
        status: "pending",
        at: proposal.createdAt,
        actorUserId: plugin.id,
        actorType: "plugin",
        auditAction: trigger.kind === "command" ? "plugin.command.bridge.proposed" : "plugin.event.bridge.proposed"
      })
    ];
    proposals.push(proposal);
    receipts[request.requestId] = proposal.id;
  }
  return { ok: true, proposals, receipts };
}

function appendPluginEventFailureAudit(
  store: StateStore,
  input: { event: PluginEventEnvelope; plugin?: LoadedPlugin; reason: string; message: string }
): void {
  store.state.auditLogs.push(
    createTimestamped("audit", {
      campaignId: input.event.campaignId,
      actorUserId: input.plugin?.id,
      actorType: input.plugin ? ("plugin" as const) : ("system" as const),
      action: "plugin.event.failed",
      targetType: input.plugin ? "plugin" : "plugin_dispatcher",
      targetId: input.plugin?.id ?? input.event.id,
      after: {
        eventId: input.event.id,
        eventType: input.event.type,
        reason: input.reason,
        message: input.message.slice(0, 200),
        packageId: input.plugin?.source.packageId,
        version: input.plugin?.version
      }
    })
  );
}

function pluginStorageProposalChanges(
  store: StateStore,
  campaignId: string,
  pluginId: string,
  storage: PluginChatCommandResult["storage"]
): { changes: ProposalChange[]; summary: { set: Array<{ key: string; size: number }>; deleted: string[] } } {
  const changes: ProposalChange[] = [];
  const summary = { set: [] as Array<{ key: string; size: number }>, deleted: [] as string[] };
  if (!storage) return { changes, summary };
  for (const [rawKey, rawValue] of Object.entries(storage.set ?? {})) {
    const key = normalizePluginStorageKey(rawKey);
    if (!key) throw new Error(`Invalid plugin storage key: ${rawKey}`);
    const value = normalizePluginStorageValue(rawValue);
    if (!value.ok) throw new Error(value.error);
    const existing = store.state.pluginStorage.find((entry) => entry.campaignId === campaignId && entry.pluginId === pluginId && entry.key === key);
    if (existing) {
      changes.push({ entity: "pluginStorage", action: "update", id: existing.id, data: { value: cloneJsonValue(value.value), updatedByType: "plugin", updatedById: pluginId } });
    } else {
      changes.push({
        entity: "pluginStorage",
        action: "create",
        data: createTimestamped("pstore", { campaignId, pluginId, key, value: cloneJsonValue(value.value), updatedByType: "plugin" as const, updatedById: pluginId })
      });
    }
    summary.set.push({ key, size: pluginStorageValueSize(value.value) });
  }
  for (const rawKey of storage.delete ?? []) {
    const key = normalizePluginStorageKey(rawKey);
    if (!key) throw new Error(`Invalid plugin storage key: ${rawKey}`);
    const existing = store.state.pluginStorage.find((entry) => entry.campaignId === campaignId && entry.pluginId === pluginId && entry.key === key);
    if (!existing) continue;
    changes.push({ entity: "pluginStorage", action: "delete", id: existing.id, data: {} });
    summary.deleted.push(key);
  }
  return { changes, summary };
}

function applyPluginStorageMutation(
  store: StateStore,
  campaignId: string,
  pluginId: string,
  storage: PluginChatCommandResult["storage"],
  updatedByType: "user" | "plugin",
  updatedById: string
): { set: Array<{ key: string; size: number }>; deleted: string[] } {
  const mutation = { set: [] as Array<{ key: string; size: number }>, deleted: [] as string[] };
  if (!storage) return mutation;
  for (const [rawKey, rawValue] of Object.entries(storage.set ?? {})) {
    const key = normalizePluginStorageKey(rawKey);
    if (!key) throw new Error(`Invalid plugin storage key: ${rawKey}`);
    const value = normalizePluginStorageValue(rawValue);
    if (!value.ok) throw new Error(value.error);
    const entry = upsertPluginStorageEntry(store, campaignId, pluginId, key, value.value, updatedByType, updatedById);
    mutation.set.push({ key: entry.key, size: pluginStorageValueSize(entry.value) });
  }
  for (const rawKey of storage.delete ?? []) {
    const key = normalizePluginStorageKey(rawKey);
    if (!key) throw new Error(`Invalid plugin storage key: ${rawKey}`);
    if (deletePluginStorageEntry(store, campaignId, pluginId, key)) mutation.deleted.push(key);
  }
  return mutation;
}

function normalizePluginStorageKey(value: string): string | undefined {
  const key = value.trim();
  return /^[a-zA-Z0-9][a-zA-Z0-9._:-]{0,79}$/.test(key) ? key : undefined;
}

function normalizePluginStorageValue(value: unknown): { ok: true; value: unknown } | { ok: false; error: string } {
  const text = JSON.stringify(value);
  if (text === undefined) return { ok: false, error: "Plugin storage value must be JSON serializable" };
  if (Buffer.byteLength(text, "utf8") > PLUGIN_STORAGE_MAX_VALUE_BYTES) return { ok: false, error: "Plugin storage value is limited to 16 KiB of JSON" };
  try {
    return { ok: true, value: JSON.parse(text) as unknown };
  } catch {
    return { ok: false, error: "Plugin storage value must be JSON serializable" };
  }
}

function pluginStorageValueSize(value: unknown): number {
  return Buffer.byteLength(JSON.stringify(value), "utf8");
}

function cloneJsonValue(value: unknown): unknown {
  return JSON.parse(JSON.stringify(value)) as unknown;
}

const PLUGIN_STORAGE_MAX_VALUE_BYTES = 16 * 1024;
const PLUGIN_STORAGE_NEAR_LIMIT_BYTES = 12 * 1024;

function pluginStoragePressureEntries(entries: PluginStorageEntry[]) {
  return entries
    .map((entry) => ({
      id: entry.id,
      campaignId: entry.campaignId,
      pluginId: entry.pluginId,
      key: entry.key,
      sizeBytes: pluginStorageValueSize(entry.value),
      updatedByType: entry.updatedByType,
      updatedAt: entry.updatedAt
    }))
    .sort((left, right) => right.sizeBytes - left.sizeBytes || left.pluginId.localeCompare(right.pluginId) || left.key.localeCompare(right.key))
    .slice(0, 10);
}

function adminPluginReviewSnapshot(store: StateStore, pluginRegistry: PluginRuntimeRegistry) {
  const plugins = pluginRegistry.listPackages();
  const reviewedPlugins = plugins.map((plugin) => publicPluginReviewInfo(plugin, ensurePluginReview(store, plugin)));
  const totals = {
    pending: reviewedPlugins.filter((item) => item.review.status === "pending").length,
    approved: reviewedPlugins.filter((item) => item.review.status === "approved").length,
    rejected: reviewedPlugins.filter((item) => item.review.status === "rejected").length,
    blocked: reviewedPlugins.filter((item) => !item.installable).length
  };
  return {
    generatedAt: nowIso(),
    policy: {
      mode: pluginReviewPolicyMode()
    },
    totals,
    plugins: reviewedPlugins.sort((left, right) => left.plugin.name.localeCompare(right.plugin.name) || right.plugin.version.localeCompare(left.plugin.version))
  };
}

function adminPluginOperations(store: StateStore, pluginRegistry: PluginRuntimeRegistry) {
  const packages = pluginRegistry.listPackages();
  const installed = store.state.permissionGrants
    .filter((grant) => grant.subjectType === "plugin")
    .map((grant) => pluginOperationalInstall(store, pluginRegistry, grant));
  const storageEntries = store.state.pluginStorage;
  const reviewSnapshot = adminPluginReviewSnapshot(store, pluginRegistry);
  const commandAuditLogs = store.state.auditLogs.filter((log) => log.action === "plugin.chatCommand" || log.action === "plugin.chatCommand.proposed");
  const failedCommandAuditLogs = store.state.auditLogs.filter((log) => log.action === "plugin.chatCommand.failed");
  const storageAuditLogs = store.state.auditLogs.filter((log) => log.action === "plugin.storageSet" || log.action === "plugin.storageDelete" || log.action === "plugin.storageMutation");
  const installAuditLogs = store.state.auditLogs.filter((log) => log.action === "plugin.install");
  const compatibilityOperations = pluginCompatibilityOperationsSummary(packages, installed);
  const installOperations = pluginInstallOperationsSummary(installAuditLogs);
  const totals = {
    catalogPluginCount: pluginRegistry.list().length,
    packageCount: packages.length,
    loadErrorCount: pluginRegistry.errors.length,
    installedGrantCount: installed.length,
    healthyInstalledCount: installed.filter((item) => item.status === "healthy").length,
    blockedInstalledCount: installed.filter((item) => item.status === "blocked").length,
    missingInstalledCount: installed.filter((item) => item.status === "missing_package").length,
    permissionDriftCount: installed.filter((item) => item.missingManifestPermissions.length > 0).length,
    incompatiblePackageCount: compatibilityOperations.incompatiblePackageCount,
    incompatibleInstalledCount: compatibilityOperations.incompatibleInstalledCount,
    storageEntryCount: storageEntries.length,
    commandAuditCount: commandAuditLogs.length,
    installAuditCount: installAuditLogs.length
  };
  const reviewOperations = pluginReviewOperationsSummary(reviewSnapshot.plugins);
  const registryOperations = pluginRegistryOperationsSummary(store, packages);
  const securityPosture = pluginSecurityPostureSummary(packages);
  const commandOperations = pluginCommandOperationsSummary(commandAuditLogs, failedCommandAuditLogs);
  const storageOperations = pluginStorageOperationsSummary(storageAuditLogs);
  const inventoryOperations = pluginPackageInventoryOperationsSummary(pluginRegistry.inventoryWarnings);
  const actionReasons = pluginOperationsActionReasons(totals, reviewOperations, registryOperations, compatibilityOperations, securityPosture, commandOperations, inventoryOperations);
  const recentCommands = commandAuditLogs.slice(-10).reverse().map(pluginCommandAuditSummary);
  const permissionDrift = installed
    .filter((item) => item.missingManifestPermissions.length > 0)
    .map((item) => ({
      campaignId: item.campaignId,
      pluginId: item.pluginId,
      name: "name" in item && item.name ? item.name : item.pluginId,
      installedVersion: item.installedVersion,
      missingPermissions: [...item.missingManifestPermissions],
      grantedPermissionCount: item.grantedPermissions.length,
      requestedPermissionCount: "requestedPermissions" in item && item.requestedPermissions
        ? item.requestedPermissions.length
        : item.grantedPermissions.length
    }))
    .sort((left, right) => left.pluginId.localeCompare(right.pluginId) || left.campaignId.localeCompare(right.campaignId))
    .slice(0, 20);
  const storage = {
    entryCount: storageEntries.length,
    byPlugin: countBy(storageEntries, (entry) => entry.pluginId),
    byCampaign: countBy(storageEntries, (entry) => entry.campaignId),
    largestEntries: pluginStoragePressureEntries(storageEntries),
    nearLimitEntries: pluginStoragePressureEntries(storageEntries.filter((entry) => pluginStorageValueSize(entry.value) >= PLUGIN_STORAGE_NEAR_LIMIT_BYTES)),
    nearLimitBytes: PLUGIN_STORAGE_NEAR_LIMIT_BYTES,
    maxValueBytes: PLUGIN_STORAGE_MAX_VALUE_BYTES
  };
  return {
    generatedAt: nowIso(),
    actionRequired: actionReasons.length > 0,
    actionReasons,
    policy: {
      review: pluginReviewPolicyMode(),
      trust: pluginRegistry.trustPolicy.policy
    },
    totals,
    reviews: reviewSnapshot.totals,
    reviewOperations,
    securityPosture,
    registryOperations,
    compatibilityOperations,
    installOperations,
    remediationQueue: pluginOperationsRemediationQueue({
      loadErrors: pluginRegistry.errors.map((error) => ({ packagePath: error.packagePath, errors: [...error.errors] })),
      installed,
      permissionDrift,
      reviewOperations,
      registryOperations,
      compatibilityOperations,
      securityPosture,
      commandOperations,
      inventoryOperations,
      storage
    }),
    permissionDrift,
    loadErrors: pluginRegistry.errors.map((error) => ({ packagePath: error.packagePath, errors: [...error.errors] })),
    installed,
    storage,
    storageOperations,
    commandOperations,
    inventoryOperations,
    recentCommands
  };
}

function pluginStorageOperationsSummary(storageAuditLogs: AuditLog[]) {
  const operations = storageAuditLogs.map(pluginStorageAuditSummary);
  const setMutationCount = operations.reduce((sum, operation) => sum + operation.setCount, 0);
  const deleteMutationCount = operations.reduce((sum, operation) => sum + operation.deleteCount, 0);
  return {
    operationCount: operations.length,
    directSetCount: operations.filter((operation) => operation.operation === "set").length,
    directDeleteCount: operations.filter((operation) => operation.operation === "delete").length,
    commandMutationCount: operations.filter((operation) => operation.operation === "command_mutation").length,
    setMutationCount,
    deleteMutationCount,
    deletedEntryCount: operations.reduce((sum, operation) => sum + (operation.deleted ? 1 : 0), 0) + operations.filter((operation) => operation.operation === "command_mutation").reduce((sum, operation) => sum + operation.deleteCount, 0),
    byPlugin: countBy(operations, (operation) => operation.pluginId ?? "unknown"),
    byCampaign: countBy(operations, (operation) => operation.campaignId ?? "unknown"),
    recentOperations: operations.slice(-10).reverse()
  };
}

function pluginStorageAuditSummary(log: AuditLog) {
  const after = isRecord(log.after) ? log.after : {};
  const setMutations = Array.isArray(after.set) ? after.set.length : log.action === "plugin.storageSet" ? 1 : 0;
  const deleteMutations = Array.isArray(after.deleted) ? after.deleted.length : log.action === "plugin.storageDelete" ? 1 : 0;
  const operation = log.action === "plugin.storageSet" ? "set" : log.action === "plugin.storageDelete" ? "delete" : "command_mutation";
  return {
    id: log.id,
    campaignId: log.campaignId,
    pluginId: typeof after.pluginId === "string" ? after.pluginId : log.targetId,
    actorType: log.actorType,
    actorUserId: log.actorUserId,
    operation,
    key: typeof after.key === "string" ? after.key : undefined,
    sizeBytes: typeof after.size === "number" ? after.size : undefined,
    deleted: typeof after.deleted === "boolean" ? after.deleted : undefined,
    setCount: setMutations,
    deleteCount: deleteMutations,
    createdAt: log.createdAt
  };
}

function pluginInstallOperationsSummary(installAuditLogs: AuditLog[]) {
  const previousByGrant = new Map<string, { version?: string; grantedPermissionCount: number }>();
  const chronological = [...installAuditLogs].sort((left, right) => Date.parse(left.createdAt) - Date.parse(right.createdAt));
  const operations = chronological.map((log) => {
    const after = isRecord(log.after) ? log.after : {};
    const pluginId = typeof after.pluginId === "string" ? after.pluginId : log.targetId;
    const grantKey = `${log.campaignId ?? "unknown"}:${pluginId ?? "unknown"}`;
    const version = typeof after.version === "string" ? after.version : undefined;
    const previous = previousByGrant.get(grantKey);
    const grantedPermissions = Array.isArray(after.grantedPermissions) ? after.grantedPermissions.filter((permission): permission is string => typeof permission === "string") : [];
    const requestedPermissions = Array.isArray(after.requestedPermissions) ? after.requestedPermissions.filter((permission): permission is string => typeof permission === "string") : [];
    const missingPermissions = Array.isArray(after.missingPermissions) ? after.missingPermissions.filter((permission): permission is string => typeof permission === "string") : [];
    const grantedPermissionCount = grantedPermissions.length;
    let versionComparison: number | undefined;
    if (previous?.version && version && previous.version !== version) {
      try {
        versionComparison = comparePluginVersions(version, previous.version);
      } catch {
        versionComparison = undefined;
      }
    }
    const operation =
      previous && previous.version && version && previous.version !== version
        && versionComparison !== undefined
        ? versionComparison < 0
          ? "rollback"
          : "upgrade"
        : previous && previous.grantedPermissionCount !== grantedPermissionCount
          ? "permission_review"
          : "install";
    previousByGrant.set(grantKey, { version, grantedPermissionCount });
    return {
      id: log.id,
      campaignId: log.campaignId,
      pluginId,
      actorUserId: log.actorUserId,
      operation,
      packageId: typeof after.packageId === "string" ? after.packageId : undefined,
      version,
      sandbox: typeof after.sandbox === "string" ? after.sandbox : undefined,
      grantedPermissionCount,
      requestedPermissionCount: requestedPermissions.length,
      missingPermissionCount: missingPermissions.length,
      createdAt: log.createdAt
    };
  });
  const versionChangeCount = operations.filter((operation) => operation.operation === "upgrade" || operation.operation === "rollback").length;
  const rollbackCount = operations.filter((operation) => operation.operation === "rollback").length;
  const permissionReviewCount = operations.filter((operation) => operation.operation === "permission_review" || operation.missingPermissionCount > 0).length;
  return {
    installCount: operations.length,
    versionChangeCount,
    rollbackCount,
    permissionReviewCount,
    byPlugin: countBy(operations, (operation) => operation.pluginId ?? "unknown"),
    byCampaign: countBy(operations, (operation) => operation.campaignId ?? "unknown"),
    recentInstalls: operations.slice(-10).reverse()
  };
}

function pluginCommandAuditSummary(log: AuditLog) {
  const after = isRecord(log.after) ? log.after : {};
  const storageMutation = isRecord(after.storageMutation) ? after.storageMutation : {};
  const setMutations = Array.isArray(storageMutation.set) ? storageMutation.set.length : 0;
  const deleteMutations = Array.isArray(storageMutation.deleted) ? storageMutation.deleted.length : 0;
  return {
    id: log.id,
    campaignId: log.campaignId,
    pluginId: typeof after.pluginId === "string" ? after.pluginId : log.targetId,
    command: typeof after.command === "string" ? after.command : undefined,
    packageId: typeof after.packageId === "string" ? after.packageId : undefined,
    version: typeof after.version === "string" ? after.version : undefined,
    sandbox: typeof after.sandbox === "string" ? after.sandbox : undefined,
    storageMutation: {
      set: setMutations,
      deleted: deleteMutations
    },
    createdAt: log.createdAt
  };
}

function pluginCommandOperationsSummary(commandAuditLogs: AuditLog[], failedCommandAuditLogs: AuditLog[]) {
  const recentCommands = commandAuditLogs.slice(-25).map(pluginCommandAuditSummary);
  const recentFailures = failedCommandAuditLogs.slice(-25).map(pluginCommandFailureAuditSummary);
  const storageMutatingCommandCount = recentCommands.filter((command) => command.storageMutation.set > 0 || command.storageMutation.deleted > 0).length;
  return {
    actionRequired: failedCommandAuditLogs.length > 0,
    commandCount: commandAuditLogs.length,
    failedCommandCount: failedCommandAuditLogs.length,
    recentCommandCount: recentCommands.length,
    recentFailureCount: recentFailures.length,
    storageMutatingCommandCount,
    byPlugin: countBy(recentCommands, (command) => command.pluginId ?? "unknown"),
    failedByPlugin: countBy(recentFailures, (command) => command.pluginId ?? "unknown"),
    failedByReason: countBy(recentFailures, (command) => command.reason ?? "unknown"),
    byCampaign: countBy(recentCommands, (command) => command.campaignId ?? "unknown"),
    recentFailures: recentFailures.slice(-10).reverse()
  };
}

function pluginCommandFailureAuditSummary(log: AuditLog) {
  const after = isRecord(log.after) ? log.after : {};
  return {
    id: log.id,
    campaignId: log.campaignId,
    pluginId: typeof after.pluginId === "string" ? after.pluginId : log.targetId,
    command: typeof after.command === "string" ? after.command : undefined,
    reason: typeof after.reason === "string" ? after.reason : undefined,
    message: typeof after.message === "string" ? after.message : undefined,
    packageId: typeof after.packageId === "string" ? after.packageId : undefined,
    version: typeof after.version === "string" ? after.version : undefined,
    sandbox: typeof after.sandbox === "string" ? after.sandbox : undefined,
    createdAt: log.createdAt
  };
}

function pluginSecurityPostureSummary(packages: LoadedPlugin[]) {
  const commandCapablePackages = packages.filter((plugin) => (plugin.chatCommands?.length ?? 0) > 0);
  const manifestOnlyCommandPackages = commandCapablePackages.filter((plugin) => plugin.source.sandbox !== "vm");
  const unsignedPackages = packages.filter((plugin) => plugin.trust.status === "unsigned");
  const untrustedPackages = packages.filter((plugin) => plugin.trust.status === "untrusted");
  const trustBlockedPackages = packages.filter((plugin) => !plugin.trust.installable);
  const trustPolicy = packages[0]?.trust.policy ?? (process.env.OTTE_PLUGIN_TRUST_POLICY === "require_trusted" ? "require_trusted" : "allow_unsigned");
  const trustKeyCount = pluginTrustKeyCount();
  const allowUnsignedInProduction = process.env.NODE_ENV === "production" && trustPolicy !== "require_trusted";
  const trustedModeWithoutKeys = trustPolicy === "require_trusted" && trustKeyCount === 0;
  const actionReasons = [
    allowUnsignedInProduction ? "plugin_trust_policy_allows_unsigned_in_production" : undefined,
    trustedModeWithoutKeys ? "plugin_trust_keys_missing" : undefined,
    manifestOnlyCommandPackages.length > 0 ? "plugin_command_without_vm_sandbox" : undefined,
    trustBlockedPackages.length > 0 ? "plugin_trust_policy_blocks" : undefined,
    untrustedPackages.length > 0 ? "untrusted_plugin_packages" : undefined,
    unsignedPackages.length > 0 ? "unsigned_plugin_packages" : undefined
  ].filter((reason): reason is string => Boolean(reason));
  const packageInfo = (plugin: LoadedPlugin) => ({
    pluginId: plugin.id,
    name: plugin.name,
    version: plugin.version,
    packageId: plugin.source.packageId,
    sandbox: plugin.source.sandbox,
    trustStatus: plugin.trust.status,
    installable: plugin.trust.installable,
    errors: plugin.trust.errors.slice(0, 3)
  });
  return {
    actionRequired: actionReasons.length > 0,
    actionReasons,
    remediation:
      actionReasons.length > 0
        ? "Require reviewed and trusted packages for production deployments, keep command-capable packages in the VM sandbox, and resolve unsigned or untrusted package inventory."
        : "Plugin packages are reviewed/trusted as required and command-capable packages use the VM sandbox.",
    runtimeConfig: {
      trustPolicy,
      trustKeyCount,
      trustKeysConfigured: trustKeyCount > 0,
      allowUnsignedInProduction,
      trustedModeWithoutKeys
    },
    vmSandboxPackageCount: packages.filter((plugin) => plugin.source.sandbox === "vm").length,
    manifestOnlyPackageCount: packages.filter((plugin) => plugin.source.sandbox === "manifest-only").length,
    commandCapablePackageCount: commandCapablePackages.length,
    manifestOnlyCommandPackageCount: manifestOnlyCommandPackages.length,
    trustedPackageCount: packages.filter((plugin) => plugin.trust.status === "trusted").length,
    unsignedPackageCount: unsignedPackages.length,
    untrustedPackageCount: untrustedPackages.length,
    trustBlockedPackageCount: trustBlockedPackages.length,
    unsignedSamples: unsignedPackages.slice(0, 5).map(packageInfo),
    untrustedSamples: untrustedPackages.slice(0, 5).map(packageInfo),
    nonVmCommandSamples: manifestOnlyCommandPackages.slice(0, 5).map(packageInfo)
  };
}

function pluginTrustKeyCount() {
  const value = process.env.OTTE_PLUGIN_TRUST_KEYS;
  if (!value?.trim()) return 0;
  try {
    const parsed = JSON.parse(value) as unknown;
    if (isRecord(parsed)) return Object.values(parsed).filter((secret) => typeof secret === "string" && secret.length > 0).length;
  } catch {
    // Fall through to comma-separated key=secret parsing for simple env files.
  }
  return value
    .split(",")
    .map((entry) => entry.trim())
    .filter((entry) => {
      const separator = entry.includes("=") ? "=" : ":";
      const [keyId, ...secretParts] = entry.split(separator);
      return Boolean(keyId?.trim() && secretParts.join(separator).trim());
    }).length;
}

function pluginPackageInventoryOperationsSummary(warnings: PluginInventoryWarning[]) {
  const duplicateVersions = warnings
    .filter((warning) => warning.code === "duplicate_plugin_package_version")
    .map((warning) => ({
      pluginId: warning.pluginId,
      name: warning.name,
      version: warning.version,
      packageCount: warning.packageIds.length,
      packageIds: warning.packageIds,
      sourceTypes: warning.sourceTypes,
      registryUrls: warning.registryUrls
    }))
    .sort((left, right) => left.pluginId.localeCompare(right.pluginId) || left.version.localeCompare(right.version))
    .slice(0, 20);
  return {
    actionRequired: duplicateVersions.length > 0,
    actionReasons: duplicateVersions.length > 0 ? ["duplicate_plugin_packages"] : [],
    duplicateVersionCount: duplicateVersions.length,
    duplicatePackageCount: duplicateVersions.reduce((sum, duplicate) => sum + duplicate.packageCount, 0),
    duplicateVersions
  };
}

function pluginOperationsActionReasons(
  totals: {
    loadErrorCount: number;
    blockedInstalledCount: number;
    missingInstalledCount: number;
    permissionDriftCount: number;
    incompatiblePackageCount: number;
    incompatibleInstalledCount: number;
  },
  reviewOperations: ReturnType<typeof pluginReviewOperationsSummary>,
  registryOperations: ReturnType<typeof pluginRegistryOperationsSummary>,
  compatibilityOperations: ReturnType<typeof pluginCompatibilityOperationsSummary>,
  securityPosture: ReturnType<typeof pluginSecurityPostureSummary>,
  commandOperations: ReturnType<typeof pluginCommandOperationsSummary>,
  inventoryOperations: ReturnType<typeof pluginPackageInventoryOperationsSummary>
) {
  return [
    totals.loadErrorCount > 0 ? "load_errors" : undefined,
    totals.blockedInstalledCount > 0 ? "blocked_installs" : undefined,
    totals.missingInstalledCount > 0 ? "missing_installed_packages" : undefined,
    totals.permissionDriftCount > 0 ? "permission_drift" : undefined,
    compatibilityOperations.actionRequired ? "core_compatibility_drift" : undefined,
    reviewOperations.actionRequired ? "review_backlog" : undefined,
    commandOperations.actionRequired ? "plugin_command_failures" : undefined,
    ...inventoryOperations.actionReasons,
    ...securityPosture.actionReasons,
    ...registryOperations.actionReasons
  ].filter((reason): reason is string => Boolean(reason));
}

function pluginOperationsRemediationQueue(input: {
  loadErrors: Array<{ packagePath: string; errors: string[] }>;
  installed: ReturnType<typeof pluginOperationalInstall>[];
  permissionDrift: Array<{
    campaignId: string;
    pluginId: string;
    name: string;
    installedVersion?: string;
    missingPermissions: PermissionName[];
  }>;
  reviewOperations: ReturnType<typeof pluginReviewOperationsSummary>;
  registryOperations: ReturnType<typeof pluginRegistryOperationsSummary>;
  compatibilityOperations: ReturnType<typeof pluginCompatibilityOperationsSummary>;
  securityPosture: ReturnType<typeof pluginSecurityPostureSummary>;
  commandOperations: ReturnType<typeof pluginCommandOperationsSummary>;
  inventoryOperations: ReturnType<typeof pluginPackageInventoryOperationsSummary>;
  storage: {
    nearLimitEntries: ReturnType<typeof pluginStoragePressureEntries>;
    maxValueBytes: number;
  };
}) {
  const remediations: Array<{
    code: string;
    severity: "warning" | "error";
    action: string;
    affectedCount: number;
    samples?: Array<Record<string, unknown>>;
  }> = [];
  if (input.loadErrors.length > 0) {
    remediations.push({
      code: "fix_plugin_load_errors",
      severity: "error",
      action: "Fix plugin package load errors or remove broken packages from the configured plugin root.",
      affectedCount: input.loadErrors.length,
      samples: input.loadErrors.slice(0, 3).map((error) => ({ packagePath: error.packagePath, errors: error.errors.slice(0, 3) }))
    });
  }
  const blockedInstalled = input.installed.filter((item) => item.status === "blocked");
  if (blockedInstalled.length > 0) {
    remediations.push({
      code: "resolve_blocked_plugin_installs",
      severity: "error",
      action: "Resolve marketplace, trust, permission, or core compatibility blocks before installed plugins can execute.",
      affectedCount: blockedInstalled.length,
      samples: blockedInstalled.slice(0, 3).map((item) => ({ campaignId: item.campaignId, pluginId: item.pluginId, issues: item.issues.slice(0, 3) }))
    });
  }
  const missingInstalled = input.installed.filter((item) => item.status === "missing_package");
  if (missingInstalled.length > 0) {
    remediations.push({
      code: "restore_missing_plugin_packages",
      severity: "error",
      action: "Restore missing plugin packages or uninstall stale campaign grants that point at unavailable packages.",
      affectedCount: missingInstalled.length,
      samples: missingInstalled.slice(0, 3).map((item) => ({ campaignId: item.campaignId, pluginId: item.pluginId, installedVersion: item.installedVersion }))
    });
  }
  if (input.permissionDrift.length > 0) {
    remediations.push({
      code: "repair_plugin_permission_drift",
      severity: "warning",
      action: "Review installed plugin grants whose manifest now requests permissions that were not granted.",
      affectedCount: input.permissionDrift.length,
      samples: input.permissionDrift.slice(0, 3).map((item) => ({
        campaignId: item.campaignId,
        pluginId: item.pluginId,
        missingPermissions: item.missingPermissions.slice(0, 3)
      }))
    });
  }
  if (input.compatibilityOperations.actionRequired) {
    remediations.push({
      code: "resolve_plugin_core_drift",
      severity: "error",
      action: "Upgrade incompatible plugin packages or hold server upgrades until installed plugin core ranges are satisfied.",
      affectedCount: input.compatibilityOperations.incompatiblePackageCount + input.compatibilityOperations.incompatibleInstalledCount,
      samples: [
        ...input.compatibilityOperations.packages.slice(0, 2).map((plugin) => ({
          pluginId: plugin.pluginId,
          version: plugin.version,
          compatibleCore: plugin.compatibleCore
        })),
        ...input.compatibilityOperations.installed.slice(0, 2).map((plugin) => ({
          campaignId: plugin.campaignId,
          pluginId: plugin.pluginId,
          installedVersion: plugin.installedVersion,
          compatibleCore: plugin.compatibleCore
        }))
      ]
    });
  }
  if (input.reviewOperations.actionRequired) {
    remediations.push({
      code: "review_marketplace_packages",
      severity: input.reviewOperations.blockedCount > 0 ? "error" : "warning",
      action: input.reviewOperations.remediation,
      affectedCount: input.reviewOperations.pendingCount + input.reviewOperations.rejectedCount + input.reviewOperations.blockedCount,
      samples: [...input.reviewOperations.pendingSamples, ...input.reviewOperations.blockedSamples].slice(0, 3).map((item) => ({
        pluginId: item.pluginId,
        version: item.version,
        packageId: item.packageId,
        status: item.status,
        installBlock: item.installBlock
      }))
    });
  }
  if (input.commandOperations.actionRequired) {
    remediations.push({
      code: "investigate_plugin_command_failures",
      severity: "error",
      action: "Inspect failed plugin command audit rows and disable, upgrade, or reconfigure plugins that fail at runtime.",
      affectedCount: input.commandOperations.failedCommandCount,
      samples: input.commandOperations.recentFailures.slice(0, 3).map((failure) => ({
        campaignId: failure.campaignId,
        pluginId: failure.pluginId,
        command: failure.command,
        reason: failure.reason,
        message: failure.message,
        packageId: failure.packageId,
        version: failure.version
      }))
    });
  }
  if (input.securityPosture.actionRequired) {
    const commandSandboxRisk = input.securityPosture.manifestOnlyCommandPackageCount > 0;
    const blockedTrustRisk = input.securityPosture.trustBlockedPackageCount > 0 || input.securityPosture.untrustedPackageCount > 0;
    remediations.push({
      code: "review_plugin_security_posture",
      severity: commandSandboxRisk || blockedTrustRisk ? "error" : "warning",
      action: input.securityPosture.remediation,
      affectedCount: input.securityPosture.manifestOnlyCommandPackageCount + input.securityPosture.trustBlockedPackageCount + input.securityPosture.untrustedPackageCount + input.securityPosture.unsignedPackageCount,
      samples: [
        ...input.securityPosture.nonVmCommandSamples.map((plugin) => ({ ...plugin, issue: "command_without_vm_sandbox" })),
        ...input.securityPosture.untrustedSamples.map((plugin) => ({ ...plugin, issue: "untrusted_package" })),
        ...input.securityPosture.unsignedSamples.map((plugin) => ({ ...plugin, issue: "unsigned_package" }))
      ].slice(0, 3)
    });
  }
  if (input.inventoryOperations.actionRequired) {
    remediations.push({
      code: "dedupe_plugin_package_versions",
      severity: "warning",
      action: "Remove or rename duplicate plugin package versions so marketplace review, install, and command resolution select one package per plugin version.",
      affectedCount: input.inventoryOperations.duplicateVersionCount,
      samples: input.inventoryOperations.duplicateVersions.slice(0, 3).map((duplicate) => ({
        pluginId: duplicate.pluginId,
        version: duplicate.version,
        packageCount: duplicate.packageCount,
        packageIds: duplicate.packageIds.slice(0, 5),
        sourceTypes: duplicate.sourceTypes
      }))
    });
  }
  const registrySyncIssues = input.registryOperations.configured.filter((registry) => registry.status !== "synced");
  const registryConfigSamples = [
    ...input.registryOperations.runtimeConfig.invalidUrlConfig.map((env) => ({
      env,
      reason: "invalid_url",
      count: input.registryOperations.runtimeConfig.invalidUrlCount
    })),
    ...input.registryOperations.runtimeConfig.insecureUrlConfig.map((env) => ({
      env,
      reason: "insecure_production_url",
      count: input.registryOperations.runtimeConfig.insecureUrlCount
    })),
    ...input.registryOperations.runtimeConfig.invalidNumericConfig.map((env) => ({
      env,
      reason: "invalid_number"
    }))
  ];
  if (registrySyncIssues.length > 0 || registryConfigSamples.length > 0) {
    remediations.push({
      code: "sync_plugin_registries",
      severity: registrySyncIssues.some((registry) => registry.status === "failed") || input.registryOperations.runtimeConfig.invalidUrlConfig.length > 0 || input.registryOperations.runtimeConfig.invalidNumericConfig.length > 0 ? "error" : "warning",
      action: "Fix plugin registry URL configuration, sync configured registries, and resolve fetch/import errors so marketplace inventory is current.",
      affectedCount: registrySyncIssues.length + input.registryOperations.runtimeConfig.invalidUrlCount + input.registryOperations.runtimeConfig.insecureUrlCount + input.registryOperations.runtimeConfig.invalidNumericConfig.length,
      samples: [
        ...registryConfigSamples,
        ...registrySyncIssues.slice(0, 3).map((registry) => ({
        registryUrl: registry.registryUrl,
        status: registry.status,
        lastErrors: registry.lastErrors.slice(0, 3)
        }))
      ].slice(0, 3)
    });
  }
  if (input.registryOperations.communityDistributionNeedsReviewPolicy) {
    remediations.push({
      code: "require_review_for_community_registries",
      severity: "warning",
      action: "Set OTTE_PLUGIN_REVIEW_POLICY=require_approved before enabling production community plugin registries so every distributed package version gets explicit admin review.",
      affectedCount: input.registryOperations.configuredRegistryCount + input.registryOperations.syncedPackageCount,
      samples: [
        ...input.registryOperations.configured.slice(0, 2).map((registry) => ({
          registryUrl: registry.registryUrl,
          status: registry.status
        })),
        ...input.registryOperations.unconfiguredPackages.slice(0, 2).map((plugin) => ({
          pluginId: plugin.pluginId,
          packageId: plugin.packageId,
          registryUrl: plugin.registryUrl
        }))
      ].slice(0, 3)
    });
  }
  const staleRegistries = input.registryOperations.configured.filter((registry) => registry.status === "synced" && registry.stale);
  if (staleRegistries.length > 0) {
    remediations.push({
      code: "refresh_stale_plugin_registries",
      severity: "warning",
      action: "Refresh stale plugin registries so marketplace package inventory and review state reflect the current upstream catalogs.",
      affectedCount: staleRegistries.length,
      samples: staleRegistries.slice(0, 3).map((registry) => ({
        registryUrl: registry.registryUrl,
        lastSyncAt: registry.lastSyncAt,
        syncAgeSeconds: registry.syncAgeSeconds,
        staleThresholdSeconds: input.registryOperations.staleThresholdSeconds
      }))
    });
  }
  if (input.registryOperations.unconfiguredRegistryPackageCount > 0) {
    remediations.push({
      code: "remove_unconfigured_registry_packages",
      severity: "warning",
      action: "Remove registry-sourced plugin packages whose origin registry is no longer configured, or restore that registry URL.",
      affectedCount: input.registryOperations.unconfiguredRegistryPackageCount,
      samples: input.registryOperations.unconfiguredPackages.slice(0, 3).map((plugin) => ({
        pluginId: plugin.pluginId,
        packageId: plugin.packageId,
        registryUrl: plugin.registryUrl
      }))
    });
  }
  if (input.storage.nearLimitEntries.length > 0) {
    remediations.push({
      code: "trim_plugin_storage_pressure",
      severity: "warning",
      action: "Trim or migrate plugin storage entries near the per-value limit before command writes start failing.",
      affectedCount: input.storage.nearLimitEntries.length,
      samples: input.storage.nearLimitEntries.slice(0, 3).map((entry) => ({
        campaignId: entry.campaignId,
        pluginId: entry.pluginId,
        key: entry.key,
        sizeBytes: entry.sizeBytes,
        maxValueBytes: input.storage.maxValueBytes,
        updatedByType: entry.updatedByType,
        updatedAt: entry.updatedAt
      }))
    });
  }
  return remediations.sort((left, right) => severityRank(right.severity) - severityRank(left.severity) || right.affectedCount - left.affectedCount || left.code.localeCompare(right.code)).slice(0, 12);
}

function pluginCompatibilityOperationsSummary(packages: LoadedPlugin[], installed: ReturnType<typeof pluginOperationalInstall>[]) {
  const incompatiblePackages = packages.filter((plugin) => !pluginCoreRangeSatisfied(plugin.compatibleCore));
  const incompatibleInstalled = installed.filter((plugin) => plugin.status !== "missing_package" && plugin.compatibleCore && !plugin.compatibleCore.satisfied);
  return {
    actionRequired: incompatiblePackages.length > 0 || incompatibleInstalled.length > 0,
    coreVersion: CORE_COMPATIBILITY_VERSION,
    incompatiblePackageCount: incompatiblePackages.length,
    incompatibleInstalledCount: incompatibleInstalled.length,
    packages: incompatiblePackages
      .map((plugin) => ({
        pluginId: plugin.id,
        name: plugin.name,
        version: plugin.version,
        packageId: plugin.source.packageId,
        sourceType: plugin.source.type,
        compatibleCore: plugin.compatibleCore
      }))
      .sort((left, right) => left.pluginId.localeCompare(right.pluginId) || left.version.localeCompare(right.version))
      .slice(0, 20),
    installed: incompatibleInstalled
      .map((plugin) => ({
        campaignId: plugin.campaignId,
        pluginId: plugin.pluginId,
        installedVersion: plugin.installedVersion,
        compatibleCore: plugin.compatibleCore?.range
      }))
      .sort((left, right) => left.pluginId.localeCompare(right.pluginId) || left.campaignId.localeCompare(right.campaignId))
      .slice(0, 20)
  };
}

function pluginRegistryOperationsSummary(store: StateStore, packages: LoadedPlugin[]) {
  const configuredRegistries = configuredPluginRegistryUrls();
  const runtimeConfig = pluginRegistryRuntimeConfig();
  const configuredRegistrySet = new Set(configuredRegistries);
  const registryPackages = packages.filter((plugin) => plugin.source.type === "registry" && plugin.source.registryUrl);
  const packageCountByRegistry = countBy(registryPackages, (plugin) => plugin.source.registryUrl ?? "unknown");
  const latestSyncByRegistry = latestPluginRegistrySyncByRegistry(store);
  const staleThresholdSeconds = pluginRegistryStaleThresholdSeconds();
  const nowMs = Date.now();
  const configured = configuredRegistries.map((registryUrl) => {
    const latestSync = latestSyncByRegistry.get(registryUrl);
    const errorCount = latestSync?.errors.length ?? 0;
    const syncAgeSeconds = latestSync ? timestampAgeSeconds(latestSync.createdAt, nowMs) : undefined;
    const stale = latestSync && errorCount === 0 && typeof syncAgeSeconds === "number" ? syncAgeSeconds >= staleThresholdSeconds : false;
    return {
      registryUrl,
      status: latestSync ? (errorCount > 0 ? "failed" : "synced") : "never_synced",
      syncedPackageCount: packageCountByRegistry[registryUrl] ?? 0,
      lastSyncAt: latestSync?.createdAt,
      syncAgeSeconds,
      stale,
      lastImported: latestSync?.imported ?? [],
      lastErrors: latestSync?.errors ?? []
    };
  });
  const unconfiguredRegistryPackages = registryPackages.filter((plugin) => !configuredRegistrySet.has(plugin.source.registryUrl ?? ""));
  const staleConfiguredRegistries = configured.filter((registry) => registry.stale);
  const syncAges = configured.map((registry) => registry.syncAgeSeconds).filter((age): age is number => typeof age === "number");
  const communityDistributionNeedsReviewPolicy = process.env.NODE_ENV === "production" && pluginReviewPolicyMode() !== "require_approved" && (configuredRegistries.length > 0 || registryPackages.length > 0);
  const actionReasons = [
    runtimeConfig.invalidUrlConfig.length > 0 ? "plugin_registry_url_config_invalid" : undefined,
    runtimeConfig.insecureUrlConfig.length > 0 ? "plugin_registry_url_insecure" : undefined,
    runtimeConfig.invalidNumericConfig.length > 0 ? "plugin_registry_numeric_config_invalid" : undefined,
    communityDistributionNeedsReviewPolicy ? "community_registry_review_policy_permissive" : undefined,
    configured.some((registry) => registry.status === "never_synced") ? "configured_registry_unsynced" : undefined,
    configured.some((registry) => registry.status === "failed") ? "registry_sync_errors" : undefined,
    staleConfiguredRegistries.length > 0 ? "stale_plugin_registry_sync" : undefined,
    unconfiguredRegistryPackages.length > 0 ? "unconfigured_registry_packages" : undefined
  ].filter((reason): reason is string => Boolean(reason));
  return {
    actionRequired: actionReasons.length > 0,
    actionReasons,
    runtimeConfig,
    communityDistributionNeedsReviewPolicy,
    configuredRegistryCount: configuredRegistries.length,
    syncedPackageCount: registryPackages.length,
    staleThresholdSeconds,
    staleConfiguredRegistryCount: staleConfiguredRegistries.length,
    oldestSyncAgeSeconds: syncAges.length > 0 ? Math.max(...syncAges) : 0,
    staleConfiguredRegistries: staleConfiguredRegistries
      .map((registry) => ({
        registryUrl: registry.registryUrl,
        status: registry.status,
        syncedPackageCount: registry.syncedPackageCount,
        lastSyncAt: registry.lastSyncAt,
        syncAgeSeconds: registry.syncAgeSeconds ?? 0
      }))
      .sort((left, right) => right.syncAgeSeconds - left.syncAgeSeconds || left.registryUrl.localeCompare(right.registryUrl))
      .slice(0, 20),
    packageCountByRegistry,
    unconfiguredRegistryPackageCount: unconfiguredRegistryPackages.length,
    unconfiguredPackages: unconfiguredRegistryPackages
      .map((plugin) => ({
        pluginId: plugin.id,
        name: plugin.name,
        version: plugin.version,
        packageId: plugin.source.packageId,
        registryUrl: plugin.source.registryUrl ?? "unknown",
        syncedAt: plugin.source.syncedAt
      }))
      .sort((left, right) => left.registryUrl.localeCompare(right.registryUrl) || left.pluginId.localeCompare(right.pluginId) || left.version.localeCompare(right.version))
      .slice(0, 20),
    configured
  };
}

function pluginRegistryStaleThresholdSeconds() {
  return envNumber("OTTE_PLUGIN_REGISTRY_STALE_SECONDS") ?? PLUGIN_REGISTRY_STALE_SECONDS;
}

function pluginRegistryRuntimeConfig() {
  const entries = (process.env.OTTE_PLUGIN_REGISTRY_URLS ?? "")
    .split(",")
    .map((entry) => entry.trim())
    .filter(Boolean);
  let invalidCount = 0;
  let insecureProductionCount = 0;
  for (const entry of entries) {
    try {
      const url = new URL(entry);
      const valid = url.protocol === "http:" || url.protocol === "https:";
      if (!valid) {
        invalidCount += 1;
        continue;
      }
      if (process.env.NODE_ENV === "production" && url.protocol === "http:" && !isLocalhostRuntimeUrl(url)) insecureProductionCount += 1;
    } catch {
      invalidCount += 1;
    }
  }
  const numericConfig = [
    runtimeNumberEnv("OTTE_PLUGIN_REGISTRY_STALE_SECONDS"),
    runtimeNumberEnv("OTTE_PLUGIN_REGISTRY_TIMEOUT_MS")
  ];
  const invalidNumericConfig = numericConfig.filter((item) => item.configured && item.value === undefined).map((item) => item.name);
  return {
    configuredEntryCount: entries.length,
    validConfiguredCount: configuredPluginRegistryUrls().length,
    invalidUrlConfig: invalidCount > 0 ? ["OTTE_PLUGIN_REGISTRY_URLS"] : [],
    invalidUrlCount: invalidCount,
    insecureUrlConfig: insecureProductionCount > 0 ? ["OTTE_PLUGIN_REGISTRY_URLS"] : [],
    insecureUrlCount: insecureProductionCount,
    invalidNumericConfig
  };
}

function runtimeNumberEnv(name: string): { name: string; configured: boolean; value?: number } {
  const rawValue = process.env[name]?.trim();
  if (!rawValue) return { name, configured: false };
  const value = Number(rawValue);
  return Number.isFinite(value) && value >= 0 ? { name, configured: true, value } : { name, configured: true };
}

function timestampAgeSeconds(value: string, nowMs: number) {
  const timestampMs = Date.parse(value);
  return Number.isFinite(timestampMs) ? Math.max(0, Math.floor((nowMs - timestampMs) / 1000)) : undefined;
}

function latestPluginRegistrySyncByRegistry(store: StateStore) {
  const latest = new Map<string, { registryUrl: string; createdAt: string; imported: string[]; errors: string[] }>();
  const logs = store.state.auditLogs
    .filter((log) => log.action === "admin.pluginRegistry.sync" || log.action === "plugin.registrySync")
    .slice()
    .sort(sortTimestampsDesc);
  for (const log of logs) {
    const registries = pluginRegistrySyncAuditRegistries(log.after);
    for (const registry of registries) {
      if (!latest.has(registry.registryUrl)) latest.set(registry.registryUrl, { ...registry, createdAt: log.createdAt });
    }
  }
  return latest;
}

function pluginRegistrySyncAuditRegistries(value: unknown) {
  if (!isRecord(value) || !Array.isArray(value.registries)) return [];
  return value.registries
    .filter(isRecord)
    .map((registry) => {
      const registryUrl = typeof registry.registryUrl === "string" ? registry.registryUrl : undefined;
      if (!registryUrl) return undefined;
      return {
        registryUrl,
        imported: Array.isArray(registry.imported) ? registry.imported.filter((entry): entry is string => typeof entry === "string") : [],
        errors: Array.isArray(registry.errors)
          ? registry.errors.map((error) => (isRecord(error) && Array.isArray(error.errors) ? error.errors.join("; ") : String(error))).filter(Boolean)
          : []
      };
    })
    .filter((registry): registry is { registryUrl: string; imported: string[]; errors: string[] } => Boolean(registry));
}

function pluginReviewOperationsSummary(plugins: ReturnType<typeof adminPluginReviewSnapshot>["plugins"]) {
  const nowMs = Date.now();
  const pending = plugins.filter((item) => item.review.status === "pending");
  const approved = plugins.filter((item) => item.review.status === "approved");
  const rejected = plugins.filter((item) => item.review.status === "rejected");
  const blocked = plugins.filter((item) => !item.installable);
  const pendingAges = pending
    .map((item) => {
      const createdAt = Date.parse(item.review.createdAt);
      return Number.isFinite(createdAt) ? Math.max(0, Math.floor((nowMs - createdAt) / (24 * 60 * 60 * 1000))) : undefined;
    })
    .filter((age): age is number => age !== undefined);
  return {
    actionRequired: pending.length > 0 || rejected.length > 0 || blocked.length > 0,
    actionReasons: pluginReviewOperationActionReasons(pending.length, rejected.length, blocked.length),
    remediation: pluginReviewOperationRemediation(pending.length, rejected.length, blocked.length),
    approvalCoverageRate: ratio(approved.length, plugins.length),
    pendingCount: pending.length,
    approvedCount: approved.length,
    rejectedCount: rejected.length,
    blockedCount: blocked.length,
    oldestPendingAgeDays: pendingAges.length > 0 ? Math.max(...pendingAges) : 0,
    sourceCounts: countBy(plugins, (item) => item.source.type),
    pendingSamples: pluginReviewOperationSamples(pending, nowMs),
    approvedSamples: pluginReviewOperationSamples(approved, nowMs),
    rejectedSamples: pluginReviewOperationSamples(rejected, nowMs),
    blockedSamples: pluginReviewOperationSamples(blocked, nowMs)
  };
}

function pluginReviewOperationActionReasons(pendingCount: number, rejectedCount: number, blockedCount: number) {
  return [
    pendingCount > 0 ? "pending_marketplace_reviews" : undefined,
    rejectedCount > 0 ? "rejected_marketplace_packages" : undefined,
    blockedCount > 0 ? "blocked_marketplace_packages" : undefined
  ].filter((reason): reason is string => Boolean(reason));
}

function pluginReviewOperationRemediation(pendingCount: number, rejectedCount: number, blockedCount: number) {
  if (pendingCount > 0) return "Approve trusted package versions or reject packages that should not install.";
  if (rejectedCount > 0) return "Confirm rejected packages are intentionally blocked or reset them to pending for re-review.";
  if (blockedCount > 0) return "Resolve trust or review blocks before allowing campaign installation or execution.";
  return "No marketplace review action is required.";
}

function pluginReviewOperationSamples(plugins: ReturnType<typeof adminPluginReviewSnapshot>["plugins"], nowMs: number) {
  return plugins
    .map((item) => {
      const createdAtMs = Date.parse(item.review.createdAt);
      return {
        reviewKey: item.review.reviewKey,
        pluginId: item.plugin.id,
        name: item.plugin.name,
        version: item.plugin.version,
        packageId: item.source.packageId,
        sourceType: item.source.type,
        status: item.review.status,
        installBlock: item.installBlock,
        createdAt: item.review.createdAt,
        ageDays: Number.isFinite(createdAtMs) ? Math.max(0, Math.floor((nowMs - createdAtMs) / (24 * 60 * 60 * 1000))) : 0
      };
    })
    .sort((left, right) => right.ageDays - left.ageDays || left.name.localeCompare(right.name) || left.version.localeCompare(right.version))
    .slice(0, 5);
}

function adminSystemOperations(store: StateStore) {
  const manifests = registeredSystems(store.state);
  const systems = manifests.map((system) => systemOperationsSummary(store, system));
  const issueCount = systems.reduce((total, system) => total + system.issues.length, 0);
  const productionReadiness = systemProductionReadinessSummary(systems);
  const productionGapCounts = systemProductionGapCounts(systems);
  const activityOperations = systemActivityOperationsSummary(store, systems);
  const promotionBlockers = systemPromotionBlockers(systems);
  const actionReasons = systemOperationsActionReasons(issueCount, productionReadiness, activityOperations);
  return {
    generatedAt: nowIso(),
    actionRequired: actionReasons.length > 0,
    actionReasons,
    totals: {
      installedSystemCount: manifests.length,
      activeCampaignCount: store.state.campaigns.length,
      actorCount: store.state.actors.length,
      itemCount: store.state.items.length,
      systemsWithActors: systems.filter((system) => system.usage.actorCount > 0).length,
      systemsWithContentIssues: systems.filter((system) => system.issues.length > 0).length,
      issueCount
    },
    productionReadiness,
    activeSystemCounts: countBy(store.state.campaigns, (campaign) => campaign.defaultSystemId ?? DEFAULT_SYSTEM_ID),
    actorSystemCounts: countBy(store.state.actors, (actor) => actor.systemId),
    itemSystemCounts: countBy(store.state.items, (item) => item.systemId),
    activityOperations,
    productionGapCounts,
    promotionBlockers,
    remediationQueue: systemOperationsRemediationQueue(productionGapCounts, activityOperations),
    systems
  };
}

function systemOperationsActionReasons(issueCount: number, productionReadiness: ReturnType<typeof systemProductionReadinessSummary>, activityOperations: ReturnType<typeof systemActivityOperationsSummary>) {
  return [
    issueCount > 0 ? "system_content_issues" : undefined,
    productionReadiness.actionRequired ? "non_primary_runtime_in_use" : undefined,
    activityOperations.nonPrimaryActivityCount > 0 ? "non_primary_runtime_recent_activity" : undefined
  ].filter(
    (reason): reason is string => Boolean(reason)
  );
}

function systemOperationsSummary(store: StateStore, system: SystemManifest) {
  const templates = hasSystemRuntimeCapability(system.id, "character-templates") ? characterTemplatesForSystem(system.id) : [];
  const compendium = hasSystemRuntimeCapability(system.id, "compendium") ? compendiumEntriesForSystem(system.id) : [];
  const threats = hasSystemRuntimeCapability(system.id, "encounter-builder") ? encounterThreatsForSystem(system.id) : [];
  const activeCampaigns = store.state.campaigns.filter((campaign) => (campaign.defaultSystemId ?? DEFAULT_SYSTEM_ID) === system.id);
  const actors = store.state.actors.filter((actor) => actor.systemId === system.id);
  const items = store.state.items.filter((item) => item.systemId === system.id);
  const issues = systemOperationsIssues(system, templates.length, compendium.length, threats.length);
  const readiness = systemProductionReadiness(system.id, activeCampaigns.length, actors.length, items.length);
  const capabilityEvidence = systemCapabilityEvidence(system.id, compendium, threats);
  const coverage = {
    characterTemplateCount: templates.length,
    compendiumEntryCount: compendium.length,
    compendiumTypeCounts: countBy([...compendium] as Array<{ type: string }>, (entry) => entry.type),
    conditionEntryCount: compendium.filter((entry) => entry.type === "condition").length,
    encounterThreatCount: threats.length,
    supportsOrigins: capabilityEvidence.origins.count > 0,
    supportsMonsterCreation: capabilityEvidence.monsterCreation.count > 0,
    supportsEquipmentPurchase: capabilityEvidence.equipmentPurchase.count > 0,
    supportsCharacterImport: true,
    supportsAdvancement: true,
    supportsRest: true,
    supportsEncounterPlanning: threats.length > 0,
    supportsCompendium: compendium.length > 0,
    capabilityEvidence
  };
  const productionCapability = systemProductionCapabilitySummary(coverage);
  const productionGaps = systemProductionGaps(readiness, coverage, issues);
  return {
    id: system.id,
    name: system.name,
    version: system.version,
    compatibleCore: system.compatibleCore,
    readiness,
    usage: {
      activeCampaignCount: activeCampaigns.length,
      actorCount: actors.length,
      itemCount: items.length,
      actorTypeCounts: countBy(actors, (actor) => actor.type),
      campaignIds: activeCampaigns.map((campaign) => campaign.id)
    },
    manifest: {
      hasClientEntrypoint: Boolean(system.entrypoints.client),
      hasServerEntrypoint: Boolean(system.entrypoints.server),
      hasActorSchema: Boolean(system.schemas.actor),
      hasItemSchema: Boolean(system.schemas.item),
      permissionCount: system.permissions.length,
      permissions: [...system.permissions]
    },
    coverage,
    productionCapability,
    issues,
    productionGaps
  };
}

function systemProductionCapabilitySummary(coverage: {
  characterTemplateCount: number;
  compendiumEntryCount: number;
  conditionEntryCount: number;
  encounterThreatCount: number;
  supportsOrigins: boolean;
  supportsMonsterCreation: boolean;
  supportsEquipmentPurchase: boolean;
  supportsCharacterImport: boolean;
  supportsAdvancement: boolean;
  supportsRest: boolean;
  supportsEncounterPlanning: boolean;
  supportsCompendium: boolean;
  capabilityEvidence?: ReturnType<typeof systemCapabilityEvidence>;
}) {
  const capabilities = [
    {
      code: "character_templates",
      label: "Character templates",
      supported: coverage.characterTemplateCount > 0,
      evidenceCount: coverage.characterTemplateCount,
      remediation: "Add at least one production-ready character template with starting data and items."
    },
    {
      code: "compendium",
      label: "Compendium content",
      supported: coverage.supportsCompendium,
      evidenceCount: coverage.compendiumEntryCount,
      remediation: "Add bounded compendium entries for actions, gear, conditions, and runtime-specific resources."
    },
    {
      code: "conditions",
      label: "Condition catalog",
      supported: coverage.conditionEntryCount > 0,
      evidenceCount: coverage.conditionEntryCount,
      remediation: "Add condition entries plus apply/remove behavior and sheet/roll integration."
    },
    {
      code: "encounter_threats",
      label: "Encounter threats",
      supported: coverage.encounterThreatCount > 0,
      evidenceCount: coverage.encounterThreatCount,
      remediation: "Add threat or bestiary entries with encounter math metadata."
    },
    {
      code: "origin_builder",
      label: "Origin builder",
      supported: coverage.supportsOrigins,
      evidenceCount: coverage.capabilityEvidence?.origins.count ?? 0,
      evidenceSamples: coverage.capabilityEvidence?.origins.samples ?? [],
      remediation: "Add guided background/species or equivalent origin choices with validation."
    },
    {
      code: "monster_creation",
      label: "Monster creation",
      supported: coverage.supportsMonsterCreation,
      evidenceCount: coverage.capabilityEvidence?.monsterCreation.count ?? 0,
      evidenceSamples: coverage.capabilityEvidence?.monsterCreation.samples ?? [],
      remediation: "Wire threat entries into adversary actor creation and action quick rolls."
    },
    {
      code: "equipment_purchase",
      label: "Equipment purchase",
      supported: coverage.supportsEquipmentPurchase,
      evidenceCount: coverage.capabilityEvidence?.equipmentPurchase.count ?? 0,
      evidenceSamples: coverage.capabilityEvidence?.equipmentPurchase.samples ?? [],
      remediation: "Add priced gear, currency mutation, inventory creation, and insufficient-funds checks."
    },
    {
      code: "character_import",
      label: "Character import",
      supported: coverage.supportsCharacterImport,
      evidenceCount: coverage.supportsCharacterImport ? 1 : 0,
      remediation: "Add normalized import with compendium-backed items and conditions."
    },
    {
      code: "advancement",
      label: "Advancement",
      supported: coverage.supportsAdvancement,
      evidenceCount: coverage.supportsAdvancement ? 1 : 0,
      remediation: "Add guided advancement options and validated level-up mutations."
    },
    {
      code: "rest_recovery",
      label: "Rest recovery",
      supported: coverage.supportsRest,
      evidenceCount: coverage.supportsRest ? 1 : 0,
      remediation: "Add short/long rest recovery for HP and system resources."
    },
    {
      code: "encounter_planning",
      label: "Encounter planning",
      supported: coverage.supportsEncounterPlanning,
      evidenceCount: coverage.supportsEncounterPlanning ? coverage.encounterThreatCount : 0,
      remediation: "Add party budget math, threat selection, and optional encounter persistence."
    }
  ];
  const supportedCapabilityCount = capabilities.filter((capability) => capability.supported).length;
  return {
    capabilityCount: capabilities.length,
    supportedCapabilityCount,
    coverageRate: ratio(supportedCapabilityCount, capabilities.length),
    missingCapabilities: capabilities.filter((capability) => !capability.supported).map((capability) => ({
      code: capability.code,
      label: capability.label,
      remediation: capability.remediation
    })),
    capabilities
  };
}

function systemActivityOperationsSummary(
  store: StateStore,
  systems: Array<{ id: string; name: string; readiness: ReturnType<typeof systemProductionReadiness> }>
) {
  const systemById = new Map(systems.map((system) => [system.id, system]));
  const activityLogs = store.state.auditLogs
    .filter((log) => log.action === "system.actor.roll" || log.action === "system.actor.rest" || log.action === "system.actor.advance")
    .sort(sortTimestampsDesc);
  const rows = activityLogs
    .map((log) => {
      const after = isRecord(log.after) ? log.after : {};
      const systemId = typeof after.systemId === "string" ? after.systemId : undefined;
      const system = systemId ? systemById.get(systemId) : undefined;
      return {
        auditLogId: log.id,
        action: log.action,
        campaignId: log.campaignId,
        actorUserId: log.actorUserId,
        systemId,
        systemName: system?.name,
        productionReady: system?.readiness.productionReady ?? false,
        actorId: typeof after.actorId === "string" ? after.actorId : log.targetId,
        actorType: typeof after.actorType === "string" ? after.actorType : undefined,
        rollId: typeof after.rollId === "string" ? after.rollId : undefined,
        label: typeof after.label === "string" ? after.label : undefined,
        restType: typeof after.restType === "string" ? after.restType : undefined,
        optionId: typeof after.optionId === "string" ? after.optionId : undefined,
        consumeResources: after.consumeResources === true,
        applyEffect: after.applyEffect === true,
        hasUsage: after.hasUsage === true,
        hasEffect: after.hasEffect === true,
        createdAt: log.createdAt
      };
    })
    .filter((row) => row.systemId);
  const nonPrimaryRows = rows.filter((row) => !row.productionReady);
  const systemsWithRecentActivity = [...new Set(nonPrimaryRows.map((row) => row.systemId).filter((systemId): systemId is string => Boolean(systemId)))];
  return {
    activityCount: rows.length,
    nonPrimaryActivityCount: nonPrimaryRows.length,
    systemsWithRecentActivity,
    actionCounts: countBy(rows, (row) => row.action),
    nonPrimaryActionCounts: countBy(nonPrimaryRows, (row) => row.action),
    systemCounts: countBy(rows, (row) => row.systemId ?? "unknown"),
    nonPrimarySystemCounts: countBy(nonPrimaryRows, (row) => row.systemId ?? "unknown"),
    recentActivity: rows.slice(0, 12),
    recentNonPrimaryActivity: nonPrimaryRows.slice(0, 12)
  };
}

function systemCapabilityEvidence(systemId: string, compendium: ReadonlyArray<{ id: string; name: string; data?: Record<string, unknown> }>, threats: ReadonlyArray<{ id: string; name: string }>) {
  if (systemId !== DND_5E_SRD_SYSTEM_ID) {
    return {
      origins: { count: 0, samples: [] as string[] },
      monsterCreation: { count: 0, samples: [] as string[] },
      equipmentPurchase: { count: 0, samples: [] as string[] }
    };
  }
  const origins = dnd5eSrdCharacterOrigins();
  const monsterCreationThreats = threats.filter((threat) => Boolean(dnd5eSrdMonsterActorData(threat.id)));
  const purchasableEntries = compendium.filter((entry) => {
    const data = entry.data ?? {};
    return Number.isFinite(Number(data.costGp)) && Number(data.costGp) >= 0 && typeof data.equipmentCategory === "string";
  });
  return {
    origins: {
      count: origins.backgrounds.length + origins.species.length,
      samples: [...origins.backgrounds.slice(0, 2).map((origin) => `background:${origin.id}`), ...origins.species.slice(0, 2).map((origin) => `species:${origin.id}`)]
    },
    monsterCreation: {
      count: monsterCreationThreats.length,
      samples: monsterCreationThreats.slice(0, 4).map((threat) => threat.id)
    },
    equipmentPurchase: {
      count: purchasableEntries.length,
      samples: purchasableEntries.slice(0, 4).map((entry) => entry.id ?? entry.name ?? "unknown")
    }
  };
}

function systemProductionGaps(
  readiness: ReturnType<typeof systemProductionReadiness>,
  coverage: {
    supportsOrigins: boolean;
    supportsMonsterCreation: boolean;
    supportsEquipmentPurchase: boolean;
    supportsEncounterPlanning: boolean;
    supportsCompendium: boolean;
  },
  issues: string[]
) {
  if (readiness.productionReady) return [];
  return [
    ...readiness.reasons,
    ...issues,
    coverage.supportsOrigins ? undefined : "missing_origin_builder",
    coverage.supportsMonsterCreation ? undefined : "missing_monster_creation",
    coverage.supportsEquipmentPurchase ? undefined : "missing_equipment_purchase",
    coverage.supportsEncounterPlanning ? undefined : "missing_encounter_planning",
    coverage.supportsCompendium ? undefined : "missing_compendium_support"
  ].filter((gap): gap is string => Boolean(gap));
}

function systemProductionReadiness(systemId: string, activeCampaignCount: number, actorCount: number, itemCount: number) {
  const productionReady = systemId === DND_5E_SRD_SYSTEM_ID;
  const used = activeCampaignCount > 0 || actorCount > 0 || itemCount > 0;
  return {
    tier: productionReady ? "primary" : "demo",
    productionReady,
    actionRequired: !productionReady && used,
    reasons: productionReady || !used ? [] : ["non_primary_runtime_in_use"]
  };
}

function systemProductionReadinessSummary(
  systems: Array<{
    id: string;
    readiness: ReturnType<typeof systemProductionReadiness>;
    usage: { activeCampaignCount: number; actorCount: number; itemCount: number };
  }>
) {
  const nonPrimaryInUse = systems.filter((system) => system.readiness.actionRequired);
  return {
    primarySystemId: DND_5E_SRD_SYSTEM_ID,
    productionReadySystemCount: systems.filter((system) => system.readiness.productionReady).length,
    demoSystemCount: systems.filter((system) => !system.readiness.productionReady).length,
    nonPrimaryActiveCampaignCount: nonPrimaryInUse.reduce((total, system) => total + system.usage.activeCampaignCount, 0),
    nonPrimaryActorCount: nonPrimaryInUse.reduce((total, system) => total + system.usage.actorCount, 0),
    nonPrimaryItemCount: nonPrimaryInUse.reduce((total, system) => total + system.usage.itemCount, 0),
    systemsNeedingProductionDepth: nonPrimaryInUse.map((system) => system.id),
    actionRequired: nonPrimaryInUse.length > 0
  };
}

function systemProductionGapCounts(
  systems: Array<{
    id: string;
    name: string;
    productionGaps: string[];
    usage: { activeCampaignCount: number; actorCount: number; itemCount: number };
  }>
) {
  const gapCounts = new Map<
    string,
    {
      code: string;
      count: number;
      systems: Array<{ id: string; name: string; activeCampaignCount: number; actorCount: number; itemCount: number }>;
    }
  >();
  for (const system of systems) {
    for (const gap of system.productionGaps) {
      const entry = gapCounts.get(gap) ?? { code: gap, count: 0, systems: [] };
      entry.count += 1;
      entry.systems.push({
        id: system.id,
        name: system.name,
        activeCampaignCount: system.usage.activeCampaignCount,
        actorCount: system.usage.actorCount,
        itemCount: system.usage.itemCount
      });
      gapCounts.set(gap, entry);
    }
  }
  return [...gapCounts.values()]
    .sort((left, right) => right.count - left.count || left.code.localeCompare(right.code))
    .slice(0, 8)
    .map((entry) => {
      const detail = systemProductionGapDetail(entry.code);
      return {
        ...entry,
        ...detail,
        systems: entry.systems
          .sort((left, right) => right.activeCampaignCount + right.actorCount + right.itemCount - (left.activeCampaignCount + left.actorCount + left.itemCount) || left.name.localeCompare(right.name))
          .slice(0, 4)
      };
    });
}

function systemProductionGapDetail(code: string): { severity: "warning" | "critical"; message: string; remediation: string } {
  switch (code) {
    case "non_primary_runtime_in_use":
      return {
        severity: "critical",
        message: "A demo rules runtime is being used by live campaign data.",
        remediation: "Migrate the campaign or harden that runtime to primary-system depth before treating the deployment as Roll20-class."
      };
    case "missing_origin_builder":
      return {
        severity: "warning",
        message: "The runtime does not expose guided character origin choices.",
        remediation: "Add background/species or equivalent origin catalogs and creation-time validation."
      };
    case "missing_monster_creation":
      return {
        severity: "warning",
        message: "The runtime cannot create adversary actors from threat or bestiary entries.",
        remediation: "Add threat stat blocks plus actor creation and action quick-roll wiring."
      };
    case "missing_equipment_purchase":
      return {
        severity: "warning",
        message: "The runtime lacks a first-class equipment purchase flow.",
        remediation: "Add priced compendium entries, currency mutation, inventory creation, and insufficient-funds checks."
      };
    case "missing_encounter_planning":
      return {
        severity: "warning",
        message: "The runtime has no encounter-planning threat budget support.",
        remediation: "Add threat catalogs, party budget math, and optional encounter persistence."
      };
    case "missing_compendium_support":
      return {
        severity: "warning",
        message: "The runtime lacks compendium-backed content.",
        remediation: "Add bounded compendium entries for actions, gear, conditions, and runtime-specific resources."
      };
    default:
      return {
        severity: "warning",
        message: "The runtime has an unresolved manifest or content issue.",
        remediation: "Inspect the system manifest, schemas, templates, compendium entries, and encounter threats for this gap code."
      };
  }
}

function systemPromotionBlockers(
  systems: Array<{
    id: string;
    name: string;
    readiness: ReturnType<typeof systemProductionReadiness>;
    usage: { activeCampaignCount: number; actorCount: number; itemCount: number };
    productionGaps: string[];
  }>
) {
  return systems
    .filter((system) => !system.readiness.productionReady && system.productionGaps.length > 0)
    .map((system) => {
      const blockers = system.productionGaps.map((gap) => ({ code: gap, ...systemProductionGapDetail(gap) }));
      return {
        systemId: system.id,
        name: system.name,
        activeCampaignCount: system.usage.activeCampaignCount,
        actorCount: system.usage.actorCount,
        itemCount: system.usage.itemCount,
        blockerCount: blockers.length,
        criticalBlockerCount: blockers.filter((blocker) => blocker.severity === "critical").length,
        blockers
      };
    })
    .sort(
      (left, right) =>
        right.criticalBlockerCount - left.criticalBlockerCount ||
        right.activeCampaignCount + right.actorCount + right.itemCount - (left.activeCampaignCount + left.actorCount + left.itemCount) ||
        right.blockerCount - left.blockerCount ||
        left.name.localeCompare(right.name)
    )
    .slice(0, 8);
}

function systemOperationsRemediationQueue(gapCounts: ReturnType<typeof systemProductionGapCounts>, activityOperations?: ReturnType<typeof systemActivityOperationsSummary>) {
  const remediations = gapCounts
    .map((gap) => ({
      code: gap.code,
      severity: gap.severity,
      action: gap.remediation,
      affectedCount: gap.count,
      message: gap.message,
      samples: gap.systems.map((system) => ({
        systemId: system.id,
        name: system.name,
        activeCampaignCount: system.activeCampaignCount,
        actorCount: system.actorCount,
        itemCount: system.itemCount
      }))
    }))
  if (activityOperations && activityOperations.nonPrimaryActivityCount > 0) {
    remediations.push({
      code: "non_primary_runtime_recent_activity",
      severity: "critical",
      action: "Review recent demo-runtime rolls, rests, and advancement before promoting or migrating those campaigns.",
      affectedCount: activityOperations.nonPrimaryActivityCount,
      message: "A demo rules runtime is actively handling recent table operations.",
      samples: activityOperations.recentNonPrimaryActivity.slice(0, 4).map((activity) => ({
        systemId: activity.systemId ?? "unknown",
        name: activity.systemName ?? activity.systemId ?? "Unknown system",
        activeCampaignCount: activity.campaignId ? 1 : 0,
        actorCount: activity.actorId ? 1 : 0,
        itemCount: 0,
        action: activity.action,
        actorId: activity.actorId,
        createdAt: activity.createdAt
      }))
    });
  }
  return remediations
    .sort((left, right) => (right.severity === "critical" ? 2 : 1) - (left.severity === "critical" ? 2 : 1) || right.affectedCount - left.affectedCount || left.code.localeCompare(right.code))
    .slice(0, 8);
}

function systemOperationsIssues(system: SystemManifest, templateCount: number, compendiumCount: number, threatCount: number): string[] {
  return [
    system.entrypoints.client ? undefined : "missing_client_entrypoint",
    system.entrypoints.server ? undefined : "missing_server_entrypoint",
    system.schemas.actor ? undefined : "missing_actor_schema",
    system.schemas.item ? undefined : "missing_item_schema",
    templateCount > 0 ? undefined : "missing_character_templates",
    compendiumCount > 0 ? undefined : "missing_compendium_entries",
    threatCount > 0 ? undefined : "missing_encounter_threats"
  ].filter((issue): issue is string => Boolean(issue));
}

async function syncPluginRegistriesForRequest(pluginRegistry: PluginRuntimeRegistry, registryUrl: string | undefined, reply: FastifyReply) {
  const configuredRegistries = configuredPluginRegistryUrls();
  if (!configuredRegistries.length) return badRequest(reply, "No plugin registries are configured");
  const requestedRegistry = registryUrl ? normalizeConfiguredPluginRegistryUrl(registryUrl) : undefined;
  if (registryUrl && !requestedRegistry) return badRequest(reply, "Plugin registryUrl must be a valid http or https URL");
  if (requestedRegistry && !configuredRegistries.includes(requestedRegistry)) return forbidden(reply, "Plugin registryUrl is not configured for this server");
  const registryUrls = requestedRegistry ? [requestedRegistry] : configuredRegistries;
  const registries = [];
  for (const url of registryUrls) registries.push(await pluginRegistry.syncRemoteRegistry(url));
  const imported = registries.flatMap((registry) => registry.imported);
  return {
    syncedAt: nowIso(),
    registries,
    plugins: imported
  };
}

function pluginOperationalInstall(store: StateStore, pluginRegistry: PluginRuntimeRegistry, grant: PermissionGrant) {
  const installedVersion = pluginVersionFromGrant(grant);
  const plugin = pluginRegistry.find(grant.subjectId, installedVersion);
  const storageEntryCount = store.state.pluginStorage.filter((entry) => entry.campaignId === grant.campaignId && entry.pluginId === grant.subjectId).length;
  if (!plugin) {
    return {
      campaignId: grant.campaignId,
      pluginId: grant.subjectId,
      installedVersion,
      status: "missing_package" as const,
      grantedPermissions: [...grant.permissions],
      missingManifestPermissions: [],
      storageEntryCount,
      issues: ["installed_plugin_package_missing"]
    };
  }
  const compatibleCore = pluginCoreCompatibilityInfo(plugin);
  const reviewBlock = pluginReviewInstallBlock(store, plugin);
  const trustBlock = plugin.trust.installable ? undefined : pluginTrustErrorMessage(plugin);
  const identityBlock = pluginGrantIdentityBlock(grant, plugin);
  const missingManifestPermissions = plugin.permissions.filter((permission) => !grant.permissions.includes(permission));
  const compatibilityBlock = pluginCoreCompatibilityBlock(plugin);
  const issues = [trustBlock ? "trust_policy_blocked" : undefined, reviewBlock ? "marketplace_review_blocked" : undefined, identityBlock ? "package_identity_drift" : undefined, missingManifestPermissions.length > 0 ? "manifest_permission_not_granted" : undefined, compatibilityBlock ? "core_compatibility_drift" : undefined].filter((issue): issue is string => Boolean(issue));
  return {
    campaignId: grant.campaignId,
    pluginId: plugin.id,
    name: plugin.name,
    installedVersion: plugin.version,
    latestVersion: plugin.distribution.latestVersion,
    updateAvailable: plugin.version !== plugin.distribution.latestVersion,
    status: trustBlock || reviewBlock || identityBlock || compatibilityBlock ? ("blocked" as const) : ("healthy" as const),
    grantedPermissions: [...grant.permissions],
    requestedPermissions: [...plugin.permissions],
    missingManifestPermissions,
    compatibleCore,
    source: { ...plugin.source },
    trust: { ...plugin.trust, errors: [...plugin.trust.errors], signature: plugin.trust.signature ? { ...plugin.trust.signature } : undefined },
    marketplaceReview: publicPluginReviewInfo(plugin, pluginReviewForDisplay(store, plugin)),
    storageEntryCount,
    issues,
    blocks: [trustBlock, reviewBlock, identityBlock, compatibilityBlock].filter((block): block is string => Boolean(block))
  };
}

function pluginCoreCompatibilityInfo(plugin: LoadedPlugin): { range: string; coreVersion: string; satisfied: boolean } {
  return {
    range: plugin.compatibleCore,
    coreVersion: CORE_COMPATIBILITY_VERSION,
    satisfied: pluginCoreRangeSatisfied(plugin.compatibleCore)
  };
}

function pluginCoreCompatibilityBlock(plugin: LoadedPlugin): string | undefined {
  const compatibleCore = pluginCoreCompatibilityInfo(plugin);
  return compatibleCore.satisfied ? undefined : `Plugin requires core ${compatibleCore.range}; server core is ${compatibleCore.coreVersion}`;
}

function pluginCoreRangeSatisfied(range: string): boolean {
  return pluginCoreCompatibility(range, CORE_COMPATIBILITY_VERSION).satisfied;
}

function publicPluginReviewInfo(plugin: LoadedPlugin, review: PluginReview): AdminPluginReviewInfo {
  const installBlock = pluginReviewInstallBlockForReview(plugin, review);
  return {
    review: { ...review },
    plugin: {
      id: plugin.id,
      name: plugin.name,
      version: plugin.version,
      permissions: [...plugin.permissions],
      chatCommands: plugin.chatCommands
    },
    source: { ...plugin.source },
    distribution: { availableVersions: [...plugin.distribution.availableVersions], latestVersion: plugin.distribution.latestVersion },
    trust: { ...plugin.trust, errors: [...plugin.trust.errors], signature: plugin.trust.signature ? { ...plugin.trust.signature } : undefined },
    installable: !installBlock,
    ...(installBlock ? { installBlock } : {})
  };
}

function publicPluginCatalogInfo(plugin: LoadedPlugin): PublicPluginCatalogInfo {
  return {
    id: plugin.id,
    name: plugin.name,
    version: plugin.version,
    compatibleCore: plugin.compatibleCore,
    ...(plugin.package
      ? {
          package: {
            publisher: plugin.package.publisher,
            license: plugin.package.license
          }
        }
      : {}),
    ...(plugin.runtime
      ? {
          runtime: {
            apiVersion: plugin.runtime.apiVersion,
            sandbox: plugin.runtime.sandbox
          }
        }
      : {}),
    permissions: [...plugin.permissions],
    ...(plugin.ui
      ? {
          ui: {
            panels: plugin.ui.panels?.map((panel) => ({ ...panel }))
          }
        }
      : {}),
    ...(plugin.chatCommands ? { chatCommands: plugin.chatCommands.map((command) => ({ ...command })) } : {}),
    ...(plugin.eventSubscriptions ? { eventSubscriptions: plugin.eventSubscriptions.map((subscription) => ({ ...subscription })) } : {}),
    source: {
      type: plugin.source.type,
      packageId: plugin.source.packageId,
      manifestChecksum: plugin.source.manifestChecksum,
      sandbox: plugin.source.sandbox,
      checksum: plugin.source.checksum,
      packageChecksum: plugin.source.packageChecksum,
      syncedAt: plugin.source.syncedAt
    },
    distribution: {
      availableVersions: [...plugin.distribution.availableVersions],
      latestVersion: plugin.distribution.latestVersion
    },
    permissionReview: {
      requestedPermissions: [...plugin.permissionReview.requestedPermissions],
      grantRequired: plugin.permissionReview.grantRequired
    },
    trust: publicPluginTrustInfo(plugin)
  };
}

function publicPluginTrustInfo(plugin: LoadedPlugin): PublicPluginCatalogInfo["trust"] {
  return {
    status: plugin.trust.status,
    policy: plugin.trust.policy,
    required: plugin.trust.required,
    installable: plugin.trust.installable,
    errors: [...plugin.trust.errors],
    ...(plugin.trust.signature
      ? {
          signature: {
            keyId: plugin.trust.signature.keyId,
            algorithm: plugin.trust.signature.algorithm,
            verified: plugin.trust.signature.verified
          }
        }
      : {})
  };
}

function marketplacePluginReviewInfo(plugin: LoadedPlugin, review: PluginReview): MarketplacePluginReviewInfo {
  const installBlock = pluginReviewInstallBlockForReview(plugin, review);
  return {
    review: {
      id: review.id,
      reviewKey: review.reviewKey,
      pluginId: review.pluginId,
      packageId: review.packageId,
      version: review.version,
      checksum: review.checksum,
      sourceType: review.sourceType,
      status: review.status,
      reviewedAt: review.reviewedAt,
      createdAt: review.createdAt,
      updatedAt: review.updatedAt
    },
    installable: !installBlock,
    ...(installBlock ? { installBlock } : {})
  };
}

function ensurePluginReview(store: StateStore, plugin: LoadedPlugin): PluginReview {
  const reviewKey = pluginReviewKey(plugin);
  const existing = store.state.pluginReviews.find((review) => review.reviewKey === reviewKey);
  if (existing) return syncPluginReviewMetadata(existing, plugin);
  const review = createPluginReview(plugin);
  store.state.pluginReviews.push(review);
  return review;
}

function pluginReviewForDisplay(store: StateStore, plugin: LoadedPlugin): PluginReview {
  const existing = store.state.pluginReviews.find((review) => review.reviewKey === pluginReviewKey(plugin));
  return existing ? syncPluginReviewMetadata(existing, plugin) : createPluginReview(plugin);
}

function syncPluginReviewMetadata(review: PluginReview, plugin: LoadedPlugin): PluginReview {
  review.pluginId = plugin.id;
  review.packageId = plugin.source.packageId;
  review.version = plugin.version;
  review.checksum = pluginReviewChecksum(plugin);
  review.sourceType = plugin.source.type;
  review.registryUrl = plugin.source.registryUrl;
  review.packageUrl = plugin.source.packageUrl;
  return review;
}

function createPluginReview(plugin: LoadedPlugin): PluginReview {
  return createTimestamped("plugrev", {
    reviewKey: pluginReviewKey(plugin),
    pluginId: plugin.id,
    packageId: plugin.source.packageId,
    version: plugin.version,
    checksum: pluginReviewChecksum(plugin),
    sourceType: plugin.source.type,
    registryUrl: plugin.source.registryUrl,
    packageUrl: plugin.source.packageUrl,
    status: "pending" as const
  }) satisfies PluginReview;
}

function updatePluginReview(review: PluginReview, status: PluginReviewStatus, notes: string | undefined, adminUserId: string): void {
  review.status = status;
  review.notes = notes;
  if (status === "pending") {
    review.reviewedAt = undefined;
    review.reviewedByUserId = undefined;
  } else {
    review.reviewedAt = nowIso();
    review.reviewedByUserId = adminUserId;
  }
  review.updatedAt = nowIso();
}

function pluginReviewInstallBlock(store: StateStore, plugin: LoadedPlugin): string | undefined {
  return pluginReviewInstallBlockForReview(plugin, ensurePluginReview(store, plugin));
}

function pluginReviewInstallBlockForReview(plugin: LoadedPlugin, review: PluginReview): string | undefined {
  if (review.status === "rejected") {
    return `Plugin ${plugin.id}@${plugin.version} was rejected by marketplace review`;
  }
  if (pluginRequiresReviewApproval(plugin) && review.status !== "approved") {
    return `Plugin ${plugin.id}@${plugin.version} requires marketplace approval before install or execution; current review status is ${review.status}`;
  }
  return undefined;
}

function pluginRequiresReviewApproval(plugin: LoadedPlugin): boolean {
  return pluginReviewPolicyMode() === "require_approved" || (process.env.NODE_ENV === "production" && plugin.source.type === "registry");
}

function pluginReviewKey(plugin: LoadedPlugin): string {
  return createHash("sha256").update([plugin.id, plugin.version, plugin.source.packageId, pluginReviewChecksum(plugin)].join("\n")).digest("hex");
}

function pluginReviewChecksum(plugin: LoadedPlugin): string {
  return pluginPackageIdentityChecksum(plugin);
}

function pluginReviewPolicyMode(): PluginReviewPolicyMode {
  return process.env.OTTE_PLUGIN_REVIEW_POLICY === "require_approved" ? "require_approved" : "allow_unreviewed";
}

function normalizePluginReviewStatus(value: unknown): PluginReviewStatus | undefined {
  return value === "pending" || value === "approved" || value === "rejected" ? value : undefined;
}

function normalizePluginReviewNotes(value: unknown): string | undefined | false {
  if (value === undefined || value === null) return undefined;
  if (typeof value !== "string") return false;
  const notes = value.trim();
  if (notes.length > 500) return false;
  return notes || undefined;
}

function pluginCampaignAuditSummary(store: StateStore, campaignId: string, pluginId: string): { installCount: number; lastInstallAt?: string; versions: string[] } {
  const installLogs = store.state.auditLogs
    .filter((log) => log.campaignId === campaignId && log.action === "plugin.install" && log.targetType === "plugin" && log.targetId === pluginId)
    .sort((left, right) => right.createdAt.localeCompare(left.createdAt));
  const versions = [...new Set(installLogs.map((log) => (isRecord(log.after) && typeof log.after.version === "string" ? log.after.version : undefined)).filter((version): version is string => Boolean(version)))];
  return {
    installCount: installLogs.length,
    lastInstallAt: installLogs[0]?.createdAt,
    versions
  };
}

function pluginCampaignInfo(
  store: StateStore,
  pluginRegistry: PluginRuntimeRegistry,
  campaignId: string,
  plugin: LoadedPlugin
): CampaignPluginCatalogInfo {
  const grant = findPluginGrant(store, campaignId, plugin.id);
  const installedVersion = pluginVersionFromGrant(grant);
  const installedPlugin = installedVersion ? pluginRegistry.find(plugin.id, installedVersion) : undefined;
  const displayPlugin = installedPlugin ?? plugin;
  const latestVersion = plugin.distribution.latestVersion;
  const availableVersions = plugin.distribution.availableVersions;
  const versionCompatibility = availableVersions.flatMap((version) => {
    const versionPlugin = pluginRegistry.find(plugin.id, version);
    if (!versionPlugin) return [];
    const compatibilityBlock = pluginCoreCompatibilityBlock(versionPlugin);
    const publicVersion = publicPluginCatalogInfo(versionPlugin);
    const versionReview = marketplacePluginReviewInfo(versionPlugin, pluginReviewForDisplay(store, versionPlugin));
    return [
      {
        version,
        compatibleCore: pluginCoreCompatibilityInfo(versionPlugin),
        permissions: [...versionPlugin.permissions],
        permissionReview: publicVersion.permissionReview,
        trust: publicVersion.trust,
        source: publicVersion.source,
        marketplaceReview: {
          installable: versionReview.installable,
          status: versionReview.review.status,
          ...(versionReview.installBlock ? { installBlock: versionReview.installBlock } : {})
        },
        ...(compatibilityBlock ? { compatibilityBlock } : {})
      }
    ];
  });
  return {
    ...publicPluginCatalogInfo(displayPlugin),
    distribution: {
      availableVersions: [...plugin.distribution.availableVersions],
      latestVersion: plugin.distribution.latestVersion
    },
    installed: Boolean(grant),
    grantedPermissions: grant?.permissions ?? [],
    missingPermissions: displayPlugin.permissions.filter((permission) => !grant?.permissions.includes(permission)),
    installedVersion,
    updateAvailable: Boolean(grant && installedVersion && installedVersion !== latestVersion),
    rollbackVersions: grant ? availableVersions.filter((version) => version !== installedVersion) : [],
    marketplaceReview: marketplacePluginReviewInfo(displayPlugin, pluginReviewForDisplay(store, displayPlugin)),
    compatibleCore: pluginCoreCompatibilityInfo(displayPlugin),
    ...(pluginCoreCompatibilityBlock(displayPlugin) ? { compatibilityBlock: pluginCoreCompatibilityBlock(displayPlugin) } : {}),
    versionCompatibility,
    audit: pluginCampaignAuditSummary(store, campaignId, plugin.id)
  };
}

function reviewedPluginPermissions(plugin: LoadedPlugin, requestedPermissions?: PermissionName[]): PermissionName[] | undefined {
  if (!requestedPermissions) return [...plugin.permissions];
  const uniquePermissions = [...new Set(requestedPermissions)];
  if (uniquePermissions.some((permission) => !plugin.permissions.includes(permission))) return undefined;
  return uniquePermissions;
}

function pluginInstallMetadata(plugin: LoadedPlugin): Record<string, unknown> {
  return {
    packageId: plugin.source.packageId,
    version: plugin.version,
    checksum: pluginPackageIdentityChecksum(plugin),
    manifestChecksum: plugin.source.manifestChecksum,
    runtimeChecksum: plugin.source.checksum,
    trust: publicPluginTrustInfo(plugin),
    installedAt: nowIso()
  };
}

function configuredPluginRegistryUrls(): string[] {
  const urls = (process.env.OTTE_PLUGIN_REGISTRY_URLS ?? "")
    .split(",")
    .map((entry) => normalizeConfiguredPluginRegistryUrl(entry))
    .filter((entry): entry is string => Boolean(entry));
  return [...new Set(urls)];
}

function normalizeConfiguredPluginRegistryUrl(value: string): string | undefined {
  const trimmed = value.trim();
  if (!trimmed) return undefined;
  try {
    const url = new URL(trimmed);
    if (url.protocol !== "http:" && url.protocol !== "https:") return undefined;
    return url.toString();
  } catch {
    return undefined;
  }
}

function pluginVersionFromGrant(grant: PermissionGrant | undefined): string | undefined {
  const metadata = grant?.metadata;
  if (!isRecord(metadata)) return undefined;
  return typeof metadata.version === "string" ? metadata.version : undefined;
}

function pluginGrantIdentityBlock(grant: PermissionGrant | undefined, plugin: LoadedPlugin): string | undefined {
  if (!grant) return undefined;
  const metadata = grant.metadata;
  const installedPackageId = isRecord(metadata) && typeof metadata.packageId === "string" ? metadata.packageId : undefined;
  const installedVersion = isRecord(metadata) && typeof metadata.version === "string" ? metadata.version : undefined;
  const installedChecksum = isRecord(metadata) && typeof metadata.checksum === "string" ? metadata.checksum : undefined;
  if (
    installedPackageId === plugin.source.packageId &&
    installedVersion === plugin.version &&
    installedChecksum !== undefined &&
    installedChecksum === pluginPackageIdentityChecksum(plugin)
  ) {
    return undefined;
  }
  return `Installed plugin ${plugin.id} package identity no longer matches the reviewed grant; reinstall the intended package before execution`;
}

function pluginTrustErrorMessage(plugin: LoadedPlugin): string {
  const reason = plugin.trust.errors.length ? plugin.trust.errors.join("; ") : `Plugin trust status is ${plugin.trust.status}`;
  return `Plugin ${plugin.id} is not installable under the current trust policy: ${reason}`;
}

function findSystemActor(store: StateStore, campaignId: string, systemId: string, actorId: string): Actor | undefined {
  return store.state.actors.find((actor) => actor.id === actorId && actor.campaignId === campaignId && actor.systemId === systemId);
}

function hasSystemRuntimeCapability(systemId: string, capability: SystemCapability): boolean {
  return systemRuntimeCapabilities(systemId).includes(capability);
}

function assertSystemRuntimeCapability(systemId: string, capability: SystemCapability): void {
  if (!hasSystemRuntimeCapability(systemId, capability)) throw new UnsupportedSystemCapabilityError(systemId, capability);
}

function systemRuntimeInfo(store: { state: Pick<EngineState, "systemInstallations"> }, system: SystemManifest, active = false) {
  const installation = systemInstallationByManifestId(store.state, system.id);
  const runtimeCapabilities = systemRuntimeCapabilities(system.id);
  return {
    ...system,
    active,
    source: isBundledSystem(system.id) ? "bundled" as const : "api" as const,
    dataDriven: !isBundledSystem(system.id),
    runtimeCapabilities,
    unsupportedCapabilities: system.capabilities.filter((capability) => !runtimeCapabilities.includes(capability)),
    installedAt: installation?.createdAt
  };
}

function systemRequirementsForCampaign(store: StateStore, campaignId: string) {
  const campaign = store.state.campaigns.find((item) => item.id === campaignId);
  const ids = new Set<string>();
  if (campaign?.defaultSystemId) ids.add(campaign.defaultSystemId);
  for (const actor of store.state.actors) if (actor.campaignId === campaignId) ids.add(actor.systemId);
  for (const item of store.state.items) if (item.campaignId === campaignId) ids.add(item.systemId);
  return registeredSystems(store.state)
    .filter((system) => ids.has(system.id))
    .map(({ id, name, version, compatibleCore, capabilities }) => ({ id, name, version, compatibleCore, capabilities }))
    .sort((left, right) => left.id.localeCompare(right.id));
}

function compendiumEntriesForSystem(systemId: string) {
  if (systemId === DND_5E_SRD_SYSTEM_ID) return dnd5eSrdCompendium();
  if (systemId === "generic-fantasy") return genericFantasyCompendium();
  if (systemId === "stellar-frontiers") return stellarFrontiersCompendium();
  if (systemId === "mystic-noir") return mysticNoirCompendium();
  assertSystemRuntimeCapability(systemId, "compendium");
  return [];
}

function compendiumEntryForSystem(systemId: string, entryId: string) {
  if (systemId === DND_5E_SRD_SYSTEM_ID) return dnd5eSrdCompendiumEntry(entryId);
  if (systemId === "generic-fantasy") return genericFantasyCompendiumEntry(entryId);
  if (systemId === "stellar-frontiers") return stellarFrontiersCompendiumEntry(entryId);
  if (systemId === "mystic-noir") return mysticNoirCompendiumEntry(entryId);
  assertSystemRuntimeCapability(systemId, "compendium");
  return undefined;
}

function characterTemplatesForSystem(systemId: string): CharacterTemplate[] {
  if (systemId === DND_5E_SRD_SYSTEM_ID) return dnd5eSrdCharacterTemplates();
  if (systemId === "generic-fantasy") return genericFantasyCharacterTemplates();
  if (systemId === "stellar-frontiers") return stellarFrontiersCharacterTemplates();
  if (systemId === "mystic-noir") return mysticNoirCharacterTemplates();
  assertSystemRuntimeCapability(systemId, "character-templates");
  return [];
}

function createTemplateItems(campaignId: string, actor: Actor, template: CharacterTemplate): Item[] {
  return template.items.flatMap((templateItem) => {
    const entry = compendiumEntryForSystem(template.systemId, templateItem.entryId);
    if (!entry || entry.type === "condition") return [];
    return [
      createTimestamped("itm", {
        campaignId,
        systemId: template.systemId,
        actorId: actor.id,
        type: entry.type,
        name: entry.name,
        data: { ...cloneRecord(entry.data), ...(templateItem.data ? cloneRecord(templateItem.data) : {}), compendiumId: entry.id, quantity: templateItem.quantity ?? 1 }
      }) satisfies Item
    ];
  });
}

function characterImportForSystem(systemId: string, input: CharacterImportInput): CharacterImportResult {
  if (systemId === DND_5E_SRD_SYSTEM_ID) return dnd5eSrdCharacterImport(input);
  if (systemId === "generic-fantasy") return genericFantasyCharacterImport(input);
  if (systemId === "stellar-frontiers") return stellarFrontiersCharacterImport(input);
  if (systemId === "mystic-noir") return mysticNoirCharacterImport(input);
  assertSystemRuntimeCapability(systemId, "character-import");
  throw new UnsupportedSystemCapabilityError(systemId, "character-import");
}

function createImportedItems(campaignId: string, actor: Actor, imported: CharacterImportResult): Item[] {
  return imported.items.flatMap((importedItem) => {
    const entry = compendiumEntryForSystem(imported.systemId, importedItem.entryId);
    if (!entry || entry.type === "condition") return [];
    return [
      createTimestamped("itm", {
        campaignId,
        systemId: imported.systemId,
        actorId: actor.id,
        type: entry.type,
        name: entry.name,
        data: { ...cloneRecord(entry.data), ...(importedItem.data ? cloneRecord(importedItem.data) : {}), compendiumId: entry.id, quantity: importedItem.quantity ?? 1 }
      }) satisfies Item
    ];
  });
}

function systemSheet(actor: Actor, items: Item[]) {
  if (actor.systemId === DND_5E_SRD_SYSTEM_ID) return dnd5eSrdSheet(actor, items);
  if (actor.systemId === "generic-fantasy") return genericFantasySheet(actor, items);
  if (actor.systemId === "stellar-frontiers") return stellarFrontiersSheet(actor, items);
  if (actor.systemId === "mystic-noir") return mysticNoirSheet(actor, items);
  throw new UnsupportedSystemCapabilityError(actor.systemId, "actor-sheet");
}

function systemQuickRolls(actor: Actor, items: Item[] = []) {
  if (actor.systemId === DND_5E_SRD_SYSTEM_ID) return dnd5eSrdQuickRolls(actor, items);
  if (actor.systemId === "generic-fantasy") return genericFantasyQuickRolls(actor, items);
  if (actor.systemId === "stellar-frontiers") return stellarFrontiersQuickRolls(actor, items);
  if (actor.systemId === "mystic-noir") return mysticNoirQuickRolls(actor, items);
  throw new UnsupportedSystemCapabilityError(actor.systemId, "quick-rolls");
}

function systemActionOptions(spellSlotLevel: number | undefined, resourceAmount?: number, useFreeResource?: boolean): SystemActionUseOptions {
  return { spellSlotLevel, resourceAmount, useFreeResource };
}

function systemActionFormula(actor: Actor, items: Item[], rollId: string, options: SystemActionUseOptions): string | undefined {
  if (actor.systemId === DND_5E_SRD_SYSTEM_ID) return dnd5eSrdActionFormula(actor, items, rollId, options);
  if (actor.systemId === "generic-fantasy") return genericFantasyActionFormula(actor, items, rollId, options);
  if (actor.systemId === "stellar-frontiers" || actor.systemId === "mystic-noir") return undefined;
  assertSystemRuntimeCapability(actor.systemId, "actions");
  return undefined;
}

function useSystemAction(actor: Actor, items: Item[], rollId: string, options: SystemActionUseOptions = {}): SystemActionUseResult {
  if (actor.systemId === DND_5E_SRD_SYSTEM_ID) return useDnd5eSrdAction(actor, items, rollId, options);
  if (actor.systemId === "generic-fantasy") return useGenericFantasyAction(actor, items, rollId, options);
  if (actor.systemId === "stellar-frontiers") return useStellarFrontiersAction(actor, items, rollId);
  if (actor.systemId === "mystic-noir") return useMysticNoirAction(actor, items, rollId);
  throw new UnsupportedSystemCapabilityError(actor.systemId, "actions");
}

function applySystemCondition(actor: Actor, conditionId: string, appliedAt?: string, options: { level?: unknown } = {}): Record<string, unknown> {
  if (actor.systemId === DND_5E_SRD_SYSTEM_ID) return applyDnd5eSrdCondition(actor, conditionId, appliedAt, options);
  if (actor.systemId === "generic-fantasy") return applyGenericFantasyCondition(actor, conditionId, appliedAt);
  if (actor.systemId === "stellar-frontiers") return applyStellarFrontiersCondition(actor, conditionId, appliedAt);
  if (actor.systemId === "mystic-noir") return applyMysticNoirCondition(actor, conditionId, appliedAt);
  throw new UnsupportedSystemCapabilityError(actor.systemId, "conditions");
}

function removeSystemCondition(actor: Actor, conditionId: string): Record<string, unknown> {
  if (actor.systemId === DND_5E_SRD_SYSTEM_ID) return removeDnd5eSrdCondition(actor, conditionId);
  if (actor.systemId === "generic-fantasy") return removeGenericFantasyCondition(actor, conditionId);
  if (actor.systemId === "stellar-frontiers") return removeStellarFrontiersCondition(actor, conditionId);
  if (actor.systemId === "mystic-noir") return removeMysticNoirCondition(actor, conditionId);
  throw new UnsupportedSystemCapabilityError(actor.systemId, "conditions");
}

function advancementOptionsForActor(actor: Actor) {
  if (actor.systemId === DND_5E_SRD_SYSTEM_ID) return dnd5eSrdAdvancementOptions(actor);
  if (actor.systemId === "generic-fantasy") return genericFantasyAdvancementOptions(actor);
  if (actor.systemId === "stellar-frontiers") return stellarFrontiersAdvancementOptions(actor);
  if (actor.systemId === "mystic-noir") return mysticNoirAdvancementOptions(actor);
  throw new UnsupportedSystemCapabilityError(actor.systemId, "advancement");
}

function applySystemAdvancement(actor: Actor, optionId: string): Record<string, unknown> {
  if (actor.systemId === DND_5E_SRD_SYSTEM_ID) return applyDnd5eSrdAdvancement(actor, optionId);
  if (actor.systemId === "generic-fantasy") return applyGenericFantasyAdvancement(actor, optionId);
  if (actor.systemId === "stellar-frontiers") return applyStellarFrontiersAdvancement(actor, optionId);
  if (actor.systemId === "mystic-noir") return applyMysticNoirAdvancement(actor, optionId);
  throw new UnsupportedSystemCapabilityError(actor.systemId, "advancement");
}

function applySystemRest(actor: Actor, restType: SystemRestType, options: SystemRestOptions = {}): SystemRestResult {
  if (actor.systemId === DND_5E_SRD_SYSTEM_ID) return applyDnd5eSrdRest(actor, restType, options);
  if (actor.systemId === "generic-fantasy") return applyGenericFantasyRest(actor, restType);
  if (actor.systemId === "stellar-frontiers") return applyStellarFrontiersRest(actor, restType);
  if (actor.systemId === "mystic-noir") return applyMysticNoirRest(actor, restType);
  throw new UnsupportedSystemCapabilityError(actor.systemId, "rest");
}

function encounterThreatsForSystem(systemId: string) {
  if (systemId === DND_5E_SRD_SYSTEM_ID) return dnd5eSrdEncounterThreats();
  if (systemId === "stellar-frontiers") return stellarFrontiersEncounterThreats();
  if (systemId === "mystic-noir") return mysticNoirEncounterThreats();
  if (systemId === "generic-fantasy") return genericFantasyEncounterThreats();
  assertSystemRuntimeCapability(systemId, "encounter-builder");
  return [];
}

function encounterPlanForSystem(systemId: string, party: Actor[], threats: EncounterThreatSelection[]): EncounterPlan {
  if (systemId === DND_5E_SRD_SYSTEM_ID) return dnd5eSrdEncounterPlan(party, threats);
  if (systemId === "generic-fantasy") return genericFantasyEncounterPlan(party, threats);
  if (systemId === "stellar-frontiers") return stellarFrontiersEncounterPlan(party, threats);
  if (systemId === "mystic-noir") return mysticNoirEncounterPlan(party, threats);
  throw new UnsupportedSystemCapabilityError(systemId, "encounter-builder");
}

function partyActorsForSystem(store: StateStore, campaignId: string, systemId: string, actorIds?: string[]): Actor[] {
  const selectedIds = actorIds === undefined ? undefined : new Set(actorIds);
  return store.state.actors.filter((actor) => actor.campaignId === campaignId && actor.systemId === systemId && actor.type === "character" && (!selectedIds || selectedIds.has(actor.id)));
}

function cloneRecord(value: Record<string, unknown>): Record<string, unknown> {
  return JSON.parse(JSON.stringify(value)) as Record<string, unknown>;
}

function titleCase(value: string): string {
  return value.charAt(0).toUpperCase() + value.slice(1);
}

function actorItems(store: StateStore, actor: Actor): Item[] {
  return store.state.items.filter((item) => item.actorId === actor.id && item.campaignId === actor.campaignId);
}

function boundedDeathSaveCount(value: unknown): number {
  const parsed = Math.floor(Number(value ?? 0));
  if (!Number.isFinite(parsed)) return 0;
  return Math.max(0, Math.min(3, parsed));
}

function applyCombatantRulesAutomation(combatant: Combat["combatants"][number]): Combat["combatants"][number] {
  const deathSaveSuccesses = boundedDeathSaveCount(combatant.deathSaveSuccesses);
  const deathSaveFailures = boundedDeathSaveCount(combatant.deathSaveFailures);
  const deathSaveOutcome = deathSaveFailures >= 3 ? "dead" : deathSaveSuccesses >= 3 ? "stable" : undefined;
  let conditions = normalizeCombatantConditionList(combatant.conditions).filter((condition) => condition !== "dead" && condition !== "stable");
  const hadConcentration = conditions.some(isCombatantConcentrationCondition);
  const concentrationBroken =
    hadConcentration &&
    (deathSaveOutcome !== undefined || combatant.defeated === true || conditions.some(isCombatantConcentrationBreakingCondition));
  if (concentrationBroken) {
    conditions = conditions.filter((condition) => !isCombatantConcentrationCondition(condition));
    if (!conditions.includes("concentration lost")) conditions.push("concentration lost");
  }
  if (deathSaveOutcome === "dead") conditions.push("dead");
  if (deathSaveOutcome === "stable") conditions.push("stable");
  return {
    ...combatant,
    defeated: deathSaveOutcome === "dead" ? true : combatant.defeated,
    conditions,
    deathSaveSuccesses,
    deathSaveFailures,
    deathSaveOutcome
  };
}

function normalizeCombatantConditionList(conditions: string[] | undefined): string[] {
  return [...new Set((conditions ?? []).map((condition) => condition.trim().toLowerCase()).filter(Boolean))];
}

function combatantConditionBase(condition: string): string {
  return condition.split(":")[0]?.trim() ?? condition.trim();
}

function isCombatantConcentrationCondition(condition: string): boolean {
  const base = combatantConditionBase(condition);
  return base === "concentration" || base === "concentrating";
}

function isCombatantConcentrationBreakingCondition(condition: string): boolean {
  return ["incapacitated", "stunned", "unconscious", "paralyzed", "petrified", "dead"].includes(combatantConditionBase(condition));
}

function advanceTimedCombatantConditions(combatants: Combat["combatants"], roundDelta: number): Combat["combatants"] {
  if (roundDelta <= 0) return combatants;
  return combatants.map((combatant) => applyCombatantRulesAutomation({
    ...combatant,
    conditions: normalizeCombatantConditionList(combatant.conditions).flatMap((condition) => advanceTimedCombatantCondition(condition, roundDelta))
  }));
}

function advanceTimedCombatantCondition(condition: string, roundDelta: number): string[] {
  const match = condition.match(/^(.+?):(\d+)$/);
  if (!match) return [condition];
  const name = match[1]?.trim();
  const duration = Number(match[2]);
  if (!name || !Number.isFinite(duration)) return [condition];
  const remaining = duration - roundDelta;
  return remaining > 0 ? [`${name}:${remaining}`] : [];
}

function syncCombatantToActorSheet(actor: Actor, previousCombatant: Combat["combatants"][number], combatant: Combat["combatants"][number], syncedAt: string): string | undefined {
  const data = cloneRecord(actor.data);
  const resourceResult = applyCombatantResourceUsage(data, previousCombatant, combatant);
  if (resourceResult.error) return resourceResult.error;
  data.conditions = (combatant.conditions ?? []).map((condition) => ({
    id: condition,
    appliedAt: syncedAt
  }));
  data.deathSaves = {
    successes: boundedDeathSaveCount(combatant.deathSaveSuccesses),
    failures: boundedDeathSaveCount(combatant.deathSaveFailures)
  };
  data.combatState = {
    combatantId: combatant.id,
    tokenId: combatant.tokenId,
    readiness: combatant.readiness ?? "normal",
    defeated: Boolean(combatant.defeated),
    deathSaveOutcome: combatant.deathSaveOutcome,
    resourceKey: combatant.resourceKey,
    resourceLabel: combatant.resourceLabel,
    resourceUsed: Boolean(combatant.resourceUsed),
    resourceSpent: resourceResult.spent,
    syncedAt
  };
  actor.data = data;
  actor.updatedAt = syncedAt;
  return undefined;
}

function applyCombatantResourceUsage(data: Record<string, unknown>, previousCombatant: Combat["combatants"][number], combatant: Combat["combatants"][number]): { spent: boolean; error?: string } {
  const resourceKey = typeof combatant.resourceKey === "string" ? combatant.resourceKey : undefined;
  if (!resourceKey || previousCombatant.resourceUsed === combatant.resourceUsed) return { spent: Boolean(combatant.resourceUsed) };
  const resources = isRecord(data.resources) ? { ...data.resources } : {};
  const currentResource = resources[resourceKey];
  if (combatant.resourceUsed) {
    const spent = spendActorResource(resources, resourceKey, currentResource);
    if (!spent) return { spent: false, error: `Resource unavailable: ${combatant.resourceLabel ?? resourceKey}` };
    data.resources = resources;
    combatant.resourceSpent = true;
    return { spent: true };
  }
  restoreActorResource(resources, resourceKey, currentResource);
  data.resources = resources;
  combatant.resourceSpent = false;
  return { spent: false };
}

function spendActorResource(resources: Record<string, unknown>, resourceKey: string, currentResource: unknown): boolean {
  if (typeof currentResource === "number") {
    if (currentResource <= 0) return false;
    resources[resourceKey] = currentResource - 1;
    return true;
  }
  if (!isRecord(currentResource)) return false;
  const current = Number(currentResource.current ?? 0);
  if (!Number.isFinite(current) || current <= 0) return false;
  resources[resourceKey] = { ...currentResource, current: current - 1 };
  return true;
}

function restoreActorResource(resources: Record<string, unknown>, resourceKey: string, currentResource: unknown): void {
  if (typeof currentResource === "number") {
    resources[resourceKey] = currentResource + 1;
    return;
  }
  if (!isRecord(currentResource)) return;
  const current = Number(currentResource.current ?? 0);
  const max = Number(currentResource.max ?? Number.POSITIVE_INFINITY);
  const nextCurrent = Number.isFinite(max) ? Math.min(max, current + 1) : current + 1;
  resources[resourceKey] = { ...currentResource, current: nextCurrent };
}

function canUpdateActorForUser(store: StateStore, userId: string, actor: Actor): boolean {
  return canCampaign(store, userId, actor.campaignId, "actor.update") || (actor.ownerUserId === userId && canCampaign(store, userId, actor.campaignId, "actor.updateOwned"));
}

function broadcastActorUpdated(broadcast: (event: EngineEvent) => void, actor: Actor): void {
  broadcast(
    createEvent({
      campaignId: actor.campaignId,
      type: "actor.updated",
      targetId: actor.id,
      payload: actor
    })
  );
}

function truthyQuery(value: string | undefined): boolean {
  return value === "1" || value === "true" || value === "yes";
}

function normalizeAssetMimeType(value: string | string[] | undefined): string {
  const contentType = Array.isArray(value) ? value[0] : value;
  const mimeType = contentType?.split(";")[0]?.trim().toLowerCase();
  return mimeType && mimeType.length > 0 ? mimeType : "application/octet-stream";
}

function displayNameFromHeader(value: string | string[] | undefined): string | undefined {
  const raw = Array.isArray(value) ? value[0] : value;
  if (!raw) return undefined;
  const decoded = safeDecodeURIComponent(raw);
  return basename(decoded).trim() || undefined;
}

function headerText(value: string | string[] | undefined): string | undefined {
  const raw = Array.isArray(value) ? value[0] : value;
  return raw ? safeDecodeURIComponent(raw).trim() : undefined;
}

function opaqueHeaderText(value: string | string[] | undefined): string | undefined {
  const raw = Array.isArray(value) ? value[0] : value;
  return raw && raw.length > 0 ? raw : undefined;
}

function normalizeAssetFolder(value: unknown): string | undefined {
  return typeof value === "string" && value.trim() ? value.trim().slice(0, 80) : undefined;
}

function normalizeGeneratedAssetName(value: unknown, kind: "map" | "token"): string {
  return typeof value === "string" && value.trim() ? value.trim().slice(0, 120) : kind === "map" ? "AI Generated Map" : "AI Generated Token";
}

function gridlessMapGenerationPrompt(prompt: string): string {
  return [
    prompt.trim(),
    "",
    "Render this as a clean gridless virtual tabletop background.",
    "Do not include square grids, hex grids, coordinates, labels, tokens, miniatures, UI chrome, or measurement markings; the VTT will overlay its own grid and tokens."
  ].join("\n");
}

function normalizeAssetTags(value: unknown): string[] {
  const values = Array.isArray(value) ? value : typeof value === "string" ? value.split(",") : [];
  return [...new Set(values.filter((item): item is string => typeof item === "string").map((item) => item.trim()).filter(Boolean).map((item) => item.slice(0, 40)))].slice(0, 12);
}

function tokenArtReuseKeyForRequest(request: Record<string, unknown>, token: Token | undefined, actor: Actor | undefined): string | undefined {
  const explicit = normalizeTokenArtReuseKey(stringFromRecord(request, "reuseKey"));
  if (explicit) return explicit;
  if (actor?.type === "monster") return normalizeTokenArtReuseKey(actor.name.replace(/\s+\d+$/, ""));
  if (token?.disposition === "hostile") return normalizeTokenArtReuseKey(token.name.replace(/\s+\d+$/, ""));
  return actor ? normalizeTokenArtReuseKey(actor.id) : undefined;
}

function normalizeTokenArtReuseKey(value: string | undefined): string | undefined {
  const normalized = value
    ?.trim()
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/^-+|-+$/g, "")
    .slice(0, 34);
  return normalized || undefined;
}

function reusableTokenArtAsset(context: AiToolContext, reuseKey: string): MapAsset | undefined {
  const tag = `reuse:${reuseKey}`;
  return context.state.assets
    .filter((asset) => asset.campaignId === context.campaignId)
    .filter((asset) => asset.mimeType.startsWith("image/"))
    .filter((asset) => asset.lifecycle?.status !== "deleted")
    .filter((asset) => asset.tags?.includes(tag))
    .sort((left, right) => right.updatedAt.localeCompare(left.updatedAt) || right.createdAt.localeCompare(left.createdAt))[0];
}

function tokenArtAssetTags(actor: Actor | undefined, token: Token | undefined, reuseKey: string | undefined): string[] {
  const tags = ["ai", "generated", "token", actor && actorIsAdversary(actor, token) ? "adversary" : "character"];
  if (reuseKey) tags.push(`reuse:${reuseKey}`);
  return normalizeAssetTags(tags);
}

function rosterActorArtPrompt(actor: Actor, adversary: boolean): string {
  return [
    `${actor.name}, ${adversary ? "adversary creature" : actor.type || "tabletop character"} token portrait.`,
    "Create a centered virtual tabletop token/portrait asset with a clean silhouette, no text, no UI, and no background grid."
  ].join("\n");
}

function actorIsAdversary(actor: Actor, token: Token | undefined): boolean {
  const type = actor.type.toLowerCase();
  if (type === "monster" || type === "adversary" || type === "enemy") return true;
  const role = stringFromRecord(actor.data, "role")?.toLowerCase() ?? stringFromRecord(actor.data, "category")?.toLowerCase();
  return role === "adversary" || role === "enemy" || role === "monster" || token?.disposition === "hostile";
}

const assetSecurityScanner = "builtin-asset-scanner";
const externalAssetSecurityScanner = "external-asset-scanner";
const eicarSignature = "EICAR-STANDARD-ANTIVIRUS-TEST-FILE";
const disallowedAssetMimeTypes = new Set([
  "text/html",
  "application/xhtml+xml",
  "application/javascript",
  "text/javascript",
  "application/x-javascript",
  "application/x-msdownload",
  "application/x-msdos-program",
  "application/x-sh",
  "application/x-bat",
  "application/java-archive"
]);
const disallowedAssetExtensions = new Set([".html", ".htm", ".js", ".mjs", ".exe", ".dll", ".bat", ".cmd", ".ps1", ".sh", ".com", ".scr", ".jar"]);

interface AssetSecurityScanResult {
  scanner: string;
  findings: AssetSecurityFinding[];
  blocked: boolean;
  security?: AssetSecurityScan;
}

interface ExternalAssetScannerResponse {
  status?: string;
  scanner?: string;
  findings?: unknown[];
}

async function scanUploadedAsset(body: Buffer, mimeType: string, sourceName: string): Promise<AssetSecurityScanResult> {
  const builtin = scanUploadedAssetBuiltIn(body, mimeType, sourceName);
  if (builtin.blocked) return builtin;
  const external = await scanUploadedAssetExternal(body, mimeType, sourceName);
  if (!external) return builtin;
  if (external.blocked) return external;
  return {
    scanner: combinedAssetSecurityScanner(builtin.scanner, external.scanner),
    findings: [...builtin.findings, ...external.findings],
    blocked: false,
    security: {
      status: "clean",
      scanner: combinedAssetSecurityScanner(builtin.scanner, external.scanner),
      scannedAt: nowIso(),
      findings: [...builtin.findings, ...external.findings]
    }
  };
}

function scanUploadedAssetBuiltIn(body: Buffer, mimeType: string, sourceName: string): AssetSecurityScanResult {
  const findings: AssetSecurityFinding[] = [];
  const extension = extname(sourceName).toLowerCase();
  const text = body.toString("utf8");
  const lowerText = text.toLowerCase();

  if (text.includes(eicarSignature)) {
    findings.push({
      code: "malware_signature",
      severity: "high",
      message: "Upload matched the EICAR malware test signature"
    });
  }

  if (disallowedAssetMimeTypes.has(mimeType) || disallowedAssetExtensions.has(extension) || looksLikeExecutableMarkup(lowerText)) {
    findings.push({
      code: "disallowed_asset_type",
      severity: "high",
      message: "Executable, script, or HTML uploads are not allowed as map assets"
    });
  }

  if (isSvgUpload(mimeType, extension, lowerText) && hasActiveSvgContent(lowerText)) {
    findings.push({
      code: "active_svg_content",
      severity: "high",
      message: "SVG uploads cannot contain scripts, event handlers, javascript URLs, or foreignObject content"
    });
  }

  if (findings.length > 0) {
    return { scanner: assetSecurityScanner, findings, blocked: true };
  }

  return {
    scanner: assetSecurityScanner,
    findings: [],
    blocked: false,
    security: {
      status: "clean",
      scanner: assetSecurityScanner,
      scannedAt: nowIso(),
      findings: []
    }
  };
}

async function scanUploadedAssetExternal(body: Buffer, mimeType: string, sourceName: string): Promise<AssetSecurityScanResult | undefined> {
  const url = process.env.OTTE_ASSET_TRUST_WEBHOOK_URL?.trim();
  if (!url) return undefined;
  const scanner = process.env.OTTE_ASSET_TRUST_SCANNER_NAME?.trim() || externalAssetSecurityScanner;
  try {
    const response = await postExternalAssetScan(url, body, mimeType, sourceName);
    return externalAssetScanResult(response, scanner);
  } catch (error) {
    const finding: AssetSecurityFinding = {
      code: "external_scanner_unavailable",
      severity: "high",
      message: `External asset scanner failed: ${errorMessage(error)}`
    };
    if (assetTrustFailClosed()) {
      return {
        scanner,
        findings: [finding],
        blocked: true
      };
    }
    return {
      scanner,
      findings: [{ ...finding, severity: "medium" }],
      blocked: false,
      security: {
        status: "clean",
        scanner,
        scannedAt: nowIso(),
        findings: [{ ...finding, severity: "medium" }]
      }
    };
  }
}

async function postExternalAssetScan(url: string, body: Buffer, mimeType: string, sourceName: string): Promise<ExternalAssetScannerResponse> {
  const controller = new AbortController();
  const timer = setTimeout(() => controller.abort(), assetTrustWebhookTimeoutMs());
  try {
    const headers: Record<string, string> = {
      "content-type": "application/json"
    };
    const token = process.env.OTTE_ASSET_TRUST_WEBHOOK_TOKEN?.trim();
    if (token) headers.authorization = `Bearer ${token}`;
    const response = await fetch(url, {
      method: "POST",
      headers,
      signal: controller.signal,
      body: JSON.stringify({
        name: sourceName,
        mimeType,
        sizeBytes: body.length,
        checksum: checksumForBuffer(body),
        contentBase64: body.toString("base64")
      })
    });
    if (!response.ok) throw new Error(`scanner_http_${response.status}`);
    return (await response.json()) as ExternalAssetScannerResponse;
  } finally {
    clearTimeout(timer);
  }
}

function externalAssetScanResult(response: ExternalAssetScannerResponse, fallbackScanner: string): AssetSecurityScanResult {
  const scanner = typeof response.scanner === "string" && response.scanner.trim() ? response.scanner.trim().slice(0, 80) : fallbackScanner;
  const findings = normalizeExternalAssetFindings(response.findings);
  const status = response.status?.trim().toLowerCase();
  if (status !== "clean" && status !== "blocked") throw new Error("scanner_invalid_status");
  if (status === "blocked" || findings.some((finding) => finding.severity === "high")) {
    return {
      scanner,
      findings: findings.length > 0 ? findings : [{ code: "external_scanner_blocked", severity: "high", message: "External asset scanner blocked upload" }],
      blocked: true
    };
  }
  return {
    scanner,
    findings,
    blocked: false,
    security: {
      status: "clean",
      scanner,
      scannedAt: nowIso(),
      findings
    }
  };
}

function normalizeExternalAssetFindings(value: unknown[] | undefined): AssetSecurityFinding[] {
  if (!Array.isArray(value)) return [];
  return value.slice(0, 20).map((item): AssetSecurityFinding | undefined => {
    if (!item || typeof item !== "object") return undefined;
    const record = item as Record<string, unknown>;
    const severity = normalizeAssetSecuritySeverity(record.severity);
    const code = typeof record.code === "string" && record.code.trim() ? record.code.trim().slice(0, 80) : "external_scanner_finding";
    const message = typeof record.message === "string" && record.message.trim() ? record.message.trim().slice(0, 240) : "External asset scanner finding";
    return { code, severity, message };
  }).filter((finding): finding is AssetSecurityFinding => Boolean(finding));
}

function normalizeAssetSecuritySeverity(value: unknown): AssetSecurityFinding["severity"] {
  const normalized = typeof value === "string" ? value.trim().toLowerCase() : "";
  return normalized === "low" || normalized === "medium" || normalized === "high" ? normalized : "high";
}

function combinedAssetSecurityScanner(left: string, right: string): string {
  return left === right ? left : `${left}+${right}`;
}

function assetTrustWebhookTimeoutMs(): number {
  const configured = Number(process.env.OTTE_ASSET_TRUST_TIMEOUT_MS);
  return Number.isFinite(configured) && configured > 0 ? Math.min(Math.floor(configured), 30_000) : 5_000;
}

function assetRuntimeNumberEnv(name: string): { name: string; configured: boolean; value?: number } {
  const rawValue = process.env[name]?.trim();
  if (!rawValue) return { name, configured: false };
  const value = Number(rawValue);
  return Number.isFinite(value) && value >= 0 ? { name, configured: true, value } : { name, configured: true };
}

function invalidAssetRuntimeConfigEnvNames(): string[] {
  return [
    "OTTE_ASSET_QUOTA_BYTES",
    "OTTE_ASSET_RETENTION_DAYS",
    "OTTE_ASSET_URL_TTL_SECONDS",
    "OTTE_ASSET_URL_MAX_TTL_SECONDS",
    "OTTE_ASSET_CDN_PURGE_TIMEOUT_MS",
    "OTTE_ASSET_TRUST_TIMEOUT_MS",
    "OTTE_ASSET_CLEANUP_GRACE_DAYS",
    "OTTE_ASSET_CLEANUP_INTERVAL_SECONDS"
  ]
    .map(assetRuntimeNumberEnv)
    .filter((item) => item.configured && item.value === undefined)
    .map((item) => item.name);
}

function assetRuntimeUrlEnv(name: string): { name: string; configured: boolean; valid: boolean } {
  const rawValue = process.env[name]?.trim();
  if (!rawValue) return { name, configured: false, valid: true };
  try {
    const url = new URL(rawValue);
    return { name, configured: true, valid: url.protocol === "http:" || url.protocol === "https:" };
  } catch {
    return { name, configured: true, valid: false };
  }
}

function isLocalhostRuntimeUrl(url: URL): boolean {
  return url.hostname === "localhost" || url.hostname === "127.0.0.1" || url.hostname === "::1";
}

function invalidAssetRuntimeUrlEnvNames(): string[] {
  return [
    "OTTE_ASSET_CDN_BASE_URL",
    "OTTE_PUBLIC_URL",
    "OTTE_ASSET_CDN_PURGE_WEBHOOK_URL",
    "OTTE_ASSET_TRUST_WEBHOOK_URL"
  ]
    .map(assetRuntimeUrlEnv)
    .filter((item) => item.configured && !item.valid)
    .map((item) => item.name);
}

function insecureProductionAssetRuntimeUrlEnvNames(): string[] {
  if (process.env.NODE_ENV !== "production") return [];
  return [
    "OTTE_ASSET_CDN_BASE_URL",
    "OTTE_PUBLIC_URL",
    "OTTE_ASSET_CDN_PURGE_WEBHOOK_URL",
    "OTTE_ASSET_TRUST_WEBHOOK_URL"
  ].filter((name) => {
    const rawValue = process.env[name]?.trim();
    if (!rawValue) return false;
    try {
      const url = new URL(rawValue);
      return url.protocol === "http:" && !isLocalhostRuntimeUrl(url);
    } catch {
      return false;
    }
  });
}

function assetRuntimeTokenMissingEnvNames(): string[] {
  if (process.env.NODE_ENV !== "production") return [];
  const tokenPairs = [
    { urlEnv: "OTTE_ASSET_CDN_PURGE_WEBHOOK_URL", tokenEnv: "OTTE_ASSET_CDN_PURGE_WEBHOOK_TOKEN" },
    { urlEnv: "OTTE_ASSET_TRUST_WEBHOOK_URL", tokenEnv: "OTTE_ASSET_TRUST_WEBHOOK_TOKEN" }
  ];
  return tokenPairs
    .filter(({ urlEnv, tokenEnv }) => {
      const urlConfig = assetRuntimeUrlEnv(urlEnv);
      return urlConfig.configured && urlConfig.valid && !envText(tokenEnv);
    })
    .map(({ tokenEnv }) => tokenEnv);
}

function configuredAssetStorageProvider(): string {
  return (process.env.OTTE_ASSET_STORAGE ?? "local").toLowerCase();
}

function assetS3RuntimeEnvRelevant(activeStorage: AssetStorage): boolean {
  const configuredProvider = configuredAssetStorageProvider();
  return (
    activeStorage.provider === "s3" &&
    (configuredProvider === "s3" ||
      configuredProvider === "minio" ||
      Boolean(envText("OTTE_S3_BUCKET")) ||
      Boolean(envText("OTTE_S3_ENDPOINT")) ||
      Boolean(envText("OTTE_S3_ACCESS_KEY_ID")) ||
      Boolean(envText("OTTE_S3_SECRET_ACCESS_KEY")))
  );
}

function assetS3EndpointRuntimeConfig(): { configured: boolean; valid: boolean; insecureInProduction: boolean } {
  const endpoint = envText("OTTE_S3_ENDPOINT");
  if (!endpoint) return { configured: false, valid: true, insecureInProduction: false };
  try {
    const url = new URL(endpoint);
    const valid = url.protocol === "http:" || url.protocol === "https:";
    const insecureInProduction = process.env.NODE_ENV === "production" && url.protocol === "http:" && !isLocalhostRuntimeUrl(url);
    return { configured: true, valid, insecureInProduction };
  } catch {
    return { configured: true, valid: false, insecureInProduction: false };
  }
}

function assetS3RuntimeConfig(activeStorage: AssetStorage): AssetS3RuntimeConfig | undefined {
  if (activeStorage.provider !== "s3" && configuredAssetStorageProvider() !== "s3" && configuredAssetStorageProvider() !== "minio") return undefined;
  const endpoint = assetS3EndpointRuntimeConfig();
  const accessKeyConfigured = Boolean(envText("OTTE_S3_ACCESS_KEY_ID"));
  const secretKeyConfigured = Boolean(envText("OTTE_S3_SECRET_ACCESS_KEY"));
  return {
    configuredProvider: configuredAssetStorageProvider(),
    active: activeStorage.provider === "s3",
    bucketConfigured: Boolean(envText("OTTE_S3_BUCKET")),
    endpointConfigured: endpoint.configured,
    endpointValid: endpoint.valid,
    endpointInsecureInProduction: endpoint.insecureInProduction,
    regionConfigured: Boolean(envText("OTTE_S3_REGION")),
    forcePathStyle: envBoolean("OTTE_S3_FORCE_PATH_STYLE", endpoint.configured),
    explicitCredentialsConfigured: accessKeyConfigured && secretKeyConfigured,
    partialExplicitCredentials: accessKeyConfigured !== secretKeyConfigured
  };
}

function assetTrustFailClosed(): boolean {
  return envBoolean("OTTE_ASSET_TRUST_FAIL_CLOSED", true);
}

function assetSecurityBlocked(reply: FastifyReply, result: AssetSecurityScanResult): FastifyReply {
  return reply.code(422).send({
    error: "asset_security_blocked",
    message: "Asset upload failed security scan",
    scanner: result.scanner,
    findings: result.findings
  });
}

function isSvgUpload(mimeType: string, extension: string, lowerText: string): boolean {
  return mimeType === "image/svg+xml" || extension === ".svg" || lowerText.includes("<svg");
}

function hasActiveSvgContent(lowerText: string): boolean {
  return lowerText.includes("<script") || /\son[a-z]+\s*=/.test(lowerText) || lowerText.includes("javascript:") || lowerText.includes("<foreignobject");
}

function looksLikeExecutableMarkup(lowerText: string): boolean {
  return /^\s*<!doctype\s+html\b/.test(lowerText) || /^\s*<html\b/.test(lowerText) || /^\s*<script\b/.test(lowerText);
}

